// === JS.html (1,251,044 chars) ===
    // STATE
    let products = [];
    let customers = [];
    let allCustomers = [];

    // O(1) lookup indexes — rebuilt by setProducts()/setCustomers()
    let productBySku = new Map();
    let productByBarcode = new Map();
    let customerById = new Map();

    /** Central setter: updates products array + rebuilds SKU/barcode indexes */
    function setProducts(data) {
        products = data || [];
        productBySku = new Map();
        productByBarcode = new Map();
        for (var i = 0; i < products.length; i++) {
            var p = products[i];
            if (p.sku) productBySku.set(p.sku, p);
            if (p.barcode) productByBarcode.set(p.barcode, p);
        }
    }

    /** Decode compact {h:[keys], r:[[values]]} → array of objects */
    function decodeCompact(compact) {
        if (!compact || !compact.h || !compact.r) return [];
        var h = compact.h, rows = compact.r, result = [];
        for (var i = 0; i < rows.length; i++) {
            var obj = {};
            for (var j = 0; j < h.length; j++) obj[h[j]] = rows[i][j];
            result.push(obj);
        }
        return result;
    }

    /** Central setter: updates allCustomers + rebuilds ID index */
    function setCustomers(data) {
        allCustomers = data || [];
        customerById = new Map();
        for (var i = 0; i < allCustomers.length; i++) {
            if (allCustomers[i].id) customerById.set(allCustomers[i].id, allCustomers[i]);
            if (allCustomers[i].id) customerById.set(String(allCustomers[i].id), allCustomers[i]);
        }
    }
