    // Local Storage Helper
    const LocalStore = {
        get: (key) => {
            try {
                const item = localStorage.getItem(key);
                return item ? JSON.parse(item) : null;
            } catch (e) {
                console.error('LocalStore get error:', e);
                return null;
            }
        },
        set: (key, value) => {
            try {
                localStorage.setItem(key, JSON.stringify(value));
            } catch (e) {
                console.error('LocalStore set error:', e);
            }
        },
        getVersion: (type) => {
            return localStorage.getItem('VERSION_' + type) || '0';
        },
        setVersion: (type, version) => {
            localStorage.setItem('VERSION_' + type, version);
            // Clear IndexedDB when version resets (mutation happened)
            if (version === '0') {
                IDBCache.remove(type === 'PRODUCTS' ? 'products' : type === 'CUSTOMERS' ? 'customers' : type.toLowerCase());
            }
        },
        // Cache with TTL (seconds) — cho dashboard, orders
        getTTL: (key) => {
            try {
                var raw = localStorage.getItem('TTL_' + key);
                if (!raw) return null;
                var obj = JSON.parse(raw);
                if (Date.now() > obj.exp) { localStorage.removeItem('TTL_' + key); return null; }
                return obj.data;
            } catch(e) { return null; }
        },
        setTTL: (key, value, ttlSeconds) => {
            try {
                localStorage.setItem('TTL_' + key, JSON.stringify({ data: value, exp: Date.now() + ttlSeconds * 1000 }));
            } catch(e) {}
        }
    };

    // IndexedDB Cache — persistent, 50MB+, ~1-5ms reads
    const IDBCache = (() => {
        const DB_NAME = 'SalesAppCache';
        const DB_VERSION = 1;
        const STORE_NAME = 'cache';
        let dbPromise = null;

        function openDB() {
            if (dbPromise) return dbPromise;
            dbPromise = new Promise((resolve, reject) => {
                const request = indexedDB.open(DB_NAME, DB_VERSION);
                request.onupgradeneeded = (e) => {
                    const db = e.target.result;
                    if (!db.objectStoreNames.contains(STORE_NAME)) {
                        db.createObjectStore(STORE_NAME);
                    }
                };
                request.onsuccess = () => resolve(request.result);
                request.onerror = () => { dbPromise = null; reject(request.error); };
            });
            return dbPromise;
        }

        return {
            // Get cached data (returns null if expired or missing)
            get: async (key) => {
                try {
                    const db = await openDB();
                    return new Promise((resolve) => {
                        const tx = db.transaction(STORE_NAME, 'readonly');
                        const req = tx.objectStore(STORE_NAME).get(key);
                        req.onsuccess = () => {
                            const row = req.result;
                            if (!row) return resolve(null);
                            if (row.exp && Date.now() > row.exp) return resolve(null);
                            resolve(row.data);
                        };
                        req.onerror = () => resolve(null);
                    });
                } catch (e) { return null; }
            },

            // Set cached data with TTL (seconds)
            set: async (key, data, ttlSeconds) => {
                try {
                    const db = await openDB();
                    const tx = db.transaction(STORE_NAME, 'readwrite');
                    tx.objectStore(STORE_NAME).put({
                        data: data,
                        exp: ttlSeconds ? Date.now() + ttlSeconds * 1000 : 0
                    }, key);
                } catch (e) { /* silently fail */ }
            },

            // Remove specific key
            remove: async (key) => {
                try {
                    const db = await openDB();
                    const tx = db.transaction(STORE_NAME, 'readwrite');
                    tx.objectStore(STORE_NAME).delete(key);
                } catch (e) { /* silently fail */ }
            },

            // Clear all cache
            clear: async () => {
                try {
                    const db = await openDB();
                    const tx = db.transaction(STORE_NAME, 'readwrite');
                    tx.objectStore(STORE_NAME).clear();
                } catch (e) { /* silently fail */ }
            }
        };
    })();

    // Flag to skip duplicate dashboard load when getInitialData already loaded it
