    // === Order Status Helpers (supports dynamic statuses from SystemSettings) ===
    // Known status → Vietnamese label mapping
    var STATUS_LABELS = {
        'Pending': 'Đang xử lý',
        'Completed': 'Hoàn thành',
        'Cancelled': 'Đã hủy',
        'chuẩn bị hàng': 'Chuẩn bị hàng',
        'đang ship': 'Đang ship'
    };
    // Known status → color classes
    var STATUS_CLASSES = {
        'Completed': 'bg-green-100 text-green-800',
        'Pending': 'bg-yellow-100 text-yellow-800',
        'Cancelled': 'bg-red-100 text-red-800',
        'chuẩn bị hàng': 'bg-blue-100 text-blue-800',
        'đang ship': 'bg-indigo-100 text-indigo-800'
    };
    var STATUS_BORDER = {
        'Completed': 'border-green-500',
        'Pending': 'border-yellow-500',
        'Cancelled': 'border-red-500',
        'chuẩn bị hàng': 'border-blue-500',
        'đang ship': 'border-indigo-500'
    };

    function getOrderStatusLabel(status) {
        return STATUS_LABELS[status] || status;
    }

    function getOrderStatusClass(status) {
        return STATUS_CLASSES[status] || 'bg-gray-100 text-gray-800';
    }

    function getOrderStatusText(status) {
        return STATUS_LABELS[status] || status;
    }

    function getBorderColorClass(status) {
        return STATUS_BORDER[status] || 'border-gray-300';
    }

    function formatDateRelative(dateString) {
        if (!dateString) return '';
        try {
            const date = new Date(dateString);
            if (isNaN(date.getTime())) return dateString;

            const now = new Date();
            const diffMs = now - date;
            const diffMins = Math.floor(diffMs / 60000);
            const diffHours = Math.floor(diffMs / 3600000);
            const diffDays = Math.floor(diffMs / 86400000);

            if (diffMins < 1) return 'Vừa xong';
            if (diffMins < 60) return `${diffMins} phút trước`;
            if (diffHours < 24) return `${diffHours} giờ trước`;
            if (diffDays < 7) return `${diffDays} ngày trước`;

            // For older dates, show full date with time
            return date.toLocaleString('vi-VN', {
                day: '2-digit',
                month: '2-digit',
                year: 'numeric',
                hour: '2-digit',
                minute: '2-digit',
                hour12: false
            });
        } catch (e) {
            return dateString;
        }
    }

    function viewOrderDetail(orderId) {
        if (!orderId) {
            showToast('Mã đơn hàng không hợp lệ', 'error');
            return;
        }

        toggleLoading(true);
        google.script.run
            .withSuccessHandler((res) => {
                toggleLoading(false);
                try {
                    if (res && res.success !== false && res.data) {
                        renderOrderDetail(res.data);
                        document.getElementById('order-detail-modal').classList.remove('hidden');
                    } else {
                        const errorMsg = res && res.message ? res.message : 'Không thể tải thông tin đơn hàng';
                        showToast(errorMsg, 'error');
                        console.error('getOrderDetail response:', res);
                    }
                } catch (e) {
                    console.error('Error processing order detail:', e);
                    showToast('Lỗi khi xử lý thông tin đơn hàng: ' + e.toString(), 'error');
                }
            })
            .withFailureHandler((error) => {
                toggleLoading(false);
                console.error('getOrderDetail error:', error);
                const errorMsg = error && error.message ? error.message : (error && error.toString ? error.toString() : 'Không thể tải thông tin đơn hàng');
                showToast('Lỗi: ' + errorMsg, 'error');
            })
            .apiHandler('getOrderDetail', orderId);
    }

    function editOrder(orderId) {
        if (!orderId) {
            showToast('Mã đơn hàng không hợp lệ', 'error');
            return;
        }

        toggleLoading(true);
        google.script.run
            .withSuccessHandler((res) => {
                toggleLoading(false);
                try {
                    if (res && res.success !== false && res.data) {
                        const order = res.data;

                        // Set editing mode
                        editingOrderId = orderId;

                        // Clear current cart
                        cart = [];

                        // Load order items into cart
                        if (order.items && order.items.length > 0) {
                            order.items.forEach(item => {
                                // Find product to get current price and other details
                                const product = productBySku.get(item.sku);
                                const currentProductPrice = product ? product.price : item.price;

                                cart.push({
                                    sku: item.sku,
                                    name: item.productName || product?.name || item.sku,
                                    productName: item.productName || product?.name || item.sku,
                                    price: item.price || 0, // Use order's price (may have been modified)
                                    originalPrice: currentProductPrice, // Store current product price as original
                                    qty: item.qty || 0,
                                    total: item.total || (item.price * item.qty) || 0,
                                    // Include other product properties if available
                                    stock: product?.stock || 0,
                                    category: product?.category || '',
                                    unit: product?.unit || '',
                                    // VAT fields
                                    applyVat: item.applyVat || false,
                                    vatRate: item.vatRate || 0,
                                    defaultVatRate: product?.defaultVatRate || 0,
                                    // Discount fields
                                    discountType: item.discountType || 'amount',
                                    discountValue: item.discountValue || 0
                                });
                            });
                        }

                        // Select customer
                        if (order.customerId) {
                            selectCustomerById(order.customerId);
                        } else {
                            clearSelectedCustomer();
                        }

                        // Fill other fields
                        const paidInput = document.getElementById('paid-amount');
                        if (paidInput) paidInput.value = order.paid || 0;

                        const discountInput = document.getElementById('discount-amount');
                        if (discountInput) discountInput.value = order.discountAmount || 0;

                        const shippingInput = document.getElementById('shipping-fee');
                        if (shippingInput) shippingInput.value = order.shippingFee || 0;

                        const couponInput = document.getElementById('coupon-code');
                        if (couponInput) couponInput.value = order.couponCode || '';

                        const notesInput = document.getElementById('order-notes');
                        if (notesInput) notesInput.value = order.notes || '';

                        const paymentMethodSelect = document.getElementById('payment-method');
                        if (paymentMethodSelect) paymentMethodSelect.value = order.paymentMethod || 'Tiền mặt';

                        const shippingAddressInput = document.getElementById('shipping-address');
                        if (shippingAddressInput) shippingAddressInput.value = order.shippingAddress || '';

                        // Set employee
                        const employeeSelect = document.getElementById('order-employee');
                        if (employeeSelect && order.employeeId) {
                            employeeSelect.value = order.employeeId;
                        }

                        // Render cart and update totals
                        renderCart();
                        calculateOrderTotal();
                        updatePaymentInfo();

                        // Switch to order page
                        showPage('order', null);

                        // Update page title to indicate editing mode
                        const pageTitle = document.querySelector('#page-order h2, #page-order h1');
                        if (pageTitle) {
                            const originalText = pageTitle.textContent;
                            pageTitle.textContent = 'Sửa Đơn Hàng: ' + orderId;
                            pageTitle.setAttribute('data-original-text', originalText);
                        }

                        showToast('Đã tải thông tin đơn hàng để chỉnh sửa', 'success');
                    } else {
                        const errorMsg = res && res.message ? res.message : 'Không thể tải thông tin đơn hàng';
                        showToast(errorMsg, 'error');
                    }
                } catch (e) {
                    console.error('Error processing order for edit:', e);
                    showToast('Lỗi khi tải đơn hàng: ' + e.toString(), 'error');
                }
            })
            .withFailureHandler((error) => {
                toggleLoading(false);
                console.error('editOrder error:', error);
                const errorMsg = error && error.message ? error.message : 'Không thể tải thông tin đơn hàng';
                showToast('Lỗi: ' + errorMsg, 'error');
            })
            .apiHandler('getOrderDetail', orderId);
    }

    // ============================================
    // EDIT ORDER MODAL (Quick Edit Popup)
    // ============================================
    let editOrderData = null; // Stores order being edited
    let editOrderItems = [];  // Items array for edit modal

    function openEditOrderModal(orderId) {
        if (!orderId) { showToast('Mã đơn hàng không hợp lệ', 'error'); return; }
        toggleLoading(true);
        google.script.run
            .withSuccessHandler(function(res) {
                toggleLoading(false);
                if (res && res.success !== false && res.data) {
                    editOrderData = res.data;
                    editOrderItems = (editOrderData.items || []).map(function(item) {
                        var product = productBySku.get(item.sku);
                        return {
                            sku: item.sku,
                            name: item.productName || (product ? product.name : item.sku),
                            qty: item.qty || 0,
                            price: item.price || 0,
                            total: item.total || (item.price * item.qty) || 0,
                            applyVat: item.applyVat || false,
                            vatRate: item.vatRate || 0,
                            vatAmount: item.vatAmount || 0,
                            discountType: item.discountType || 'amount',
                            discountValue: item.discountValue || 0,
                            stock: product ? product.stock : 0
                        };
                    });
                    renderEditOrderModal();
                    document.getElementById('order-edit-modal').classList.remove('hidden');
                } else {
                    showToast(res && res.message ? res.message : 'Không thể tải đơn hàng', 'error');
                }
            })
            .withFailureHandler(function(err) {
                toggleLoading(false);
                showToast('Lỗi: ' + (err.message || err), 'error');
            })
            .apiHandler('getOrderDetail', orderId);
    }

    function renderEditOrderModal() {
        var o = editOrderData;
        document.getElementById('edit-order-title').textContent = 'Sửa Đơn Hàng: ' + (o.orderId || o.id);

        // Populate customer dropdown — build HTML string first to avoid O(n²) innerHTML +=
        var custSelect = document.getElementById('edit-order-customer');
        var custOpts = ['<option value="">Khách lẻ</option>'];
        (allCustomers || []).forEach(function(c) {
            custOpts.push('<option value="' + escapeHtml(c.id) + '"' + (c.id === o.customerId ? ' selected' : '') + '>' + escapeHtml(c.name) + (c.phone ? ' - ' + c.phone : '') + '</option>');
        });
        custSelect.innerHTML = custOpts.join('');

        // Populate employee dropdown
        var empSelect = document.getElementById('edit-order-employee');
        var empList = employees.length > 0 ? employees : employeesData || [];
        if (empList.length > 0) {
            populateEditOrderEmployees(empSelect, empList, o.employeeId);
        } else {
            // Fallback: show current user while loading full list
            if (currentUser) {
                empSelect.innerHTML = '<option value="' + escapeHtml(currentUser.employeeId || '') + '" selected>' + escapeHtml(currentUser.employeeName || currentUser.username || '') + '</option>';
            }
            google.script.run
                .withSuccessHandler(function(res) {
                    if (res && res.success && res.data) {
                        employees = res.data || [];
                        populateEditOrderEmployees(empSelect, employees, o.employeeId);
                    }
                })
                .apiHandler('getEmployees', null);
        }

        // Status — dynamically populate from existing order statuses
        var statusSelect = document.getElementById('edit-order-status');
        var defaultStatuses = ['Pending', 'Completed', 'Cancelled'];
        var allStatuses = defaultStatuses.slice();
        (ordersData || []).forEach(function(ord) {
            if (ord.status && allStatuses.indexOf(ord.status) === -1) allStatuses.push(ord.status);
        });
        if (o.status && allStatuses.indexOf(o.status) === -1) allStatuses.push(o.status);
        statusSelect.innerHTML = allStatuses.map(function(s) {
            return '<option value="' + escapeHtml(s) + '"' + (s === (o.status || 'Pending') ? ' selected' : '') + '>' + escapeHtml(s) + '</option>';
        }).join('');
        var pmSelect = document.getElementById('edit-order-payment-method');
        pmSelect.innerHTML = '';
        (paymentMethods || [{ name: 'Tiền mặt' }, { name: 'Chuyển khoản' }]).forEach(function(pm) {
            var pmName = pm.name || pm;
            pmSelect.innerHTML += '<option value="' + escapeHtml(pmName) + '"' + (pmName === o.paymentMethod ? ' selected' : '') + '>' + escapeHtml(pmName) + '</option>';
        });

        // Init product search for adding
        initEditOrderProductSearch();

        // Fields
        document.getElementById('edit-order-discount').value = o.discountAmount || 0;
        document.getElementById('edit-order-shipping').value = o.shippingFee || 0;
        document.getElementById('edit-order-notes').value = o.notes || '';
        document.getElementById('edit-order-paid').value = o.paid || 0;

        // Show/hide date field based on ALLOW_EDIT_ORDER_DATE setting
        var dateRow = document.getElementById('edit-order-date-row');
        if (dateRow) {
            if (allowEditOrderDate) {
                dateRow.classList.remove('hidden');
                var dateInput = document.getElementById('edit-order-date');
                if (dateInput && o.date) {
                    var d = new Date(o.date);
                    if (!isNaN(d.getTime())) {
                        var pad = function(n) { return n < 10 ? '0' + n : n; };
                        dateInput.value = d.getFullYear() + '-' + pad(d.getMonth()+1) + '-' + pad(d.getDate()) +
                            'T' + pad(d.getHours()) + ':' + pad(d.getMinutes());
                    }
                }
            } else {
                dateRow.classList.add('hidden');
            }
        }

        renderEditOrderItems();
        recalcEditOrderTotal();
    }

    function populateEditOrderEmployees(select, empList, selectedId) {
        select.innerHTML = '';
        empList.forEach(function(e) {
            var empId = e.id || e[0];
            var empName = e.name || e[1] || '';
            if (e.status && e.status !== 'Active') return;
            select.innerHTML += '<option value="' + escapeHtml(empId) + '"' + (empId === selectedId ? ' selected' : '') + '>' + escapeHtml(empName) + '</option>';
        });
    }

    function renderEditOrderItems() {
        var tbody = document.getElementById('edit-order-items-body');
        if (!tbody) return;
        if (editOrderItems.length === 0) {
            tbody.innerHTML = '<tr><td colspan="5" class="text-center text-gray-400 py-4 text-sm">Chưa có sản phẩm</td></tr>';
            return;
        }
        tbody.innerHTML = editOrderItems.map(function(item, i) {
            return '<tr class="border-t">' +
                '<td class="px-3 py-2"><div class="text-sm font-medium">' + escapeHtml(item.name) + '</div><div class="text-xs text-gray-400">' + escapeHtml(item.sku) + '</div></td>' +
                '<td class="px-2 py-2 text-center"><input type="number" min="0.1" step="0.1" value="' + item.qty + '" class="w-16 px-1 py-1 border rounded text-center text-sm" onchange="updateEditOrderItem(' + i + ', \'qty\', this.value)"></td>' +
                '<td class="px-2 py-2 text-right"><input type="number" min="0" value="' + item.price + '" class="w-24 px-1 py-1 border rounded text-right text-sm" onchange="updateEditOrderItem(' + i + ', \'price\', this.value)"></td>' +
                '<td class="px-3 py-2 text-right text-sm font-medium">' + formatMoney(item.qty * item.price) + '</td>' +
                '<td class="px-1 py-2 text-center"><button onclick="removeEditOrderItem(' + i + ')" class="text-red-500 hover:text-red-700 text-lg" title="Xóa">✕</button></td>' +
                '</tr>';
        }).join('');
    }

    function updateEditOrderItem(index, field, value) {
        if (!editOrderItems[index]) return;
        editOrderItems[index][field] = parseFloat(value) || 0;
        editOrderItems[index].total = editOrderItems[index].qty * editOrderItems[index].price;
        renderEditOrderItems();
        recalcEditOrderTotal();
    }

    function removeEditOrderItem(index) {
        editOrderItems.splice(index, 1);
        renderEditOrderItems();
        recalcEditOrderTotal();
    }

    function addItemToEditOrder(sku) {
        if (!sku) return;

        // Check if already in list
        var existing = editOrderItems.find(function(it) { return it.sku === sku; });
        if (existing) {
            existing.qty += 1;
            existing.total = existing.qty * existing.price;
        } else {
            var product = productBySku.get(sku);
            if (!product) { showToast('Không tìm thấy sản phẩm', 'error'); return; }
            var eVatRate = product.defaultVatRate || 0;
            var eVatInc = product.vatIncluded || false;
            var ePrice = product.price || 0;
            var eAutoVat = false;
            if (eVatInc && eVatRate > 0) {
                ePrice = Math.round(ePrice / (1 + eVatRate / 100));
                eAutoVat = true;
            }
            editOrderItems.push({
                sku: product.sku,
                name: product.name,
                qty: 1,
                price: ePrice,
                total: ePrice,
                applyVat: eAutoVat,
                vatRate: eVatRate,
                vatAmount: 0,
                discountType: 'amount',
                discountValue: 0,
                stock: product.stock || 0
            });
        }
        // Clear search
        var searchEl = document.getElementById('edit-order-product-search');
        if (searchEl) { searchEl.value = ''; searchEl.focus(); }
        var resultsEl = document.getElementById('edit-order-product-results');
        if (resultsEl) resultsEl.classList.add('hidden');
        renderEditOrderItems();
        recalcEditOrderTotal();
    }

    function initEditOrderProductSearch() {
        var searchEl = document.getElementById('edit-order-product-search');
        var resultsEl = document.getElementById('edit-order-product-results');
        if (!searchEl || !resultsEl) return;
        searchEl.value = '';

        var debounceTimer;
        searchEl.addEventListener('input', function() {
            clearTimeout(debounceTimer);
            debounceTimer = setTimeout(function() {
                var term = searchEl.value.trim().toLowerCase();
                if (!term) { resultsEl.classList.add('hidden'); return; }
                var matches = (products || []).filter(function(p) {
                    if (p.status && p.status !== 'Active') return false;
                    return (p.name && p.name.toLowerCase().indexOf(term) !== -1) ||
                           (p.sku && p.sku.toLowerCase().indexOf(term) !== -1) ||
                           (p.barcode && p.barcode.indexOf(term) !== -1);
                }).slice(0, 10);
                if (matches.length === 0) {
                    resultsEl.innerHTML = '<div class="px-3 py-2 text-sm text-gray-400">Không tìm thấy</div>';
                } else {
                    resultsEl.innerHTML = matches.map(function(p) {
                        return '<div class="px-3 py-2 text-sm cursor-pointer hover:bg-blue-50 border-b last:border-0" onclick="addItemToEditOrder(\'' + escapeHtml(p.sku) + '\')">' +
                            '<span class="font-medium">' + escapeHtml(p.name) + '</span>' +
                            '<span class="text-gray-400 ml-2">' + escapeHtml(p.sku) + '</span>' +
                            '<span class="float-right text-blue-600">' + formatMoney(p.price) + '</span></div>';
                    }).join('');
                }
                resultsEl.classList.remove('hidden');
            }, 200);
        });

        // Enter = add first match
        searchEl.addEventListener('keydown', function(e) {
            if (e.key === 'Enter') {
                e.preventDefault();
                var term = searchEl.value.trim().toLowerCase();
                if (!term) return;
                var match = (products || []).find(function(p) {
                    if (p.status && p.status !== 'Active') return false;
                    return (p.sku && p.sku.toLowerCase() === term) ||
                           (p.barcode && p.barcode === term) ||
                           (p.name && p.name.toLowerCase().indexOf(term) !== -1) ||
                           (p.sku && p.sku.toLowerCase().indexOf(term) !== -1);
                });
                if (match) addItemToEditOrder(match.sku);
                else showToast('Không tìm thấy sản phẩm', 'warning');
            }
            if (e.key === 'Escape') { resultsEl.classList.add('hidden'); searchEl.value = ''; }
        });

        // Click outside to close
        document.addEventListener('click', function(e) {
            if (!searchEl.contains(e.target) && !resultsEl.contains(e.target)) {
                resultsEl.classList.add('hidden');
            }
        });
    }

    function recalcEditOrderTotal() {
        var subtotal = editOrderItems.reduce(function(sum, item) { return sum + (item.qty * item.price); }, 0);
        var discount = parseFloat(document.getElementById('edit-order-discount').value) || 0;
        var shipping = parseFloat(document.getElementById('edit-order-shipping').value) || 0;
        var total = subtotal - discount + shipping;
        if (total < 0) total = 0;
        var paid = parseFloat(document.getElementById('edit-order-paid').value) || 0;
        var debt = total - paid;
        if (debt < 0) debt = 0;

        document.getElementById('edit-order-subtotal').textContent = formatMoney(subtotal);
        document.getElementById('edit-order-discount-display').textContent = '-' + formatMoney(discount);
        document.getElementById('edit-order-shipping-display').textContent = formatMoney(shipping);
        document.getElementById('edit-order-total').textContent = formatMoney(total);
        document.getElementById('edit-order-debt').textContent = formatMoney(debt);
    }

    function saveEditOrder() {
        if (!editOrderData) return;
        if (editOrderItems.length === 0) { showToast('Đơn hàng cần ít nhất 1 sản phẩm', 'error'); return; }

        var discount = parseFloat(document.getElementById('edit-order-discount').value) || 0;
        var shipping = parseFloat(document.getElementById('edit-order-shipping').value) || 0;
        var subtotal = editOrderItems.reduce(function(sum, it) { return sum + (it.qty * it.price); }, 0);
        var total = Math.max(0, subtotal - discount + shipping);
        var paid = parseFloat(document.getElementById('edit-order-paid').value) || 0;

        // Read custom order date if feature enabled
        var orderDatePayload = null;
        if (allowEditOrderDate) {
            var dateInput = document.getElementById('edit-order-date');
            if (dateInput && dateInput.value) {
                orderDatePayload = new Date(dateInput.value).toISOString();
            }
        }

        var payload = {
            orderId: editOrderData.orderId || editOrderData.id,
            customerId: document.getElementById('edit-order-customer').value || '',
            employeeId: document.getElementById('edit-order-employee').value || '',
            status: document.getElementById('edit-order-status').value,
            paymentMethod: document.getElementById('edit-order-payment-method').value,
            discountAmount: discount,
            shippingFee: shipping,
            notes: document.getElementById('edit-order-notes').value || '',
            paid: paid,
            total: total,
            debt: Math.max(0, total - paid),
            orderDate: orderDatePayload,
            items: editOrderItems.map(function(it) {
                return {
                    sku: it.sku,
                    productName: it.name,
                    qty: it.qty,
                    price: it.price,
                    total: it.qty * it.price,
                    applyVat: it.applyVat || false,
                    vatRate: it.vatRate || 0,
                    vatAmount: it.vatAmount || 0,
                    discountType: it.discountType || 'amount',
                    discountValue: it.discountValue || 0
                };
            })
        };

        var btnSave = document.getElementById('btn-save-edit-order');
        setBtnLoading(btnSave, true, 'Đang lưu...');
        toggleLoading(true);
        google.script.run
            .withSuccessHandler(function(res) {
                toggleLoading(false);
                setBtnLoading(btnSave, false);
                if (res && res.success !== false) {
                    showToast('Đã cập nhật đơn hàng thành công!', 'success');
                    closeEditOrderModal();
                    // Invalidate products cache (stock có thể thay đổi)
                    LocalStore.setVersion('PRODUCTS', '0');
                    localStorage.removeItem('TTL_products-manage');
                    setProducts([]);
                    // Refresh order list
                    loadOrders(true);
                } else {
                    showToast(res && res.message ? res.message : 'Lỗi cập nhật đơn hàng', 'error');
                }
            })
            .withFailureHandler(function(err) {
                toggleLoading(false);
                setBtnLoading(btnSave, false);
                showToast('Lỗi: ' + (err.message || err), 'error');
            })
            .apiHandler('updateOrder', payload);
    }

    function closeEditOrderModal() {
        document.getElementById('order-edit-modal').classList.add('hidden');
        editOrderData = null;
        editOrderItems = [];
    }

    let currentOrderDetail = null; // Store current order for status update

    function renderOrderDetail(order) {
        currentOrderDetail = order; // Store for later use
        const content = document.getElementById('order-detail-content');
        if (!content) return;

        // Load company info if not loaded
        if (!companyInfo) {
            loadCompanyInfo();
        }

        const itemsHtml = order.items.map(item => `
            <tr class="border-b">
                <td class="py-2">${item.productName}</td>
                <td class="py-2 text-center">${item.qty}</td>
                <td class="py-2 text-right">${formatMoney(item.price)}</td>
                <td class="py-2 text-right font-medium">${formatMoney(item.total)}</td>
            </tr>
        `).join('');

        // Calculate subtotal and VAT breakdown
        let subtotalBeforeVAT = 0;
        const vatByRate = {}; // {10: 140000, 5: 10000}
        let totalVAT = 0;

        order.items.forEach(item => {
            const itemTotal = item.total || 0;
            const hasVAT = item.hasVAT || false;
            const vatRate = parseFloat(item.vatRate) || 0;

            if (hasVAT && vatRate > 0) {
                // Calculate price before VAT: total / (1 + rate/100)
                const priceBeforeVAT = itemTotal / (1 + vatRate / 100);
                const vatAmount = itemTotal - priceBeforeVAT;

                subtotalBeforeVAT += priceBeforeVAT;
                totalVAT += vatAmount;

                // Group by VAT rate
                if (!vatByRate[vatRate]) {
                    vatByRate[vatRate] = 0;
                }
                vatByRate[vatRate] += vatAmount;
            } else {
                // No VAT
                subtotalBeforeVAT += itemTotal;
            }
        });

        const subtotal = subtotalBeforeVAT + totalVAT; // Total including VAT
        const discountAmount = order.discountAmount || 0;
        const shippingFee = order.shippingFee || 0;
        const finalTotal = subtotal - discountAmount + shippingFee;

        const statusSelect = orderStatusConfig.map(s =>
            `<option value="${s}" ${order.status === s ? 'selected' : ''}>${getOrderStatusLabel(s)}</option>`
        ).join('');

        // Parse date safely
        let orderDate;
        try {
            if (order.date instanceof Date) {
                orderDate = order.date;
            } else if (typeof order.date === 'string') {
                orderDate = new Date(order.date);
                if (isNaN(orderDate.getTime())) {
                    orderDate = new Date();
                }
            } else {
                orderDate = new Date();
            }
        } catch (e) {
            console.error('Error parsing order date:', e);
            orderDate = new Date();
        }

        const formattedDate = orderDate.toLocaleDateString('vi-VN', {
            year: 'numeric',
            month: 'long',
            day: 'numeric',
            hour: '2-digit',
            minute: '2-digit'
        });

        content.innerHTML = `
            <div class="print-only mb-6 text-center border-b-2 border-gray-300 pb-4" style="display: none;">
                <div class="mb-4">
                    ${companyInfo && companyInfo.name ? `<h2 class="text-xl font-bold text-gray-800 mb-2">${companyInfo.name}</h2>` : ''}
                    <h1 class="text-3xl font-bold text-gray-900 mb-2">HÓA ĐƠN BÁN HÀNG</h1>
                    ${companyInfo && companyInfo.address ? `<p class="text-xs text-gray-600 mt-1">${companyInfo.address}</p>` : ''}
                    ${companyInfo && companyInfo.phone ? `<p class="text-xs text-gray-600">ĐT: ${companyInfo.phone}</p>` : ''}
                    ${companyInfo && companyInfo.tax ? `<p class="text-xs text-gray-600">MST: ${companyInfo.tax}</p>` : ''}
                    <div class="text-sm text-gray-600 space-y-1 mt-3">
                        <p><strong>Mã đơn hàng:</strong> ${order.id}</p>
                        <p><strong>Ngày xuất:</strong> ${formattedDate}</p>
                    </div>
                    <div id="qr-code-print-${order.id}" style="display: inline-block; margin: 10px 0;"></div>
                </div>
                <div class="text-left border-t pt-4 mt-4">
                    <div style="background-color: #F9FAFB; padding: 15px; border-radius: 8px; border-left: 4px solid #3B82F6; margin-bottom: 15px;">
                        <h4 style="color: #1F2937; margin: 0 0 10px 0; font-size: 16px; font-weight: bold;">Thông Tin Khách Hàng</h4>
                        <p class="text-sm mb-1"><strong>Tên khách hàng:</strong> ${order.customerName || 'Khách lẻ'}</p>
                        ${order.customerPhone ? `<p class="text-sm mb-1"><strong>Điện thoại:</strong> ${order.customerPhone}</p>` : ''}
                        ${order.customerEmail ? `<p class="text-sm mb-1"><strong>Email:</strong> ${order.customerEmail}</p>` : ''}
                        ${order.customerAddress ? `<p class="text-sm mb-1"><strong>Địa chỉ:</strong> ${order.customerAddress}</p>` : ''}
                        ${order.customerType === 'Doanh nghiệp' && order.customerCompanyName ? `<p class="text-sm mb-1"><strong>Tên công ty:</strong> ${order.customerCompanyName}</p>` : ''}
                        ${order.customerType === 'Doanh nghiệp' && order.customerTaxCode ? `<p class="text-sm mb-1"><strong>Mã số thuế:</strong> ${order.customerTaxCode}</p>` : ''}
                    </div>
                    ${order.notes ? `
                    <div style="background-color: #FFF7ED; padding: 15px; border-radius: 8px; border-left: 4px solid #F59E0B; margin-top: 15px;">
                        <h4 style="color: #1F2937; margin: 0 0 8px 0; font-size: 14px; font-weight: bold;">Ghi Chú Đơn Hàng:</h4>
                        <p style="margin: 0; color: #6B7280; font-size: 14px; white-space: pre-line;">${order.notes}</p>
                    </div>
                    ` : ''}
                </div>
            </div>

            <!-- Thông tin đơn hàng - 2 cột -->
            <div class="grid grid-cols-1 md:grid-cols-2 gap-6 no-print">
                <!-- Cột trái: Thông tin chung -->
                <div class="space-y-4">
                    <div class="bg-blue-50 rounded-lg p-4">
                        <h3 class="text-sm font-semibold text-blue-800 mb-3 uppercase tracking-wide">Thông tin đơn hàng</h3>
                        <div class="space-y-2">
                            <div class="flex justify-between items-center">
                                <span class="text-sm text-gray-500">Mã đơn:</span>
                                <span class="font-bold text-base text-gray-900">${order.id}</span>
                            </div>
                            <div class="flex justify-between items-center">
                                <span class="text-sm text-gray-500">Ngày:</span>
                                <span class="text-sm text-gray-900">${orderDate.toLocaleDateString('vi-VN')}</span>
                            </div>
                            <div class="flex justify-between items-center">
                                <span class="text-sm text-gray-500">Khách hàng:</span>
                                <span class="text-sm font-medium text-gray-900">${order.customerName || 'Khách lẻ'}</span>
                            </div>
                            ${order.paymentMethod ? `
                            <div class="flex justify-between items-center">
                                <span class="text-sm text-gray-500">Thanh toán:</span>
                                <span class="text-sm font-medium text-gray-900">${order.paymentMethod}</span>
                            </div>
                            ` : ''}
                            ${order.employeeId || order.assignedTo ? `
                            <div class="flex justify-between items-center">
                                <span class="text-sm text-gray-500">Nhân viên:</span>
                                <span class="text-sm text-gray-900">${order.employeeName || order.assignedTo || ''}</span>
                            </div>
                            ` : ''}
                        </div>
                    </div>

                    ${order.shippingAddress || order.shippingStatus ? `
                    <div class="bg-gray-50 rounded-lg p-4">
                        <h3 class="text-sm font-semibold text-gray-700 mb-3 uppercase tracking-wide">Giao hàng</h3>
                        <div class="space-y-2">
                            ${order.shippingAddress ? `
                            <div>
                                <span class="text-sm text-gray-500">Địa chỉ:</span>
                                <p class="text-sm text-gray-900 mt-1">${order.shippingAddress}</p>
                            </div>
                            ` : ''}
                            ${order.shippingStatus ? `
                            <div class="flex justify-between items-center">
                                <span class="text-sm text-gray-500">Trạng thái:</span>
                                <span class="text-sm font-medium">${order.shippingStatus}</span>
                            </div>
                            ` : ''}
                        </div>
                    </div>
                    ` : ''}

                    ${order.notes ? `
                    <div class="bg-yellow-50 rounded-lg p-4">
                        <h3 class="text-sm font-semibold text-yellow-800 mb-2 uppercase tracking-wide">Ghi chú</h3>
                        <p class="text-sm text-gray-700 whitespace-pre-line">${order.notes}</p>
                    </div>
                    ` : ''}
                </div>

                <!-- Cột phải: Trạng thái & Thanh toán -->
                <div class="space-y-4">
                    <div class="bg-gray-50 rounded-lg p-4">
                        <h3 class="text-sm font-semibold text-gray-700 mb-3 uppercase tracking-wide">Trạng thái đơn hàng</h3>
                        <select id="order-status-select" class="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm">
                            ${statusSelect}
                        </select>
                        <button onclick="updateOrderStatus('${order.id}')" class="mt-2 w-full px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 text-sm font-medium transition-colors">
                            Cập nhật trạng thái
                        </button>
                    </div>

                    <div class="bg-green-50 rounded-lg p-4">
                        <h3 class="text-sm font-semibold text-green-800 mb-3 uppercase tracking-wide">Thanh toán</h3>
                        <div class="space-y-2">
                            <div class="flex justify-between items-center">
                                <span class="text-sm text-gray-600">Tổng tiền:</span>
                                <span class="font-bold text-blue-600">${formatMoney(order.total)}</span>
                            </div>
                            <div class="flex justify-between items-center">
                                <span class="text-sm text-gray-600">Đã thanh toán:</span>
                                <span class="font-semibold text-green-600">${formatMoney(order.paid)}</span>
                            </div>
                            <div class="flex justify-between items-center border-t border-green-200 pt-2">
                                <span class="text-sm font-medium">Còn nợ:</span>
                                <span class="font-bold ${order.debt > 0 ? 'text-red-600' : 'text-green-600'}">${formatMoney(order.debt)}</span>
                            </div>
                        </div>
                    </div>

                    ${order.debt > 0 ? `
                    <button onclick="showPaymentModal('${order.id}', ${order.debt}, '${(order.customerName || 'Khách lẻ').replace(/'/g, "\\'")}')"
                        class="w-full px-4 py-3 bg-gradient-to-r from-green-500 to-emerald-600 text-white rounded-lg hover:from-green-600 hover:to-emerald-700 flex items-center justify-center gap-2 font-medium transition-colors shadow-sm">
                        <span>💰</span> Thanh toán nợ (${formatMoney(order.debt)})
                    </button>
                    ` : ''}
                </div>
            </div>

            <!-- Chi tiết sản phẩm - Full width -->
            <div class="mt-6">
                <h3 class="text-base font-semibold text-gray-800 mb-3 no-print">Chi Tiết Sản Phẩm</h3>
                <p class="text-lg font-bold mb-2 print-only" style="display: none;">DANH SÁCH SẢN PHẨM</p>
                    
                    ${(() => {
                // Separate items by VAT status - FIXED
                const itemsWithVAT = order.items.filter(item => item.applyVat === true);
                const itemsWithoutVAT = order.items.filter(item => item.applyVat !== true);

                let html = '';

                // Table 1: Items WITH VAT (grouped by rate)
                if (itemsWithVAT.length > 0) {
                    const vatGroups = {};
                    itemsWithVAT.forEach(item => {
                        const rate = item.vatRate || 0;
                        if (!vatGroups[rate]) vatGroups[rate] = [];
                        vatGroups[rate].push(item);
                    });

                    Object.entries(vatGroups).sort((a, b) => parseFloat(b[0]) - parseFloat(a[0])).forEach(([rate, items]) => {
                        html += `
                                    <p class="text-md font-bold mb-2 ${itemsWithoutVAT.length > 0 || Object.keys(vatGroups).length > 1 ? 'mt-4' : ''} text-green-700">
                                        📋 SẢN PHẨM CÓ VAT (${rate}%)
                                    </p>
                                    <table class="w-full border-collapse mb-2">
                                        <thead>
                                            <tr class="border-b-2 border-gray-300 text-left text-sm font-semibold">
                                                <th class="pb-3">STT</th>
                                                <th class="pb-3">Tên Sản Phẩm</th>
                                                <th class="pb-3 text-center">SL</th>
                                                <th class="pb-3 text-right">Đơn Giá</th>
                                                <th class="pb-3 text-right">VAT (${rate}%)</th>
                                                <th class="pb-3 text-right">Thành Tiền</th>
                                            </tr>
                                        </thead>
                                        <tbody>
                                            ${items.map((item, idx) => {
                            const basePrice = (item.price || 0) * (item.qty || 0);
                            const vatAmount = basePrice * (parseFloat(rate) / 100);
                            const total = basePrice + vatAmount;
                            return `
                                                    <tr class="border-b">
                                                        <td class="py-2 text-center">${idx + 1}</td>
                                                        <td class="py-2">${item.productName || item.sku || ''}</td>
                                                        <td class="py-2 text-center">${item.qty || 0}</td>
                                                        <td class="py-2 text-right">${formatMoney(item.price || 0)}</td>
                                                        <td class="py-2 text-right text-green-600">${formatMoney(vatAmount)}</td>
                                                        <td class="py-2 text-right font-medium">${formatMoney(total)}</td>
                                                    </tr>
                                                `;
                        }).join('')}
                                            <tr class="border-t-2 border-gray-300 font-semibold bg-green-50">
                                                <td colspan="4" class="py-2 text-right">Tổng VAT (${rate}%):</td>
                                                <td class="py-2 text-right text-green-600">
                                                    ${formatMoney(items.reduce((sum, item) => {
                            const basePrice = (item.price || 0) * (item.qty || 0);
                            return sum + (basePrice * (parseFloat(rate) / 100));
                        }, 0))}
                                                </td>
                                                <td class="py-2 text-right">
                                                    ${formatMoney(items.reduce((sum, item) => {
                            const basePrice = (item.price || 0) * (item.qty || 0);
                            const vatAmount = basePrice * (parseFloat(rate) / 100);
                            return sum + basePrice + vatAmount;
                        }, 0))}
                                                </td>
                                            </tr>
                                        </tbody>
                                    </table>
                                `;
                    });
                }

                // Table 2: Items WITHOUT VAT
                if (itemsWithoutVAT.length > 0) {
                    html += `
                                <p class="text-md font-bold mb-2 ${itemsWithVAT.length > 0 ? 'mt-4' : ''} text-gray-700">
                                    📋 SẢN PHẨM KHÔNG VAT
                                </p>
                                <table class="w-full border-collapse mb-2">
                                    <thead>
                                        <tr class="border-b-2 border-gray-300 text-left text-sm font-semibold">
                                            <th class="pb-3">STT</th>
                                            <th class="pb-3">Tên Sản Phẩm</th>
                                            <th class="pb-3 text-center">Số Lượng</th>
                                            <th class="pb-3 text-right">Đơn Giá</th>
                                            <th class="pb-3 text-right">Thành Tiền</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        ${itemsWithoutVAT.map((item, idx) => `
                                            <tr class="border-b">
                                                <td class="py-2 text-center">${idx + 1}</td>
                                                <td class="py-2">${item.productName || item.sku || ''}</td>
                                                <td class="py-2 text-center">${item.qty || 0}</td>
                                                <td class="py-2 text-right">${formatMoney(item.price || 0)}</td>
                                                <td class="py-2 text-right font-medium">${formatMoney((item.price || 0) * (item.qty || 0))}</td>
                                            </tr>
                                        `).join('')}
                                        <tr class="border-t-2 border-gray-300 font-semibold bg-gray-50">
                                            <td colspan="4" class="py-2 text-right">Tổng:</td>
                                            <td class="py-2 text-right">
                                                ${formatMoney(itemsWithoutVAT.reduce((sum, item) => sum + ((item.price || 0) * (item.qty || 0)), 0))}
                                            </td>
                                        </tr>
                                    </tbody>
                                </table>
                            `;
                }

                return html;
            })()}
                </div>

                <!-- Tổng tiền & Thanh toán - 2 cột -->
                <div class="grid grid-cols-1 md:grid-cols-2 gap-6 border-t-2 border-gray-300 pt-4 mt-4">
                    <!-- Cột trái: Breakdown tổng tiền -->
                    <div class="space-y-2">
                        <div class="flex justify-between text-sm">
                            <span class="font-medium">Tạm tính (chưa VAT):</span>
                            <span>${formatMoney(subtotalBeforeVAT)}</span>
                        </div>
                        ${Object.keys(vatByRate).length > 0 ? `
                            ${Object.entries(vatByRate).sort((a, b) => parseFloat(b[0]) - parseFloat(a[0])).map(([rate, amount]) => `
                                <div class="flex justify-between text-sm text-green-600">
                                    <span>VAT (${rate}%):</span>
                                    <span>+${formatMoney(amount)}</span>
                                </div>
                            `).join('')}
                            <div class="flex justify-between text-sm font-medium border-t pt-2">
                                <span>Tổng tiền hàng:</span>
                                <span>${formatMoney(subtotal)}</span>
                            </div>
                        ` : `
                            <div class="flex justify-between text-sm font-medium">
                                <span>Tổng tiền hàng:</span>
                                <span>${formatMoney(subtotal)}</span>
                            </div>
                        `}
                        ${discountAmount > 0 ? `
                        <div class="flex justify-between text-sm text-red-600">
                            <span>Giảm giá:</span>
                            <span>-${formatMoney(discountAmount)}</span>
                        </div>
                        ${order.couponCode ? `<div class="text-xs text-gray-500 ml-2">Mã: ${order.couponCode}</div>` : ''}
                        ` : ''}
                        ${shippingFee > 0 ? `
                        <div class="flex justify-between text-sm">
                            <span>Phí vận chuyển:</span>
                            <span>${formatMoney(shippingFee)}</span>
                        </div>
                        ` : ''}
                        <div class="flex justify-between font-bold text-xl border-t-2 border-gray-300 pt-3 mt-2">
                            <span>TỔNG TIỀN:</span>
                            <span class="text-blue-600">${formatMoney(order.total)}</span>
                        </div>
                        <div class="flex justify-between text-sm mt-2">
                            <span>Đã thanh toán:</span>
                            <span class="text-green-600 font-semibold">${formatMoney(order.paid)}</span>
                        </div>
                        <div class="flex justify-between text-sm">
                            <span>Còn nợ:</span>
                            <span class="${order.debt > 0 ? 'text-red-600 font-bold' : 'text-gray-500'}">${formatMoney(order.debt)}</span>
                        </div>
                        ${order.debt === 0 ? `
                        <div class="mt-3 pt-2 border-t text-center text-green-600 font-semibold print-only" style="display: none;">
                            ✓ ĐÃ THANH TOÁN ĐỦ
                        </div>
                        ` : ''}
                    </div>

                    <!-- Cột phải: Lịch sử thanh toán + Actions -->
                    <div class="space-y-4 no-print">
                        <div>
                            <div class="flex justify-between items-center mb-2">
                                <p class="text-sm text-gray-500 font-medium">Lịch sử thanh toán</p>
                                <button onclick="loadOrderPaymentHistory('${order.id}')" class="text-xs text-blue-600 hover:text-blue-800">Làm mới</button>
                            </div>
                            <div id="order-payment-history-container" class="bg-gray-50 rounded-lg p-3 max-h-48 overflow-y-auto">
                                <p class="text-center text-gray-400 text-sm py-2">Đang tải...</p>
                            </div>
                        </div>

                        ${order.status === 'Completed' ? `
                        <button onclick="createWarrantiesForOrder('${order.id}')"
                            class="w-full px-4 py-2.5 bg-blue-600 text-white rounded-lg hover:bg-blue-700 flex items-center justify-center gap-2 text-sm font-medium transition-colors">
                            <svg class="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2"
                                    d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z">
                                </path>
                            </svg>
                            Tạo Phiếu Bảo Hành
                        </button>
                        ` : ''}
                    </div>
                </div>

                <div class="print-only mt-6 pt-4 border-t text-center text-xs text-gray-500" style="display: none;">
                    <p>Cảm ơn quý khách đã sử dụng dịch vụ!</p>
                    ${companyInfo && companyInfo.notes ? `<p class="mt-2 text-left" style="white-space: pre-line;">${companyInfo.notes}</p>` : ''}
                    ${companyInfo && companyInfo.email ? `<p class="mt-2">Email: ${companyInfo.email}</p>` : ''}
                    ${companyInfo && companyInfo.website ? `<p>Website: ${companyInfo.website}</p>` : ''}
                    <p class="mt-2">Hóa đơn được tạo tự động từ hệ thống Quản Lý Bán Hàng</p>
                </div>
            </div>
        `;

        // Load payment history after rendering
        setTimeout(function() {
            loadOrderPaymentHistory(order.id);
        }, 100);
    }

    function closeOrderDetailModal() {
        document.getElementById('order-detail-modal').classList.add('hidden');
    }

    // PAYMENT MODAL - Thanh toán nợ
    function showPaymentModal(orderId, maxAmount, customerName) {
        var modal = document.getElementById('payment-modal');
        if (!modal) {
            // Fallback to prompt if modal not found
            var amount = prompt('Nhập số tiền thanh toán (Tối đa: ' + formatMoney(maxAmount) + '):', maxAmount);
            if (amount && !isNaN(amount) && parseFloat(amount) > 0) {
                var paymentAmount = parseFloat(amount);
                if (paymentAmount > maxAmount) {
                    showToast('Số tiền thanh toán không được vượt quá số nợ!', 'warning');
                    return;
                }
                addPaymentToOrder(orderId, paymentAmount, 'Tiền mặt', '');
            }
            return;
        }

        // Set order info
        document.getElementById('payment-order-id').textContent = orderId;
        document.getElementById('payment-order-id-input').value = orderId;
        document.getElementById('payment-customer-name').textContent = customerName || 'Khách lẻ';
        document.getElementById('payment-debt-amount').textContent = formatMoney(maxAmount);
        document.getElementById('payment-max-amount').value = maxAmount;

        // Reset form
        document.getElementById('payment-amount').value = formatNumberInput(maxAmount);
        document.getElementById('payment-method-select').value = 'Tiền mặt';
        document.getElementById('payment-transaction-code').value = '';
        document.getElementById('payment-note').value = '';
        // Hide and clear QR on reset
        var qrContainer = document.getElementById('payment-qr-container');
        if (qrContainer) qrContainer.classList.add('hidden');
        var qrImg = document.getElementById('payment-qr-img');
        if (qrImg) qrImg.src = '';

        // Show modal
        modal.classList.remove('hidden');

        // Focus on amount input
        setTimeout(function() {
            document.getElementById('payment-amount').select();
        }, 100);
    }

    function closePaymentModal() {
        var modal = document.getElementById('payment-modal');
        if (modal) {
            modal.classList.add('hidden');
        }
    }

    function formatPaymentInput(input) {
        // Remove non-numeric characters
        var value = input.value.replace(/[^\d]/g, '');
        if (value) {
            // Format with thousand separators
            value = parseInt(value).toLocaleString('vi-VN');
        }
        input.value = value;
    }

    function formatNumberInput(num) {
        return parseInt(num).toLocaleString('vi-VN');
    }

    function parseFormattedNumber(str) {
        // Remove thousand separators and parse
        return parseInt(String(str).replace(/\./g, '').replace(/,/g, '')) || 0;
    }

    function setPaymentAmount(percentage) {
        var maxAmount = parseFloat(document.getElementById('payment-max-amount').value) || 0;
        var amount = Math.round(maxAmount * percentage);
        document.getElementById('payment-amount').value = formatNumberInput(amount);
        updatePaymentQR();
    }

    function submitPayment(event) {
        event.preventDefault();

        var orderId = document.getElementById('payment-order-id-input').value;
        var maxAmount = parseFloat(document.getElementById('payment-max-amount').value) || 0;
        var amountStr = document.getElementById('payment-amount').value;
        var amount = parseFormattedNumber(amountStr);
        var paymentMethod = document.getElementById('payment-method-select').value;
        var transactionCode = document.getElementById('payment-transaction-code').value.trim();
        var note = document.getElementById('payment-note').value.trim();

        // Validate
        if (!orderId) {
            showToast('Không tìm thấy mã đơn hàng!', 'error');
            return;
        }

        if (amount <= 0) {
            showToast('Vui lòng nhập số tiền hợp lệ!', 'warning');
            document.getElementById('payment-amount').focus();
            return;
        }

        if (amount > maxAmount) {
            showToast('Số tiền thanh toán không được vượt quá số nợ (' + formatMoney(maxAmount) + ')!', 'warning');
            document.getElementById('payment-amount').focus();
            return;
        }

        // Submit payment
        addPaymentToOrder(orderId, amount, paymentMethod, transactionCode, note);
    }

    function addPaymentToOrder(orderId, amount, paymentMethod, transactionCode, note) {
        if (!orderId || !amount || amount <= 0) {
            showToast('Vui lòng nhập số tiền hợp lệ!', 'warning');
            return;
        }

        toggleLoading(true);
        google.script.run
            .withSuccessHandler(function(res) {
                toggleLoading(false);
                if (res && res.success) {
                    showToast(res.message || 'Thanh toán thành công!', 'success');
                    closePaymentModal();
                    closeOrderDetailModal();
                    loadOrders(true); // Force refresh
                    loadDashboard();
                } else {
                    showToast(res.message || 'Không thể thanh toán', 'error');
                }
            })
            .withFailureHandler(function(error) {
                toggleLoading(false);
                showToast(error.message || 'Không thể thanh toán', 'error');
            })
            .apiHandler('addPaymentToOrder', {
                orderId: orderId,
                amount: amount,
                paymentMethod: paymentMethod || 'Tiền mặt',
                transactionCode: transactionCode || '',
                note: note || ''
            });
    }

    // Load payment history for an order
    function loadOrderPaymentHistory(orderId) {
        var container = document.getElementById('order-payment-history-container');
        if (!container) return;

        container.innerHTML = '<p class="text-center text-gray-400 text-sm py-2">Đang tải...</p>';

        google.script.run
            .withSuccessHandler(function(res) {
                if (res && res.success !== false) {
                    var payments = res.data || res || [];
                    if (!Array.isArray(payments)) payments = [];

                    if (payments.length === 0) {
                        container.innerHTML = '<p class="text-center text-gray-400 text-sm py-3">Chưa có lịch sử thanh toán</p>';
                        return;
                    }

                    var html = '<div class="space-y-2">';
                    payments.forEach(function(p, idx) {
                        var dateStr = '';
                        try {
                            if (p.date) {
                                var d = new Date(p.date);
                                dateStr = d.toLocaleString('vi-VN', {
                                    day: '2-digit',
                                    month: '2-digit',
                                    year: 'numeric',
                                    hour: '2-digit',
                                    minute: '2-digit'
                                });
                            }
                        } catch (e) {
                            dateStr = p.date || '';
                        }

                        var methodIcon = '💵';
                        if (p.paymentMethod === 'Chuyển khoản') methodIcon = '🏦';
                        else if (p.paymentMethod === 'Ví điện tử') methodIcon = '📱';
                        else if (p.paymentMethod === 'Thẻ') methodIcon = '💳';

                        html += '<div class="bg-white rounded-lg p-3 border border-gray-200 shadow-sm">';
                        html += '<div class="flex justify-between items-start">';
                        html += '<div>';
                        html += '<p class="text-xs text-gray-500">' + dateStr + '</p>';
                        html += '<p class="font-bold text-green-600">' + formatMoney(p.amount || 0) + '</p>';
                        html += '</div>';
                        html += '<span class="text-xs px-2 py-1 bg-gray-100 rounded">' + methodIcon + ' ' + (p.paymentMethod || 'Tiền mặt') + '</span>';
                        html += '</div>';
                        if (p.transactionCode) {
                            html += '<p class="text-xs text-gray-500 mt-1">Mã GD: ' + p.transactionCode + '</p>';
                        }
                        if (p.note) {
                            html += '<p class="text-xs text-gray-600 mt-1 italic">' + p.note + '</p>';
                        }
                        html += '<p class="text-xs text-gray-400 mt-1">Người nhận: ' + (p.receivedBy || '-') + '</p>';
                        html += '</div>';
                    });
                    html += '</div>';

                    container.innerHTML = html;
                } else {
                    container.innerHTML = '<p class="text-center text-red-500 text-sm py-2">Không thể tải lịch sử</p>';
                }
            })
            .withFailureHandler(function(error) {
                container.innerHTML = '<p class="text-center text-red-500 text-sm py-2">Lỗi: ' + (error.message || error) + '</p>';
            })
            .apiHandler('getOrderPaymentHistory', orderId);
    }

    // Quick status change — click badge trên danh sách đơn hàng
    function quickChangeStatus(badgeEl, orderId) {
        // Nếu đã có dropdown đang mở, đóng nó
        var existing = document.getElementById('quick-status-dropdown');
        if (existing) existing.remove();

        // Chỉ dùng trạng thái từ config (không quét thêm từ data)
        var statuses = orderStatusConfig.slice();

        var currentStatus = badgeEl.textContent.trim();

        // Tạo dropdown popup
        var dropdown = document.createElement('div');
        dropdown.id = 'quick-status-dropdown';
        dropdown.className = 'absolute z-50 bg-white border border-gray-200 rounded-lg shadow-lg py-1 min-w-[140px]';
        dropdown.innerHTML = statuses.map(function(s) {
            var cls = s === currentStatus ? 'bg-blue-50 text-blue-700 font-semibold' : 'text-gray-700 hover:bg-gray-50';
            return '<div class="px-3 py-1.5 text-xs cursor-pointer ' + cls + '" data-status="' + escapeHtml(s) + '">' + escapeHtml(s) + (s === currentStatus ? ' ✓' : '') + '</div>';
        }).join('');

        // Vị trí dropdown
        var rect = badgeEl.getBoundingClientRect();
        dropdown.style.position = 'fixed';
        dropdown.style.top = (rect.bottom + 4) + 'px';
        dropdown.style.left = rect.left + 'px';
        document.body.appendChild(dropdown);

        // Click handler cho mỗi option
        dropdown.addEventListener('click', function(e) {
            var statusDiv = e.target.closest('[data-status]');
            if (!statusDiv) return;
            var newStatus = statusDiv.dataset.status;
            dropdown.remove();
            if (newStatus === currentStatus) return;

            badgeEl.textContent = '...';
            google.script.run
                .withSuccessHandler(function(res) {
                    if (res && res.success) {
                        showToast('Đổi trạng thái → ' + newStatus, 'success');
                        // Cập nhật trong ordersData
                        var ord = ordersData.find(function(o) { return o.id === orderId; });
                        if (ord) ord.status = newStatus;
                        localStorage.removeItem('TTL_orders');
                        renderOrdersList(ordersData, false);
                    } else {
                        showToast(res && res.message || 'Lỗi cập nhật', 'error');
                        badgeEl.textContent = currentStatus;
                    }
                })
                .withFailureHandler(function(err) {
                    showToast('Lỗi: ' + (err.message || err), 'error');
                    badgeEl.textContent = currentStatus;
                })
                .apiHandler('updateOrderStatus', { orderId: orderId, status: newStatus });
        });

        // Đóng dropdown khi click ra ngoài
        setTimeout(function() {
            document.addEventListener('click', function closeDropdown(e) {
                if (!dropdown.contains(e.target) && e.target !== badgeEl) {
                    dropdown.remove();
                    document.removeEventListener('click', closeDropdown);
                }
            });
        }, 10);
    }

    // Color class mapping for shipping status badge
    function shippingStatusClass(s) {
        var map = {
            'Chờ giao':   'bg-gray-100 text-gray-600',
            'Đang giao':  'bg-blue-100 text-blue-700',
            'Đã giao':    'bg-green-100 text-green-700',
            'Không giao': 'bg-red-100 text-red-600'
        };
        return map[s] || 'bg-gray-100 text-gray-600';
    }

    // Quick shipping status change — click badge trên danh sách đơn
    function quickChangeShippingStatus(badgeEl, orderId) {
        var existing = document.getElementById('quick-shipping-dropdown');
        if (existing) existing.remove();

        var statuses = ['Chờ giao', 'Đang giao', 'Đã giao', 'Không giao'];
        var currentStatus = badgeEl.textContent.trim();

        var dropdown = document.createElement('div');
        dropdown.id = 'quick-shipping-dropdown';
        dropdown.className = 'absolute z-50 bg-white border border-gray-200 rounded-lg shadow-lg py-1 min-w-[140px]';
        dropdown.innerHTML = statuses.map(function(s) {
            var cls = s === currentStatus ? 'bg-indigo-50 text-indigo-700 font-semibold' : 'text-gray-700 hover:bg-gray-50';
            return '<div class="px-3 py-1.5 text-xs cursor-pointer ' + cls + '" data-status="' + escapeHtml(s) + '">'
                + escapeHtml(s) + (s === currentStatus ? ' ✓' : '') + '</div>';
        }).join('');

        var rect = badgeEl.getBoundingClientRect();
        dropdown.style.position = 'fixed';
        dropdown.style.top = (rect.bottom + 4) + 'px';
        dropdown.style.left = rect.left + 'px';
        document.body.appendChild(dropdown);

        dropdown.addEventListener('click', function(e) {
            var el = e.target.closest('[data-status]');
            if (!el) return;
            var newStatus = el.dataset.status;
            dropdown.remove();
            if (newStatus === currentStatus) return;

            badgeEl.textContent = '...';
            google.script.run
                .withSuccessHandler(function(res) {
                    if (res && res.success) {
                        showToast('Giao hàng → ' + newStatus, 'success');
                        var ord = ordersData.find(function(o) { return o.id === orderId; });
                        if (ord) ord.shippingStatus = newStatus;
                        localStorage.removeItem('TTL_orders');
                        // Update badge in place without full re-render
                        badgeEl.textContent = newStatus;
                        badgeEl.className = 'px-2 py-1 rounded-full text-xs cursor-pointer hover:ring-2 hover:ring-indigo-300 transition ' + shippingStatusClass(newStatus);
                    } else {
                        showToast(res && res.message || 'Lỗi cập nhật', 'error');
                        badgeEl.textContent = currentStatus;
                    }
                })
                .withFailureHandler(function(err) {
                    showToast('Lỗi: ' + (err.message || err), 'error');
                    badgeEl.textContent = currentStatus;
                })
                .apiHandler('updateShippingStatus', { orderId: orderId, shippingStatus: newStatus });
        });

        // Close on outside click
        setTimeout(function() {
            document.addEventListener('click', function closeDropdown(e) {
                if (!dropdown.contains(e.target) && e.target !== badgeEl) {
                    dropdown.remove();
                    document.removeEventListener('click', closeDropdown);
                }
            });
        }, 10);
    }

    function updateOrderStatus(orderId) {
        var statusSelect = document.getElementById('order-status-select');
        if (!statusSelect) return;

        var newStatus = statusSelect.value;
        if (!newStatus) {
            showToast('Vui lòng chọn trạng thái!', 'warning');
            return;
        }

        if (newStatus === 'Cancelled') {
            showConfirmModal(
                'Hủy Đơn Hàng',
                'Bạn có chắc chắn muốn hủy đơn hàng này?\n\nHệ thống sẽ:\n- Hoàn trả hàng vào kho\n- Hoàn trả công nợ khách hàng\n- Ghi nhận giao dịch hoàn tiền',
                'Hủy Đơn',
                () => {
                    toggleLoading(true);
                    google.script.run
                        .withSuccessHandler((res) => {
                            toggleLoading(false);
                            if (res && res.success) {
                                showToast(res.message || 'Cập nhật trạng thái thành công!', 'success');
                                localStorage.removeItem('TTL_orders');
                                loadOrders(true);
                                localStorage.removeItem('TTL_dashboard');
                                loadDashboard(true);
                                closeOrderDetailModal();
                            } else {
                                showToast(res.message || 'Không thể cập nhật trạng thái', 'error');
                                statusSelect.value = order.status; // Reset to previous value
                            }
                        })
                        .withFailureHandler((error) => {
                            toggleLoading(false);
                            showToast(error.message || 'Không thể cập nhật trạng thái', 'error');
                            statusSelect.value = order.status; // Reset to previous value
                        })
                        .apiHandler('updateOrderStatus', { orderId, status: newStatus });
                }
            );
            if (currentOrderDetail) {
                statusSelect.value = currentOrderDetail.status; // Reset to previous value until confirmed
            }
            return;
        }

        // For non-cancelled status updates, proceed normally
        toggleLoading(true);
        google.script.run
            .withSuccessHandler((res) => {
                toggleLoading(false);
                if (res && res.success) {
                    showToast(res.message || 'Cập nhật trạng thái thành công!', 'success');
                    localStorage.removeItem('TTL_orders');
                    loadOrders(true);
                    localStorage.removeItem('TTL_dashboard');
                    loadDashboard(true);
                    closeOrderDetailModal();
                } else {
                    showToast(res.message || 'Không thể cập nhật trạng thái', 'error');
                    if (currentOrderDetail) {
                        statusSelect.value = currentOrderDetail.status; // Reset to previous value
                    }
                }
            })
            .withFailureHandler((error) => {
                toggleLoading(false);
                showToast(error.message || 'Không thể cập nhật trạng thái', 'error');
                if (currentOrderDetail) {
                    statusSelect.value = currentOrderDetail.status; // Reset to previous value
                }
            })
            .apiHandler('updateOrderStatus', { orderId, status: newStatus });
    }

    function cancelOrder(orderId) {
        showConfirmModal(
            'Hủy Đơn Hàng',
            'Bạn có chắc chắn muốn hủy đơn hàng này?\n\nHệ thống sẽ:\n- Hoàn trả hàng vào kho\n- Hoàn trả công nợ khách hàng\n- Ghi nhận giao dịch hoàn tiền',
            'Hủy Đơn',
            () => {
                toggleLoading(true);
                google.script.run
                    .withSuccessHandler((res) => {
                        toggleLoading(false);
                        if (res && res.success) {
                            showToast(res.message || 'Hủy đơn hàng thành công!', 'success');
                            // Invalidate products cache (stock đã hoàn trả khi hủy đơn)
                            LocalStore.setVersion('PRODUCTS', '0');
                            localStorage.removeItem('TTL_products-manage');
                            setProducts([]);
                            localStorage.removeItem('TTL_orders');
                            loadOrders(true);
                            localStorage.removeItem('TTL_dashboard');
                            loadDashboard(true);
                        } else {
                            showToast(res.message || 'Không thể hủy đơn hàng', 'error');
                        }
                    })
                    .withFailureHandler((error) => {
                        toggleLoading(false);
                        showToast(error.message || 'Không thể hủy đơn hàng', 'error');
                    })
                    .apiHandler('updateOrderStatus', { orderId, status: 'Cancelled' });
            }
        );
    }

    function cancelOrderOld(orderId) {
        if (!confirm('Bạn có chắc muốn hủy đơn hàng này?\n\nHệ thống sẽ:\n- Hoàn trả hàng vào kho\n- Hoàn trả công nợ khách hàng\n- Ghi nhận giao dịch hoàn tiền')) {
            return;
        }

        toggleLoading(true);
        google.script.run
            .withSuccessHandler((res) => {
                toggleLoading(false);
                if (res && res.success) {
                    showToast(res.message || 'Hủy đơn hàng thành công!', 'success');
                    loadOrders();
                    loadDashboard();
                } else {
                    showToast(res.message || 'Không thể hủy đơn hàng', 'error');
                }
            })
            .withFailureHandler((error) => {
                toggleLoading(false);
                showToast(error.message || 'Không thể hủy đơn hàng', 'error');
            })
            .apiHandler('updateOrderStatus', { orderId, status: 'Cancelled' });
    }

    // PRODUCTS MANAGEMENT

    // Update quick stats for product management page
    function updateProductQuickStats(productsData) {
        const now = new Date();
        let total = productsData.length;
        let inStock = 0;
        let lowStock = 0;
        let outOfStock = 0;
        let totalValue = 0;
        let onSale = 0;

        productsData.forEach(p => {
            const stock = parseFloat(p.stock) || 0;
            const minStock = parseFloat(p.minStock) || 5;
            // Giá trị kho = tồn kho × giá nhập (importPrice), không phải giá bán
            const costPrice = parseFloat(p.importPrice) || 0;

            // Stock status
            if (stock <= 0) {
                outOfStock++;
            } else {
                inStock++;
                if (stock <= minStock) {
                    lowStock++;
                }
            }

            // Total inventory value (cost-based)
            totalValue += stock * costPrice;

            // Expiring soon check (within 30 days)
            if (p.expiryDate) {
                const expiry = new Date(p.expiryDate);
                const daysLeft = Math.floor((expiry - now) / (1000 * 60 * 60 * 24));
                if (daysLeft >= 0 && daysLeft <= 30) onSale++;
            }
        });

        // Update DOM elements
        const totalEl = document.getElementById('quick-stat-total');
        const inStockEl = document.getElementById('quick-stat-instock');
        const lowStockEl = document.getElementById('quick-stat-lowstock');
        const outStockEl = document.getElementById('quick-stat-outstock');
        const valueEl = document.getElementById('quick-stat-value');
        const onSaleEl = document.getElementById('quick-stat-onsale');

        if (totalEl) totalEl.textContent = total;
        if (inStockEl) inStockEl.textContent = inStock;
        if (lowStockEl) lowStockEl.textContent = lowStock;
        if (outStockEl) outStockEl.textContent = outOfStock;
        if (valueEl) valueEl.textContent = formatMoney(totalValue);
        if (onSaleEl) onSaleEl.textContent = onSale;
    }

    function loadProductsManage(forceRefresh) {
        // Setup search listener unconditionally (must work regardless of cache hit)
        const searchEl = document.getElementById('product-manage-search');
        if (searchEl && !searchEl._listenerAttached) {
            searchEl.oninput = debounce(() => applyProductFilters('manage'), 200);
            searchEl._listenerAttached = true;
        }

        // Cache-first: hiển thị cache ngay, skip backend nếu cache còn hạn
        if (!forceRefresh) {
            var cachedProducts = LocalStore.getTTL('products-manage');
            if (cachedProducts && Array.isArray(cachedProducts) && cachedProducts.length > 0) {
                setProducts(cachedProducts);
                renderProductsManage(products, true);
                updateProductQuickStats(products);
                setTimeout(() => { initializeCategoryFilters(); }, 100);
                loadActivePromotions(); // Ensure promo map is loaded for manage tab
                return;
            }
        }

        toggleLoading(true);
        google.script.run
            .withSuccessHandler((res) => {
                try {
                    toggleLoading(false);
                    if (res && res.success && res.data) {
                        setProducts(res.data || []);
                        LocalStore.setTTL('products-manage', products, 600); // 10 phút (mutation handlers đã xóa cache)
                        renderProductsManage(products, true);
                        // Update quick stats
                        updateProductQuickStats(products);
                        // Initialize category filters AFTER products are loaded
                        setTimeout(() => {
                            initializeCategoryFilters();
                        }, 100);
                        loadActivePromotions(); // Load promo map for manage tab
                    } else {
                        console.warn('Products response:', res);
                        setProducts([]);
                        renderProductsManage([]);
                        if (res && res.message) {
                            showToast(res.message, 'warning');
                        }
                    }
                } catch (e) {
                    console.error('Error processing products:', e);
                    showToast('Lỗi khi xử lý dữ liệu sản phẩm: ' + e.toString(), 'error');
                }
            })
            .withFailureHandler(onError)
            .apiHandler('getProducts', null);
    }

    function renderProductsManage(data, resetPage = false) {
        const tbody = document.getElementById('products-manage-body');
        if (!tbody) return;

        // Save filtered products for pagination
        filteredProductsManage = data || [];

        // Reset to page 1 if requested
        if (resetPage) {
            productsManageCurrentPage = 1;
        }

        // Calculate pagination
        const totalItems = filteredProductsManage.length;
        const totalPages = Math.ceil(totalItems / productsManageItemsPerPage);
        const startIndex = (productsManageCurrentPage - 1) * productsManageItemsPerPage;
        const endIndex = startIndex + productsManageItemsPerPage;
        const dataToRender = filteredProductsManage.slice(startIndex, endIndex);

        if (dataToRender.length === 0) {
            const emptyHtml = `
                <div class="flex flex-col items-center py-12">
                    <svg class="w-16 h-16 text-gray-300 mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4"></path>
                    </svg>
                    <p class="text-gray-400 text-sm mb-4">Chưa có sản phẩm nào</p>
                    <button onclick="showProductModal(null)" class="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 text-sm">
                        Thêm sản phẩm đầu tiên
                    </button>
                </div>
            `;
            tbody.innerHTML = `<tr><td colspan="11">${emptyHtml}</td></tr>`;
            const mobileCards = document.getElementById('products-mobile-cards');
            if (mobileCards) mobileCards.innerHTML = emptyHtml;
            return;
        }

        tbody.innerHTML = '';
        const mobileCards = document.getElementById('products-mobile-cards');
        if (mobileCards) mobileCards.innerHTML = '';

        // DocumentFragment: batch DOM writes → single reflow
        const fragment = document.createDocumentFragment();
        const mobileFragment = mobileCards ? document.createDocumentFragment() : null;

        dataToRender.forEach(p => {
            // Check if product is expiring soon (within 30 days)
            const now = new Date();
            const expiryD = p.expiryDate ? new Date(p.expiryDate) : null;
            const daysToExpiry = expiryD ? Math.floor((expiryD - now) / (1000 * 60 * 60 * 24)) : null;
            const isExpiringSoon = daysToExpiry !== null && daysToExpiry >= 0 && daysToExpiry <= 30;
            const isExpired = daysToExpiry !== null && daysToExpiry < 0;

            // Get current price + promo price if active
            const currentPrice = p.price;
            const promoPrice = (typeof getPromoPrice === 'function') ? getPromoPrice(p) : null;

            const isChecked = typeof _bulkSelectedSkus !== 'undefined' && _bulkSelectedSkus.has(p.sku);
            const stockLow = (p.stock || 0) <= (p.minStock || 0);
            const stockZero = (p.stock || 0) === 0;

            // ── Desktop Table Row ──
            const tr = document.createElement('tr');
            tr.className = (p.isFeatured ? 'bg-yellow-50' : '') + ' hover:bg-gray-50 transition-colors cursor-pointer';
            tr.innerHTML = `
                <td class="py-3 px-2 w-8 text-center" onclick="event.stopPropagation()">
                    <input type="checkbox" class="bc-row-check w-4 h-4 rounded border-gray-300 text-blue-600"
                        data-sku="${escapeHtml(p.sku)}"
                        ${isChecked ? 'checked' : ''}
                        onchange="toggleProductBulkSelect('${escapeHtml(p.sku)}', this.checked)">
                </td>
                <td class="py-3 px-4 font-medium text-sm">
                    <div class="flex items-center gap-2">
                        ${p.image ? '<img src="' + escapeHtml(p.image) + '" class="w-8 h-8 object-cover rounded-lg border border-gray-200 flex-shrink-0" loading="lazy" onerror="this.style.display=\'none\'">' : '<div class="w-8 h-8 bg-gray-100 rounded-lg flex items-center justify-center flex-shrink-0 text-gray-400 text-xs">📷</div>'}
                        <div>
                            <span class="text-gray-800">${escapeHtml(p.sku || '')}</span>
                            ${p.isFeatured ? '<span class="ml-1 text-xs bg-yellow-400 text-yellow-900 px-1 rounded">⭐</span>' : ''}
                            ${isExpired ? '<span class="ml-1 text-xs bg-red-700 text-white px-1 rounded">Hết HSD</span>' : isExpiringSoon ? '<span class="ml-1 text-xs bg-orange-500 text-white px-1 rounded">Sắp HSD</span>' : ''}
                        </div>
                    </div>
                </td>
                <td class="py-3 px-4 text-sm text-gray-800">${escapeHtml(p.name || '')}</td>
                <td class="py-3 px-4 text-sm text-gray-500">${escapeHtml(p.category || '')}</td>
                <td class="py-3 px-4 text-right text-sm">
                    ${promoPrice ? `
                        <span class="text-pink-600 font-bold">${formatMoney(promoPrice)}</span>
                        <span class="text-xs text-gray-400 line-through ml-1">${formatMoney(currentPrice)}</span>
                        <div class="text-xs text-pink-500 font-medium">🏷️ KM</div>
                    ` : `<span class="text-gray-800 font-medium">${formatMoney(currentPrice)}</span>`}
                    ${p.expiryDate ? `<div class="text-xs text-gray-400">${isExpired ? '🔴' : isExpiringSoon ? '🟠' : '🟢'} HSD: ${new Date(p.expiryDate).toLocaleDateString('vi-VN')}</div>` : ''}
                </td>
                <td class="py-3 px-4 text-right text-sm text-gray-500 hidden lg:table-cell">${p.vipPrice > 0 ? formatMoney(p.vipPrice) : '-'}</td>
                <td class="py-3 px-4 text-right text-sm text-gray-500 hidden lg:table-cell">${p.wholesalePrice > 0 ? formatMoney(p.wholesalePrice) : '-'}</td>
                <td class="py-3 px-4 text-center text-sm font-semibold ${stockZero ? 'text-red-600' : stockLow ? 'text-orange-500' : 'text-gray-700'}">${p.stock || 0}</td>
                <td class="py-3 px-4 text-center text-xs hidden lg:table-cell">${p.trackSerial ? '<span class="inline-flex items-center gap-1 px-2 py-0.5 rounded-full bg-indigo-50 text-indigo-600 font-medium">🔖 Có</span>' : '<span class="text-gray-300">-</span>'}</td>
                <td class="py-3 px-4 text-center text-xs text-gray-500 hidden lg:table-cell">${escapeHtml(p.unit || '')}</td>
                <td class="py-3 px-4 text-center">
                    <div class="flex items-center justify-center gap-1">
                        <button onclick="event.stopPropagation(); showBarcodeModal('${escapeHtml(p.sku)}', '${(p.name || '').replace(/'/g, "\\'")}')" class="w-7 h-7 flex items-center justify-center rounded-lg hover:bg-gray-100 text-gray-500" title="Mã vạch">📦</button>
                        <button onclick="event.stopPropagation(); viewProductStatistics('${escapeHtml(p.sku)}')" class="w-7 h-7 flex items-center justify-center rounded-lg hover:bg-purple-50 text-purple-500" title="Thống kê">📊</button>
                        <button onclick="event.stopPropagation(); showProductPurchaseHistoryModal('${escapeHtml(p.sku)}', '${(p.name || '').replace(/'/g, "\\'")}')" class="w-7 h-7 flex items-center justify-center rounded-lg hover:bg-green-50 text-green-600" title="Lịch sử nhập hàng">
                          <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" class="w-4 h-4"><path fill-rule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm.75-13a.75.75 0 00-1.5 0v5c0 .414.336.75.75.75h4a.75.75 0 000-1.5h-3.25V5z" clip-rule="evenodd"/></svg>
                        </button>
                        <button onclick="event.stopPropagation(); editProduct('${escapeHtml(p.sku)}')" class="w-7 h-7 flex items-center justify-center rounded-lg hover:bg-blue-50 text-blue-500" title="Sửa">✏️</button>
                        <button onclick="event.stopPropagation(); deleteProduct('${escapeHtml(p.sku)}')" class="w-7 h-7 flex items-center justify-center rounded-lg hover:bg-red-50 text-red-500" title="Xóa">🗑️</button>
                    </div>
                </td>
            `;
            tr.addEventListener('click', function (e) {
                if (e.target.tagName === 'BUTTON' || e.target.closest('button') || e.target.tagName === 'INPUT') return;
                viewProductDetail(p.sku);
            });
            fragment.appendChild(tr);

            // ── Mobile Card ──
            if (mobileFragment) {
                const card = document.createElement('div');
                card.className = 'px-4 py-3 ' + (p.isFeatured ? 'bg-yellow-50' : 'bg-white');
                card.innerHTML = `
                    <div class="flex items-start gap-3">
                        <!-- Checkbox -->
                        <div class="pt-0.5 flex-shrink-0" onclick="event.stopPropagation()">
                            <input type="checkbox" class="bc-row-check w-4 h-4 rounded border-gray-300 text-blue-600"
                                data-sku="${escapeHtml(p.sku)}"
                                ${isChecked ? 'checked' : ''}
                                onchange="toggleProductBulkSelect('${escapeHtml(p.sku)}', this.checked)">
                        </div>
                        <!-- Thumbnail -->
                        ${p.image ? '<img src="' + escapeHtml(p.image) + '" class="w-10 h-10 object-cover rounded-lg border border-gray-200 flex-shrink-0" loading="lazy" onerror="this.style.display=\'none\'">' : ''}
                        <!-- Main content -->
                        <div class="flex-1 min-w-0" onclick="viewProductDetail('${escapeHtml(p.sku)}')">
                            <div class="flex items-start justify-between gap-2 mb-1">
                                <div class="min-w-0">
                                    <p class="font-semibold text-gray-900 text-sm truncate">${escapeHtml(p.name || '')}</p>
                                    <p class="text-xs text-gray-400 mt-0.5">
                                        ${escapeHtml(p.sku || '')}
                                        ${p.category ? ' · ' + escapeHtml(p.category) : ''}
                                        ${p.isFeatured ? ' · ⭐' : ''}
                                    </p>
                                </div>
                                <!-- Price -->
                                <div class="text-right flex-shrink-0">
                                    ${promoPrice ? `
                                        <p class="font-bold text-sm text-pink-600">${formatMoney(promoPrice)}</p>
                                        <p class="text-xs text-gray-400 line-through">${formatMoney(currentPrice)}</p>
                                    ` : `<p class="font-bold text-sm text-gray-800">${formatMoney(currentPrice)}</p>`}
                                    ${p.expiryDate ? `<p class="text-xs ${isExpired ? 'text-red-600' : isExpiringSoon ? 'text-orange-500' : 'text-gray-400'}">HSD: ${new Date(p.expiryDate).toLocaleDateString('vi-VN')}</p>` : ''}
                                </div>
                            </div>
                            <!-- Stock badge + unit -->
                            <div class="flex items-center gap-2 mt-1.5 flex-wrap">
                                <span class="inline-flex items-center px-2 py-0.5 rounded-full text-xs font-semibold ${stockZero ? 'bg-red-100 text-red-700' : stockLow ? 'bg-orange-100 text-orange-700' : 'bg-green-100 text-green-700'}">
                                    ${stockZero ? 'Hết hàng' : stockLow ? '⚠️ Sắp hết' : '✓ Còn hàng'}: ${p.stock || 0}${p.unit ? ' ' + escapeHtml(p.unit) : ''}
                                </span>
                                ${promoPrice ? '<span class="inline-flex items-center px-2 py-0.5 rounded-full text-xs font-semibold bg-pink-100 text-pink-700">🏷️ KM</span>' : ''}
                                ${isExpired ? '<span class="inline-flex items-center px-2 py-0.5 rounded-full text-xs font-semibold bg-red-100 text-red-700">⚠️ Hết HSD</span>' : isExpiringSoon ? '<span class="inline-flex items-center px-2 py-0.5 rounded-full text-xs font-semibold bg-orange-100 text-orange-700">⏳ Sắp HSD</span>' : ''}
                            </div>
                        </div>
                        <!-- Action buttons -->
                        <div class="flex flex-col gap-1 flex-shrink-0">
                            <button onclick="event.stopPropagation(); editProduct('${escapeHtml(p.sku)}')"
                                class="w-8 h-8 flex items-center justify-center rounded-lg bg-blue-50 text-blue-600 hover:bg-blue-100 text-sm" title="Sửa">✏️</button>
                            <button onclick="event.stopPropagation(); showBarcodeModal('${escapeHtml(p.sku)}', '${(p.name || '').replace(/'/g, "\\'")}')"
                                class="w-8 h-8 flex items-center justify-center rounded-lg bg-gray-50 text-gray-600 hover:bg-gray-100 text-sm" title="Mã vạch">📦</button>
                            <button onclick="event.stopPropagation(); deleteProduct('${escapeHtml(p.sku)}')"
                                class="w-8 h-8 flex items-center justify-center rounded-lg bg-red-50 text-red-500 hover:bg-red-100 text-sm" title="Xóa">🗑️</button>
                        </div>
                    </div>
                `;
                mobileFragment.appendChild(card);
            }
        });

        // Batch append: single reflow
        tbody.appendChild(fragment);
        if (mobileCards && mobileFragment) mobileCards.appendChild(mobileFragment);

        // Render pagination controls
        renderPagination('products-manage', totalPages, totalItems, productsManageCurrentPage, productsManageItemsPerPage);
    }

    function goToProductsManagePage(page) {
        if (page < 1 || page > Math.ceil(filteredProductsManage.length / productsManageItemsPerPage)) return;
        productsManageCurrentPage = page;
        renderProductsManage(filteredProductsManage, false);
    }

    function generateNextProductSku() {
        var maxNum = 0;
        if (products && products.length > 0) {
            for (var i = 0; i < products.length; i++) {
                var sku = String(products[i].sku || '');
                var match = sku.match(/^SP(\d+)$/i);
                if (match) {
                    var num = parseInt(match[1], 10);
                    if (num > maxNum) maxNum = num;
                }
            }
        }
        return 'SP' + String(maxNum + 1).padStart(3, '0');
    }

    function showProductModal(sku = null) {
        const modal = document.getElementById('product-modal');
        const form = document.getElementById('product-form');
        form.reset();
        document.getElementById('product-id').value = '';

        // Populate brand datalist from existing products
        var brandList = document.getElementById('product-brand-list');
        if (brandList) {
            var brands = [];
            products.forEach(function(p) { if (p.brand && brands.indexOf(p.brand) === -1) brands.push(p.brand); });
            brands.sort();
            brandList.innerHTML = brands.map(function(b) { return '<option value="' + escapeHtml(b) + '">'; }).join('');
        }

        if (sku) {
            const product = productBySku.get(sku);
            if (product) {
                document.getElementById('product-modal-title').innerText = 'Sửa Sản Phẩm';
                document.getElementById('product-sku').value = product.sku || '';
                document.getElementById('product-sku').readOnly = true;
                document.getElementById('product-name').value = product.name || '';
                document.getElementById('product-category').value = product.category || '';
                document.getElementById('product-import-price').value = product.importPrice ? parseInt(product.importPrice).toLocaleString('vi-VN') : '';
                document.getElementById('product-sell-price').value = product.price ? parseInt(product.price).toLocaleString('vi-VN') : '';
                // Use String() with dot decimal to avoid browser locale converting 10.1 → "10,1" which breaks type=number validation
                document.getElementById('product-stock').value = product.stock != null ? String(product.stock).replace(',', '.') : 0;
                document.getElementById('product-unit').value = product.unit || '';
                document.getElementById('product-warranty-months').value = product.warrantyMonths || '';
                document.getElementById('product-status').value = product.status || 'Active';
                document.getElementById('product-description').value = product.description || '';
                populateProductImagePreview(product.image || '');
                document.getElementById('product-supplier-id').value = product.supplierId || '';
                document.getElementById('product-min-stock').value = product.minStock || '';
                document.getElementById('product-max-stock').value = product.maxStock || '';
                document.getElementById('product-barcode').value = product.barcode || '';
                document.getElementById('product-tags').value = product.tags || '';
                // Show print barcode button if barcode or sku exists
                const btnPrintBC = document.getElementById('btn-print-barcode-product');
                if (btnPrintBC) btnPrintBC.style.display = (product.barcode || product.sku) ? 'flex' : 'none';
                // New fields
                document.getElementById('product-vip-price').value = product.vipPrice ? parseInt(product.vipPrice).toLocaleString('vi-VN') : '';
                document.getElementById('product-wholesale-price').value = product.wholesalePrice ? parseInt(product.wholesalePrice).toLocaleString('vi-VN') : '';
                document.getElementById('product-lot-number').value = product.lotNumber || '';
                document.getElementById('product-expiry-date').value = product.expiryDate ? toLocalDateStr(product.expiryDate) : '';
                document.getElementById('product-is-featured').checked = product.isFeatured || false;
                document.getElementById('product-display-order').value = product.displayOrder || '';
                // Brand
                document.getElementById('product-brand').value = product.brand || '';
                // Serial tracking
                var trackSerialInput = document.getElementById('product-track-serial');
                if (trackSerialInput) trackSerialInput.checked = product.trackSerial || false;
                toggleProductSerialPanel(product.sku);
                // VAT fields
                const vatInput = document.getElementById('product-vat-rate');
                if (vatInput) {
                    vatInput.value = product.defaultVatRate || 0;
                }
                const vatIncInput = document.getElementById('product-vat-included');
                if (vatIncInput) {
                    vatIncInput.checked = product.vatIncluded || false;
                }
                setTimeout(calcVatPreview, 50);

                // Show promo banner if product has active promotion
                const promoBanner = document.getElementById('product-promo-banner');
                const promoDetail = document.getElementById('product-promo-detail');
                const promoPriceEl = document.getElementById('product-promo-price');
                if (promoBanner) {
                    const promoPrice = (typeof getPromoPrice === 'function') ? getPromoPrice(product) : null;
                    if (promoPrice) {
                        const promo = (typeof activePromotions !== 'undefined') ? activePromotions[product.sku] : null;
                        let detail = '';
                        if (promo) {
                            if (promo.type === 'percent') detail = `Giảm ${promo.value}%${promo.maxDiscount > 0 ? ' (tối đa ' + formatMoney(promo.maxDiscount) + ')' : ''}`;
                            else if (promo.type === 'fixed') detail = `Giảm ${formatMoney(promo.value)}`;
                            if (promo.endDate) detail += ` · HH: ${new Date(promo.endDate).toLocaleDateString('vi-VN')}`;
                        }
                        if (promoDetail) promoDetail.textContent = detail;
                        if (promoPriceEl) promoPriceEl.textContent = formatMoney(promoPrice);
                        promoBanner.classList.remove('hidden');
                    } else {
                        promoBanner.classList.add('hidden');
                    }
                }
            }
        } else {
            document.getElementById('product-modal-title').innerText = 'Thêm Sản Phẩm';
            document.getElementById('product-sku').readOnly = false;
            document.getElementById('product-sku').value = generateNextProductSku();
            // Hide serial panel for new product
            var serialPanel = document.getElementById('product-serial-panel');
            if (serialPanel) serialPanel.classList.add('hidden');
            // Hide promo banner for new product
            const promoBannerNew = document.getElementById('product-promo-banner');
            if (promoBannerNew) promoBannerNew.classList.add('hidden');
        }
        modal.classList.remove('hidden');
    }

    function closeProductModal() {
        document.getElementById('product-modal').classList.add('hidden');
        const btnPrintBC = document.getElementById('btn-print-barcode-product');
        if (btnPrintBC) btnPrintBC.style.display = 'none';
        // Reset upload UI
        resetProductImageUpload();
        // Reset serial panel
        var serialPanel = document.getElementById('product-serial-panel');
        if (serialPanel) serialPanel.classList.add('hidden');
    }

    // =====================================================
    // PRODUCT SERIAL PANEL (add serials directly from product modal)
    // =====================================================
    var _productSerialList = []; // current loaded serials for this product

    function toggleProductSerialPanel(sku) {
        var panel = document.getElementById('product-serial-panel');
        var checked = document.getElementById('product-track-serial')?.checked;
        var currentSku = sku || document.getElementById('product-sku')?.value;
        if (!panel) return;
        // Only show when editing existing product + trackSerial checked
        if (checked && currentSku && document.getElementById('product-sku')?.readOnly) {
            panel.classList.remove('hidden');
            loadProductSerials(currentSku);
        } else {
            panel.classList.add('hidden');
        }
    }

    function loadProductSerials(sku) {
        var listEl = document.getElementById('product-serial-list');
        var countEl = document.getElementById('product-serial-count');
        if (!listEl) return;
        listEl.innerHTML = '<div class="text-gray-400 text-xs">Đang tải...</div>';
        google.script.run
            .withSuccessHandler(function(res) {
                _productSerialList = (res && res.success && res.data) ? res.data : [];
                renderProductSerialList();
            })
            .withFailureHandler(function() {
                listEl.innerHTML = '<div class="text-red-400 text-xs">Lỗi tải serial</div>';
            })
            .apiHandler('getSerials', { sku: sku });
    }

    function renderProductSerialList() {
        var listEl = document.getElementById('product-serial-list');
        var countEl = document.getElementById('product-serial-count');
        if (!listEl) return;
        var available = _productSerialList.filter(function(s) { return s.status === 'Available'; });
        var sold = _productSerialList.filter(function(s) { return s.status === 'Sold'; });
        if (countEl) countEl.textContent = available.length + ' khả dụng / ' + _productSerialList.length + ' tổng';
        if (_productSerialList.length === 0) {
            listEl.innerHTML = '<div class="text-gray-400 text-xs py-1">Chưa có serial nào</div>';
            return;
        }
        var statusColors = { Available: 'bg-green-100 text-green-700', Sold: 'bg-blue-100 text-blue-700', Returned: 'bg-yellow-100 text-yellow-700', Warranty: 'bg-orange-100 text-orange-700' };
        listEl.innerHTML = _productSerialList.map(function(s) {
            var cls = statusColors[s.status] || 'bg-gray-100 text-gray-600';
            return '<div class="flex items-center justify-between px-2 py-1 rounded ' + (s.status === 'Available' ? 'bg-white border' : 'bg-gray-50') + '">' +
                '<span class="font-mono text-xs">' + escapeHtml(s.serialNo) + '</span>' +
                '<span class="text-xs px-1.5 py-0.5 rounded ' + cls + '">' + escapeHtml(s.status) + '</span></div>';
        }).join('');
    }

    function addProductSerials() {
        var input = document.getElementById('product-serial-input');
        var raw = (input ? input.value.trim() : '');
        if (!raw) return;
        var sku = document.getElementById('product-sku')?.value;
        if (!sku) { showToast('Không xác định được mã SP', 'error'); return; }
        // Parse: comma, newline, or space separated
        var serials = raw.split(/[,\n\r]+/).map(function(s) { return s.trim(); }).filter(Boolean);
        if (serials.length === 0) return;
        // Check duplicates with existing
        var existing = _productSerialList.map(function(s) { return s.serialNo; });
        var dupes = serials.filter(function(s) { return existing.indexOf(s) !== -1; });
        if (dupes.length > 0) {
            showToast('Serial đã tồn tại: ' + dupes.join(', '), 'warning');
            serials = serials.filter(function(s) { return existing.indexOf(s) === -1; });
            if (serials.length === 0) return;
        }
        input.value = '';
        var btn = input.nextElementSibling;
        setBtnLoading(btn, true, 'Lưu...');
        google.script.run
            .withSuccessHandler(function(res) {
                setBtnLoading(btn, false);
                if (res && res.success) {
                    showToast('Đã thêm ' + serials.length + ' serial', 'success');
                    loadProductSerials(sku);
                } else {
                    showToast((res && res.message) || 'Lỗi thêm serial', 'error');
                }
            })
            .withFailureHandler(function(err) {
                setBtnLoading(btn, false);
                showToast('Lỗi: ' + (err.message || err), 'error');
            })
            .apiHandler('addProductSerials', { sku: sku, serialNos: serials });
    }

    // =====================================================
    // PRODUCT IMAGE UPLOAD (Google Drive)
    // =====================================================
    var _isUploadingProductImage = false;

    function handleProductImageSelect(input) {
        var file = input.files[0];
        if (!file) return;
        if (_isUploadingProductImage) {
            showToast('Đang upload ảnh, vui lòng đợi...', 'warning');
            input.value = '';
            return;
        }
        if (!file.type.startsWith('image/')) {
            showToast('Vui lòng chọn file ảnh (JPG, PNG, GIF)', 'warning');
            input.value = '';
            return;
        }
        // Max 5MB before resize
        if (file.size > 5 * 1024 * 1024) {
            showToast('Ảnh quá lớn (tối đa 5MB)', 'warning');
            input.value = '';
            return;
        }
        // Show preview immediately
        var reader = new FileReader();
        reader.onload = function(e) {
            showProductImagePreview(e.target.result);
        };
        reader.readAsDataURL(file);
        // Resize then upload
        resizeAndUploadProductImage(file);
    }

    function resizeAndUploadProductImage(file) {
        var maxDim = 800;
        var canvas = document.createElement('canvas');
        var ctx = canvas.getContext('2d');
        var img = new Image();
        img.onload = function() {
            URL.revokeObjectURL(img.src); // Free memory
            var w = img.width, h = img.height;
            if (w > maxDim || h > maxDim) {
                if (w > h) { h = Math.round(h * maxDim / w); w = maxDim; }
                else { w = Math.round(w * maxDim / h); h = maxDim; }
            }
            canvas.width = w;
            canvas.height = h;
            ctx.drawImage(img, 0, 0, w, h);
            // Convert to JPEG base64 (quality 80%)
            var base64 = canvas.toDataURL('image/jpeg', 0.8);
            var base64Data = base64.split(',')[1]; // Remove data:image/jpeg;base64, prefix
            uploadProductImageToDrive(base64Data, file.name);
        };
        img.src = URL.createObjectURL(file);
    }

    function uploadProductImageToDrive(base64Data, fileName) {
        _isUploadingProductImage = true;
        var uploadingEl = document.getElementById('product-image-uploading');
        var labelEl = document.getElementById('product-image-label');
        var fileInput = document.getElementById('product-image-file');
        if (uploadingEl) uploadingEl.classList.remove('hidden');
        if (labelEl) labelEl.textContent = 'Đang upload...';
        if (fileInput) fileInput.disabled = true;

        google.script.run
            .withSuccessHandler(function(res) {
                _isUploadingProductImage = false;
                if (uploadingEl) uploadingEl.classList.add('hidden');
                if (fileInput) fileInput.disabled = false;
                if (labelEl) labelEl.textContent = 'Đổi ảnh';
                if (res && res.success && res.data) {
                    var imageUrl = res.data.url;
                    document.getElementById('product-image').value = imageUrl;
                    showProductImagePreview(imageUrl);
                    showToast('Upload ảnh thành công!', 'success');
                } else {
                    showToast((res && res.message) || 'Lỗi upload ảnh', 'error');
                    if (labelEl) labelEl.textContent = 'Chọn ảnh sản phẩm';
                }
            })
            .withFailureHandler(function(err) {
                _isUploadingProductImage = false;
                if (uploadingEl) uploadingEl.classList.add('hidden');
                if (fileInput) fileInput.disabled = false;
                if (labelEl) labelEl.textContent = 'Chọn ảnh sản phẩm';
                showToast('Lỗi upload: ' + (err.message || err.toString()), 'error');
            })
            .apiHandler('uploadProductImage', { data: base64Data, fileName: fileName });
    }

    function showProductImagePreview(src) {
        var container = document.getElementById('product-image-preview-container');
        var img = document.getElementById('product-image-preview');
        if (container && img) {
            img.src = src;
            container.classList.remove('hidden');
        }
    }

    function removeProductImage() {
        document.getElementById('product-image').value = '';
        var container = document.getElementById('product-image-preview-container');
        if (container) container.classList.add('hidden');
        var labelEl = document.getElementById('product-image-label');
        if (labelEl) labelEl.textContent = 'Chọn ảnh sản phẩm';
        var fileInput = document.getElementById('product-image-file');
        if (fileInput) fileInput.value = '';
    }

    function resetProductImageUpload() {
        removeProductImage();
        var uploadingEl = document.getElementById('product-image-uploading');
        if (uploadingEl) uploadingEl.classList.add('hidden');
    }

    // Populate image preview when editing product
    function populateProductImagePreview(imageUrl) {
        if (imageUrl && imageUrl.trim()) {
            document.getElementById('product-image').value = imageUrl;
            showProductImagePreview(imageUrl);
            var labelEl = document.getElementById('product-image-label');
            if (labelEl) labelEl.textContent = 'Đổi ảnh';
        } else {
            resetProductImageUpload();
        }
    }

    // =====================================================
    // BARCODE SCANNER (camera removed — use keyboard/manual input only)
    // =====================================================
    var _scannerTarget = null;    // kept for confirmManualBarcode compatibility

    // =====================================================
    // END BARCODE SCANNER (camera removed)
    // =====================================================

    function printBarcodeFromEditForm() {
        const sku = document.getElementById('product-sku').value.trim();
        const name = document.getElementById('product-name').value.trim();
        const price = parseMoneyInput(document.getElementById('product-sell-price'));
        const barcodeVal = document.getElementById('product-barcode').value.trim() || sku;
        if (!barcodeVal) { showToast('Chưa có mã vạch hoặc SKU', 'warning'); return; }
        // Override barcode value in modal after open
        showBarcodeModal(sku, name, price);
        setTimeout(function() {
            const bcInput = document.getElementById('bc-value');
            if (bcInput && barcodeVal !== sku) {
                bcInput.value = barcodeVal;
                bcUpdatePreview();
            }
        }, 80);
    }

    function saveProduct(event) {
        event.preventDefault();

        // Validation
        var sku = document.getElementById('product-sku').value.trim();
        const name = document.getElementById('product-name').value.trim();
        const sellPrice = parseMoneyInput(document.getElementById('product-sell-price'));

        // Auto-generate SKU if empty
        if (!sku) {
            sku = generateNextProductSku();
            document.getElementById('product-sku').value = sku;
        }

        // Check duplicate SKU when creating new
        var isEditMode = document.getElementById('product-sku').readOnly;
        if (!isEditMode) {
            var existing = productBySku.get(sku);
            if (existing) {
                showToast('Mã sản phẩm "' + sku + '" đã tồn tại!', 'warning');
                document.getElementById('product-sku').focus();
                return;
            }
        }

        if (!name) {
            showToast('Vui lòng nhập tên sản phẩm!', 'warning');
            document.getElementById('product-name').focus();
            return;
        }
        if (sellPrice < 0) {
            showToast('Giá bán phải là số dương!', 'warning');
            document.getElementById('product-sell-price').focus();
            return;
        }

        const productData = {
            sku: sku,
            name: name,
            category: document.getElementById('product-category').value.trim() || '',
            importPrice: parseMoneyInput(document.getElementById('product-import-price')),
            sellPrice: sellPrice,
            price: sellPrice, // Also set price for compatibility
            stock: parseFloat(String(document.getElementById('product-stock').value).replace(',', '.')) || 0,
            unit: document.getElementById('product-unit').value.trim() || '',
            warrantyMonths: parseFloat(document.getElementById('product-warranty-months').value) || 0,
            status: document.getElementById('product-status').value || 'Active',
            description: document.getElementById('product-description').value.trim() || '',
            image: document.getElementById('product-image').value.trim() || '',
            supplierId: document.getElementById('product-supplier-id').value.trim() || '',
            minStock: parseFloat(document.getElementById('product-min-stock').value) || 0,
            maxStock: parseFloat(document.getElementById('product-max-stock').value) || 0,
            barcode: document.getElementById('product-barcode').value.trim() || '',
            tags: document.getElementById('product-tags').value.trim() || '',
            // New fields
            vipPrice: parseMoneyInput(document.getElementById('product-vip-price')),
            wholesalePrice: parseMoneyInput(document.getElementById('product-wholesale-price')),
            lotNumber: document.getElementById('product-lot-number').value.trim() || '',
            expiryDate: document.getElementById('product-expiry-date').value || '',
            isFeatured: document.getElementById('product-is-featured').checked,
            displayOrder: parseFloat(document.getElementById('product-display-order').value) || 0,
            // VAT fields
            defaultVatRate: parseFloat(document.getElementById('product-vat-rate')?.value) || window._tempVATRate || 0,
            vatIncluded: document.getElementById('product-vat-included')?.checked || false,
            trackSerial: document.getElementById('product-track-serial')?.checked || false,
            brand: document.getElementById('product-brand')?.value.trim() || ''
        };

        const isEdit = document.getElementById('product-sku').readOnly;
        var btnSaveProduct = document.getElementById('btn-save-product');
        setBtnLoading(btnSaveProduct, true, isEdit ? 'Đang cập nhật...' : 'Đang lưu...');
        btnSaveProduct._btnLoadingApplied = true; // Prevent toggleLoading from overwriting _origHTML
        toggleLoading(true, isEdit ? 'Đang cập nhật sản phẩm...' : 'Đang thêm sản phẩm...');
        google.script.run
            .withSuccessHandler((res) => {
                toggleLoading(false);
                setBtnLoading(btnSaveProduct, false);
                if (res.success) {
                    showToast(isEdit ? 'Cập nhật sản phẩm thành công!' : 'Thêm sản phẩm thành công!', 'success');
                    closeProductModal();
                    localStorage.removeItem('TTL_products-manage');
                    loadProductsManage(true);
                    if (document.getElementById('page-order').classList.contains('hidden') === false) {
                        loadData();
                    }
                } else {
                    showToast('Lỗi: ' + res.message, 'error');
                }
            })
            .withFailureHandler((err) => {
                toggleLoading(false);
                setBtnLoading(btnSaveProduct, false);
                onError(err);
            })
            .apiHandler(isEdit ? 'updateProduct' : 'createProduct', productData);
    }

    function viewProductDetail(sku) {
        const product = productBySku.get(sku);
        if (!product) {
            showToast('Không tìm thấy sản phẩm!', 'error');
            return;
        }

        const modal = document.getElementById('product-detail-modal');
        const content = document.getElementById('product-detail-content');

        const minStock = product.minStock || 10;
        const stockClass = product.stock === 0 ? 'text-red-600 font-bold' : product.stock <= minStock ? 'text-red-600 font-bold' : product.stock < (minStock * 2) ? 'text-yellow-600' : 'text-green-600';
        const statusClass = product.status === 'Active' ? 'bg-green-100 text-green-800' : 'bg-gray-100 text-gray-800';

        const isLowStock = (product.minStock && product.stock <= product.minStock) || (!product.minStock && product.stock < 10);
        const promoPrice = (typeof getPromoPrice === 'function') ? getPromoPrice(product) : null;
        content.innerHTML = `
            <!-- Stock alert -->
            ${isLowStock ? `
            <div class="mb-4 p-3 bg-red-50 border border-red-200 rounded-xl flex items-center gap-2">
                <span class="text-base">⚠️</span>
                <p class="text-sm text-red-700 font-medium">${product.stock === 0 ? 'Sản phẩm đã hết hàng!' : 'Sản phẩm sắp hết hàng!'} ${product.minStock ? '(Tối thiểu: ' + product.minStock + ')' : ''}</p>
            </div>
            ` : ''}

            <!-- Hero: Tên + SKU + Trạng thái -->
            <div class="flex items-start justify-between gap-3 mb-4">
                <div class="flex-1 min-w-0">
                    <p class="text-xs text-gray-400 mb-0.5">${escapeHtml(product.sku || '')}</p>
                    <h3 class="text-base font-bold text-gray-900 leading-tight">${escapeHtml(product.name || '')}</h3>
                    ${product.category ? `<p class="text-xs text-gray-500 mt-1">📂 ${escapeHtml(product.category)}</p>` : ''}
                    ${promoPrice ? `<span class="inline-block mt-1.5 px-2 py-0.5 bg-pink-100 text-pink-700 rounded-full text-xs font-semibold">🏷️ Đang khuyến mãi</span>` : ''}
                </div>
                <span class="flex-shrink-0 px-2.5 py-1 rounded-full text-xs font-semibold ${statusClass}">
                    ${product.status === 'Active' ? '✅ Đang bán' : '⏸ Ngừng bán'}
                </span>
            </div>

            ${product.image ? `
            <img src="${escapeHtml(product.image)}" alt="${escapeHtml(product.name)}" class="w-full h-36 object-contain rounded-xl border border-gray-100 bg-gray-50 mb-4" onerror="this.style.display='none'">
            ` : ''}

            <!-- Giá & Tồn kho nổi bật -->
            <div class="grid ${canViewImportPrice() ? 'grid-cols-3' : 'grid-cols-2'} gap-2 mb-4">
                <div class="${promoPrice ? 'bg-pink-50' : 'bg-blue-50'} rounded-xl p-3 text-center">
                    <p class="text-xs text-gray-500 mb-1">Giá Bán</p>
                    ${promoPrice ? `
                        <p class="font-bold text-pink-600 text-sm">${formatMoney(promoPrice)}</p>
                        <p class="text-xs text-gray-400 line-through">${formatMoney(product.price || 0)}</p>
                    ` : `<p class="font-bold text-blue-600 text-sm">${formatMoney(product.price || 0)}</p>`}
                </div>
                ${canViewImportPrice() ? `<div class="bg-gray-50 rounded-xl p-3 text-center">
                    <p class="text-xs text-gray-500 mb-1">Giá Nhập</p>
                    <p class="font-semibold text-gray-700 text-sm">${formatMoney(product.importPrice || 0)}</p>
                </div>` : ''}
                <div class="${product.stock === 0 ? 'bg-red-50' : isLowStock ? 'bg-orange-50' : 'bg-green-50'} rounded-xl p-3 text-center">
                    <p class="text-xs text-gray-500 mb-1">Tồn Kho</p>
                    <p class="font-bold text-sm ${stockClass}">${product.stock || 0} <span class="text-xs font-normal">${escapeHtml(product.unit || 'cái')}</span></p>
                </div>
            </div>

            <!-- Chi tiết dạng list -->
            <div class="space-y-0 divide-y divide-gray-100 rounded-xl overflow-hidden border border-gray-100 mb-4">
                ${promoPrice ? `
                <div class="flex justify-between items-center px-3 py-2.5 bg-pink-50">
                    <span class="text-xs text-pink-600 font-semibold">🏷️ Giá Khuyến Mãi</span>
                    <span class="text-sm font-bold text-pink-600">${formatMoney(promoPrice)}</span>
                </div>` : ''}
                ${product.vipPrice > 0 ? `
                <div class="flex justify-between items-center px-3 py-2.5 bg-white">
                    <span class="text-xs text-gray-500">Giá VIP</span>
                    <span class="text-sm font-medium text-purple-600">${formatMoney(product.vipPrice)}</span>
                </div>` : ''}
                ${product.wholesalePrice > 0 ? `
                <div class="flex justify-between items-center px-3 py-2.5 bg-white">
                    <span class="text-xs text-gray-500">Giá Bán Buôn</span>
                    <span class="text-sm font-medium text-indigo-600">${formatMoney(product.wholesalePrice)}</span>
                </div>` : ''}
                ${product.minStock ? `
                <div class="flex justify-between items-center px-3 py-2.5 bg-white">
                    <span class="text-xs text-gray-500">Tồn tối thiểu</span>
                    <span class="text-sm text-gray-700">${product.minStock} ${escapeHtml(product.unit || 'cái')}</span>
                </div>` : ''}
                ${product.supplierId ? `
                <div class="flex justify-between items-center px-3 py-2.5 bg-white">
                    <span class="text-xs text-gray-500">Nhà Cung Cấp</span>
                    <span class="text-sm text-gray-700">${escapeHtml(product.supplierId)}</span>
                </div>` : ''}
                ${product.brand ? `
                <div class="flex justify-between items-center px-3 py-2.5 bg-white">
                    <span class="text-xs text-gray-500">Thương Hiệu</span>
                    <span class="text-sm font-medium text-gray-700">${escapeHtml(product.brand)}</span>
                </div>` : ''}
                ${product.barcode ? `
                <div class="flex justify-between items-center px-3 py-2.5 bg-white">
                    <span class="text-xs text-gray-500">Barcode</span>
                    <span class="text-sm font-mono text-gray-700">${escapeHtml(product.barcode)}</span>
                </div>` : ''}
                ${product.warrantyMonths > 0 ? `
                <div class="flex justify-between items-center px-3 py-2.5 bg-white">
                    <span class="text-xs text-gray-500">Bảo Hành</span>
                    <span class="text-sm text-gray-700">${product.warrantyMonths} tháng</span>
                </div>` : ''}
                ${product.lotNumber ? `
                <div class="flex justify-between items-center px-3 py-2.5 bg-white">
                    <span class="text-xs text-gray-500">Số Lô</span>
                    <span class="text-sm font-mono text-gray-700">${escapeHtml(product.lotNumber)}</span>
                </div>` : ''}
                ${product.expiryDate ? `
                <div class="flex justify-between items-center px-3 py-2.5 ${new Date(product.expiryDate) < new Date() ? 'bg-red-50' : 'bg-white'}">
                    <span class="text-xs text-gray-500">Hạn Sử Dụng</span>
                    <span class="text-sm font-medium ${new Date(product.expiryDate) < new Date() ? 'text-red-600' : 'text-gray-700'}">${new Date(product.expiryDate).toLocaleDateString('vi-VN')}</span>
                </div>` : ''}
                ${product.defaultVatRate > 0 ? `
                <div class="flex justify-between items-center px-3 py-2.5 bg-white">
                    <span class="text-xs text-gray-500">VAT</span>
                    <span class="text-sm text-gray-700">${product.defaultVatRate}%${product.vatIncluded ? ' <span class="text-xs text-orange-600">(giá đã gồm VAT)</span>' : ''}</span>
                </div>` : ''}
                ${product.isFeatured ? `
                <div class="flex justify-between items-center px-3 py-2.5 bg-yellow-50">
                    <span class="text-xs text-gray-500">Nổi Bật</span>
                    <span class="text-sm">⭐ Có</span>
                </div>` : ''}
            </div>

            ${product.tags ? `
            <div class="mb-4">
                <p class="text-xs text-gray-500 mb-2">Tags</p>
                <div class="flex flex-wrap gap-1.5">
                    ${product.tags.split(',').map(tag => `<span class="px-2.5 py-1 bg-blue-100 text-blue-700 rounded-full text-xs font-medium">${escapeHtml(tag.trim())}</span>`).join('')}
                </div>
            </div>` : ''}

            ${product.description ? `
            <div class="bg-gray-50 rounded-xl p-3">
                <p class="text-xs text-gray-500 mb-1.5">Mô Tả</p>
                <p id="product-desc-text" class="text-sm text-gray-700 leading-relaxed overflow-hidden" style="display:-webkit-box;-webkit-line-clamp:3;-webkit-box-orient:vertical;">${escapeHtml(product.description)}</p>
                ${product.description.length > 120 ? `<button onclick="toggleProductDesc()" id="product-desc-toggle" class="text-xs text-blue-600 mt-1 hover:underline">Xem thêm</button>` : ''}
            </div>` : ''}
        `;

        // Bind footer action buttons
        const editBtn = document.getElementById('product-detail-edit-btn');
        const barcodeBtn = document.getElementById('product-detail-barcode-btn');
        if (editBtn) editBtn.onclick = function() { closeProductDetailModal(); editProduct(product.sku); };
        if (barcodeBtn) barcodeBtn.onclick = function() { showBarcodeModal(product.sku, product.name, product.price); };

        modal.classList.remove('hidden');
        modal.style.display = 'flex';
    }

    function closeProductDetailModal() {
        const modal = document.getElementById('product-detail-modal');
        modal.classList.add('hidden');
        modal.style.display = '';
    }

    function toggleProductDesc() {
        const text = document.getElementById('product-desc-text');
        const btn = document.getElementById('product-desc-toggle');
        if (!text || !btn) return;
        const isCollapsed = text.style.webkitLineClamp === '3';
        text.style.webkitLineClamp = isCollapsed ? 'unset' : '3';
        btn.textContent = isCollapsed ? 'Thu gọn' : 'Xem thêm';
    }

    function editProduct(sku) {
        showProductModal(sku);
    }

    // Product Tab Management
    let currentProductTab = 'all';

    function switchProductTab(tab) {
        currentProductTab = tab;

        // Update tab styles
        document.querySelectorAll('.product-tab').forEach(btn => {
            btn.classList.remove('border-blue-500', 'text-blue-600');
            btn.classList.add('border-transparent', 'text-gray-500');
        });
        const activeTab = document.getElementById('product-tab-' + tab);
        if (activeTab) {
            activeTab.classList.remove('border-transparent', 'text-gray-500');
            activeTab.classList.add('border-blue-500', 'text-blue-600');
        }

        // Load data based on tab
        toggleLoading(true);
        switch (tab) {
            case 'featured':
                google.script.run
                    .withSuccessHandler((res) => {
                        toggleLoading(false);
                        if (res && res.success && res.data) {
                            renderProductsManage(res.data, true); // Reset to page 1
                        } else {
                            renderProductsManage([]);
                        }
                    })
                    .withFailureHandler(onError)
                    .apiHandler('getFeaturedProducts', null);
                break;
            case 'onsale':
                google.script.run
                    .withSuccessHandler((res) => {
                        toggleLoading(false);
                        if (res && res.success && res.data) {
                            renderProductsManage(res.data, true); // Reset to page 1
                        } else {
                            renderProductsManage([]);
                        }
                    })
                    .withFailureHandler(onError)
                    .apiHandler('getProductsOnSale', null);
                break;
            case 'topselling':
                google.script.run
                    .withSuccessHandler((res) => {
                        toggleLoading(false);
                        if (res && res.success && res.data) {
                            // Transform top selling data for display
                            const displayData = res.data.map(p => ({
                                ...p,
                                name: p.name + ` (${p.totalQty} bán)`,
                                price: p.totalRevenue / p.totalQty || p.price
                            }));
                            renderProductsManage(displayData);
                        } else {
                            renderProductsManage([]);
                        }
                    })
                    .withFailureHandler(onError)
                    .apiHandler('getTopSellingProducts', { limit: 50 });
                break;
            case 'lowstock':
                google.script.run
                    .withSuccessHandler((res) => {
                        toggleLoading(false);
                        if (res && res.success && res.data) {
                            renderProductsManage(res.data, true); // Reset to page 1
                        } else {
                            renderProductsManage([]);
                        }
                    })
                    .withFailureHandler(onError)
                    .apiHandler('getLowStockProducts', null);
                break;
            default:
                loadProductsManage();
        }
    }

    // Toggle product export dropdown menu
    function toggleProductExportMenu() {
        const menu = document.getElementById('product-export-menu');
        if (menu) {
            menu.classList.toggle('hidden');
        }
    }

    // Close export menu when clicking outside
    document.addEventListener('click', function(e) {
        const menu = document.getElementById('product-export-menu');
        if (menu && !menu.classList.contains('hidden')) {
            const btn = e.target.closest('button');
            if (!btn || !btn.textContent.includes('Xuất dữ liệu')) {
                menu.classList.add('hidden');
            }
        }
    });

    // Export Products to CSV
    function exportProductsCSV() {
        toggleLoading(true);
        google.script.run
            .withSuccessHandler((res) => {
                toggleLoading(false);
                if (res && res.success && res.data) {
                    const csvContent = res.data;
                    const blob = new Blob(['\uFEFF' + csvContent], { type: 'text/csv;charset=utf-8;' });
                    const link = document.createElement('a');
                    const url = URL.createObjectURL(blob);
                    link.setAttribute('href', url);
                    link.setAttribute('download', 'SanPham_' + toLocalDateStr() + '.csv');
                    link.style.visibility = 'hidden';
                    document.body.appendChild(link);
                    link.click();
                    document.body.removeChild(link);
                    showToast('Đã xuất CSV thành công!', 'success');
                } else {
                    showToast('Lỗi khi xuất CSV: ' + (res.message || 'Unknown error'), 'error');
                }
            })
            .withFailureHandler((error) => {
                toggleLoading(false);
                showToast('Lỗi khi xuất CSV: ' + error.toString(), 'error');
            })
            .apiHandler('exportProductsToCSV', {});
    }

    // Import Products from CSV
    function showImportProductsModal() {
        document.getElementById('import-products-modal').classList.remove('hidden');
    }

    function closeImportProductsModal() {
        document.getElementById('import-products-modal').classList.add('hidden');
        document.getElementById('import-csv-content').value = '';
        document.getElementById('import-csv-file').value = '';
    }

    function handleCSVFileSelect(event) {
        const file = event.target.files[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = (e) => {
            document.getElementById('import-csv-content').value = e.target.result;
        };
        reader.readAsText(file, 'UTF-8');
    }

    function importProductsFromCSV() {
        const csvContent = document.getElementById('import-csv-content').value.trim();
        if (!csvContent) {
            showToast('Vui lòng nhập hoặc chọn file CSV!', 'warning');
            return;
        }

        const updateExisting = document.getElementById('import-update-existing').checked;
        const skipErrors = document.getElementById('import-skip-errors').checked;

        toggleLoading(true);
        google.script.run
            .withSuccessHandler((res) => {
                toggleLoading(false);
                if (res && res.success) {
                    showToast(res.message || 'Import thành công!', 'success');
                    closeImportProductsModal();
                    localStorage.removeItem('TTL_products-manage');
                    loadProductsManage(true);
                } else {
                    showToast('Lỗi: ' + (res.message || 'Unknown error'), 'error');
                    if (res.data && res.data.errors && res.data.errors.length > 0) {
                        console.error('Import errors:', res.data.errors);
                    }
                }
            })
            .withFailureHandler((error) => {
                toggleLoading(false);
                showToast('Lỗi khi import: ' + error.toString(), 'error');
            })
            .apiHandler('importProductsFromCSV', {
                csvContent: csvContent,
                options: {
                    updateExisting: updateExisting,
                    skipErrors: skipErrors
                }
            });
    }

    // View Product Statistics
    function viewProductStatistics(sku) {
        toggleLoading(true);
        google.script.run
            .withSuccessHandler((res) => {
                toggleLoading(false);
                if (res && res.success && res.data) {
                    const stats = res.data;
                    const modal = document.getElementById('product-statistics-modal');
                    const content = document.getElementById('product-statistics-content');
                    const title = document.getElementById('product-statistics-title');

                    title.innerText = 'Thống Kê: ' + stats.name;

                    content.innerHTML = `
                        <div class="grid grid-cols-2 gap-4 mb-6">
                            <div class="bg-blue-50 p-4 rounded-lg">
                                <p class="text-sm text-gray-600 mb-1">Tổng Số Lượng Bán</p>
                                <p class="text-2xl font-bold text-blue-600">${stats.totalQty || 0}</p>
                            </div>
                            <div class="bg-green-50 p-4 rounded-lg">
                                <p class="text-sm text-gray-600 mb-1">Tổng Doanh Thu</p>
                                <p class="text-2xl font-bold text-green-600">${formatMoney(stats.totalRevenue || 0)}</p>
                            </div>
                            <div class="bg-purple-50 p-4 rounded-lg" style="${userPermissions && userPermissions.reports_profit && userPermissions.reports_profit.length > 0 ? '' : 'display:none'}">
                                <p class="text-sm text-gray-600 mb-1">Tổng Lợi Nhuận</p>
                                <p class="text-2xl font-bold text-purple-600">${formatMoney(stats.totalProfit || 0)}</p>
                            </div>
                            <div class="bg-yellow-50 p-4 rounded-lg" style="${userPermissions && userPermissions.reports_profit && userPermissions.reports_profit.length > 0 ? '' : 'display:none'}">
                                <p class="text-sm text-gray-600 mb-1">Tỷ Suất Lợi Nhuận</p>
                                <p class="text-2xl font-bold text-yellow-600">${(stats.profitMargin || 0).toFixed(1)}%</p>
                            </div>
                            <div class="bg-indigo-50 p-4 rounded-lg">
                                <p class="text-sm text-gray-600 mb-1">Số Đơn Hàng</p>
                                <p class="text-2xl font-bold text-indigo-600">${stats.orderCount || 0}</p>
                            </div>
                            <div class="bg-pink-50 p-4 rounded-lg">
                                <p class="text-sm text-gray-600 mb-1">Giá Trị Đơn TB</p>
                                <p class="text-2xl font-bold text-pink-600">${formatMoney(stats.avgOrderValue || 0)}</p>
                            </div>
                            <div class="bg-teal-50 p-4 rounded-lg">
                                <p class="text-sm text-gray-600 mb-1">Ngày TB Giữa Đơn</p>
                                <p class="text-2xl font-bold text-teal-600">${stats.avgDaysBetweenOrders || 0} ngày</p>
                            </div>
                            <div class="bg-orange-50 p-4 rounded-lg">
                                <p class="text-sm text-gray-600 mb-1">Tỷ Lệ Quay Vòng</p>
                                <p class="text-2xl font-bold text-orange-600">${(stats.turnoverRate || 0).toFixed(2)}</p>
                            </div>
                        </div>
                        <div class="border-t pt-4">
                            <p class="text-sm text-gray-600 mb-2">Trạng Thái Tồn Kho: <span class="font-bold ${stats.stockStatus === 'Low' ? 'text-red-600' : stats.stockStatus === 'Out' ? 'text-red-800' : 'text-green-600'}">${stats.stockStatus === 'Low' ? 'Sắp Hết' : stats.stockStatus === 'Out' ? 'Hết Hàng' : 'Bình Thường'}</span></p>
                        </div>
                    `;

                    modal.classList.remove('hidden');
                } else {
                    showToast('Không thể lấy thống kê sản phẩm', 'error');
                }
            })
            .withFailureHandler(onError)
            .apiHandler('getProductStatistics', sku);
    }

    function closeProductStatisticsModal() {
        document.getElementById('product-statistics-modal').classList.add('hidden');
    }

    function deleteProduct(sku) {
        const product = productBySku.get(sku);
        const productName = product ? product.name : sku;

        showConfirmModal(
            'Xóa Sản Phẩm',
            `Bạn có chắc chắn muốn xóa sản phẩm "${productName}"?\n\n⚠️ Lưu ý: Hành động này không thể hoàn tác.`,
            'Xóa',
            () => {
                toggleLoading(true);
                google.script.run
                    .withSuccessHandler((res) => {
                        toggleLoading(false);
                        if (res.success) {
                            showToast('Xóa sản phẩm thành công!', 'success');
                            localStorage.removeItem('TTL_products-manage');
                            loadProductsManage(true);
                            if (document.getElementById('page-order').classList.contains('hidden') === false) {
                                loadData();
                            }
                        } else {
                            showToast('Lỗi: ' + res.message, 'error');
                        }
                    })
                    .withFailureHandler(onError)
                    .apiHandler('deleteProduct', sku);
            }
        );
    }

    // CUSTOMERS MANAGEMENT
    function loadCustomersManage(forceRefresh) {
        // Setup event listeners unconditionally (must work regardless of cache hit)
        const searchEl = document.getElementById('customer-manage-search');
        if (searchEl && !searchEl._listenerAttached) {
            searchEl.oninput = debounce(() => filterCustomersManage(), 200);
            searchEl._listenerAttached = true;
        }
        const tierFilter = document.getElementById('customer-tier-filter');
        if (tierFilter && !tierFilter._listenerAttached) {
            tierFilter.onchange = () => filterCustomersManage();
            tierFilter._listenerAttached = true;
        }
        const debtFilter = document.getElementById('customer-debt-filter');
        if (debtFilter && !debtFilter._listenerAttached) {
            debtFilter.onchange = () => filterCustomersManage();
            debtFilter._listenerAttached = true;
        }

        // Cache-first: hiển thị cache ngay, skip backend nếu cache còn hạn
        if (!forceRefresh) {
            var cachedCustomers = LocalStore.getTTL('customers-manage');
            if (cachedCustomers && Array.isArray(cachedCustomers) && cachedCustomers.length > 0) {
                customers = cachedCustomers;
                renderCustomersManage(customers, true);
                updateCustomerStats();
                return;
            }
        }

        toggleLoading(true);
        google.script.run
            .withSuccessHandler((res) => {
                try {
                    toggleLoading(false);
                    if (res && res.success !== false) {
                        // Handle both direct array and wrapped response
                        const customerData = res.data || res;
                        customers = Array.isArray(customerData) ? customerData : [];
                        LocalStore.setTTL('customers-manage', customers, 600); // 10 phút (mutation handlers đã xóa cache)
                        renderCustomersManage(customers, true); // Reset to page 1
                        updateCustomerStats(); // Update stats after loading
                    } else {
                        console.warn('Customers response:', res);
                        customers = [];
                        renderCustomersManage([]);
                        updateCustomerStats();
                        if (res && res.message) {
                            showToast(res.message, 'warning');
                        } else if (!res) {
                            showToast('Không thể tải dữ liệu khách hàng. Vui lòng thử lại.', 'warning');
                        }
                    }
                } catch (e) {
                    console.error('Error processing customers:', e);
                    showToast('Lỗi khi xử lý dữ liệu khách hàng: ' + e.toString(), 'error');
                    customers = [];
                    renderCustomersManage([]);
                }
            })
            .withFailureHandler((error) => {
                toggleLoading(false);
                console.error('Failed to load customers:', error);
                showToast('Lỗi khi tải dữ liệu khách hàng: ' + (error.message || error.toString()), 'error');
                customers = [];
                renderCustomersManage([]);
            })
            .apiHandler('getCustomers', null);
    }

    function renderCustomersManage(data, resetPage = false) {
        const tbody = document.getElementById('customers-manage-body');
        const mobileContainer = document.getElementById('customers-list-mobile');
        if (!tbody) return;

        // Save filtered customers for pagination
        filteredCustomers = data || [];

        // Reset to page 1 if requested
        if (resetPage) {
            customersCurrentPage = 1;
        }

        // Calculate pagination
        const totalItems = filteredCustomers.length;
        const totalPages = Math.ceil(totalItems / customersItemsPerPage);
        const startIndex = (customersCurrentPage - 1) * customersItemsPerPage;
        const endIndex = startIndex + customersItemsPerPage;
        const dataToRender = filteredCustomers.slice(startIndex, endIndex);

        if (dataToRender.length === 0) {
            tbody.innerHTML = `
                <tr>
                    <td colspan="7" class="text-center py-12">
                        <div class="flex flex-col items-center">
                            <svg class="w-16 h-16 text-gray-300 mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0zm6 3a2 2 0 11-4 0 2 2 0 014 0zM7 10a2 2 0 11-4 0 2 2 0 014 0z"></path>
                            </svg>
                            <p class="text-gray-400 text-sm">Chưa có khách hàng nào</p>
                            <button onclick="showCustomerModal()" class="mt-4 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 text-sm">
                                Thêm khách hàng đầu tiên
                            </button>
                        </div>
                    </td>
                </tr>
            `;
            if (mobileContainer) mobileContainer.innerHTML = '<p class="text-center py-8 text-gray-400">Chưa có khách hàng nào</p>';
            return;
        }

        // Desktop table rows - use DocumentFragment for batch DOM writes
        tbody.innerHTML = '';
        const custFragment = document.createDocumentFragment();
        dataToRender.forEach(c => {
            const tr = document.createElement('tr');
            const debtClass = (c.debt || 0) > 0 ? 'text-red-600 font-medium' : '';
            const tierBadge = c.memberTier ? `<span class="px-2 py-1 bg-yellow-100 text-yellow-800 rounded text-xs mr-1">${c.memberTier}</span>` : '';
            const tagsBadges = c.tags ? c.tags.split(',').slice(0, 2).map(tag => `<span class="px-1 py-0.5 bg-blue-100 text-blue-800 rounded text-xs mr-1">${tag.trim()}</span>`).join('') : '';

            tr.innerHTML = `
                <td class="py-3 font-medium">${c.id || ''}</td>
                <td class="py-3">
                    <div class="flex items-center gap-2">
                        <span>${c.name || ''}</span>
                        ${tierBadge}
                    </div>
                    ${tagsBadges ? `<div class="mt-1">${tagsBadges}</div>` : ''}
                </td>
                <td class="py-3">${c.phone || ''}</td>
                <td class="py-3 hidden lg:table-cell">${c.email || ''}</td>
                <td class="py-3 hidden xl:table-cell">${c.address || ''}</td>
                <td class="py-3 text-right ${debtClass}">
                    ${formatMoney(c.debt || 0)}
                    ${c.creditLimit > 0 ? `<div class="text-xs text-gray-500">Hạn mức: ${formatMoney(c.creditLimit)}</div>` : ''}
                </td>
                <td class="py-3 text-center">
                    <button onclick="event.stopPropagation(); showCustomerHistoryModal('${c.id}')" class="text-purple-600 hover:text-purple-800 mr-2" title="Lịch sử mua hàng">📊</button>
                    <button onclick="event.stopPropagation(); viewCustomerDetail('${c.id}')" class="text-green-600 hover:text-green-800 mr-2" title="Xem chi tiết">👁️</button>
                    <button onclick="event.stopPropagation(); editCustomer('${c.id}')" class="text-blue-600 hover:text-blue-800 mr-2" title="Sửa">✏️</button>
                    <button onclick="event.stopPropagation(); deleteCustomer('${c.id}')" class="text-red-600 hover:text-red-800 mr-2" title="Xóa">🗑️</button>
                    ${(c.debt || 0) > 0 ? `<button onclick="event.stopPropagation(); payCustomerDebt('${c.id}', ${c.debt})" class="text-green-600 hover:text-green-800 text-xs">Thanh toán</button>` : ''}
                </td>
            `;

            // Add click event to row to view customer detail
            tr.style.cursor = 'pointer';
            tr.classList.add('hover:bg-gray-50', 'transition-colors');
            tr.addEventListener('click', function (e) {
                // Don't trigger if clicking on buttons
                if (e.target.tagName === 'BUTTON' || e.target.closest('button')) {
                    return;
                }
                viewCustomerDetail(c.id);
            });

            custFragment.appendChild(tr);
        });

        // Batch append: single reflow
        tbody.appendChild(custFragment);

        // Mobile card view
        if (mobileContainer) {
            mobileContainer.innerHTML = dataToRender.map(c => {
                const debt = c.debt || 0;
                const debtClass = debt > 0 ? 'text-red-600 font-bold' : 'text-green-600';
                const tierBadge = c.memberTier ? `<span class="px-2 py-0.5 bg-yellow-100 text-yellow-800 rounded-full text-xs font-medium">${c.memberTier}</span>` : '';
                const tagsBadges = c.tags ? c.tags.split(',').slice(0, 2).map(tag => `<span class="px-1.5 py-0.5 bg-blue-100 text-blue-700 rounded text-xs">${tag.trim()}</span>`).join('') : '';

                return `
                    <div class="mobile-card" style="cursor: pointer;" onclick="if(event.target.tagName !== 'BUTTON' && !event.target.closest('button')) viewCustomerDetail('${c.id}')">
                        <div class="flex justify-between items-start mb-2">
                            <div>
                                <p class="font-bold text-gray-900">${escapeHtml(c.name || '')}</p>
                                <p class="text-xs text-gray-500">${escapeHtml(c.id || '')}</p>
                            </div>
                            <div class="flex items-center gap-1">
                                ${tierBadge}
                            </div>
                        </div>
                        <div class="grid grid-cols-2 gap-2 text-sm mb-2">
                            <div><span class="text-gray-500">SĐT:</span> ${escapeHtml(c.phone || '-')}</div>
                            <div><span class="text-gray-500">Nợ:</span> <span class="${debtClass}">${formatMoney(debt)}</span></div>
                        </div>
                        ${tagsBadges ? `<div class="flex gap-1 mb-2">${tagsBadges}</div>` : ''}
                        <div class="flex gap-3 pt-2 border-t border-gray-100">
                            <button onclick="event.stopPropagation(); showCustomerHistoryModal('${c.id}')" class="text-purple-600 hover:text-purple-800 text-sm" title="Lịch sử">📊</button>
                            <button onclick="event.stopPropagation(); viewCustomerDetail('${c.id}')" class="text-green-600 hover:text-green-800 text-sm" title="Xem">👁️</button>
                            <button onclick="event.stopPropagation(); editCustomer('${c.id}')" class="text-blue-600 hover:text-blue-800 text-sm" title="Sửa">✏️</button>
                            <button onclick="event.stopPropagation(); deleteCustomer('${c.id}')" class="text-red-600 hover:text-red-800 text-sm" title="Xóa">🗑️</button>
                            ${debt > 0 ? `<button onclick="event.stopPropagation(); payCustomerDebt('${c.id}', ${debt})" class="text-green-600 hover:text-green-800 text-xs ml-auto">Thanh toán</button>` : ''}
                        </div>
                    </div>
                `;
            }).join('');
        }

        // Render pagination controls
        renderPagination('customers', totalPages, totalItems, customersCurrentPage, customersItemsPerPage);
    }

    function goToCustomersPage(page) {
        if (page < 1 || page > Math.ceil(filteredCustomers.length / customersItemsPerPage)) return;
        customersCurrentPage = page;
        renderCustomersManage(filteredCustomers, false);
    }

    function generateNextCustomerId() {
        var maxNum = 0;
        if (customers && customers.length > 0) {
            for (var i = 0; i < customers.length; i++) {
                var id = String(customers[i].id || '');
                var match = id.match(/^KH(\d+)$/i);
                if (match) {
                    var num = parseInt(match[1], 10);
                    if (num > maxNum) maxNum = num;
                }
            }
        }
        return 'KH' + String(maxNum + 1).padStart(3, '0');
    }

    function showCustomerModal(customerId = null) {
        const modal = document.getElementById('customer-modal');
        const form = document.getElementById('customer-form');
        form.reset();
        document.getElementById('customer-id').value = '';

        if (customerId) {
            const customer = customers.find(c => c.id === customerId);
            if (customer) {
                document.getElementById('customer-modal-title').innerText = 'Sửa Khách Hàng';
                document.getElementById('customer-code').value = customer.id || '';
                document.getElementById('customer-code').readOnly = true;
                document.getElementById('customer-name').value = customer.name || '';
                document.getElementById('customer-phone').value = customer.phone || '';
                document.getElementById('customer-email').value = customer.email || '';
                document.getElementById('customer-address').value = customer.address || '';
                document.getElementById('customer-group').value = customer.group || '';
                document.getElementById('customer-type').value = customer.customerType || 'Cá nhân';
                document.getElementById('customer-id-number').value = customer.idNumber || '';
                document.getElementById('customer-company-name').value = customer.companyName || '';
                document.getElementById('customer-tax-code').value = customer.taxCode || '';
                document.getElementById('customer-birthday').value = customer.birthday ? toLocalDateStr(customer.birthday) : '';
                document.getElementById('customer-credit-limit').value = customer.creditLimit || '';
                document.getElementById('customer-member-tier').value = customer.memberTier || 'Bronze';
                document.getElementById('customer-status').value = customer.status || 'Active';
                document.getElementById('customer-tags').value = customer.tags || '';
                document.getElementById('customer-notes').value = customer.notes || '';

                // Show/hide company fields
                toggleCompanyFields(customer.customerType === 'Doanh nghiệp');
            }
        } else {
            document.getElementById('customer-modal-title').innerText = 'Thêm Khách Hàng';
            document.getElementById('customer-code').readOnly = false;
            document.getElementById('customer-code').value = generateNextCustomerId();
            toggleCompanyFields(false);
        }

        // Add event listener for customer type change
        const customerTypeSelect = document.getElementById('customer-type');
        if (customerTypeSelect) {
            customerTypeSelect.onchange = function () {
                toggleCompanyFields(this.value === 'Doanh nghiệp');
            };
        }

        modal.classList.remove('hidden');
    }

    function toggleCompanyFields(show) {
        // ALWAYS SHOW company fields for VNPT export compatibility
        const companyFields = document.getElementById('company-fields');
        if (companyFields) {
            companyFields.classList.remove('hidden');
        }
    }

    function closeCustomerModal() {
        document.getElementById('customer-modal').classList.add('hidden');
    }

    function saveCustomer(event) {
        event.preventDefault();

        // Validation
        const name = document.getElementById('customer-name').value.trim();
        const phone = document.getElementById('customer-phone').value.trim();
        const email = document.getElementById('customer-email').value.trim();

        if (!name) {
            showToast('Vui lòng nhập tên khách hàng!', 'warning');
            document.getElementById('customer-name').focus();
            return;
        }
        if (phone && !/^[0-9]{10,11}$/.test(phone.replace(/[\s-]/g, ''))) {
            showToast('Số điện thoại không hợp lệ! (10-11 chữ số)', 'warning');
            document.getElementById('customer-phone').focus();
            return;
        }
        if (email && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
            showToast('Email không hợp lệ!', 'warning');
            document.getElementById('customer-email').focus();
            return;
        }

        // Auto-generate ID if empty
        var customerId = document.getElementById('customer-code').value.trim();
        if (!customerId) {
            customerId = generateNextCustomerId();
            document.getElementById('customer-code').value = customerId;
        }

        // Check duplicate when creating new
        var isEditMode = document.getElementById('customer-code').readOnly;
        if (!isEditMode) {
            var existing = customers.find(function(c) { return c.id === customerId; });
            if (existing) {
                showToast('Mã khách hàng "' + customerId + '" đã tồn tại!', 'warning');
                document.getElementById('customer-code').focus();
                return;
            }
        }

        const customerData = {
            id: customerId,
            name: name,
            phone: phone || '',
            email: email || '',
            address: document.getElementById('customer-address').value.trim() || '',
            group: document.getElementById('customer-group').value || '',
            customerType: document.getElementById('customer-type').value || 'Cá nhân',
            idNumber: document.getElementById('customer-id-number').value.trim() || '',
            companyName: document.getElementById('customer-company-name').value.trim() || '',
            taxCode: document.getElementById('customer-tax-code').value.trim() || '',
            birthday: document.getElementById('customer-birthday').value || '',
            creditLimit: parseFloat(document.getElementById('customer-credit-limit').value) || 0,
            memberTier: document.getElementById('customer-member-tier').value || 'Bronze',
            status: document.getElementById('customer-status').value || 'Active',
            tags: document.getElementById('customer-tags').value.trim() || '',
            notes: document.getElementById('customer-notes').value.trim() || ''
        };

        const isEdit = document.getElementById('customer-code').readOnly;
        const isFromOrderPage = document.getElementById('page-order') && !document.getElementById('page-order').classList.contains('hidden');
        const newCustomerId = isEdit ? null : customerData.id;

        toggleLoading(true);
        google.script.run
            .withSuccessHandler((res) => {
                toggleLoading(false);
                if (res.success) {
                    showToast(isEdit ? 'Cập nhật khách hàng thành công!' : 'Thêm khách hàng thành công!', 'success');
                    closeCustomerModal();

                    // If adding from order page, auto-select the new customer
                    if (isFromOrderPage && !isEdit && newCustomerId) {
                        // Reload data first to get the new customer
                        loadData();
                        // Then select the customer after a short delay
                        setTimeout(() => {
                            selectCustomerById(newCustomerId);
                        }, 300);
                    } else {
                        localStorage.removeItem('TTL_customers-manage');
                        loadCustomersManage(true);
                        loadData(); // Refresh for order page
                    }
                } else {
                    showToast('Lỗi: ' + res.message, 'error');
                }
            })
            .withFailureHandler(onError)
            .apiHandler(isEdit ? 'updateCustomer' : 'createCustomer', customerData);
    }

