    function applyPrintSettingsToUI(settings) {
        if (!settings) return;
        setSettingVal('print-company-name', settings.companyName);
        setSettingVal('print-company-address', settings.companyAddress);
        setSettingVal('print-company-phone', settings.companyPhone);
        setSettingVal('print-company-email', settings.companyEmail);
        setSettingVal('print-company-tax', settings.companyTax);
        setSettingVal('print-company-website', settings.companyWebsite);
        setSettingVal('print-invoice-title', settings.invoiceTitle || 'HÓA ĐƠN TẠM TÍNH');
        setSettingVal('print-footer-note', settings.footerNote || 'Cảm ơn quý khách và hẹn gặp lại');
        setSettingVal('print-font-size', settings.fontSize || 14);
        setSettingVal('print-show-logo', settings.showLogo || 'true');
        setSettingVal('print-show-qr', settings.showQR || 'true');
        setSettingVal('print-show-border', settings.showBorder || 'true');
        setSettingVal('print-template-id', settings.templateId || 'professional');
        setSettingVal('print-show-unit', settings.showUnit !== undefined ? (settings.showUnit ? 'true' : 'false') : 'true');
        setSettingVal('print-show-signatures', settings.showSignatures ? 'true' : 'false');
        setSettingVal('print-show-bank-info', settings.showBankInfo ? 'true' : 'false');
        setSettingVal('print-bank-id', settings.bankId || '');
        setSettingVal('print-bank-name', settings.bankName || '');
        setSettingVal('print-bank-account', settings.bankAccount || '');
        setSettingVal('print-bank-account-name', settings.bankAccountName || '');

        if (settings.logo) {
            currentPrintLogo = settings.logo;
            document.getElementById('print-logo-filename').textContent = 'Logo đã lưu';
            document.getElementById('print-logo-preview').style.display = 'block';
            document.getElementById('print-logo-preview-img').src = settings.logo;
            document.getElementById('print-logo-clear').style.display = 'inline-block';
        } else {
            clearPrintLogo();
        }

        var elBarcode = document.getElementById('print-show-barcode');
        if (elBarcode) elBarcode.value = (settings.showBarcode === true || settings.showBarcode === 'true') ? 'true' : 'false';
        var elPaperSize = document.getElementById('print-paper-size');
        if (elPaperSize) elPaperSize.value = settings.paperSize || 'A4';
        var elPadding = document.getElementById('print-padding');
        var elPaddingVal = document.getElementById('print-padding-val');
        var padVal = settings.padding !== undefined ? settings.padding : 20;
        if (elPadding) elPadding.value = padVal;
        if (elPaddingVal) elPaddingVal.textContent = padVal + 'px';
        var elLH = document.getElementById('print-line-height');
        var elLHVal = document.getElementById('print-line-height-val');
        var lhVal = settings.lineHeight !== undefined ? settings.lineHeight : 1.5;
        if (elLH) elLH.value = lhVal;
        if (elLHVal) elLHVal.textContent = parseFloat(lhVal).toFixed(1);

        currentPrintSettings = settings;
    }

    // VietQR URL builder
    function buildVietQRUrl(bankId, accountNo, amount, addInfo, accountName, template) {
        if (!bankId || !accountNo) return '';
        // Sanitize path segments: only allow alphanumeric chars
        var safeBankId = String(bankId).replace(/[^a-zA-Z0-9]/g, '');
        var safeAccountNo = String(accountNo).replace(/[^a-zA-Z0-9]/g, '');
        if (!safeBankId || !safeAccountNo) return '';
        var url = 'https://img.vietqr.io/image/' + safeBankId + '-' + safeAccountNo + '-' + (template || 'compact2') + '.png';
        var params = [];
        if (amount) params.push('amount=' + Math.round(amount));
        if (addInfo) params.push('addInfo=' + encodeURIComponent(addInfo));
        if (accountName) params.push('accountName=' + encodeURIComponent(accountName));
        if (params.length > 0) url += '?' + params.join('&');
        return url;
    }

    // Auto-fill bank name when bankId changes in settings
    function onBankIdChange() {
        var sel = document.getElementById('print-bank-id');
        if (!sel) return;
        var bankId = sel.value;
        var bankNameInput = document.getElementById('print-bank-name');
        if (bankId && bankNameInput) {
            var opt = sel.options[sel.selectedIndex];
            bankNameInput.value = opt.text.replace(/\s*\(.*\)/, '');
        }
        updateBankQRPreview();
    }

    // Preview QR in settings page
    function updateBankQRPreview() {
        var bankId = (document.getElementById('print-bank-id') || {}).value || '';
        var accountNo = (document.getElementById('print-bank-account') || {}).value || '';
        var accountName = (document.getElementById('print-bank-account-name') || {}).value || '';
        var preview = document.getElementById('bank-qr-preview');
        var img = document.getElementById('bank-qr-preview-img');
        if (!preview || !img) return;
        if (bankId && accountNo) {
            var url = buildVietQRUrl(bankId, accountNo, 0, '', accountName, 'compact2');
            img.src = url;
            preview.classList.remove('hidden');
        } else {
            preview.classList.add('hidden');
        }
    }

    // Show/hide QR on payment modal when selecting Chuyển khoản
    function updatePaymentQR() {
        var method = (document.getElementById('payment-method-select') || {}).value || '';
        var container = document.getElementById('payment-qr-container');
        var img = document.getElementById('payment-qr-img');
        if (!container || !img) return;

        var settings = currentPrintSettings || {};
        var bankId = settings.bankId || '';
        var accountNo = settings.bankAccount || '';
        var accountName = settings.bankAccountName || '';

        if (method === 'Chuyển khoản' && bankId && accountNo) {
            // Get current order amount
            var amountStr = (document.getElementById('payment-amount') || {}).value || '';
            var amount = parseFormattedNumber(amountStr) || 0;
            var orderId = (document.getElementById('payment-order-id-input') || {}).value || '';
            var addInfo = orderId ? ('TT ' + orderId) : '';
            var url = buildVietQRUrl(bankId, accountNo, amount, addInfo, accountName, 'compact2');
            img.src = url;
            container.classList.remove('hidden');
        } else {
            container.classList.add('hidden');
        }
    }

    function loadPrintSettingsToUI() {
        // Reuse already-loaded data instead of duplicate API call
        if (currentPrintSettings) {
            applyPrintSettingsToUI(currentPrintSettings);
            return;
        }
        toggleLoading(true);
        google.script.run
            .withSuccessHandler((res) => {
                toggleLoading(false);
                if (res && res.success !== false) {
                    const settings = res.data || res;
                    applyPrintSettingsToUI(settings);
                }
            })
            .withFailureHandler((err) => {
                toggleLoading(false);
                console.error('Failed to load print settings to UI', err);
            })
            .apiHandler('getPrintSettings', null);
    }

    // Note: savePrintSettings and resetPrintSettings are defined later in the file (around line 11470+)
    // The following legacy versions are kept as no-ops to avoid duplicate function errors
    // See the main versions below for actual implementation

    // ===== PAYMENT METHODS MANAGEMENT =====
    let paymentMethods = [];

    /**
     * Load payment methods and render table
     */
    function loadPaymentMethods(forceRefresh) {
        // Cache-first
        if (!forceRefresh) {
            var cached = LocalStore.getTTL('paymentMethods');
            if (cached && Array.isArray(cached)) {
                paymentMethods = cached;
                renderPaymentMethodsTable();
                updatePaymentMethodDropdowns();
                return;
            }
        }
        google.script.run
            .withSuccessHandler((res) => {
                if (res && res.success !== false) {
                    paymentMethods = res.data || res || [];
                    renderPaymentMethodsTable();
                    updatePaymentMethodDropdowns();
                    LocalStore.setTTL('paymentMethods', paymentMethods, 600);
                }
            })
            .withFailureHandler((error) => {
                console.error('Error loading payment methods:', error);
            })
            .apiHandler('getPaymentMethods', null);
    }

    /**
     * Render payment methods table in settings
     */
    function renderPaymentMethodsTable() {
        const tbody = document.getElementById('payment-methods-tbody');
        if (!tbody) return;

        if (!paymentMethods || paymentMethods.length === 0) {
            tbody.innerHTML = `
                <tr>
                    <td colspan="4" class="px-4 py-8 text-center text-gray-500">
                        Chưa có phương thức thanh toán nào
                    </td>
                </tr>
            `;
            return;
        }

        tbody.innerHTML = paymentMethods.map(pm => `
            <tr class="hover:bg-gray-50">
                <td class="px-4 py-3">
                    <span class="font-medium">${escapeHtml(pm.name)}</span>
                </td>
                <td class="px-4 py-3 text-sm text-gray-600">
                    ${escapeHtml(pm.description || '-')}
                </td>
                <td class="px-4 py-3 text-center">
                    <span class="px-2 py-1 text-xs rounded-full ${pm.status === 'Active' ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-600'}">
                        ${pm.status === 'Active' ? 'Hoạt động' : 'Tạm ngưng'}
                    </span>
                </td>
                <td class="px-4 py-3 text-center">
                    <button onclick="editPaymentMethod('${pm.id}')" class="text-blue-600 hover:text-blue-800 mr-2" title="Sửa">✏️</button>
                    <button onclick="deletePaymentMethod('${pm.id}')" class="text-red-600 hover:text-red-800" title="Xóa">🗑️</button>
                </td>
            </tr>
        `).join('');
    }

    /**
     * Show modal to add new payment method
     */
    function showAddPaymentMethodModal() {
        document.getElementById('payment-method-modal-title').textContent = 'Thêm Phương Thức Thanh Toán';
        document.getElementById('payment-method-id').value = '';
        document.getElementById('payment-method-name').value = '';
        document.getElementById('payment-method-description').value = '';
        document.getElementById('payment-method-status').value = 'Active';
        document.getElementById('payment-method-modal').classList.remove('hidden');
    }

    /**
     * Edit payment method
     */
    function editPaymentMethod(id) {
        const pm = paymentMethods.find(p => p.id === id);
        if (!pm) {
            showToast('Không tìm thấy phương thức thanh toán!', 'error');
            return;
        }

        document.getElementById('payment-method-modal-title').textContent = 'Sửa Phương Thức Thanh Toán';
        document.getElementById('payment-method-id').value = pm.id;
        document.getElementById('payment-method-name').value = pm.name;
        document.getElementById('payment-method-description').value = pm.description || '';
        document.getElementById('payment-method-status').value = pm.status || 'Active';
        document.getElementById('payment-method-modal').classList.remove('hidden');
    }

    /**
     * Close payment method modal
     */
    function closePaymentMethodModal() {
        document.getElementById('payment-method-modal').classList.add('hidden');
    }

    /**
     * Submit payment method form
     */
    function submitPaymentMethod(event) {
        event.preventDefault();

        const id = document.getElementById('payment-method-id').value;
        const name = document.getElementById('payment-method-name').value.trim();
        const description = document.getElementById('payment-method-description').value.trim();
        const status = document.getElementById('payment-method-status').value;

        if (!name) {
            showToast('Vui lòng nhập tên phương thức!', 'warning');
            return;
        }

        const data = { name, description, status };
        const isEdit = id !== '';
        const apiAction = isEdit ? 'updatePaymentMethod' : 'createPaymentMethod';

        if (isEdit) {
            data.id = id;
        }

        toggleLoading(true);
        google.script.run
            .withSuccessHandler((res) => {
                toggleLoading(false);
                if (res && res.success) {
                    showToast(res.message || (isEdit ? 'Cập nhật thành công!' : 'Thêm mới thành công!'), 'success');
                    closePaymentMethodModal();
                    localStorage.removeItem('TTL_paymentMethods');
                    loadPaymentMethods();
                } else {
                    showToast(res?.message || 'Có lỗi xảy ra!', 'error');
                }
            })
            .withFailureHandler((error) => {
                toggleLoading(false);
                showToast('Lỗi: ' + (error.message || error), 'error');
            })
            .apiHandler(apiAction, data);
    }

    /**
     * Delete payment method
     */
    function deletePaymentMethod(id) {
        const pm = paymentMethods.find(p => p.id === id);
        if (!pm) return;

        showConfirmModal(
            'Xóa Phương Thức Thanh Toán',
            `Bạn có chắc chắn muốn xóa phương thức "${pm.name}"?`,
            'Xóa',
            () => {
                toggleLoading(true);
                google.script.run
                    .withSuccessHandler((res) => {
                        toggleLoading(false);
                        if (res && res.success) {
                            showToast('Xóa thành công!', 'success');
                            localStorage.removeItem('TTL_paymentMethods');
                            loadPaymentMethods();
                        } else {
                            showToast(res?.message || 'Có lỗi xảy ra!', 'error');
                        }
                    })
                    .withFailureHandler((error) => {
                        toggleLoading(false);
                        showToast('Lỗi: ' + (error.message || error), 'error');
                    })
                    .apiHandler('deletePaymentMethod', id);
            }
        );
    }

    /**
     * Update all payment method dropdowns in the app
     */
    function updatePaymentMethodDropdowns() {
        const activeMethods = paymentMethods.filter(pm => pm.status === 'Active');
        const dropdownIds = [
            'payment-method',           // Order form
            'purchase-payment-method',  // Purchase form
            'transaction-payment-method', // Transaction form
            'order-filter-payment',     // Order filter
            'payment-method-select',    // Add payment modal
            'transaction-filter-payment-method', // Transaction filter
            'purchase-filter-payment-method', // Purchase filter
            'supplier-debt-payment-method', // Supplier debt payment modal
            'pp-payment-method' // Purchase payment modal
        ];

        // Icon mapping for payment methods
        const icons = {
            'Tiền mặt': '💵',
            'Chuyển khoản': '🏦',
            'Ví điện tử': '📱',
            'Thẻ tín dụng': '💳',
            'Thẻ': '💳',
            'Khác': '💰'
        };

        dropdownIds.forEach(id => {
            const dropdown = document.getElementById(id);
            if (dropdown) {
                const currentValue = dropdown.value;
                const isFilter = id === 'order-filter-payment' || id === 'transaction-filter-payment-method' || id === 'purchase-filter-payment-method';

                // Build options HTML
                let optionsHtml = isFilter ? '<option value="">Tất cả</option>' : '';
                activeMethods.forEach(pm => {
                    const icon = icons[pm.name] || '💰';
                    optionsHtml += `<option value="${escapeHtml(pm.name)}">${icon} ${escapeHtml(pm.name)}</option>`;
                });

                dropdown.innerHTML = optionsHtml;

                // Restore previous value if still exists
                if (currentValue && activeMethods.some(pm => pm.name === currentValue)) {
                    dropdown.value = currentValue;
                }
            }
        });
    }

