    function exportInvoicePDFFromPreview() {
        if (!currentOrderDetail) {
            showToast('Không có thông tin đơn hàng', 'error');
            return;
        }

        // Check if html2canvas is available
        if (typeof html2canvas === 'undefined') {
            showToast('Thư viện PDF chưa được tải. Vui lòng thử lại sau vài giây.', 'error');
            return;
        }

        if (typeof window.jspdf === 'undefined') {
            showToast('Thư viện PDF chưa được tải. Vui lòng thử lại sau vài giây.', 'error');
            return;
        }

        const previewContent = document.getElementById('invoice-preview-content');
        if (!previewContent) {
            showToast('Không tìm thấy nội dung hóa đơn', 'error');
            return;
        }

        const order = currentOrderDetail;
        const orderDate = new Date(order.date);
        const formattedDate = orderDate.toLocaleDateString('vi-VN');

        // Show loading
        showToast('Đang tạo PDF...', 'info');

        // First, convert any canvas elements (like QR codes) to images before capturing
        const canvasElements = previewContent.querySelectorAll('canvas');
        const canvasPromises = [];
        canvasElements.forEach((canvas, index) => {
            try {
                const img = document.createElement('img');
                const dataUrl = canvas.toDataURL('image/png');
                if (dataUrl && dataUrl.startsWith('data:image')) {
                    img.src = dataUrl;
                    img.style.width = canvas.width + 'px';
                    img.style.height = canvas.height + 'px';
                    img.style.display = 'block';
                    img.style.margin = '0 auto';

                    // Wait for image to load
                    const promise = new Promise((resolve) => {
                        img.onload = () => {
                            if (canvas.parentNode) {
                                canvas.parentNode.replaceChild(img, canvas);
                            }
                            resolve();
                        };
                        img.onerror = () => {
                            // If image fails to load, just remove the canvas
                            canvas.remove();
                            resolve();
                        };
                        // Timeout after 1 second
                        setTimeout(resolve, 1000);
                    });
                    canvasPromises.push(promise);
                } else {
                    // If canvas can't be converted, remove it
                    canvas.remove();
                }
            } catch (e) {
                console.warn('Could not convert canvas to image:', e);
                // Remove problematic canvas
                canvas.remove();
            }
        });

        // Wait for all canvas conversions and images to load
        Promise.all(canvasPromises).then(() => {
            // Wait a bit more for DOM to update
            setTimeout(() => {
                // Use html2canvas to capture the HTML content
                html2canvas(previewContent, {
                    scale: 1.5, // Reduced scale to avoid memory issues
                    useCORS: true,
                    allowTaint: false, // Don't allow taint to avoid CORS issues
                    logging: false,
                    backgroundColor: '#ffffff',
                    windowWidth: previewContent.scrollWidth,
                    windowHeight: previewContent.scrollHeight,
                    removeContainer: false
                }).then(canvas => {
                    // Validate canvas
                    if (!canvas || canvas.width === 0 || canvas.height === 0) {
                        throw new Error('Canvas không hợp lệ');
                    }

                    // Validate and convert canvas data
                    let imgData;
                    let imageFormat = 'PNG';
                    try {
                        imgData = canvas.toDataURL('image/png', 0.95);

                        // Validate data URL
                        if (!imgData || imgData.length < 100 || !imgData.startsWith('data:image/png')) {
                            // Try JPEG as fallback
                            imgData = canvas.toDataURL('image/jpeg', 0.95);
                            imageFormat = 'JPEG';
                            if (!imgData || !imgData.startsWith('data:image/jpeg')) {
                                throw new Error('Dữ liệu hình ảnh không hợp lệ');
                            }
                        }
                    } catch (e) {
                        console.error('Error converting canvas to data URL:', e);
                        // Try JPEG as fallback
                        try {
                            imgData = canvas.toDataURL('image/jpeg', 0.95);
                            imageFormat = 'JPEG';
                            if (!imgData || !imgData.startsWith('data:image/jpeg')) {
                                throw new Error('Không thể chuyển đổi canvas thành hình ảnh');
                            }
                        } catch (e2) {
                            throw new Error('Lỗi khi tạo hình ảnh từ canvas: ' + e2.message);
                        }
                    }

                    const { jsPDF } = window.jspdf;

                    // Calculate PDF dimensions
                    const imgWidth = 210; // A4 width in mm
                    const pageHeight = 297; // A4 height in mm
                    const imgHeight = (canvas.height * imgWidth) / canvas.width;
                    let heightLeft = imgHeight;

                    const doc = new jsPDF('p', 'mm', 'a4');
                    let position = 0;

                    // Add first page
                    try {
                        doc.addImage(imgData, imageFormat, 0, position, imgWidth, imgHeight, undefined, 'FAST');
                        heightLeft -= pageHeight;

                        // Add additional pages if needed
                        while (heightLeft > 0) {
                            position = heightLeft - imgHeight;
                            doc.addPage();
                            doc.addImage(imgData, imageFormat, 0, position, imgWidth, imgHeight, undefined, 'FAST');
                            heightLeft -= pageHeight;
                        }
                    } catch (e) {
                        console.error('Error adding image to PDF:', e);
                        throw new Error('Lỗi khi thêm hình ảnh vào PDF: ' + e.message);
                    }

                    // Save PDF
                    const fileName = `HoaDon_${order.id}_${formattedDate.replace(/\//g, '-')}.pdf`;
                    doc.save(fileName);
                    showToast('Đã xuất PDF thành công!', 'success');
                }).catch(error => {
                    console.error('Error generating PDF:', error);
                    let errorMessage = 'Lỗi khi tạo PDF';

                    if (error.message) {
                        errorMessage += ': ' + error.message;
                    } else if (error.toString().includes('Incomplete') || error.toString().includes('corrupt')) {
                        errorMessage = 'Lỗi: Hình ảnh không hợp lệ. Vui lòng thử lại hoặc kiểm tra kết nối mạng.';
                    } else {
                        errorMessage += ': ' + error.toString();
                    }

                    showToast(errorMessage, 'error');
                });
            }, 300); // Wait 300ms for DOM to update after canvas conversion
        });
    }

    function sendInvoiceEmail() {
        if (!currentOrderDetail) {
            showToast('Không có thông tin đơn hàng', 'error');
            return;
        }

        const order = currentOrderDetail;
        let customerEmail = '';

        // Try to get customer email
        if (order.customerId) {
            const customer = customers.find(c => c.id === order.customerId);
            if (customer && customer.email) {
                customerEmail = customer.email;
            }
        }

        // Ask for email if not found
        if (!customerEmail) {
            customerEmail = prompt('Nhập email khách hàng để gửi hóa đơn:');
            if (!customerEmail || !customerEmail.includes('@')) {
                showToast('Email không hợp lệ', 'error');
                return;
            }
        } else {
            const confirmSend = confirm(`Gửi hóa đơn đến ${customerEmail}?`);
            if (!confirmSend) {
                customerEmail = prompt('Nhập email khách hàng để gửi hóa đơn:', customerEmail);
                if (!customerEmail || !customerEmail.includes('@')) {
                    showToast('Email không hợp lệ', 'error');
                    return;
                }
            }
        }

        toggleLoading(true);
        google.script.run
            .withSuccessHandler((res) => {
                toggleLoading(false);
                if (res && res.success) {
                    showToast(res.message || 'Đã gửi email thành công!', 'success');
                } else {
                    showToast(res.message || 'Lỗi khi gửi email', 'error');
                }
            })
            .withFailureHandler((error) => {
                toggleLoading(false);
                showToast('Lỗi khi gửi email: ' + (error.message || error.toString()), 'error');
            })
            .apiHandler('sendInvoiceEmail', {
                orderId: order.id,
                customerEmail: customerEmail
            });
    }

