    function renderCustomersReport(data) {
        const totalEl = document.getElementById('customers-total');
        const totalRevenueEl = document.getElementById('customers-total-revenue');
        const totalDebtEl = document.getElementById('customers-total-debt');
        const vipEl = document.getElementById('customers-vip');

        if (totalEl) totalEl.textContent = data.totalCustomers || 0;
        if (totalRevenueEl) totalRevenueEl.textContent = formatMoney(data.totalRevenue || 0);
        if (totalDebtEl) totalDebtEl.textContent = formatMoney(data.totalDebt || 0);
        if (vipEl) vipEl.textContent = data.vipCount || 0;

        const tbody = document.getElementById('customers-report-body');
        if (!tbody) return;

        if (!data.customers || data.customers.length === 0) {
            tbody.innerHTML = '<tr><td colspan="8" class="text-center py-8 text-gray-400">Không có dữ liệu</td></tr>';
            return;
        }

        tbody.innerHTML = '';
        data.customers.forEach(customer => {
            const tier = customer.totalRevenue >= 10000000 ? 'VIP' :
                customer.totalRevenue >= 5000000 ? 'Gold' :
                    customer.totalRevenue >= 2000000 ? 'Silver' : 'Bronze';
            const tierClass = tier === 'VIP' ? 'bg-purple-100 text-purple-800' :
                tier === 'Gold' ? 'bg-yellow-100 text-yellow-800' :
                    tier === 'Silver' ? 'bg-gray-100 text-gray-800' : 'bg-blue-100 text-blue-800';
            const lastOrderDate = customer.lastOrderDate ? new Date(customer.lastOrderDate).toLocaleDateString('vi-VN') : 'Chưa có';

            const tr = document.createElement('tr');
            tr.innerHTML = `
                <td class="py-3 font-medium">${customer.id || ''}</td>
                <td class="py-3">${customer.name || ''}</td>
                <td class="py-3 text-center">${customer.orderCount || 0}</td>
                <td class="py-3 text-right font-semibold text-green-600">${formatMoney(customer.totalRevenue || 0)}</td>
                <td class="py-3 text-right">${formatMoney(customer.totalPaid || 0)}</td>
                <td class="py-3 text-right ${customer.debt > 0 ? 'text-red-600 font-semibold' : ''}">${formatMoney(customer.debt || 0)}</td>
                <td class="py-3">${lastOrderDate}</td>
                <td class="py-3 text-center">
                    <span class="px-2 py-1 rounded-full text-xs ${tierClass}">${tier}</span>
                </td>
            `;
            tbody.appendChild(tr);
        });
    }

