    function renderProfitReport(data) {
        console.log('Profit Report Data:', data);
        const totalRevenueEl = document.getElementById('profit-total-revenue');
        const totalCostEl = document.getElementById('profit-total-cost');
        const grossEl = document.getElementById('profit-gross');
        const marginEl = document.getElementById('profit-margin');

        // Helper to ensure number
        const safeNum = (val) => {
            const n = Number(val);
            return isNaN(n) ? 0 : n;
        };

        if (totalRevenueEl) totalRevenueEl.textContent = formatMoney(safeNum(data.totalRevenue));
        if (totalCostEl) totalCostEl.textContent = formatMoney(safeNum(data.totalCost));
        if (grossEl) grossEl.textContent = formatMoney(safeNum(data.grossProfit));

        const rev = safeNum(data.totalRevenue);
        const gross = safeNum(data.grossProfit);
        const margin = rev > 0 ? ((gross / rev) * 100).toFixed(1) : 0;
        if (marginEl) marginEl.textContent = margin + '%';

        const tbody = document.getElementById('profit-report-body');
        if (!tbody) return;

        if (!data.periodData || data.periodData.length === 0) {
            tbody.innerHTML = '<tr><td colspan="6" class="text-center py-8 text-gray-400">Không có dữ liệu</td></tr>';
            return;
        }

        tbody.innerHTML = '';
        data.periodData.forEach(item => {
            const revenue = safeNum(item.revenue);
            const cost = safeNum(item.cost);
            const profit = revenue - cost;
            const itemMargin = revenue > 0 ? ((profit / revenue) * 100).toFixed(1) : 0;
            const profitClass = profit >= 0 ? 'text-green-600' : 'text-red-600';

            const tr = document.createElement('tr');
            tr.innerHTML = `
                <td class="py-3 font-medium">${item.period}</td>
                <td class="py-3 text-right">${formatMoney(revenue)}</td>
                <td class="py-3 text-right text-red-600">${formatMoney(cost)}</td>
                <td class="py-3 text-right font-semibold ${profitClass}">${formatMoney(profit)}</td>
                <td class="py-3 text-right ${profitClass}">${itemMargin}%</td>
                <td class="py-3 text-right">${item.orderCount || 0}</td>
            `;
            tbody.appendChild(tr);
        });
    }

