    function renderComparisonReport(data) {
        const current = data.currentPeriod || {};
        const previous = data.previousPeriod || {};
        const changes = data.changes || {};

        // Current period
        document.getElementById('comparison-current-revenue').textContent = formatMoney(current.totalRevenue || 0);
        document.getElementById('comparison-current-orders').textContent = current.totalOrders || 0;
        document.getElementById('comparison-current-avg').textContent = formatMoney(current.avgOrder || 0);

        // Previous period
        document.getElementById('comparison-previous-revenue').textContent = formatMoney(previous.totalRevenue || 0);
        document.getElementById('comparison-previous-orders').textContent = previous.totalOrders || 0;
        document.getElementById('comparison-previous-avg').textContent = formatMoney(previous.avgOrder || 0);

        // Changes
        const revenueChange = changes.revenue || {};
        const ordersChange = changes.orders || {};
        const avgChange = changes.avgOrder || {};
        const itemsChange = changes.items || {};

        const revenueChangeEl = document.getElementById('comparison-revenue-change');
        const revenuePercentEl = document.getElementById('comparison-revenue-percent');
        if (revenueChangeEl) {
            revenueChangeEl.textContent = formatMoney(revenueChange.value || 0);
            revenueChangeEl.className = 'text-xl font-bold ' + (revenueChange.isPositive ? 'text-green-600' : 'text-red-600');
        }
        if (revenuePercentEl) {
            revenuePercentEl.textContent = (revenueChange.percent || 0).toFixed(1) + '%';
            revenuePercentEl.className = 'text-sm ' + (revenueChange.isPositive ? 'text-green-600' : 'text-red-600');
        }

        const ordersChangeEl = document.getElementById('comparison-orders-change');
        const ordersPercentEl = document.getElementById('comparison-orders-percent');
        if (ordersChangeEl) {
            ordersChangeEl.textContent = (ordersChange.value || 0) > 0 ? '+' + ordersChange.value : ordersChange.value || 0;
            ordersChangeEl.className = 'text-xl font-bold ' + (ordersChange.isPositive ? 'text-green-600' : 'text-red-600');
        }
        if (ordersPercentEl) {
            ordersPercentEl.textContent = (ordersChange.percent || 0).toFixed(1) + '%';
            ordersPercentEl.className = 'text-sm ' + (ordersChange.isPositive ? 'text-green-600' : 'text-red-600');
        }

        const avgChangeEl = document.getElementById('comparison-avg-change');
        const avgPercentEl = document.getElementById('comparison-avg-percent');
        if (avgChangeEl) {
            avgChangeEl.textContent = formatMoney(avgChange.value || 0);
            avgChangeEl.className = 'text-xl font-bold ' + (avgChange.isPositive ? 'text-green-600' : 'text-red-600');
        }
        if (avgPercentEl) {
            avgPercentEl.textContent = (avgChange.percent || 0).toFixed(1) + '%';
            avgPercentEl.className = 'text-sm ' + (avgChange.isPositive ? 'text-green-600' : 'text-red-600');
        }

        const itemsChangeEl = document.getElementById('comparison-items-change');
        const itemsPercentEl = document.getElementById('comparison-items-percent');
        if (itemsChangeEl) {
            itemsChangeEl.textContent = (itemsChange.value || 0) > 0 ? '+' + itemsChange.value : itemsChange.value || 0;
            itemsChangeEl.className = 'text-xl font-bold ' + (itemsChange.isPositive ? 'text-green-600' : 'text-red-600');
        }
        if (itemsPercentEl) {
            itemsPercentEl.textContent = (itemsChange.percent || 0).toFixed(1) + '%';
            itemsPercentEl.className = 'text-sm ' + (itemsChange.isPositive ? 'text-green-600' : 'text-red-600');
        }
    }

