    function renderEmployeesReport(data) {
        document.getElementById('employees-total').textContent = data.totalEmployees || 0;
        document.getElementById('employees-revenue').textContent = formatMoney(data.totalRevenue || 0);
        document.getElementById('employees-orders').textContent = data.totalOrders || 0;
        document.getElementById('employees-commission').textContent = formatMoney(data.totalCommission || 0);

        const tbody = document.getElementById('employees-report-body');
        if (!tbody) return;

        if (!data.employees || data.employees.length === 0) {
            tbody.innerHTML = '<tr><td colspan="9" class="text-center py-8 text-gray-400">Không có dữ liệu nhân viên</td></tr>';
            return;
        }

        tbody.innerHTML = '';
        data.employees.forEach((employee, index) => {
            const tr = document.createElement('tr');
            tr.className = 'cursor-pointer hover:bg-blue-50 transition-colors';
            tr.title = 'Click để xem đơn hàng';
            tr.innerHTML = `
                <td class="py-3">${index + 1}</td>
                <td class="py-3 font-medium">${escapeHtml(employee.id || '')}</td>
                <td class="py-3">${escapeHtml(employee.name || '')}</td>
                <td class="py-3">${escapeHtml(employee.position || '-')}</td>
                <td class="py-3 text-right text-blue-600 font-semibold underline decoration-dotted">${employee.totalOrders || 0}</td>
                <td class="py-3 text-right text-green-600">${employee.completedOrders || 0}</td>
                <td class="py-3 text-right font-semibold">${formatMoney(employee.totalRevenue || 0)}</td>
                <td class="py-3 text-right">${formatMoney(employee.avgOrderValue || 0)}</td>
                <td class="py-3 text-right text-yellow-600 font-semibold">${formatMoney(employee.totalCommission || 0)}</td>
            `;
            tr.addEventListener('click', function() {
                viewEmployeeOrders(employee.id, employee.name);
            });
            tbody.appendChild(tr);
        });
    }

    function viewEmployeeOrders(employeeId, employeeName) {
        const startDate = document.getElementById('report-start-date')?.value || '';
        const endDate = document.getElementById('report-end-date')?.value || '';
        const modal = document.getElementById('employee-orders-modal');
        const nameEl = document.getElementById('employee-orders-modal-name');
        const tbodyEl = document.getElementById('employee-orders-tbody');
        if (!modal) return;

        if (nameEl) nameEl.textContent = escapeHtml(employeeName || employeeId);
        if (tbodyEl) tbodyEl.innerHTML = '<tr><td colspan="6" class="text-center py-6 text-gray-400">Đang tải...</td></tr>';
        modal.classList.remove('hidden');

        google.script.run
            .withSuccessHandler(function(res) {
                if (!tbodyEl) return;
                const orders = (res && res.data && res.data.orders) ? res.data.orders : [];
                if (orders.length === 0) {
                    tbodyEl.innerHTML = '<tr><td colspan="6" class="text-center py-6 text-gray-400">Không có đơn hàng trong kỳ này</td></tr>';
                    return;
                }
                const statusColor = { 'Completed': 'text-green-600', 'Cancelled': 'text-red-500', 'Pending': 'text-yellow-500' };
                tbodyEl.innerHTML = orders.map(function(o) {
                    const sc = statusColor[o.status] || 'text-gray-500';
                    return `<tr class="hover:bg-gray-50">
                        <td class="py-2.5 font-mono text-xs">${escapeHtml(o.id || '')}</td>
                        <td class="py-2.5 text-gray-500">${escapeHtml(o.date || '')}</td>
                        <td class="py-2.5">${escapeHtml(o.customerName || '-')}</td>
                        <td class="py-2.5 text-gray-500 text-xs max-w-[180px] truncate" title="${escapeHtml(o.productSummary || '')}">${escapeHtml(o.productSummary || '-')}</td>
                        <td class="py-2.5 text-right font-semibold">${formatMoney(o.total || 0)}</td>
                        <td class="py-2.5 ${sc} font-medium">${escapeHtml(o.status || '')}</td>
                    </tr>`;
                }).join('');
            })
            .withFailureHandler(function(err) {
                if (tbodyEl) tbodyEl.innerHTML = '<tr><td colspan="6" class="text-center py-6 text-red-400">Lỗi tải dữ liệu</td></tr>';
            })
            .apiHandler('getEmployeeOrders', { employeeId: employeeId, startDate: startDate, endDate: endDate });
    }

