    function renderWarrantyReport(data) {
        const summary = data.summary || {};

        // Update summary cards
        const totalEl = document.getElementById('warranty-total');
        const activeEl = document.getElementById('warranty-active');
        const expiredEl = document.getElementById('warranty-expired');
        const expiringEl = document.getElementById('warranty-expiring-soon');
        const requestsEl = document.getElementById('warranty-total-requests');
        const costEl = document.getElementById('warranty-total-cost');
        const avgCostEl = document.getElementById('warranty-avg-cost');

        if (totalEl) totalEl.textContent = summary.totalWarranties || 0;
        if (activeEl) activeEl.textContent = summary.activeWarranties || 0;
        if (expiredEl) expiredEl.textContent = summary.expiredWarranties || 0;
        if (expiringEl) expiringEl.textContent = summary.expiringSoon || 0;
        if (requestsEl) requestsEl.textContent = summary.totalRequests || 0;
        if (costEl) costEl.textContent = formatMoney(summary.totalCost || 0);
        if (avgCostEl) avgCostEl.textContent = formatMoney(summary.avgCost || 0);

        // Render by status
        const statusTbody = document.getElementById('warranty-status-body');
        if (statusTbody) {
            statusTbody.innerHTML = '';
            if (data.byStatus && Object.keys(data.byStatus).length > 0) {
                Object.entries(data.byStatus).forEach(([status, count]) => {
                    const tr = document.createElement('tr');
                    tr.innerHTML = `
                        <td class="py-2">${status}</td>
                        <td class="py-2 text-right font-semibold">${count}</td>
                    `;
                    statusTbody.appendChild(tr);
                });
            } else {
                statusTbody.innerHTML = '<tr><td colspan="2" class="text-center py-4 text-gray-400">Không có dữ liệu</td></tr>';
            }
        }

        // Render top products
        const productsTbody = document.getElementById('warranty-top-products-body');
        if (productsTbody) {
            productsTbody.innerHTML = '';
            if (data.topProducts && data.topProducts.length > 0) {
                data.topProducts.forEach((product, index) => {
                    const tr = document.createElement('tr');
                    tr.innerHTML = `
                        <td class="py-2">${index + 1}</td>
                        <td class="py-2 font-medium">${product.sku}</td>
                        <td class="py-2">${product.productName}</td>
                        <td class="py-2 text-right">${product.total}</td>
                        <td class="py-2 text-right">${product.active}</td>
                        <td class="py-2 text-right text-red-600">${product.expired}</td>
                        <td class="py-2 text-right">${product.requests}</td>
                    `;
                    productsTbody.appendChild(tr);
                });
            } else {
                productsTbody.innerHTML = '<tr><td colspan="7" class="text-center py-4 text-gray-400">Không có dữ liệu</td></tr>';
            }
        }

        // Render top customers
        const customersTbody = document.getElementById('warranty-top-customers-body');
        if (customersTbody) {
            customersTbody.innerHTML = '';
            if (data.topCustomers && data.topCustomers.length > 0) {
                data.topCustomers.forEach((customer, index) => {
                    const tr = document.createElement('tr');
                    tr.innerHTML = `
                        <td class="py-2">${index + 1}</td>
                        <td class="py-2 font-medium">${customer.customerId}</td>
                        <td class="py-2">${customer.customerName}</td>
                        <td class="py-2 text-right">${customer.total}</td>
                        <td class="py-2 text-right">${customer.active}</td>
                        <td class="py-2 text-right text-red-600">${customer.expired}</td>
                    `;
                    customersTbody.appendChild(tr);
                });
            } else {
                customersTbody.innerHTML = '<tr><td colspan="6" class="text-center py-4 text-gray-400">Không có dữ liệu</td></tr>';
            }
        }

        // Render expiring warranties
        const expiringTbody = document.getElementById('warranty-expiring-body');
        if (expiringTbody) {
            expiringTbody.innerHTML = '';
            if (data.expiringWarranties && data.expiringWarranties.length > 0) {
                data.expiringWarranties.forEach((warranty) => {
                    const expirationDate = new Date(warranty.expirationDate);
                    const daysLeft = warranty.daysUntilExpiration || 0;
                    const tr = document.createElement('tr');
                    tr.innerHTML = `
                        <td class="py-2 font-medium">${warranty.id}</td>
                        <td class="py-2">${warranty.productName}</td>
                        <td class="py-2">${warranty.customerName}</td>
                        <td class="py-2">${expirationDate.toLocaleDateString('vi-VN')}</td>
                        <td class="py-2 text-right ${daysLeft <= 7 ? 'text-red-600 font-bold' : daysLeft <= 15 ? 'text-orange-600' : ''}">${daysLeft} ngày</td>
                    `;
                    expiringTbody.appendChild(tr);
                });
            } else {
                expiringTbody.innerHTML = '<tr><td colspan="5" class="text-center py-4 text-gray-400">Không có phiếu bảo hành sắp hết hạn</td></tr>';
            }
        }
    }

