    function renderTopProductsChart(reportData) {
        const ctx = document.getElementById('top-products-chart');
        if (!ctx) return;

        // Destroy existing chart if exists
        if (topProductsChart) {
            topProductsChart.destroy();
        }

        if (!reportData.products || reportData.products.length === 0) {
            ctx.parentElement.innerHTML = '<p class="text-center text-gray-400 py-20">Chưa có dữ liệu</p>';
            return;
        }

        const labels = reportData.products.map(p => p.name || p.sku);
        const data = reportData.products.map(p => p.qty || 0);
        const colors = [
            'rgba(59, 130, 246, 0.8)',
            'rgba(34, 197, 94, 0.8)',
            'rgba(251, 191, 36, 0.8)',
            'rgba(239, 68, 68, 0.8)',
            'rgba(168, 85, 247, 0.8)'
        ];

        topProductsChart = new Chart(ctx, {
            type: 'doughnut',
            data: {
                labels: labels,
                datasets: [{
                    label: 'Số Lượng Bán',
                    data: data,
                    backgroundColor: colors.slice(0, data.length),
                    borderWidth: 2,
                    borderColor: '#fff'
                }]
            },
            options: {
                responsive: true,
                maintainAspectRatio: false,
                plugins: {
                    legend: {
                        position: 'right',
                        labels: {
                            padding: 15,
                            font: {
                                size: 12
                            }
                        }
                    },
                    tooltip: {
                        callbacks: {
                            label: function (context) {
                                const label = context.label || '';
                                const value = context.parsed || 0;
                                const total = context.dataset.data.reduce((a, b) => a + b, 0);
                                const percentage = ((value / total) * 100).toFixed(1);
                                return label + ': ' + value + ' sản phẩm (' + percentage + '%)';
                            }
                        }
                    }
                }
            }
        });
    }

    // REFRESH FUNCTIONS

    /**
     * Initialize Create Order page components
     * Ensures employees, customers and products are loaded when entering the page
     */
    function initCreateOrderPage() {
        // 1. Load Employees
        try {
            if (typeof loadEmployeesForOrder === 'function') {
                loadEmployeesForOrder();
            }
        } catch (e) {
            console.error('Error loading employees', e);
        }

        // 2. Load/Refresh Customers for order page
        try {
            if (!allCustomers || allCustomers.length === 0) {
                // Customers not loaded, load them
                google.script.run
                    .withSuccessHandler(function(res) {
                        if (res && res.success !== false) {
                            const customerData = res.data || res;
                            customers = Array.isArray(customerData) ? customerData : [];
                            setCustomers(customers);
                            console.log('initCreateOrderPage: Customers loaded:', allCustomers.length);
                        }
                    })
                    .withFailureHandler(function(err) {
                        console.error('Error loading customers for order:', err);
                    })
                    .apiHandler('getCustomers', {});
            }
        } catch (e) {
            console.error('Error loading customers', e);
        }

        // 3. Load Products for POS search (no product table rendering needed)
        // POS mode: render cart table (empty initially)
        renderCart();

        if (typeof products !== 'undefined' && Array.isArray(products) && products.length > 0) {
            console.log('initCreateOrderPage: Products ready for POS search:', products.length);
        } else {
            // Try local storage first for faster load
            try {
                const cached = LocalStore.get('products');
                if (cached && Array.isArray(cached) && cached.length > 0) {
                    setProducts(cached);
                    console.log('initCreateOrderPage: Products loaded from cache for POS search:', products.length);
                    return;
                }
            } catch (e) {
                // Cache check failed
            }

            // Fallback to full load
            loadDataWithCallback(() => {
                console.log('initCreateOrderPage: Data loaded for POS search:', products ? products.length : 0);
            });
        }

        // Auto-focus search bar for rapid product entry
        setTimeout(() => {
            const searchEl = document.getElementById('product-search');
            if (searchEl) searchEl.focus();
        }, 200);
    }

    /**
     * Refresh data for Create Order page
     */
    function refreshOrderData() {
        showToast('Đang làm mới dữ liệu...', 'info');
        // Clear cache for products and customers
        google.script.run
            .withSuccessHandler(() => {
                // Reload data after cache cleared
                loadData();
                showToast('Đã làm mới dữ liệu thành công', 'success');
            })
            .withFailureHandler((err) => {
                console.error('Error clearing cache:', err);
                // Still try to reload data even if cache clear fails
                loadData();
                showToast('Đã làm mới dữ liệu', 'success');
            })
            .apiHandler('clearCache', { sheetName: null }); // Clear all cache
    }

    /**
     * Refresh data for Orders List page
     */
    function refreshOrdersData() {
        showToast('Đang làm mới dữ liệu...', 'info');
        localStorage.removeItem('TTL_orders'); // Xóa localStorage cache
        // Clear server-side cache
        google.script.run
            .withSuccessHandler(() => {
                loadOrders(true); // Force refresh bypass cache
                showToast('Đã làm mới dữ liệu đơn hàng thành công', 'success');
            })
            .withFailureHandler((err) => {
                console.error('Error clearing cache:', err);
                loadOrders(true);
                showToast('Đã làm mới dữ liệu đơn hàng', 'success');
            })
            .apiHandler('clearCache', { sheetName: 'Đơn Hàng' });
    }

