    function loadShopSettings() {
        google.script.run
            .withSuccessHandler(function(res) {
                if (res && res.success && res.data) {
                    allowNegativeStock = res.data.value === 'true';
                    var cb = document.getElementById('setting-allow-negative-stock');
                    if (cb) cb.checked = allowNegativeStock;
                }
            })
            .withFailureHandler(function() {})
            .apiHandler('getShopSetting', { key: 'ALLOW_NEGATIVE_STOCK' });

        google.script.run
            .withSuccessHandler(function(res) {
                if (res && res.success && res.data) {
                    allowEditOrderDate = res.data.value === 'true';
                    var cb = document.getElementById('setting-allow-edit-order-date');
                    if (cb) cb.checked = allowEditOrderDate;
                }
            })
            .withFailureHandler(function() {})
            .apiHandler('getShopSetting', { key: 'ALLOW_EDIT_ORDER_DATE' });

        google.script.run
            .withSuccessHandler(function(res) {
                if (res && res.success && res.data) {
                    autoCreateWarranty = res.data.value !== 'false';
                    var cb = document.getElementById('setting-auto-create-warranty');
                    if (cb) cb.checked = autoCreateWarranty;
                }
            })
            .withFailureHandler(function() {})
            .apiHandler('getShopSetting', { key: 'AUTO_CREATE_WARRANTY' });
    }

    function saveShopSetting(key, value) {
        if (key === 'ALLOW_NEGATIVE_STOCK') allowNegativeStock = value;
        if (key === 'ALLOW_EDIT_ORDER_DATE') allowEditOrderDate = value;
        if (key === 'AUTO_CREATE_WARRANTY') autoCreateWarranty = value;
        google.script.run
            .withSuccessHandler(function(res) {
                if (res && res.success) showToast('Đã lưu cài đặt', 'success');
            })
            .withFailureHandler(function(e) { showToast('Lỗi: ' + e, 'error'); })
            .apiHandler('saveShopSetting', { key: key, value: String(value) });
    }

    // === Order Status Management (Settings tab) ===
    function renderOrderStatusList() {
        var container = document.getElementById('order-status-list');
        if (!container) return;
        // Protected statuses cannot be deleted
        var protectedStatuses = ['Pending', 'Completed', 'Cancelled'];
        container.innerHTML = orderStatusConfig.map(function(s, i) {
            var isProtected = protectedStatuses.indexOf(s) !== -1;
            var label = STATUS_LABELS[s] || '';
            return '<div class="flex items-center gap-2 p-2.5 bg-gray-50 rounded-lg group" draggable="true" data-idx="' + i + '">' +
                '<span class="cursor-grab text-gray-400 hover:text-gray-600" title="Kéo để sắp xếp">☰</span>' +
                '<span class="inline-block w-3 h-3 rounded-full ' + (getOrderStatusClass(s).split(' ')[0] || 'bg-gray-200') + '"></span>' +
                '<input type="text" value="' + escapeHtml(s) + '" class="flex-1 px-2 py-1 border border-transparent rounded text-sm focus:border-blue-400 focus:bg-white bg-transparent" ' +
                    'onblur="editOrderStatus(' + i + ', this.value)" onkeydown="if(event.key===\'Enter\'){this.blur();}">' +
                (label ? '<span class="text-xs text-gray-400">(' + escapeHtml(label) + ')</span>' : '') +
                (isProtected ? '<span class="text-xs text-gray-300 px-2" title="Trạng thái mặc định, không thể xóa">🔒</span>' :
                    '<button onclick="removeOrderStatus(' + i + ')" class="opacity-0 group-hover:opacity-100 px-2 py-1 text-red-500 hover:bg-red-50 rounded text-sm transition" title="Xóa">✕</button>') +
                '</div>';
        }).join('');

        // Drag & drop reorder
        var items = container.querySelectorAll('[draggable]');
        var dragIdx = null;
        items.forEach(function(item) {
            item.addEventListener('dragstart', function(e) {
                dragIdx = parseInt(item.dataset.idx);
                item.classList.add('opacity-50');
            });
            item.addEventListener('dragend', function() { item.classList.remove('opacity-50'); });
            item.addEventListener('dragover', function(e) { e.preventDefault(); item.classList.add('bg-blue-50'); });
            item.addEventListener('dragleave', function() { item.classList.remove('bg-blue-50'); });
            item.addEventListener('drop', function(e) {
                e.preventDefault();
                item.classList.remove('bg-blue-50');
                var dropIdx = parseInt(item.dataset.idx);
                if (dragIdx !== null && dragIdx !== dropIdx) {
                    var moved = orderStatusConfig.splice(dragIdx, 1)[0];
                    orderStatusConfig.splice(dropIdx, 0, moved);
                    saveOrderStatuses();
                    renderOrderStatusList();
                }
            });
        });
    }

    function addOrderStatus() {
        var input = document.getElementById('new-order-status-input');
        if (!input) return;
        var val = input.value.trim();
        if (!val) { showToast('Vui lòng nhập tên trạng thái', 'warning'); return; }
        if (orderStatusConfig.indexOf(val) !== -1) { showToast('Trạng thái đã tồn tại', 'warning'); return; }
        orderStatusConfig.push(val);
        input.value = '';
        saveOrderStatuses();
        renderOrderStatusList();
    }

    function editOrderStatus(idx, newVal) {
        newVal = newVal.trim();
        if (!newVal) { renderOrderStatusList(); return; } // revert empty
        var old = orderStatusConfig[idx];
        if (newVal === old) return; // no change
        if (orderStatusConfig.indexOf(newVal) !== -1) { showToast('Trạng thái đã tồn tại', 'warning'); renderOrderStatusList(); return; }
        orderStatusConfig[idx] = newVal;
        saveOrderStatuses();
        renderOrderStatusList();
    }

    function removeOrderStatus(idx) {
        var name = orderStatusConfig[idx];
        showConfirmModal(
            'Xóa trạng thái "' + name + '"?',
            'Đơn hàng đang dùng trạng thái này vẫn giữ nguyên giá trị cũ.',
            'Xóa',
            function() {
                orderStatusConfig.splice(idx, 1);
                saveOrderStatuses();
                renderOrderStatusList();
            }
        );
    }

    function saveOrderStatuses() {
        google.script.run
            .withSuccessHandler(function(res) {
                if (res && res.success && res.data && res.data.statuses) {
                    orderStatusConfig = res.data.statuses;
                    showToast('Đã lưu trạng thái đơn hàng', 'success');
                } else if (res && res.data && res.data.success && res.data.statuses) {
                    orderStatusConfig = res.data.statuses;
                    showToast('Đã lưu trạng thái đơn hàng', 'success');
                } else {
                    showToast('Lỗi lưu trạng thái', 'error');
                }
            })
            .withFailureHandler(function(e) { showToast('Lỗi: ' + e, 'error'); })
            .apiHandler('updateOrderStatuses', { statuses: orderStatusConfig });
    }
    // === End Order Status Management ===

    function loadPrintSettingsToForm() {
        console.log('loadPrintSettingsToForm called');

        // Verify settings page is visible
        const settingsPage = document.getElementById('page-settings');
        if (!settingsPage || settingsPage.classList.contains('hidden')) {
            console.warn('Settings page is not visible, will retry in 200ms');
            setTimeout(() => loadPrintSettingsToForm(), 200);
            return;
        }

        toggleLoading(true);
        google.script.run
            .withSuccessHandler((res) => {
                toggleLoading(false);
                console.log('loadPrintSettingsToForm response:', res);

                if (res && res.success && res.data) {
                    const settings = res.data;

                    // Helper function to safely set value
                    const setValue = (id, value, defaultValue = '') => {
                        const el = document.getElementById(id);
                        if (el) {
                            el.value = (value !== undefined && value !== null && value !== '') ? value : defaultValue;
                            console.log('Set ' + id + ' to: ' + (value || defaultValue));
                        } else {
                            console.warn('Element not found: ' + id);
                        }
                    };

                    // Helper function to set value without default (preserve empty)
                    const setValueRaw = (id, value) => {
                        const el = document.getElementById(id);
                        if (el) {
                            el.value = (value !== undefined && value !== null) ? String(value) : '';
                            console.log('Set ' + id + ' to: ' + (value ? (id.includes('Token') ? '***' : value) : '(empty)'));
                        } else {
                            console.warn('Element not found: ' + id);
                        }
                    };

                    // Load company info
                    setValueRaw('print-company-name', settings.companyName);
                    setValueRaw('print-company-address', settings.companyAddress);
                    setValueRaw('print-company-phone', settings.companyPhone);
                    setValueRaw('print-company-email', settings.companyEmail);
                    setValueRaw('print-company-tax', settings.companyTax);
                    setValueRaw('print-company-website', settings.companyWebsite);

                    // Load print template settings
                    setValue('print-invoice-title', settings.invoiceTitle, 'HÓA ĐƠN BÁN HÀNG');
                    setValueRaw('print-footer-note', settings.footerNote);
                    setValue('print-font-size', settings.fontSize, '14');

                    const showLogoEl = document.getElementById('print-show-logo');
                    if (showLogoEl) showLogoEl.value = settings.showLogo !== undefined ? (settings.showLogo ? 'true' : 'false') : 'false';

                    const showQREl = document.getElementById('print-show-qr');
                    if (showQREl) showQREl.value = settings.showQR !== undefined ? (settings.showQR ? 'true' : 'false') : 'false';

                    const showBorderEl = document.getElementById('print-show-border');
                    if (showBorderEl) showBorderEl.value = settings.showBorder !== undefined ? (settings.showBorder ? 'true' : 'false') : 'false';

                    // New fields
                    const templateIdEl = document.getElementById('print-template-id');
                    if (templateIdEl) templateIdEl.value = settings.templateId || 'professional';

                    const showUnitEl = document.getElementById('print-show-unit');
                    if (showUnitEl) showUnitEl.value = settings.showUnit !== undefined ? (settings.showUnit ? 'true' : 'false') : 'true';

                    const showSignaturesEl = document.getElementById('print-show-signatures');
                    if (showSignaturesEl) showSignaturesEl.value = settings.showSignatures ? 'true' : 'false';

                    const showBankInfoEl = document.getElementById('print-show-bank-info');
                    if (showBankInfoEl) showBankInfoEl.value = settings.showBankInfo ? 'true' : 'false';

                    setValueRaw('print-bank-name', settings.bankName);
                    setValueRaw('print-bank-account', settings.bankAccount);
                    setValueRaw('print-bank-account-name', settings.bankAccountName);
                    const bankIdEl = document.getElementById('print-bank-id');
                    if (bankIdEl && settings.bankId) bankIdEl.value = settings.bankId;

                    // Load logo if exists
                    if (settings.logo) {
                        currentPrintLogo = settings.logo;
                        document.getElementById('print-logo-filename').textContent = 'Logo đã lưu';
                        document.getElementById('print-logo-preview').style.display = 'block';
                        document.getElementById('print-logo-preview-img').src = settings.logo;
                        document.getElementById('print-logo-clear').style.display = 'inline-block';
                    } else {
                        if (typeof clearPrintLogo === 'function') clearPrintLogo();
                    }

                    // Load Feature 7-10 fields
                    const showBarcodeEl = document.getElementById('print-show-barcode');
                    if (showBarcodeEl) showBarcodeEl.value = (settings.showBarcode === true || settings.showBarcode === 'true') ? 'true' : 'false';
                    const paperSizeEl = document.getElementById('print-paper-size');
                    if (paperSizeEl) paperSizeEl.value = settings.paperSize || 'A4';
                    const paddingEl = document.getElementById('print-padding');
                    const paddingValEl = document.getElementById('print-padding-val');
                    var pv = settings.padding !== undefined ? settings.padding : 20;
                    if (paddingEl) paddingEl.value = pv;
                    if (paddingValEl) paddingValEl.textContent = pv + 'px';
                    const lhEl = document.getElementById('print-line-height');
                    const lhValEl = document.getElementById('print-line-height-val');
                    var lhv = settings.lineHeight !== undefined ? settings.lineHeight : 1.5;
                    if (lhEl) lhEl.value = lhv;
                    if (lhValEl) lhValEl.textContent = parseFloat(lhv).toFixed(1);

                    // #4: copies
                    var copiesEl = document.getElementById('print-copies');
                    if (copiesEl) copiesEl.value = settings.copies || 1;

                    // #6: border color
                    var bcEl = document.getElementById('print-border-color');
                    if (bcEl) bcEl.value = settings.borderColor || '#000000';

                    // #7: custom column headers
                    var colFields = ['col-stt','col-ten-hang','col-dvt','col-sl','col-don-gia','col-thanh-tien'];
                    var colKeys  = ['colStt','colTenHang','colDvt','colSl','colDonGia','colThanhTien'];
                    colFields.forEach(function(fid, i) {
                        var cel = document.getElementById(fid);
                        if (cel) cel.value = settings[colKeys[i]] || '';
                    });

                    // Also update global variable
                    currentPrintSettings = settings;

                } else {
                    console.error('Failed to load print settings:', res);
                }
            })
            .withFailureHandler((error) => {
                toggleLoading(false);
                console.error('Error loading print settings:', error);
            })
            .apiHandler('getPrintSettings', {});
    }

    function savePrintSettings() {
        // Helper function to safely get value
        const getValue = (id, defaultValue = '') => {
            const el = document.getElementById(id);
            return el ? (el.value || defaultValue) : defaultValue;
        };

        const getTrimmedValue = (id, defaultValue = '') => {
            const el = document.getElementById(id);
            return el ? (el.value.trim() || defaultValue) : defaultValue;
        };

        const settings = {
            companyName: getTrimmedValue('print-company-name'),
            companyAddress: getTrimmedValue('print-company-address'),
            companyPhone: getTrimmedValue('print-company-phone'),
            companyEmail: getTrimmedValue('print-company-email'),
            companyTax: getTrimmedValue('print-company-tax'),
            companyWebsite: getTrimmedValue('print-company-website'),
            invoiceTitle: getTrimmedValue('print-invoice-title', 'HÓA ĐƠN TẠM TÍNH'),
            footerNote: getTrimmedValue('print-footer-note'),
            fontSize: parseInt(getValue('print-font-size', '14')) || 14,
            showLogo: getValue('print-show-logo') === 'true',
            showQR: getValue('print-show-qr') === 'true',
            showBorder: getValue('print-show-border') === 'true',
            templateId: getValue('print-template-id', 'professional'),
            showUnit: getValue('print-show-unit') === 'true',
            showSignatures: getValue('print-show-signatures') === 'true',
            showBankInfo: getValue('print-show-bank-info') === 'true',
            bankId: getValue('print-bank-id') || '',
            bankName: getTrimmedValue('print-bank-name'),
            bankAccount: getTrimmedValue('print-bank-account'),
            bankAccountName: getTrimmedValue('print-bank-account-name'),
            logo: currentPrintLogo || '',
            showBarcode: getValue('print-show-barcode') === 'true',
            paperSize: getValue('print-paper-size') || 'A4',
            padding: parseInt(getValue('print-padding') || '20') || 20,
            lineHeight: parseFloat(getValue('print-line-height') || '1.5') || 1.5,
            // #4: copies
            copies: parseInt(getValue('print-copies') || '1') || 1,
            // #6: border color
            borderColor: getValue('print-border-color') || '#000000',
            // #7: custom column headers
            colStt: getTrimmedValue('col-stt'),
            colTenHang: getTrimmedValue('col-ten-hang'),
            colDvt: getTrimmedValue('col-dvt'),
            colSl: getTrimmedValue('col-sl'),
            colDonGia: getTrimmedValue('col-don-gia'),
            colThanhTien: getTrimmedValue('col-thanh-tien'),
        };

        toggleLoading(true);
        google.script.run
            .withSuccessHandler((res) => {
                toggleLoading(false);
                if (res && res.success) {
                    showToast('Lưu cài đặt mẫu in thành công!', 'success');
                    localStorage.removeItem('TTL_printSettings');
                    // #5: also persist per-template overrides
                    if (typeof savePerTemplateSettings === 'function') {
                        savePerTemplateSettings(settings.templateId, {
                            borderColor: settings.borderColor,
                            copies: settings.copies,
                            colStt: settings.colStt, colTenHang: settings.colTenHang,
                            colDvt: settings.colDvt, colSl: settings.colSl,
                            colDonGia: settings.colDonGia, colThanhTien: settings.colThanhTien
                        });
                    }
                    currentPrintSettings = null;
                    setTimeout(() => {
                        loadPrintSettings();
                    }, 500);
                } else {
                    showToast('Lỗi: ' + (res.message || 'Không thể lưu cài đặt'), 'error');
                }
            })
            .withFailureHandler((error) => {
                toggleLoading(false);
                showToast('Lỗi: ' + (error.message || 'Không thể lưu cài đặt'), 'error');
            })
            .apiHandler('savePrintSettings', settings);
    }

    function resetPrintSettings() {
        if (confirm('Bạn có chắc chắn muốn đặt lại tất cả cài đặt về mặc định?')) {
            document.getElementById('print-company-name').value = '';
            document.getElementById('print-company-address').value = '';
            document.getElementById('print-company-phone').value = '';
            document.getElementById('print-company-email').value = '';
            document.getElementById('print-company-tax').value = '';
            document.getElementById('print-company-website').value = '';
            document.getElementById('print-invoice-title').value = 'HÓA ĐƠN TẠM TÍNH';
            document.getElementById('print-footer-note').value = '';
            document.getElementById('print-font-size').value = '14';
            document.getElementById('print-show-logo').value = 'true';
            document.getElementById('print-show-qr').value = 'true';
            document.getElementById('print-show-border').value = 'true';
            // New fields
            var el;
            el = document.getElementById('print-template-id'); if (el) el.value = 'professional';
            el = document.getElementById('print-show-unit'); if (el) el.value = 'true';
            el = document.getElementById('print-show-signatures'); if (el) el.value = 'false';
            el = document.getElementById('print-show-bank-info'); if (el) el.value = 'false';
            el = document.getElementById('print-bank-id'); if (el) el.value = '';
            el = document.getElementById('print-bank-name'); if (el) el.value = '';
            el = document.getElementById('print-bank-account'); if (el) el.value = '';
            el = document.getElementById('print-bank-account-name'); if (el) el.value = '';
            el = document.getElementById('print-show-barcode'); if (el) el.value = 'false';
            el = document.getElementById('print-paper-size'); if (el) el.value = 'A4';
            el = document.getElementById('print-padding'); if (el) { el.value = '20'; document.getElementById('print-padding-val').textContent = '20px'; }
            el = document.getElementById('print-line-height'); if (el) { el.value = '1.5'; document.getElementById('print-line-height-val').textContent = '1.5'; }
            // Reset new fields
            el = document.getElementById('print-copies'); if (el) el.value = '1';
            el = document.getElementById('print-border-color'); if (el) el.value = '#000000';
            ['col-stt','col-ten-hang','col-dvt','col-sl','col-don-gia','col-thanh-tien'].forEach(function(fid) {
                var cel = document.getElementById(fid); if (cel) cel.value = '';
            });
            clearPrintLogo();
            showToast('Đã đặt lại cài đặt về mặc định', 'info');
        }
    }

    // #1: Guide modal
    function showPrintGuideModal() {
        var m = document.getElementById('print-guide-modal');
        if (m) m.classList.remove('hidden');
    }
    function closePrintGuideModal() {
        var m = document.getElementById('print-guide-modal');
        if (m) m.classList.add('hidden');
    }

    // #3: Restore invoice template to default — shows default HTML in a copy-paste modal
    function resetInvoiceTemplateFile() {
        var tid = (document.getElementById('print-template-id') || {}).value || 'a4';
        var nameMap = { 'a4': 'A4', 'a5': 'A5 Cổ điển', 'receipt': 'Phiếu thu 80mm' };
        var tname = nameMap[tid] || tid;
        if (!['a4','a5','receipt'].includes(tid)) {
            showToast('Chỉ hỗ trợ khôi phục mẫu A4, A5 hoặc Phiếu thu 80mm', 'warning');
            return;
        }
        toggleLoading(true);
        google.script.run
            .withSuccessHandler(function(res) {
                toggleLoading(false);
                if (res && res.success && res.data) {
                    _showTemplateResetModal(tname, res.data.fileToEdit, res.data.defaultHtml);
                } else {
                    showToast('Lỗi: ' + ((res && res.message) || 'Không thể lấy nội dung mẫu mặc định'), 'error');
                }
            })
            .withFailureHandler(function(err) {
                toggleLoading(false);
                showToast('Lỗi kết nối khi lấy mẫu mặc định', 'error');
            })
            .apiHandler('resetInvoiceTemplate', { templateId: tid });
    }
    function _showTemplateResetModal(tname, fileName, defaultHtml) {
        // Reuse guide modal or create inline
        var existing = document.getElementById('template-reset-modal');
        if (existing) existing.remove();
        var modal = document.createElement('div');
        modal.id = 'template-reset-modal';
        modal.className = 'fixed inset-0 bg-black/60 z-50 flex items-center justify-center';
        modal.innerHTML = '<div class="bg-white rounded-2xl shadow-xl w-full max-w-2xl mx-4 max-h-[90vh] flex flex-col">'
            + '<div class="flex items-center justify-between px-6 py-4 border-b">'
            + '<h3 class="text-base font-bold text-gray-900">🔁 Khôi phục mẫu "' + tname + '"</h3>'
            + '<button onclick="document.getElementById(\'template-reset-modal\').remove()" class="text-gray-400 hover:text-gray-600 text-2xl">&times;</button>'
            + '</div>'
            + '<div class="px-6 py-4 text-sm text-gray-700 overflow-y-auto flex-1">'
            + '<p class="mb-3 text-orange-700 bg-orange-50 border border-orange-200 rounded-lg p-3">GAS không cho phép tự ghi đè file HTML từ code. Hãy <strong>sao chép toàn bộ nội dung bên dưới</strong> và dán vào file <code class="bg-orange-100 px-1 rounded">' + fileName + '</code> trong GAS Editor.</p>'
            + '<div class="flex gap-2 mb-2"><button onclick="(function(){var t=document.getElementById(\'tpl-reset-content\');var r=document.createRange();r.selectNode(t);window.getSelection().removeAllRanges();window.getSelection().addRange(r);try{document.execCommand(\'copy\');showToast(\'Đã sao chép!\',\'success\');}catch(e){};})()" class="px-3 py-1.5 bg-blue-600 text-white rounded-lg text-xs hover:bg-blue-700">📋 Sao chép</button></div>'
            + '<pre id="tpl-reset-content" class="bg-gray-50 border border-gray-200 rounded-lg p-3 text-xs overflow-x-auto whitespace-pre-wrap break-words max-h-64 overflow-y-auto">' + defaultHtml.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;') + '</pre>'
            + '</div>'
            + '<div class="px-6 py-4 border-t flex justify-end"><button onclick="document.getElementById(\'template-reset-modal\').remove()" class="px-5 py-2 bg-gray-800 text-white rounded-xl text-sm">Đóng</button></div>'
            + '</div>';
        document.body.appendChild(modal);
    }

    // #4: Inline template editor — load, edit, save HTML template via PropertiesService
    function openTemplateEditor() {
        var tid = (document.getElementById('print-template-id') || {}).value || 'a4';
        if (!['a4','a5','receipt'].includes(tid)) {
            showToast('Chỉ hỗ trợ chỉnh sửa mẫu A4, A5 hoặc Phiếu thu 80mm', 'warning');
            return;
        }
        var nameMap = { 'a4': 'A4 Chuẩn', 'a5': 'A5 Cổ điển', 'receipt': 'Phiếu thu 80mm' };
        toggleLoading(true);
        google.script.run
            .withSuccessHandler(function(res) {
                toggleLoading(false);
                if (res && res.success && res.data) {
                    _showTemplateEditorModal(tid, nameMap[tid], res.data.html, res.data.isCustom);
                } else {
                    showToast('Lỗi tải mẫu: ' + ((res && res.message) || 'Không xác định'), 'error');
                }
            })
            .withFailureHandler(function(err) {
                toggleLoading(false);
                showToast('Lỗi kết nối', 'error');
            })
            .apiHandler('getTemplateSource', { templateId: tid });
    }

    function _showTemplateEditorModal(tid, tname, html, isCustom) {
        var existing = document.getElementById('template-editor-modal');
        if (existing) existing.remove();
        var customBadge = isCustom ? '<span class="ml-2 px-2 py-0.5 text-xs bg-green-100 text-green-700 rounded-full font-medium">Đã chỉnh sửa</span>' : '';
        var modal = document.createElement('div');
        modal.id = 'template-editor-modal';
        modal.className = 'fixed inset-0 bg-black/60 z-50 flex items-center justify-center';
        modal.innerHTML = '<div class="bg-white rounded-2xl shadow-xl w-full max-w-4xl mx-4 flex flex-col" style="height:90vh">'
            + '<div class="flex items-center justify-between px-6 py-4 border-b flex-shrink-0">'
            + '<div class="flex items-center gap-2"><h3 class="text-base font-bold text-gray-900">✏️ Chỉnh Sửa Mẫu "' + tname + '"</h3>' + customBadge + '</div>'
            + '<button onclick="document.getElementById(\'template-editor-modal\').remove()" class="text-gray-400 hover:text-gray-600 text-2xl">&times;</button>'
            + '</div>'
            + '<div class="px-6 py-3 bg-blue-50 border-b text-xs text-blue-800 flex-shrink-0">'
            + '💡 Chỉnh sửa HTML mẫu in trực tiếp. Dùng placeholder <code class="bg-blue-100 px-1 rounded">{{TEN_PLACEHOLDER}}</code> để chèn dữ liệu động. Lưu xong, in hóa đơn sẽ dùng mẫu mới ngay lập tức.'
            + '</div>'
            + '<textarea id="tpl-editor-content" class="flex-1 font-mono text-xs p-4 resize-none border-0 outline-none overflow-auto" spellcheck="false">' + html.replace(/</g,'&lt;').replace(/>/g,'&gt;') + '</textarea>'
            + '<div class="px-6 py-4 border-t flex items-center justify-between gap-3 flex-shrink-0">'
            + '<button onclick="_clearTemplateCustom(\'' + tid + '\')" class="px-4 py-2 text-sm bg-red-50 text-red-600 border border-red-200 rounded-lg hover:bg-red-100">🔁 Khôi phục gốc</button>'
            + '<div class="flex gap-2">'
            + '<button onclick="document.getElementById(\'template-editor-modal\').remove()" class="px-5 py-2 border border-gray-200 text-gray-700 rounded-xl text-sm">Hủy</button>'
            + '<button onclick="_saveTemplateEdit(\'' + tid + '\')" class="px-5 py-2 bg-green-600 text-white rounded-xl text-sm hover:bg-green-700">💾 Lưu Mẫu</button>'
            + '</div></div>'
            + '</div>';
        document.body.appendChild(modal);
        // Decode HTML entities in textarea so user edits real HTML
        var ta = document.getElementById('tpl-editor-content');
        if (ta) ta.value = html;
    }

    function _saveTemplateEdit(tid) {
        var ta = document.getElementById('tpl-editor-content');
        if (!ta) return;
        var html = ta.value.trim();
        if (!html) { showToast('Nội dung mẫu không được trống', 'warning'); return; }
        toggleLoading(true);
        google.script.run
            .withSuccessHandler(function(res) {
                toggleLoading(false);
                if (res && res.success) {
                    showToast('Đã lưu mẫu in thành công!', 'success');
                    document.getElementById('template-editor-modal').remove();
                } else {
                    showToast('Lỗi lưu: ' + ((res && res.message) || 'Không xác định'), 'error');
                }
            })
            .withFailureHandler(function(err) {
                toggleLoading(false);
                showToast('Lỗi kết nối khi lưu mẫu', 'error');
            })
            .apiHandler('saveInvoiceTemplate', { templateId: tid, html: html });
    }

    function _clearTemplateCustom(tid) {
        if (!confirm('Khôi phục mẫu về file gốc? Mọi chỉnh sửa đã lưu sẽ bị xóa.')) return;
        toggleLoading(true);
        google.script.run
            .withSuccessHandler(function(res) {
                toggleLoading(false);
                if (res && res.success) {
                    showToast('Đã khôi phục mẫu gốc', 'success');
                    document.getElementById('template-editor-modal').remove();
                } else {
                    showToast('Lỗi: ' + ((res && res.message) || ''), 'error');
                }
            })
            .withFailureHandler(function(err) {
                toggleLoading(false);
                showToast('Lỗi kết nối', 'error');
            })
            .apiHandler('clearCustomInvoiceTemplate', { templateId: tid });
    }

    // #5: Per-template settings — save/load per templateId in localStorage
    var _perTemplateSettingsKey = 'TTL_printSettings_per_template';
    function savePerTemplateSettings(templateId, overrides) {
        try {
            var all = JSON.parse(localStorage.getItem(_perTemplateSettingsKey) || '{}');
            all[templateId] = overrides;
            localStorage.setItem(_perTemplateSettingsKey, JSON.stringify(all));
        } catch(e) {}
    }
    function loadPerTemplateSettings(templateId) {
        try {
            var all = JSON.parse(localStorage.getItem(_perTemplateSettingsKey) || '{}');
            return all[templateId] || null;
        } catch(e) { return null; }
    }
    // Called when template dropdown changes — save current settings for previous template, load for new
    function onPrintTemplateChange() {
        var tid = (document.getElementById('print-template-id') || {}).value || '';
        if (!tid) return;
        // Load per-template overrides if any
        var overrides = loadPerTemplateSettings(tid);
        if (overrides) {
            var colFields = ['col-stt','col-ten-hang','col-dvt','col-sl','col-don-gia','col-thanh-tien'];
            var colKeys  = ['colStt','colTenHang','colDvt','colSl','colDonGia','colThanhTien'];
            colFields.forEach(function(fid, i) {
                var cel = document.getElementById(fid);
                if (cel && overrides[colKeys[i]] !== undefined) cel.value = overrides[colKeys[i]];
            });
            var bcEl = document.getElementById('print-border-color');
            if (bcEl && overrides.borderColor) bcEl.value = overrides.borderColor;
            var cpEl = document.getElementById('print-copies');
            if (cpEl && overrides.copies) cpEl.value = overrides.copies;
        }
    }
    // Hook into savePrintSettings to also persist per-template overrides
    var _origSavePrintSettings = null; // see below

    function togglePasswordVisibility(inputId) {
        const input = document.getElementById(inputId);
        const toggle = document.getElementById(inputId + '-toggle');
        if (input.type === 'password') {
            input.type = 'text';
            toggle.innerText = '🙈';
        } else {
            input.type = 'password';
            toggle.innerText = '👁️';
        }
    }

    function handlePaymentMethodChange() {
        var method = (document.getElementById('payment-method') || {}).value || '';
        var container = document.getElementById('order-qr-container');
        var img = document.getElementById('order-qr-img');
        if (!container || !img) return;

        var settings = currentPrintSettings || {};
        var bankId = settings.bankId || '';
        var accountNo = settings.bankAccount || '';
        var accountName = settings.bankAccountName || '';

        if (method === 'Chuyển khoản' && bankId && accountNo) {
            var totalEl = document.getElementById('cart-final-total');
            var amount = totalEl ? parseFormattedNumber(totalEl.textContent) : 0;
            var url = buildVietQRUrl(bankId, accountNo, amount, '', accountName, 'compact2');
            img.src = url;
            container.classList.remove('hidden');
        } else {
            container.classList.add('hidden');
        }
    }

    function previewPrintTemplate() {
        const getValue = (id, def) => { const el = document.getElementById(id); return el ? (el.value || def) : def; };
        const paperSize = getValue('print-paper-size', 'A4');
        const padding = (parseInt(getValue('print-padding', '20')) || 20) + 'px';
        const lineHeight = parseFloat(getValue('print-line-height', '1.5')) || 1.5;
        const settings = {
            companyName: getValue('print-company-name', '') || 'Tên Công Ty Mẫu',
            companyAddress: getValue('print-company-address', '') || '123 Đường ABC, TP.HCM',
            companyPhone: getValue('print-company-phone', '') || '0901 234 567',
            companyEmail: getValue('print-company-email', '') || 'info@example.com',
            companyTax: getValue('print-company-tax', '') || '0123456789',
            companyWebsite: getValue('print-company-website', '') || '',
            invoiceTitle: getValue('print-invoice-title', 'HÓA ĐƠN TẠM TÍNH'),
            footerNote: getValue('print-footer-note', '') || 'Cảm ơn quý khách và hẹn gặp lại!',
            fontSize: parseInt(getValue('print-font-size', '14')) || 14,
            showLogo: getValue('print-show-logo', 'true') === 'true',
            showQR: getValue('print-show-qr', 'true') === 'true',
            showBarcode: getValue('print-show-barcode', 'false') === 'true',
            showBorder: getValue('print-show-border', 'true') === 'true',
            showUnit: getValue('print-show-unit', 'true') === 'true',
            showSignatures: getValue('print-show-signatures', 'false') === 'true',
            showBankInfo: getValue('print-show-bank-info', 'false') === 'true',
            bankName: getValue('print-bank-name', ''),
            bankAccount: getValue('print-bank-account', ''),
            bankAccountName: getValue('print-bank-account-name', ''),
            templateId: getValue('print-template-id', 'professional'),
            logo: currentPrintLogo || '',
            paperSize: paperSize,
            padding: parseInt(getValue('print-padding', '20')) || 20,
            lineHeight: lineHeight,
        };

        // Build dummy order for preview
        const dummyOrder = {
            id: 'ORD-PREVIEW',
            date: new Date().toISOString(),
            customerName: 'Nguyễn Văn A',
            customerPhone: '0901 234 567',
            customerAddress: '123 Đường Lê Lợi, Q.1, TP.HCM',
            employeeName: 'Nhân Viên Mẫu',
            items: [
                { productName: 'Sản phẩm mẫu 1', unit: 'Cái', qty: 2, price: 150000, total: 270000, discountType: 'percent', discountValue: 10, discountAmount: 30000 },
                { productName: 'Sản phẩm mẫu 2', unit: 'Hộp', qty: 1, price: 250000, total: 250000, discountType: 'amount', discountValue: 0, discountAmount: 0 },
            ],
            subtotal: 550000,
            discountAmount: 50000,
            shippingFee: 30000,
            total: 530000,
            paid: 300000,
            debt: 230000,
            notes: 'Ghi chú đơn hàng mẫu',
            paymentMethod: 'Tiền mặt',
        };

        const info = {
            name: settings.companyName,
            address: settings.companyAddress,
            phone: settings.companyPhone,
            email: settings.companyEmail,
            tax: settings.companyTax,
            website: settings.companyWebsite,
        };

        const options = {
            templateId: settings.templateId,
            invoiceTitle: settings.invoiceTitle,
            footerNote: settings.footerNote,
            showUnit: settings.showUnit,
            showDiscount: true,
            showItemDiscount: true,
            showShipping: true,
            showDebt: true,
            showBank: settings.showBankInfo && !!(settings.bankAccount),
            showSignatures: settings.showSignatures,
            showLogo: settings.showLogo,
            logo: settings.logo,
            bankName: settings.bankName,
            bankAccount: settings.bankAccount,
            bankAccountName: settings.bankAccountName,
            showQR: settings.showQR,
            showBarcode: settings.showBarcode,
        };

        const paperCSS = {
            'A4':     '@page { size: A4; margin: 1cm; }',
            'A5':     '@page { size: A5; margin: 0.8cm; }',
            'K80':    '@page { size: 80mm auto; margin: 3mm; }',
            'Letter': '@page { size: Letter; margin: 1cm; }',
        }[paperSize] || '@page { size: A4; margin: 1cm; }';

        function _openPreviewWindow(bodyHtml) {
            const previewWindow = window.open('', '_blank', 'width=900,height=700');
            if (!previewWindow) { showToast('Không thể mở cửa sổ xem trước. Vui lòng cho phép popup.', 'error'); return; }
            previewWindow.document.write(`<!DOCTYPE html>
<html><head><meta charset="UTF-8"><title>Xem Trước Mẫu In</title>
<style>
  @media print { ${paperCSS} body { margin:0; padding:0; } }
  body { font-family: Arial, sans-serif; padding: ${padding}; color: #000; line-height: ${lineHeight}; font-size: ${settings.fontSize}px; }
</style></head>
<body>${bodyHtml}</body></html>`);
            previewWindow.document.close();
        }

        // For GAS-based templates (a4/a5/receipt): call GAS previewInvoiceTemplate with dummy order
        // This always reflects the custom saved template immediately — no real orderId needed
        const gasTemplates = ['a4', 'a5', 'receipt'];
        if (gasTemplates.includes(settings.templateId)) {
            const previewDummyOrder = {
                id: 'HD-PREVIEW',
                date: new Date().toISOString(),
                customerName: 'Nguyễn Văn A',
                customerPhone: '0901 234 567',
                customerAddress: '123 Đường Lê Lợi, Q.1, TP.HCM',
                employeeName: 'Nhân Viên Mẫu',
                items: [
                    { productName: 'Sản phẩm mẫu 1', unit: 'Cái', qty: 2, price: 150000, total: 270000, discountType: 'percent', discountValue: 10, discountAmount: 30000 },
                    { productName: 'Sản phẩm mẫu 2', unit: 'Hộp', qty: 1, price: 250000, total: 250000, discountType: 'amount', discountValue: 0, discountAmount: 0 },
                ],
                subtotal: 550000,
                discountAmount: 50000,
                shippingFee: 30000,
                total: 530000,
                paid: 300000,
                debt: 230000,
                notes: 'Ghi chú đơn hàng mẫu',
                paymentMethod: 'Tiền mặt',
            };
            toggleLoading(true);
            google.script.run
                .withSuccessHandler(function(res) {
                    toggleLoading(false);
                    if (res && res.success && res.data && res.data.html) {
                        _openPreviewWindow(res.data.html);
                    } else {
                        showToast('Lỗi tải xem trước: ' + ((res && res.message) || ''), 'error');
                    }
                })
                .withFailureHandler(function(err) {
                    toggleLoading(false);
                    showToast('Lỗi kết nối khi xem trước', 'error');
                })
                .apiHandler('previewInvoiceTemplate', {
                    order: previewDummyOrder,
                    templateId: settings.templateId,
                    options: {
                        companyName: settings.companyName,
                        companyAddress: settings.companyAddress,
                        companyPhone: settings.companyPhone,
                        companyTax: settings.companyTax,
                        invoiceTitle: settings.invoiceTitle,
                        footerNote: settings.footerNote,
                        showUnit: settings.showUnit,
                        showDiscount: true,
                        showItemDiscount: true,
                        showShipping: true,
                        showDebt: true,
                        showSignatures: settings.showSignatures,
                    }
                });
            return;
        }

        // For JS-rendered templates (professional): use local render
        let bodyHtml = (typeof renderInvoiceTemplate === 'function')
            ? renderInvoiceTemplate(dummyOrder, info, options)
            : '<p>Không thể tải template. Vui lòng thử lại.</p>';

        // Pre-render QR/barcode using parent page's loaded libraries (avoid CDN in popup)
        if (settings.showQR || settings.showBarcode) {
            const tmpDiv = document.createElement('div');
            tmpDiv.style.cssText = 'position:absolute;left:-9999px;top:0';
            tmpDiv.innerHTML = bodyHtml;
            document.body.appendChild(tmpDiv);
            try {
                tmpDiv.querySelectorAll('[data-qr]').forEach(function(el) {
                    var t = el.getAttribute('data-qr');
                    if (t && typeof QRCode !== 'undefined') { try { new QRCode(el, {text:t,width:100,height:100,correctLevel:QRCode.CorrectLevel.M}); } catch(e){} }
                });
                tmpDiv.querySelectorAll('svg[data-barcode]').forEach(function(el) {
                    var v = el.getAttribute('data-barcode');
                    if (v && typeof JsBarcode !== 'undefined') { try { JsBarcode(el, v, {format:'CODE128',width:1.5,height:40,displayValue:false,margin:0}); } catch(e){} }
                });
            } catch(e) {}
            bodyHtml = tmpDiv.innerHTML;
            document.body.removeChild(tmpDiv);
        }

        _openPreviewWindow(bodyHtml);
    }


    // ============================================
    // TRANSACTION CATEGORIES MANAGEMENT
    // ============================================

    function showCategoriesModal() {
        const modal = document.getElementById('categories-modal');
        if (modal) {
            modal.classList.remove('hidden');
            loadCategories();
        }
    }

    function closeCategoriesModal() {
        const modal = document.getElementById('categories-modal');
        if (modal) {
            modal.classList.add('hidden');
        }
    }

    function loadCategories() {
        toggleLoading(true);
        google.script.run
            .withSuccessHandler((res) => {
                toggleLoading(false);
                if (res && res.success !== false) {
                    const categories = res.data || [];
                    renderCategories(categories);
                } else {
                    showToast('Không thể tải danh mục', 'error');
                }
            })
            .withFailureHandler((error) => {
                toggleLoading(false);
                showToast('Lỗi: ' + (error.message || error.toString()), 'error');
            })
            .apiHandler('getTransactionCategories');
    }

    function renderCategories(categories) {
        const list = document.getElementById('categories-list');
        if (!list) return;

        if (categories.length === 0) {
            list.innerHTML = '<p class="text-gray-400 text-center py-8">Chưa có danh mục nào</p>';
            return;
        }

        // Group by type
        const incomeCategories = categories.filter(c => c.type === 'Income' && c.status === 'active');
        const expenseCategories = categories.filter(c => c.type === 'Expense' && c.status === 'active');

        let html = '';

        // Income categories
        if (incomeCategories.length > 0) {
            html += '<div class="mb-4"><h3 class="text-lg font-semibold text-green-700 mb-2">📥 Danh Mục Thu</h3>';
            incomeCategories.forEach(cat => {
                html += renderCategoryItem(cat);
            });
            html += '</div>';
        }

        // Expense categories
        if (expenseCategories.length > 0) {
            html += '<div><h3 class="text-lg font-semibold text-red-700 mb-2">📤 Danh Mục Chi</h3>';
            expenseCategories.forEach(cat => {
                html += renderCategoryItem(cat);
            });
            html += '</div>';
        }

        list.innerHTML = html;
    }

    function renderCategoryItem(cat) {
        return `
            <div class="flex items-center justify-between p-3 border border-gray-200 rounded-lg hover:bg-gray-50 mb-2">
                <div class="flex items-center gap-3">
                    <span class="text-2xl">${cat.icon || '📁'}</span>
                    <div>
                        <div class="font-medium text-gray-900">${cat.name}</div>
                        <div class="text-xs text-gray-500">${cat.description || ''}</div>
                    </div>
                </div>
                <div class="flex items-center gap-2">
                    <span class="w-8 h-8 rounded-full border-2 border-gray-300" style="background-color: ${cat.color}"></span>
                    <button onclick="showCategoryForm('${cat.id}')" class="p-2 text-blue-600 hover:bg-blue-50 rounded" title="Sửa">
                        <svg class="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z"></path>
                        </svg>
                    </button>
                    <button onclick="deleteCategory('${cat.id}')" class="p-2 text-red-600 hover:bg-red-50 rounded" title="Xóa">
                        <svg class="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path>
                        </svg>
                    </button>
                </div>
            </div>
        `;
    }

    function showCategoryForm(categoryId) {
        const modal = document.getElementById('category-form-modal');
        const title = document.getElementById('category-form-title');
        const form = document.getElementById('category-form');

        if (!modal || !form) return;

        // Move modal to body to escape any stacking context from parent modals
        if (modal.parentNode !== document.body) {
            document.body.appendChild(modal);
        }

        // Reset form
        form.reset();
        document.getElementById('category-id').value = '';
        document.getElementById('category-color').value = '#3b82f6';
        document.getElementById('category-color-text').value = '#3b82f6';

        // Sync color input changes
        document.getElementById('category-color').oninput = function() {
            document.getElementById('category-color-text').value = this.value;
        };
        document.getElementById('category-color-text').oninput = function() {
            document.getElementById('category-color').value = this.value;
        };

        if (categoryId) {
            // Edit mode
            title.textContent = 'Sửa Danh Mục';
            toggleLoading(true);

            // Find category from loaded list
            google.script.run
                .withSuccessHandler((res) => {
                    toggleLoading(false);
                    if (res && res.success !== false) {
                        const categories = res.data || [];
                        const cat = categories.find(c => c.id === categoryId);
                        if (cat) {
                            document.getElementById('category-id').value = cat.id;
                            document.getElementById('category-name').value = cat.name;
                            document.getElementById('category-type').value = cat.type;
                            document.getElementById('category-icon').value = cat.icon || '📁';
                            document.getElementById('category-color').value = cat.color || '#3b82f6';
                            document.getElementById('category-color-text').value = cat.color || '#3b82f6';
                            document.getElementById('category-description').value = cat.description || '';
                        }
                    }
                })
                .withFailureHandler((error) => {
                    toggleLoading(false);
                    showToast('Lỗi: ' + (error.message || error.toString()), 'error');
                })
                .apiHandler('getTransactionCategories');
        } else {
            // Add mode
            title.textContent = 'Thêm Danh Mục';
        }

        modal.classList.remove('hidden');
    }

    function closeCategoryForm() {
        const modal = document.getElementById('category-form-modal');
        if (modal) {
            modal.classList.add('hidden');
        }
    }

    function saveCategory(event) {
        event.preventDefault();

        const categoryId = document.getElementById('category-id').value;
        const categoryData = {
            id: categoryId || undefined,
            name: document.getElementById('category-name').value,
            type: document.getElementById('category-type').value,
            icon: document.getElementById('category-icon').value,
            color: document.getElementById('category-color').value,
            description: document.getElementById('category-description').value
        };

        toggleLoading(true);
        const apiAction = categoryId ? 'updateTransactionCategory' : 'createTransactionCategory';

        google.script.run
            .withSuccessHandler((res) => {
                toggleLoading(false);
                if (res && res.success !== false) {
                    showToast(categoryId ? 'Cập nhật danh mục thành công!' : 'Thêm danh mục thành công!', 'success');
                    closeCategoryForm();
                    loadCategories();
                } else {
                    showToast(res.message || 'Có lỗi xảy ra', 'error');
                }
            })
            .withFailureHandler((error) => {
                toggleLoading(false);
                showToast('Lỗi: ' + (error.message || error.toString()), 'error');
            })
            .apiHandler(apiAction, categoryData);
    }

    function deleteCategory(categoryId) {
        if (!categoryId) return;

        if (!confirm('Bạn có chắc chắn muốn xóa danh mục này?\n\nDanh mục sẽ bị ẩn và không thể khôi phục!')) {
            return;
        }

        toggleLoading(true);
        google.script.run
            .withSuccessHandler((res) => {
                toggleLoading(false);
                if (res && res.success !== false) {
                    showToast('Xóa danh mục thành công!', 'success');
                    loadCategories();
                } else {
                    showToast(res.message || 'Không thể xóa danh mục', 'error');
                }
            })
            .withFailureHandler((error) => {
                toggleLoading(false);
                showToast('Lỗi: ' + (error.message || error.toString()), 'error');
            })
            .apiHandler('deleteTransactionCategory', categoryId);
    }


    // ============================================
    // PURCHASES MANAGEMENT (NHẬP HÀNG)
    // ============================================

    /**
     * Load suppliers list
     */
    function loadSuppliers() {
        google.script.run
            .withSuccessHandler((res) => {
                if (res && res.success && res.data) {
                    suppliers = res.data || [];
                    populateSupplierDropdown();
                } else {
                    suppliers = [];
                }
            })
            .withFailureHandler((error) => {
                console.error('Error loading suppliers:', error);
                suppliers = [];
            })
            .apiHandler('getSuppliers', null);
    }

    /**
     * Populate supplier dropdown (filter select + searchable purchase dropdown)
     */
    function populateSupplierDropdown() {
        // Filter dropdown (plain select - unchanged)
        var filterSelect = document.getElementById('purchase-filter-supplier');
        if (filterSelect) {
            while (filterSelect.options.length > 1) filterSelect.remove(1);
            suppliers.forEach(function(s) {
                var opt = document.createElement('option');
                opt.value = s.id;
                opt.textContent = s.name + (s.phone ? ' - ' + s.phone : '');
                filterSelect.appendChild(opt);
            });
        }
        // Init searchable supplier for purchase form
        initPurchaseSupplierSearch();
    }

    /**
     * Searchable supplier dropdown for purchase form
     */
    function initPurchaseSupplierSearch() {
        var input = document.getElementById('purchase-supplier-search');
        var hidden = document.getElementById('purchase-supplier-select');
        var dropdown = document.getElementById('purchase-supplier-dropdown');
        if (!input || !hidden || !dropdown) return;

        // Remove old listeners by cloning
        var newInput = input.cloneNode(true);
        input.parentNode.replaceChild(newInput, input);
        input = newInput;

        function renderSupplierList(keyword) {
            var kw = (keyword || '').toLowerCase().trim();
            var filtered = suppliers.filter(function(s) {
                if (!kw) return true;
                var text = (s.name + ' ' + (s.phone || '') + ' ' + (s.id || '')).toLowerCase();
                return text.indexOf(kw) !== -1;
            });
            if (filtered.length === 0) {
                dropdown.innerHTML = '<div class="px-3 py-2 text-sm text-gray-400">Không tìm thấy NCC</div>';
            } else {
                dropdown.innerHTML = filtered.map(function(s) {
                    return '<div class="px-3 py-2 text-sm cursor-pointer hover:bg-blue-50 transition-colors" data-id="' + escapeHtml(s.id) + '" data-name="' + escapeHtml(s.name) + '" data-phone="' + escapeHtml(s.phone || '') + '">'
                        + '<span class="font-medium">' + escapeHtml(s.name) + '</span>'
                        + (s.phone ? ' <span class="text-gray-400">- ' + escapeHtml(s.phone) + '</span>' : '')
                        + '</div>';
                }).join('');
            }
            dropdown.classList.remove('hidden');
        }

        input.addEventListener('focus', function() { renderSupplierList(input.value); });
        input.addEventListener('input', function() {
            hidden.value = '';
            renderSupplierList(input.value);
        });

        dropdown.addEventListener('click', function(e) {
            var item = e.target.closest('[data-id]');
            if (!item) return;
            hidden.value = item.dataset.id;
            input.value = item.dataset.name + (item.dataset.phone ? ' - ' + item.dataset.phone : '');
            dropdown.classList.add('hidden');
        });

        // Close dropdown on outside click
        document.addEventListener('click', function(e) {
            if (!e.target.closest('#purchase-supplier-wrapper')) {
                dropdown.classList.add('hidden');
            }
        });
    }

    /**
     * Load purchases list
     */
    function loadPurchases(forceRefresh) {
        // Load suppliers first if not loaded
        if (suppliers.length === 0) {
            loadSuppliers();
        }

        const supplierId = document.getElementById('purchase-filter-supplier')?.value || '';
        const startDate = document.getElementById('purchase-filter-start-date')?.value || '';
        const endDate = document.getElementById('purchase-filter-end-date')?.value || '';
        const status = document.getElementById('purchase-filter-status')?.value || '';
        const search = document.getElementById('purchase-search')?.value || '';
        const hasActiveFilter = supplierId || startDate || endDate || status || search;

        // Cache-first (chỉ khi không có filter active)
        if (!forceRefresh && !hasActiveFilter) {
            var cached = LocalStore.getTTL('purchases');
            if (cached && Array.isArray(cached) && cached.length > 0) {
                purchasesData = cached;
                renderPurchasesList(purchasesData, true);
                loadPurchaseStats({}); // Stats vẫn load từ backend
                return;
            }
        }

        toggleLoading(true);
        google.script.run
            .withSuccessHandler((res) => {
                toggleLoading(false);
                console.log('loadPurchases: API response received:', res);
                console.log('loadPurchases: Response type:', typeof res, 'Is null:', res === null, 'Is undefined:', res === undefined);

                // Handle null/undefined response
                if (res === null || res === undefined) {
                    console.error('loadPurchases: Received null/undefined response from API');
                    purchasesData = [];
                    renderPurchasesList([]);
                    showToast('Lỗi: Không nhận được phản hồi từ server. Vui lòng kiểm tra logs hoặc thử lại.', 'error');
                    return;
                }

                if (res && res.success !== false) {
                    const data = res.data || res;
                    console.log('loadPurchases: Data extracted:', data, 'Type:', typeof data, 'IsArray:', Array.isArray(data));

                    if (Array.isArray(data)) {
                        purchasesData = data;
                        console.log('loadPurchases: Loaded ' + purchasesData.length + ' purchases before search filter');

                        // Convert date strings back to Date objects for display
                        purchasesData = purchasesData.map(p => ({
                            ...p,
                            date: p.date ? new Date(p.date) : new Date(),
                            receivedDate: p.receivedDate ? new Date(p.receivedDate) : null
                        }));

                        // Apply search filter if provided
                        if (search && search.trim() !== '') {
                            purchasesData = purchasesData.filter(p => {
                                const searchLower = search.toLowerCase();
                                return (p.id && p.id.toLowerCase().includes(searchLower)) ||
                                    (p.supplier && p.supplier.name && p.supplier.name.toLowerCase().includes(searchLower));
                            });
                            console.log('loadPurchases: After search filter: ' + purchasesData.length);
                        }

                        // Cache khi không có filter
                        if (!hasActiveFilter && purchasesData.length > 0) {
                            LocalStore.setTTL('purchases', purchasesData, 600);
                        }
                        renderPurchasesList(purchasesData, true);
                    } else {
                        console.warn('loadPurchases: Data is not an array:', data);
                        purchasesData = [];
                        renderPurchasesList([]);
                        showToast('Dữ liệu nhập hàng không hợp lệ', 'warning');
                    }
                } else {
                    console.warn('loadPurchases: Response indicates failure:', res);
                    purchasesData = [];
                    renderPurchasesList([]);
                    const errorMsg = res && res.message ? res.message : 'Không thể tải danh sách nhập hàng';
                    showToast(errorMsg, 'error');
                }
            })
            .withFailureHandler((error) => {
                toggleLoading(false);
                console.error('loadPurchases: API call failed:', error);
                purchasesData = [];
                renderPurchasesList([]);
                showToast('Lỗi khi tải dữ liệu nhập hàng: ' + (error.message || error.toString()), 'error');
            })
            .apiHandler('getPurchaseHistory', { supplierId, status, startDate, endDate, search: search });

        // Also load stats
        loadPurchaseStats({ supplierId, status, startDate, endDate });
    }

    // ===== PURCHASE STATS & CHARTS =====
    function loadPurchaseStats(filters = {}) {
        google.script.run
            .withSuccessHandler((res) => {
                if (res && res.success !== false) {
                    const stats = res.data || res;

                    // Update dashboard cards
                    const totalEl = document.getElementById('purchase-stat-total');
                    const paidEl = document.getElementById('purchase-stat-paid');
                    const debtEl = document.getElementById('purchase-stat-debt');
                    const countEl = document.getElementById('purchase-stat-count');
                    if (totalEl) totalEl.textContent = formatMoney(stats.totalAmount || 0);
                    if (paidEl) paidEl.textContent = formatMoney(stats.totalPaid || 0);
                    if (debtEl) debtEl.textContent = formatMoney(stats.totalDebt || 0);
                    if (countEl) countEl.textContent = stats.purchaseCount || 0;

                    // Render payment method breakdown
                    renderPurchasePaymentBreakdown(stats.paymentMethodBreakdown || {});

                    // Render supplier stats table
                    renderSupplierStatsTable(stats.supplierBreakdown || {});

                }
            })
            .withFailureHandler((error) => {
                console.error('Failed to load purchase stats:', error);
            })
            .apiHandler('getPurchaseStats', filters);
    }

    function renderPurchasePaymentBreakdown(breakdown) {
        const container = document.getElementById('purchase-payment-method-breakdown');
        if (!container) return;

        const methods = Object.keys(breakdown);
        if (methods.length === 0) {
            container.innerHTML = '<div class="text-center text-gray-500 py-4 col-span-full">Không có dữ liệu</div>';
            return;
        }

        const icons = { 'Tiền mặt': '💵', 'Chuyển khoản': '🏦', 'Ví điện tử': '📱', 'Thẻ tín dụng': '💳', 'Thẻ': '💳', 'Khác': '💰' };
        const colors = {
            'Tiền mặt': { bg: 'bg-green-50', border: 'border-green-200', text: 'text-green-700', amount: 'text-green-900' },
            'Chuyển khoản': { bg: 'bg-blue-50', border: 'border-blue-200', text: 'text-blue-700', amount: 'text-blue-900' },
            'Ví điện tử': { bg: 'bg-purple-50', border: 'border-purple-200', text: 'text-purple-700', amount: 'text-purple-900' },
            'Thẻ tín dụng': { bg: 'bg-orange-50', border: 'border-orange-200', text: 'text-orange-700', amount: 'text-orange-900' }
        };
        const defaultColor = { bg: 'bg-gray-50', border: 'border-gray-200', text: 'text-gray-700', amount: 'text-gray-900' };

        let html = '';
        methods.forEach(method => {
            const data = breakdown[method];
            const icon = icons[method] || '💰';
            const color = colors[method] || defaultColor;
            html += `
                <div class="${color.bg} rounded-xl p-4 border ${color.border}">
                    <div class="flex items-center gap-2 mb-2">
                        <span class="text-xl">${icon}</span>
                        <span class="text-sm font-medium ${color.text}">${escapeHtml(method)}</span>
                    </div>
                    <div class="text-xl font-bold ${color.amount}">${formatMoney(data.paid || 0)}</div>
                    <div class="flex justify-between text-xs mt-2">
                        <span class="text-gray-500">${data.count || 0} phiếu</span>
                        <span class="text-red-500">Nợ: ${formatMoney(data.debt || 0)}</span>
                    </div>
                </div>
            `;
        });
        container.innerHTML = html;
    }

    function renderSupplierStatsTable(supplierBreakdown) {
        const tbody = document.getElementById('purchase-supplier-stats-body');
        if (!tbody) return;

        const suppliers = Object.keys(supplierBreakdown);
        if (suppliers.length === 0) {
            tbody.innerHTML = '<tr><td colspan="6" class="text-center py-4 text-gray-400">Không có dữ liệu</td></tr>';
            return;
        }

        // Sort by total descending
        suppliers.sort((a, b) => (supplierBreakdown[b].total || 0) - (supplierBreakdown[a].total || 0));

        let html = '';
        suppliers.forEach(name => {
            const data = supplierBreakdown[name];
            const debtAmount = data.debt || 0;
            const sid = data.supplierId || '';
            html += `
                <tr class="hover:bg-gray-50 border-b border-gray-100">
                    <td class="py-3 px-4 font-medium">${escapeHtml(name)}</td>
                    <td class="py-3 px-4 text-center">${data.count || 0}</td>
                    <td class="py-3 px-4 text-right font-medium">${formatMoney(data.total || 0)}</td>
                    <td class="py-3 px-4 text-right text-green-600">${formatMoney(data.paid || 0)}</td>
                    <td class="py-3 px-4 text-right ${debtAmount > 0 ? 'text-red-600 font-medium' : 'text-gray-500'}">${formatMoney(debtAmount)}</td>
                    <td class="py-3 px-4 text-center">
                        ${sid ? `<button onclick="paySupplierDebt('${sid}', ${debtAmount}, '${escapeHtml(name)}')" class="px-3 py-1 ${debtAmount > 0 ? 'bg-green-600 hover:bg-green-700' : 'bg-blue-600 hover:bg-blue-700'} text-white text-xs rounded-lg">${debtAmount > 0 ? 'Thanh toán' : 'Ứng trước'}</button>` : '<span class="text-gray-400 text-xs">-</span>'}
                    </td>
                </tr>
            `;
        });
        tbody.innerHTML = html;
    }

    // ===== SUPPLIER DETAIL MODAL =====
    var currentSupplierDetailId = null;

    function viewSupplierDetail(supplierId) {
        var supplier = suppliersData.find(function(s) { return s.id === supplierId; });
        if (!supplier) {
            showToast('Không tìm thấy nhà cung cấp!', 'error');
            return;
        }

        currentSupplierDetailId = supplierId;

        var modal = document.getElementById('supplier-detail-modal');
        var nameEl = document.getElementById('supplier-detail-name');
        var content = document.getElementById('supplier-detail-content');
        var purchaseBody = document.getElementById('supplier-purchase-history-body');
        var paymentBody = document.getElementById('supplier-payment-history-body');

        if (nameEl) nameEl.textContent = supplier.name;

        // Reset loading states
        if (purchaseBody) purchaseBody.innerHTML = '<tr><td colspan="7" class="text-center py-8 text-gray-500">Chuyển sang tab để xem...</td></tr>';
        if (paymentBody) paymentBody.innerHTML = '<tr><td colspan="6" class="text-center py-8 text-gray-500">Chuyển sang tab để xem...</td></tr>';
        var purchaseMobile = document.getElementById('supplier-purchase-mobile');
        var paymentMobile = document.getElementById('supplier-payment-mobile');
        if (purchaseMobile) purchaseMobile.innerHTML = '<p class="text-center py-8 text-gray-500">Chuyển sang tab để xem...</p>';
        if (paymentMobile) paymentMobile.innerHTML = '<p class="text-center py-8 text-gray-500">Chuyển sang tab để xem...</p>';

        // Reset stats
        ['sup-stat-purchase-count', 'sup-stat-total-value', 'sup-stat-total-paid', 'sup-stat-total-debt'].forEach(function(id) {
            var el = document.getElementById(id);
            if (el) el.textContent = id === 'sup-stat-purchase-count' ? '0' : '0 ₫';
        });

        // Build info tab content
        var debtClass = supplier.debt > 0 ? 'text-red-600 font-bold' : 'text-green-600';
        var statusColor = supplier.status === 'Active' ? 'bg-green-100 text-green-800' : 'bg-gray-100 text-gray-800';
        var statusText = supplier.status === 'Active' ? 'Hoạt động' : 'Ngừng hoạt động';

        content.innerHTML =
            '<div class="grid grid-cols-1 sm:grid-cols-2 gap-4">' +
                '<div>' +
                    '<p class="text-sm text-gray-500 mb-1">Mã NCC</p>' +
                    '<p class="font-bold text-lg">' + escapeHtml(supplier.id) + '</p>' +
                '</div>' +
                '<div>' +
                    '<p class="text-sm text-gray-500 mb-1">Tên NCC</p>' +
                    '<p class="font-medium text-lg">' + escapeHtml(supplier.name) + '</p>' +
                '</div>' +
                '<div>' +
                    '<p class="text-sm text-gray-500 mb-1">Số Điện Thoại</p>' +
                    '<p>' + escapeHtml(supplier.phone || 'Chưa có') + '</p>' +
                '</div>' +
                '<div>' +
                    '<p class="text-sm text-gray-500 mb-1">Email</p>' +
                    '<p class="break-all">' + escapeHtml(supplier.email || 'Chưa có') + '</p>' +
                '</div>' +
                '<div class="sm:col-span-2">' +
                    '<p class="text-sm text-gray-500 mb-1">Địa Chỉ</p>' +
                    '<p>' + escapeHtml(supplier.address || 'Chưa có') + '</p>' +
                '</div>' +
                '<div>' +
                    '<p class="text-sm text-gray-500 mb-1">Trạng Thái</p>' +
                    '<span class="px-2 py-1 rounded-full text-xs font-medium ' + statusColor + '">' + statusText + '</span>' +
                '</div>' +
                '<div>' +
                    '<p class="text-sm text-gray-500 mb-1">Công Nợ</p>' +
                    '<p class="supplier-debt-display font-bold text-lg ' + debtClass + '">' + formatMoney(supplier.debt || 0) + '</p>' +
                '</div>' +
                (supplier.notes ? '<div class="sm:col-span-2"><p class="text-sm text-gray-500 mb-1">Ghi Chú</p><p class="text-sm bg-gray-50 p-2 rounded">' + escapeHtml(supplier.notes) + '</p></div>' : '') +
            '</div>' +
            '<div class="supplier-debt-warning mt-4 p-3 ' + (supplier.debt > 0 ? 'bg-yellow-50 border border-yellow-200' : 'bg-blue-50 border border-blue-200') + ' rounded-lg">' +
                '<p class="text-sm ' + (supplier.debt > 0 ? 'text-yellow-700' : 'text-blue-700') + ' mb-2">' + (supplier.debt > 0 ? 'NCC đang có công nợ' : 'NCC không có công nợ') + '</p>' +
                '<button onclick="closeSupplierDetailModal(); paySupplierDebt(\'' + escapeHtml(supplier.id) + '\', ' + (supplier.debt || 0) + ', \'' + escapeHtml(supplier.name) + '\')" ' +
                'class="px-4 py-2 ' + (supplier.debt > 0 ? 'bg-green-600 hover:bg-green-700' : 'bg-blue-600 hover:bg-blue-700') + ' text-white rounded-lg text-sm">' + (supplier.debt > 0 ? 'Thanh toán công nợ' : 'Ứng trước') + '</button>' +
            '</div>' +
            '<div class="mt-4 flex gap-2">' +
                '<button onclick="closeSupplierDetailModal(); editSupplier(\'' + escapeHtml(supplier.id) + '\')" class="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 text-sm">✏️ Chỉnh sửa</button>' +
            '</div>';

        // Reset to info tab
        switchSupplierDetailTab('info');
        modal.classList.remove('hidden');

        // Auto-sync: fetch real debt from purchase orders to correct stale data
        google.script.run
            .withSuccessHandler(function(res) {
                if (res && res.success && res.data && res.data.stats) {
                    var realDebt = res.data.stats.totalDebt || 0;
                    // Update suppliersData cache
                    var idx = suppliersData.findIndex(function(s) { return s.id === supplierId; });
                    if (idx >= 0) suppliersData[idx].debt = realDebt;
                    // Update debt display in info tab
                    var debtEls = content.querySelectorAll('.supplier-debt-display');
                    if (debtEls.length > 0) {
                        debtEls[0].className = 'supplier-debt-display font-bold text-lg ' + (realDebt > 0 ? 'text-red-600' : 'text-green-600');
                        debtEls[0].textContent = formatMoney(realDebt);
                    }
                    // Show/hide debt warning
                    var debtWarning = content.querySelector('.supplier-debt-warning');
                    if (debtWarning) {
                        debtWarning.style.display = realDebt > 0 ? 'block' : 'none';
                        if (realDebt > 0) {
                            var payBtn = debtWarning.querySelector('button');
                            if (payBtn) {
                                payBtn.setAttribute('onclick', "closeSupplierDetailModal(); paySupplierDebt('" + escapeHtml(supplier.id) + "', " + realDebt + ", '" + escapeHtml(supplier.name) + "')");
                            }
                        }
                    }
                    // Update stats too
                    var statDebt = document.getElementById('sup-stat-total-debt');
                    if (statDebt) statDebt.textContent = formatMoney(realDebt);
                }
            })
            .withFailureHandler(function() {})
            .apiHandler('getSupplierPurchaseHistory', { supplierId: supplierId });
    }

    function closeSupplierDetailModal() {
        document.getElementById('supplier-detail-modal').classList.add('hidden');
        currentSupplierDetailId = null;
    }

    function switchSupplierDetailTab(tab) {
        // Update tab buttons
        document.querySelectorAll('.supplier-tab-btn').forEach(function(btn) {
            btn.classList.remove('border-orange-500', 'text-orange-600');
            btn.classList.add('border-transparent', 'text-gray-500');
        });
        var activeBtn = document.getElementById('sup-tab-' + tab);
        if (activeBtn) {
            activeBtn.classList.remove('border-transparent', 'text-gray-500');
            activeBtn.classList.add('border-orange-500', 'text-orange-600');
        }

        // Toggle content visibility
        document.getElementById('sup-tab-content-info').classList.toggle('hidden', tab !== 'info');
        document.getElementById('sup-tab-content-purchases').classList.toggle('hidden', tab !== 'purchases');
        document.getElementById('sup-tab-content-payments').classList.toggle('hidden', tab !== 'payments');

        // Load data when switching to history tabs
        if (tab === 'purchases' && currentSupplierDetailId) {
            loadSupplierPurchaseHistory(currentSupplierDetailId);
        }
        if (tab === 'payments' && currentSupplierDetailId) {
            loadSupplierPaymentHistory(currentSupplierDetailId);
        }
    }

    function loadSupplierPurchaseHistory(supplierId) {
        google.script.run
            .withSuccessHandler(function(res) {
                var purchaseBody = document.getElementById('supplier-purchase-history-body');
                var purchaseMobile = document.getElementById('supplier-purchase-mobile');

                if (res && res.success && res.data) {
                    var purchases = res.data.purchases || [];
                    var stats = res.data.stats || {};

                    // Update stats
                    var statCount = document.getElementById('sup-stat-purchase-count');
                    var statValue = document.getElementById('sup-stat-total-value');
                    var statPaid = document.getElementById('sup-stat-total-paid');
                    var statDebt = document.getElementById('sup-stat-total-debt');
                    if (statCount) statCount.textContent = (stats.totalPurchases || 0).toLocaleString();
                    if (statValue) statValue.textContent = formatMoney(stats.totalValue || 0);
                    if (statPaid) statPaid.textContent = formatMoney(stats.totalPaid || 0);
                    if (statDebt) statDebt.textContent = formatMoney(stats.totalDebt || 0);

                    if (purchases.length === 0) {
                        if (purchaseBody) purchaseBody.innerHTML = '<tr><td colspan="7" class="text-center py-8 text-gray-500">Chưa có đơn nhập hàng nào</td></tr>';
                        if (purchaseMobile) purchaseMobile.innerHTML = '<p class="text-center py-8 text-gray-500">Chưa có đơn nhập hàng nào</p>';
                    } else {
                        // Desktop table
                        if (purchaseBody) {
                            purchaseBody.innerHTML = purchases.map(function(p) {
                                var debt = p.debt || 0;
                                var debtClass = debt > 0 ? 'text-red-600 font-medium' : 'text-gray-500';
                                var statusClass = getPurchaseStatusClass(p.status);
                                var dateStr = '';
                                try {
                                    if (p.date) dateStr = new Date(p.date).toLocaleDateString('vi-VN');
                                } catch (e) { dateStr = p.date || ''; }

                                return '<tr class="hover:bg-gray-50">' +
                                    '<td class="py-3 px-4 font-medium">' + (p.id || '') + '</td>' +
                                    '<td class="py-3 px-4">' + dateStr + '</td>' +
                                    '<td class="py-3 px-4 text-right font-medium">' + formatMoney(p.total || 0) + '</td>' +
                                    '<td class="py-3 px-4 text-right text-green-600">' + formatMoney(p.paid || 0) + '</td>' +
                                    '<td class="py-3 px-4 text-right ' + debtClass + '">' + formatMoney(debt) + '</td>' +
                                    '<td class="py-3 px-4 text-center"><span class="px-2 py-1 rounded text-xs ' + statusClass + '">' + (p.status || 'N/A') + '</span></td>' +
                                    '<td class="py-3 px-4 text-sm text-gray-600 max-w-xs truncate" title="' + escapeHtml(p.notes || '') + '">' + escapeHtml(p.notes || '-') + '</td>' +
                                    '</tr>';
                            }).join('');
                        }
                        // Mobile cards
                        if (purchaseMobile) {
                            purchaseMobile.innerHTML = purchases.map(function(p) {
                                var debt = p.debt || 0;
                                var statusClass = getPurchaseStatusClass(p.status);
                                var dateStr = '';
                                try {
                                    if (p.date) dateStr = new Date(p.date).toLocaleDateString('vi-VN');
                                } catch (e) { dateStr = p.date || ''; }

                                return '<div class="mobile-card">' +
                                    '<div class="flex justify-between items-start mb-2">' +
                                        '<span class="font-medium text-sm">' + (p.id || '') + '</span>' +
                                        '<span class="px-2 py-1 rounded text-xs ' + statusClass + '">' + (p.status || 'N/A') + '</span>' +
                                    '</div>' +
                                    '<p class="text-xs text-gray-500 mb-2">' + dateStr + '</p>' +
                                    '<div class="grid grid-cols-3 gap-2 text-sm">' +
                                        '<div><p class="text-gray-500 text-xs">Tổng tiền</p><p class="font-medium">' + formatMoney(p.total || 0) + '</p></div>' +
                                        '<div><p class="text-gray-500 text-xs">Đã TT</p><p class="text-green-600">' + formatMoney(p.paid || 0) + '</p></div>' +
                                        '<div><p class="text-gray-500 text-xs">Còn nợ</p><p class="' + (debt > 0 ? 'text-red-600 font-medium' : 'text-gray-500') + '">' + formatMoney(debt) + '</p></div>' +
                                    '</div>' +
                                    (p.notes ? '<p class="text-xs text-gray-500 mt-2 truncate" title="' + escapeHtml(p.notes) + '">' + escapeHtml(p.notes) + '</p>' : '') +
                                '</div>';
                            }).join('');
                        }
                    }
                } else {
                    if (purchaseBody) purchaseBody.innerHTML = '<tr><td colspan="7" class="text-center py-8 text-red-500">Không thể tải lịch sử nhập hàng</td></tr>';
                    if (purchaseMobile) purchaseMobile.innerHTML = '<p class="text-center py-8 text-red-500">Không thể tải lịch sử nhập hàng</p>';
                }
            })
            .withFailureHandler(function(error) {
                var purchaseBody = document.getElementById('supplier-purchase-history-body');
                var purchaseMobile = document.getElementById('supplier-purchase-mobile');
                if (purchaseBody) purchaseBody.innerHTML = '<tr><td colspan="7" class="text-center py-8 text-red-500">Lỗi: ' + (error.message || error) + '</td></tr>';
                if (purchaseMobile) purchaseMobile.innerHTML = '<p class="text-center py-8 text-red-500">Lỗi: ' + (error.message || error) + '</p>';
            })
            .apiHandler('getSupplierPurchaseHistory', { supplierId: supplierId });
    }

    function loadSupplierPaymentHistory(supplierId) {
        google.script.run
            .withSuccessHandler(function(res) {
                var paymentBody = document.getElementById('supplier-payment-history-body');
                var paymentMobile = document.getElementById('supplier-payment-mobile');

                if (res && res.success !== false && res.data) {
                    var payments = res.data.payments || [];

                    if (payments.length === 0) {
                        if (paymentBody) paymentBody.innerHTML = '<tr><td colspan="6" class="text-center py-8 text-gray-500">Chưa có lịch sử thanh toán</td></tr>';
                        if (paymentMobile) paymentMobile.innerHTML = '<p class="text-center py-8 text-gray-500">Chưa có lịch sử thanh toán</p>';
                    } else {
                        // Desktop table
                        if (paymentBody) {
                            paymentBody.innerHTML = payments.map(function(p) {
                                var dateStr = '';
                                try {
                                    if (p.date) {
                                        var d = new Date(p.date);
                                        dateStr = d.toLocaleString('vi-VN', {
                                            day: '2-digit', month: '2-digit', year: 'numeric',
                                            hour: '2-digit', minute: '2-digit'
                                        });
                                    }
                                } catch (e) { dateStr = p.date || ''; }

                                var methodIcon = getPaymentMethodIcon(p.paymentMethod);
                                var categoryLabel = p.category === 'Purchase' ? 'Nhập hàng' : 'TT Công nợ';
                                var categoryClass = p.category === 'Purchase' ? 'bg-blue-100 text-blue-700' : 'bg-orange-100 text-orange-700';

                                return '<tr class="hover:bg-gray-50">' +
                                    '<td class="py-3 px-4 text-sm">' + dateStr + '</td>' +
                                    '<td class="py-3 px-4 text-right font-bold text-green-600">' + formatMoney(p.amount || 0) + '</td>' +
                                    '<td class="py-3 px-4 text-center"><span class="inline-flex items-center gap-1 px-2 py-1 bg-gray-100 rounded text-xs">' + methodIcon + ' ' + (p.paymentMethod || 'Tiền mặt') + '</span></td>' +
                                    '<td class="py-3 px-4 text-center"><span class="px-2 py-1 rounded text-xs ' + categoryClass + '">' + categoryLabel + '</span></td>' +
                                    '<td class="py-3 px-4 text-sm text-gray-600 max-w-xs truncate" title="' + escapeHtml(p.note || '') + '">' + escapeHtml(p.note || '-') + '</td>' +
                                    '<td class="py-3 px-4 text-sm text-gray-500">' + escapeHtml(p.createdBy || '-') + '</td>' +
                                    '</tr>';
                            }).join('');
                        }
                        // Mobile cards
                        if (paymentMobile) {
                            paymentMobile.innerHTML = payments.map(function(p) {
                                var dateStr = '';
                                try {
                                    if (p.date) {
                                        var d = new Date(p.date);
                                        dateStr = d.toLocaleString('vi-VN', {
                                            day: '2-digit', month: '2-digit', year: 'numeric',
                                            hour: '2-digit', minute: '2-digit'
                                        });
                                    }
                                } catch (e) { dateStr = p.date || ''; }

                                var methodIcon = getPaymentMethodIcon(p.paymentMethod);
                                var categoryLabel = p.category === 'Purchase' ? 'Nhập hàng' : 'TT Công nợ';
                                var categoryClass = p.category === 'Purchase' ? 'bg-blue-100 text-blue-700' : 'bg-orange-100 text-orange-700';

                                return '<div class="mobile-card">' +
                                    '<div class="flex justify-between items-start mb-2">' +
                                        '<p class="text-xs text-gray-500">' + dateStr + '</p>' +
                                        '<span class="font-bold text-green-600">' + formatMoney(p.amount || 0) + '</span>' +
                                    '</div>' +
                                    '<div class="flex flex-wrap gap-2 mb-2">' +
                                        '<span class="inline-flex items-center gap-1 px-2 py-1 bg-gray-100 rounded text-xs">' + methodIcon + ' ' + (p.paymentMethod || 'Tiền mặt') + '</span>' +
                                        '<span class="px-2 py-1 rounded text-xs ' + categoryClass + '">' + categoryLabel + '</span>' +
                                    '</div>' +
                                    (p.note ? '<p class="text-xs text-gray-600 truncate" title="' + escapeHtml(p.note) + '">' + escapeHtml(p.note) + '</p>' : '') +
                                    (p.createdBy ? '<p class="text-xs text-gray-400 mt-1">' + escapeHtml(p.createdBy) + '</p>' : '') +
                                '</div>';
                            }).join('');
                        }
                    }
                } else {
                    if (paymentBody) paymentBody.innerHTML = '<tr><td colspan="6" class="text-center py-8 text-red-500">Không thể tải lịch sử thanh toán</td></tr>';
                    if (paymentMobile) paymentMobile.innerHTML = '<p class="text-center py-8 text-red-500">Không thể tải lịch sử thanh toán</p>';
                }
            })
            .withFailureHandler(function(error) {
                var paymentBody = document.getElementById('supplier-payment-history-body');
                var paymentMobile = document.getElementById('supplier-payment-mobile');
                if (paymentBody) paymentBody.innerHTML = '<tr><td colspan="6" class="text-center py-8 text-red-500">Lỗi: ' + (error.message || error) + '</td></tr>';
                if (paymentMobile) paymentMobile.innerHTML = '<p class="text-center py-8 text-red-500">Lỗi: ' + (error.message || error) + '</p>';
            })
            .apiHandler('getSupplierPaymentHistory', { supplierId: supplierId });
    }

    function getPurchaseStatusClass(status) {
        var classes = {
            'Completed': 'bg-green-100 text-green-800',
            'Pending': 'bg-yellow-100 text-yellow-800',
            'Cancelled': 'bg-red-100 text-red-800'
        };
        return classes[status] || 'bg-gray-100 text-gray-800';
    }

    function paySupplierDebt(supplierId, maxAmount, supplierName) {
        var isAdvance = maxAmount <= 0;
        document.getElementById('supplier-debt-id').value = supplierId;
        document.getElementById('supplier-debt-max').value = maxAmount;
        document.getElementById('supplier-debt-name').textContent = supplierName;
        document.getElementById('supplier-debt-current').textContent = isAdvance ? '0 đ' : formatMoney(maxAmount);
        document.getElementById('supplier-debt-amount').value = isAdvance ? '' : maxAmount;
        document.getElementById('supplier-debt-amount').max = isAdvance ? '' : maxAmount;
        document.getElementById('supplier-debt-amount').placeholder = isAdvance ? 'Nhập số tiền ứng trước...' : '0';
        document.getElementById('supplier-debt-payment-method').value = 'Tiền mặt';
        // Update modal title for advance payment
        var titleEl = document.querySelector('#supplier-debt-modal .modal-header h3');
        if (titleEl) titleEl.textContent = isAdvance ? 'Ứng Trước Cho NCC' : 'Thanh Toán Công Nợ NCC';
        document.getElementById('supplier-debt-modal').classList.remove('hidden');
    }

    function closeSupplierDebtModal() {
        document.getElementById('supplier-debt-modal').classList.add('hidden');
    }

    function setSupplierDebtAmount(ratio) {
        const max = parseFloat(document.getElementById('supplier-debt-max').value) || 0;
        document.getElementById('supplier-debt-amount').value = Math.round(max * ratio);
    }

    function confirmPaySupplierDebt() {
        const supplierId = document.getElementById('supplier-debt-id').value;
        const maxAmount = parseFloat(document.getElementById('supplier-debt-max').value) || 0;
        const amount = parseFloat(document.getElementById('supplier-debt-amount').value) || 0;
        const paymentMethod = document.getElementById('supplier-debt-payment-method').value;
        const supplierName = document.getElementById('supplier-debt-name').textContent;

        if (amount <= 0) {
            showToast('Số tiền thanh toán phải lớn hơn 0!', 'warning');
            return;
        }
        if (maxAmount > 0 && amount > maxAmount) {
            showToast('Số tiền thanh toán không được vượt quá công nợ!', 'warning');
            return;
        }

        var isAdvance = maxAmount <= 0;
        var confirmTitle = isAdvance ? 'Xác nhận ứng trước' : 'Xác nhận thanh toán';
        var confirmMsg = isAdvance
            ? `Ứng trước ${formatMoney(amount)} cho NCC "${supplierName}" bằng ${paymentMethod}?`
            : `Thanh toán ${formatMoney(amount)} cho NCC "${supplierName}" bằng ${paymentMethod}?`;

        showConfirmModal(
            confirmTitle,
            confirmMsg,
            isAdvance ? 'Ứng trước' : 'Thanh toán',
            () => {
                closeSupplierDebtModal();
                toggleLoading(true);
                google.script.run
                    .withSuccessHandler((res) => {
                        toggleLoading(false);
                        if (res && res.success) {
                            showToast(res.message || 'Thanh toán công nợ NCC thành công!', 'success');
                            localStorage.removeItem('TTL_purchases');
                            localStorage.removeItem('TTL_suppliers');
                            loadPurchases();
                            loadPurchaseStats();
                            loadSuppliers();
                            if (typeof loadSuppliersManage === 'function') loadSuppliersManage();
                        } else {
                            showToast(res.message || 'Không thể thanh toán công nợ', 'error');
                        }
                    })
                    .withFailureHandler((error) => {
                        toggleLoading(false);
                        showToast(error.message || 'Không thể thanh toán công nợ', 'error');
                    })
                    .apiHandler('paySupplierDebt', { supplierId, amount, paymentMethod, isAdvance: isAdvance });
            }
        );
    }

    // ===== PURCHASE PAYMENT MODAL =====
    function showPurchasePaymentModal(purchaseId, debtAmount, supplierName, supplierId) {
        document.getElementById('pp-id').value = purchaseId;
        document.getElementById('pp-max').value = debtAmount;
        document.getElementById('pp-supplier-id').value = supplierId;
        document.getElementById('pp-purchase-id').textContent = purchaseId;
        document.getElementById('pp-supplier-name').textContent = supplierName;
        document.getElementById('pp-debt-amount').textContent = formatMoney(debtAmount);
        document.getElementById('pp-amount').value = debtAmount;
        document.getElementById('pp-amount').max = debtAmount;
        document.getElementById('pp-payment-method').value = 'Tiền mặt';
        document.getElementById('purchase-payment-modal').classList.remove('hidden');
    }

    function closePurchasePaymentModal() {
        document.getElementById('purchase-payment-modal').classList.add('hidden');
    }

    function setPurchasePayAmount(ratio) {
        const max = parseFloat(document.getElementById('pp-max').value) || 0;
        document.getElementById('pp-amount').value = Math.round(max * ratio);
    }

    function confirmPurchasePayment() {
        const purchaseId = document.getElementById('pp-id').value;
        const maxAmount = parseFloat(document.getElementById('pp-max').value) || 0;
        const amount = parseFloat(document.getElementById('pp-amount').value) || 0;
        const paymentMethod = document.getElementById('pp-payment-method').value;
        const supplierName = document.getElementById('pp-supplier-name').textContent;

        if (amount <= 0) {
            showToast('Số tiền thanh toán phải lớn hơn 0!', 'warning');
            return;
        }
        if (amount > maxAmount) {
            showToast('Số tiền thanh toán không được vượt quá công nợ!', 'warning');
            return;
        }

        const newStatus = amount >= maxAmount ? 'Completed' : 'Pending';

        showConfirmModal(
            'Xác nhận thanh toán',
            `Thanh toán ${formatMoney(amount)} cho phiếu nhập ${purchaseId} (${supplierName}) bằng ${paymentMethod}?`,
            'Thanh toán',
            () => {
                closePurchasePaymentModal();
                toggleLoading(true);
                google.script.run
                    .withSuccessHandler((res) => {
                        toggleLoading(false);
                        if (res && res.success) {
                            showToast(res.message || 'Thanh toán phiếu nhập thành công!', 'success');
                            localStorage.removeItem('TTL_purchases');
                            localStorage.removeItem('TTL_suppliers');
                            loadPurchases();
                            loadPurchaseStats();
                            loadSuppliers();
                            if (typeof loadSuppliersManage === 'function') loadSuppliersManage();
                        } else {
                            showToast(res.message || 'Không thể thanh toán', 'error');
                        }
                    })
                    .withFailureHandler((error) => {
                        toggleLoading(false);
                        showToast(error.message || 'Lỗi thanh toán', 'error');
                    })
                    .apiHandler('updatePurchaseStatus', { purchaseId, status: newStatus, paidAmount: amount, paymentMethod });
            }
        );
    }

    function applyPurchaseFilters() {
        loadPurchases();
    }

    function resetPurchaseFilters() {
        const ids = ['purchase-filter-start-date', 'purchase-filter-end-date', 'purchase-filter-supplier',
                     'purchase-filter-status', 'purchase-filter-payment-method', 'purchase-search'];
        ids.forEach(id => { const el = document.getElementById(id); if (el) el.value = ''; });
        loadPurchases();
    }

    function recalculateSupplierDebts() {
        showConfirmModal(
            'Đồng bộ công nợ NCC',
            'Tính lại công nợ tất cả NCC dựa trên dữ liệu phiếu nhập thực tế. Bạn có chắc chắn?',
            'Đồng bộ',
            () => {
                toggleLoading(true);
                google.script.run
                    .withSuccessHandler((res) => {
                        toggleLoading(false);
                        if (res && res.success) {
                            showToast(res.message || 'Đồng bộ công nợ NCC thành công!', 'success');
                            loadPurchaseStats();
                        } else {
                            showToast(res.message || 'Lỗi đồng bộ', 'error');
                        }
                    })
                    .withFailureHandler((error) => {
                        toggleLoading(false);
                        showToast(error.message || 'Lỗi đồng bộ', 'error');
                    })
                    .apiHandler('recalculateSupplierDebts', {});
            }
        );
    }

    /**
     * Render purchases list
     */
    function renderPurchasesList(purchases, resetPage = false) {
        const tbody = document.getElementById('purchases-list-body');
        if (!tbody) return;

        // Save filtered purchases for pagination
        filteredPurchases = purchases || [];

        // Reset to page 1 if requested
        if (resetPage) {
            purchasesCurrentPage = 1;
        }

        // Calculate pagination
        const totalItems = filteredPurchases.length;
        const totalPages = Math.ceil(totalItems / purchasesItemsPerPage);
        const startIndex = (purchasesCurrentPage - 1) * purchasesItemsPerPage;
        const endIndex = startIndex + purchasesItemsPerPage;
        const dataToRender = filteredPurchases.slice(startIndex, endIndex);

        if (!dataToRender || dataToRender.length === 0) {
            tbody.innerHTML = '<tr><td colspan="8" class="text-center py-8 text-gray-400">Không có dữ liệu</td></tr>';
            return;
        }

        tbody.innerHTML = dataToRender.map(p => {
            const statusColors = {
                'Completed': 'bg-green-100 text-green-800',
                'Pending': 'bg-yellow-100 text-yellow-800',
                'Cancelled': 'bg-red-100 text-red-800'
            };
            const statusColor = statusColors[p.status] || 'bg-gray-100 text-gray-800';
            const date = p.date ? new Date(p.date).toLocaleDateString('vi-VN') : '';
            const supplierName = p.supplier ? p.supplier.name : (p.supplierId || 'N/A');

            return `
                <tr class="hover:bg-gray-50 border-b border-gray-100" style="cursor: pointer;" onclick="if(event.target.tagName !== 'BUTTON' && !event.target.closest('button')) viewPurchaseDetail('${p.id}')">
                    <td class="px-4 py-3 font-medium">${p.id}</td>
                    <td class="px-4 py-3">${date}</td>
                    <td class="px-4 py-3">${supplierName}</td>
                    <td class="px-4 py-3 text-right font-medium">${formatMoney(p.total)}</td>
                    <td class="px-4 py-3 text-right">${formatMoney(p.paid)}</td>
                    <td class="px-4 py-3 text-right ${p.debt > 0 ? 'text-red-600 font-medium' : ''}">${formatMoney(p.debt)}</td>
                    <td class="px-4 py-3 text-center">
                        <span class="px-2 py-1 rounded-full text-xs font-medium ${statusColor}">${p.status}</span>
                    </td>
                    <td class="px-4 py-3 text-center">
                        <button onclick="event.stopPropagation(); viewPurchaseDetail('${p.id}')" class="text-blue-600 hover:text-blue-800 mr-2" title="Xem chi tiết">
                            👁️
                        </button>
                        <button onclick="event.stopPropagation(); printPurchase('${p.id}')" class="text-purple-600 hover:text-purple-800 mr-2" title="In phiếu nhập">
                            🖨️
                        </button>
                        ${p.debt > 0 && p.status !== 'Completed' ? `
                            <button onclick="event.stopPropagation(); showPurchasePaymentModal('${p.id}', ${p.debt}, '${escapeHtml(supplierName)}', '${p.supplierId}')" class="text-green-600 hover:text-green-800 mr-2" title="Thanh toán nợ">
                                💰
                            </button>
                        ` : ''}
                        ${p.status !== 'Completed' ? `
                            <button onclick="event.stopPropagation(); editPurchase('${p.id}')" class="text-orange-600 hover:text-orange-800 mr-2" title="Sửa">
                                ✏️
                            </button>
                        ` : ''}
                        <button onclick="event.stopPropagation(); deletePurchase('${p.id}')" class="text-red-600 hover:text-red-800" title="Xóa">
                            🗑️
                        </button>
                    </td>
                </tr>
            `;
        }).join('');
    }

    /**
     * Refresh purchases data
     */
    function refreshPurchasesData() {
        showToast('Đang làm mới dữ liệu...', 'info');
        localStorage.removeItem('TTL_purchases');
        google.script.run
            .withSuccessHandler(() => {
                loadPurchases();
                showToast('Đã làm mới dữ liệu nhập hàng thành công', 'success');
            })
            .withFailureHandler((err) => {
                console.error('Error clearing cache:', err);
                loadPurchases();
                showToast('Đã làm mới dữ liệu nhập hàng', 'success');
            })
            .apiHandler('clearCache', { sheetName: 'Phiếu Nhập' });
    }

    /**
     * Show purchase modal
     */
    function closePurchaseSearchAndAddProduct(prefillName) {
        var resultsDiv = document.getElementById('purchase-product-search-results');
        if (resultsDiv) resultsDiv.classList.add('hidden');
        showProductModal(null);
        // Pre-fill tên SP vào form thêm sản phẩm
        setTimeout(function() {
            var nameInput = document.getElementById('product-name');
            if (nameInput && prefillName) nameInput.value = prefillName;
        }, 300);
    }

    function showPurchaseModal(purchaseId = null) {
        purchaseCart = [];
        selectedPurchaseProduct = null;
        editingPurchaseId = purchaseId; // Track if editing
        const modal = document.getElementById('purchase-modal');
        const modalTitle = document.getElementById('purchase-modal-title');
        const submitBtn = document.getElementById('btn-save-purchase');

        if (modal) {
            modal.classList.remove('hidden');
            // Update modal title and button text based on mode
            if (modalTitle) {
                modalTitle.textContent = purchaseId ? 'Sửa Phiếu Nhập Hàng' : 'Tạo Phiếu Nhập Hàng';
            }
            if (submitBtn) {
                setBtnLoading(submitBtn, false);
                submitBtn.innerHTML = purchaseId ? '💾 Cập Nhật Phiếu Nhập' : '📦 Lưu Phiếu Nhập';
            }
            // Load suppliers if not loaded
            if (suppliers.length === 0) {
                loadSuppliers();
            }
            // Load products if not loaded (needed for product search)
            if (!products || products.length === 0) {
                loadData();
            }
            // Initialize product search
            initializePurchaseProductSearch();
            // Reset form
            resetPurchaseForm();
            // Load purchase detail if editing
            if (purchaseId) {
                loadPurchaseDetail(purchaseId);
            }
        }
    }

    /**
     * Initialize product search for purchase
     */
    // Re-trigger purchase search when category filter changes
    function filterPurchaseProductSearch() {
        var searchInput = document.getElementById('purchase-product-search');
        if (searchInput && searchInput.value.trim()) {
            filterPurchaseProducts(searchInput.value.trim());
        }
    }

    function initializePurchaseProductSearch() {
        const searchInput = document.getElementById('purchase-product-search');
        const resultsDiv = document.getElementById('purchase-product-search-results');

        if (!searchInput || !resultsDiv) return;

        // Populate category filter dropdown
        var catSelect = document.getElementById('purchase-category-filter');
        if (catSelect) {
            // Build categories from products if allCategories empty
            var cats = allCategories && allCategories.length > 0 ? allCategories : [];
            if (cats.length === 0 && products && products.length > 0) {
                var catSet = {};
                products.forEach(function(p) { if (p.category) catSet[p.category] = true; });
                cats = Object.keys(catSet).sort();
            }
            catSelect.innerHTML = '<option value="">Tất cả DM</option>';
            cats.forEach(function(c) {
                catSelect.innerHTML += '<option value="' + escapeHtml(c) + '">' + escapeHtml(c) + '</option>';
            });
        }

        // Clear previous listeners by cloning
        const newSearchInput = searchInput.cloneNode(true);
        searchInput.parentNode.replaceChild(newSearchInput, searchInput);

        const newSearchInputRef = document.getElementById('purchase-product-search');

        // Input event with debounce
        let searchTimeout;
        newSearchInputRef.addEventListener('input', function (e) {
            const query = e.target.value.trim();

            clearTimeout(searchTimeout);

            if (query.length < 1) {
                resultsDiv.classList.add('hidden');
                return;
            }

            searchTimeout = setTimeout(() => {
                filterPurchaseProducts(query);
            }, 200);
        });

        // Keyboard navigation
        newSearchInputRef.addEventListener('keydown', function (e) {
            const options = resultsDiv.querySelectorAll('.purchase-product-option');
            const activeOption = resultsDiv.querySelector('.purchase-product-option.active');

            if (e.key === 'ArrowDown') {
                e.preventDefault();
                if (activeOption) {
                    activeOption.classList.remove('active');
                    const next = activeOption.nextElementSibling;
                    if (next && next.classList.contains('purchase-product-option')) {
                        next.classList.add('active');
                        next.scrollIntoView({ block: 'nearest' });
                    }
                } else if (options.length > 0) {
                    options[0].classList.add('active');
                }
            } else if (e.key === 'ArrowUp') {
                e.preventDefault();
                if (activeOption) {
                    activeOption.classList.remove('active');
                    const prev = activeOption.previousElementSibling;
                    if (prev && prev.classList.contains('purchase-product-option')) {
                        prev.classList.add('active');
                        prev.scrollIntoView({ block: 'nearest' });
                    }
                }
            } else if (e.key === 'Enter') {
                e.preventDefault();
                const query = newSearchInputRef.value.trim();
                // Exact barcode/SKU match → auto-increment if already in cart
                const exactMatch = products && (productByBarcode.get(query) || productBySku.get(query));
                if (exactMatch) {
                    var existIdx = purchaseCart.findIndex(function(item) { return item.sku === exactMatch.sku; });
                    if (existIdx >= 0) {
                        purchaseCart[existIdx].qty += 1;
                        var ei = purchaseCart[existIdx];
                        ei.total = ei.qty * ei.importPrice - getPurchaseItemDiscountAmount(ei);
                        renderPurchaseCart();
                        newSearchInputRef.value = '';
                        resultsDiv.classList.add('hidden');
                        showToast('📦 +1 ' + exactMatch.name + ' (SL: ' + purchaseCart[existIdx].qty + ')', 'success');
                        return;
                    }
                }
                if (activeOption) {
                    activeOption.click();
                } else if (options.length > 0) {
                    options[0].click();
                }
            } else if (e.key === 'Escape') {
                resultsDiv.classList.add('hidden');
            }
        });

        // Hide results when clicking outside
        document.addEventListener('click', function (e) {
            if (!newSearchInputRef.contains(e.target) && !resultsDiv.contains(e.target)) {
                resultsDiv.classList.add('hidden');
            }
        });
    }

    /**
     * Filter products for purchase search
     */
    function filterPurchaseProducts(query) {
        const resultsDiv = document.getElementById('purchase-product-search-results');
        if (!resultsDiv) return;
        if (!products || products.length === 0) {
            resultsDiv.innerHTML = '<div class="p-3 text-center"><p class="text-sm text-gray-500">Đang tải sản phẩm...</p></div>';
            resultsDiv.classList.remove('hidden');
            return;
        }

        const queryLower = query.toLowerCase();
        const catFilter = (document.getElementById('purchase-category-filter') || {}).value || '';

        // Filter products by name, SKU, barcode, or category
        const filtered = products.filter(product => {
            if (!product) return false;
            // Category filter
            if (catFilter && (product.category || '') !== catFilter) return false;
            const name = (product.name || '').toLowerCase();
            const sku = (product.sku || '').toLowerCase();
            const barcode = (product.barcode || '').toLowerCase();
            const category = (product.category || '').toLowerCase();

            return name.includes(queryLower) ||
                sku.includes(queryLower) ||
                barcode.includes(queryLower) ||
                category.includes(queryLower);
        });

        // Render results
        if (filtered.length === 0) {
            resultsDiv.innerHTML = '<div class="p-3 text-center"><p class="text-sm text-gray-500">Không tìm thấy sản phẩm</p></div>';
            resultsDiv.classList.remove('hidden');
            return;
        }

        let html = '';
        filtered.slice(0, 10).forEach(product => { // Limit to 10 results
            const displayName = escapeHtml(product.name || product.sku);
            const displaySku = escapeHtml(product.sku);
            const displayCategory = product.category ? escapeHtml(product.category) : '';
            const displayPrice = product.importPrice > 0 ? formatMoneyPrecise(product.importPrice) : 'Chưa có giá nhập';
            const displayStock = product.stock || 0;

            html += `
                <div 
                    class="purchase-product-option p-3 hover:bg-blue-50 cursor-pointer border-b border-gray-100 last:border-b-0 transition-colors"
                    data-product-sku="${escapeHtml(product.sku)}"
                    onclick="selectPurchaseProduct('${escapeHtml(product.sku)}')"
                    onmouseenter="this.classList.add('bg-blue-50', 'active')"
                    onmouseleave="this.classList.remove('bg-blue-50', 'active')"
                >
                    <div class="font-medium text-gray-900">${displayName}</div>
                    <div class="text-xs text-gray-500 mt-1">
                        Mã: ${displaySku}${displayCategory ? ' • ' + displayCategory : ''} • Giá nhập: ${displayPrice} • Tồn: ${displayStock}
                    </div>
                </div>
            `;
        });

        resultsDiv.innerHTML = html;
        resultsDiv.classList.remove('hidden');
    }

    /**
     * Select product for purchase
     */
    function selectPurchaseProduct(sku) {
        const product = productBySku.get(sku);
        if (!product) return;

        selectedPurchaseProduct = product;

        // Update display
        const searchInput = document.getElementById('purchase-product-search');
        const resultsDiv = document.getElementById('purchase-product-search-results');
        const displayDiv = document.getElementById('purchase-selected-product-display');
        const nameSpan = document.getElementById('purchase-selected-product-name');
        const skuSpan = document.getElementById('purchase-selected-product-sku');
        const priceSpan = document.getElementById('purchase-selected-product-price');
        const priceInput = document.getElementById('purchase-product-import-price');

        if (searchInput) searchInput.value = '';
        if (resultsDiv) resultsDiv.classList.add('hidden');
        if (displayDiv) displayDiv.classList.remove('hidden');
        if (nameSpan) nameSpan.textContent = product.name || product.sku;
        if (skuSpan) skuSpan.textContent = `(${product.sku})`;
        if (priceSpan) priceSpan.textContent = product.importPrice > 0 ? formatMoneyPrecise(product.importPrice) : 'Chưa có';
        if (priceInput) {
            // Pre-fill import price if available
            if (product.importPrice > 0) {
                priceInput.value = product.importPrice;
            }
        }

        // Auto-fill VAT from product data
        var vatInput = document.getElementById('purchase-product-vat');
        var vatInclInput = document.getElementById('purchase-vat-included');
        if (vatInput && product.vatRate > 0) vatInput.value = product.vatRate;
        if (vatInclInput && product.vatIncluded) vatInclInput.checked = true;

        // Focus on quantity input
        const qtyInput = document.getElementById('purchase-product-qty');
        if (qtyInput) {
            qtyInput.focus();
            qtyInput.select();
        }

        // Fetch import price history (non-blocking)
        loadImportPriceHistory(product.sku, product.importPrice);
    }

    /**
     * Load and display import price history for a product
     */
    function loadImportPriceHistory(sku, currentPrice) {
        const historyDiv = document.getElementById('purchase-price-history');
        if (!historyDiv) return;
        historyDiv.classList.add('hidden');

        google.script.run
            .withSuccessHandler(function(res) {
                if (!res || !res.success || !res.data || res.data.length === 0) {
                    historyDiv.innerHTML = '<span class="text-gray-400">Chưa có lịch sử nhập hàng cho SP này</span>';
                    historyDiv.classList.remove('hidden');
                    return;
                }

                var history = res.data;
                var lastPrice = history[0].importPrice;

                // Price change warning
                var warning = '';
                if (currentPrice > 0 && lastPrice > 0) {
                    var changePercent = ((currentPrice - lastPrice) / lastPrice * 100).toFixed(1);
                    if (Math.abs(changePercent) > 10) {
                        var isUp = changePercent > 0;
                        warning = '<span class="ml-2 px-1.5 py-0.5 rounded text-white ' +
                            (isUp ? 'bg-red-500' : 'bg-green-500') + '">' +
                            (isUp ? '⬆' : '⬇') + ' ' + Math.abs(changePercent) + '% so với lần trước</span>';
                    }
                }

                var html = '<div class="flex items-center gap-2 mb-1">' +
                    '<span class="font-medium text-gray-700">📊 Lịch sử giá nhập</span>' + warning + '</div>';
                html += '<div class="flex flex-wrap gap-3">';
                history.forEach(function(h) {
                    var date = h.date ? new Date(h.date).toLocaleDateString('vi-VN') : '?';
                    html += '<span class="inline-flex items-center gap-1 text-gray-600">' +
                        '<span class="text-gray-400">' + date + ':</span> ' +
                        '<span class="font-medium">' + formatMoneyPrecise(h.importPrice) + '</span>' +
                        '<span class="text-gray-400">×' + h.qty + '</span>' +
                        '</span>';
                });
                html += '</div>';

                historyDiv.innerHTML = html;
                historyDiv.classList.remove('hidden');
            })
            .withFailureHandler(function() {
                historyDiv.classList.add('hidden');
            })
            .apiHandler('getProductImportPriceHistory', sku);
    }

    /**
     * Clear product selection
     */
    function clearPurchaseProductSelection() {
        selectedPurchaseProduct = null;
        const displayDiv = document.getElementById('purchase-selected-product-display');
        const priceInput = document.getElementById('purchase-product-import-price');
        const qtyInput = document.getElementById('purchase-product-qty');
        const historyDiv = document.getElementById('purchase-price-history');

        if (displayDiv) displayDiv.classList.add('hidden');
        if (historyDiv) historyDiv.classList.add('hidden');
        if (priceInput) priceInput.value = '';
        if (qtyInput) qtyInput.value = '1';
        var vatInput = document.getElementById('purchase-product-vat');
        var vatInclInput = document.getElementById('purchase-vat-included');
        if (vatInput) vatInput.value = '';
        if (vatInclInput) vatInclInput.checked = false;
    }

    /**
     * Reset purchase form
     */
    function resetPurchaseForm() {
        document.getElementById('purchase-supplier-select').value = '';
        var supplierSearch = document.getElementById('purchase-supplier-search');
        if (supplierSearch) supplierSearch.value = '';
        document.getElementById('purchase-notes').value = '';
        document.getElementById('purchase-payment-method').value = 'Tiền mặt';
        document.getElementById('purchase-paid').value = (0).toLocaleString('vi-VN');
        document.getElementById('purchase-items-list').innerHTML = '';
        document.getElementById('purchase-total').innerText = '0 ₫';
        document.getElementById('purchase-product-search').value = '';
        document.getElementById('purchase-product-qty').value = '1';
        document.getElementById('purchase-product-import-price').value = '';
        var vatInput = document.getElementById('purchase-product-vat');
        if (vatInput) vatInput.value = '';
        var vatInclInput = document.getElementById('purchase-vat-included');
        if (vatInclInput) vatInclInput.checked = false;
        purchaseCart = [];
        selectedPurchaseProduct = null;
        // Reset submit button loading state
        var btnSave = document.getElementById('btn-save-purchase');
        if (btnSave) setBtnLoading(btnSave, false);
        // Don't reset editingPurchaseId here - it's set in showPurchaseModal
        clearPurchaseProductSelection();
    }

    /**
     * Load purchase detail for editing/viewing
     */
    function loadPurchaseDetail(purchaseId) {
        if (!purchaseId) {
            showToast('Mã phiếu nhập không hợp lệ', 'error');
            return;
        }

        toggleLoading(true);
        google.script.run
            .withSuccessHandler((res) => {
                toggleLoading(false);
                try {
                    if (res && res.success !== false && res.data) {
                        const purchase = res.data;

                        // Ensure items is an array
                        if (!purchase.items || !Array.isArray(purchase.items)) {
                            console.warn('loadPurchaseDetail: items is not an array:', purchase.items);
                            purchase.items = [];
                        }

                        const supplierSelect = document.getElementById('purchase-supplier-select');
                        const notesInput = document.getElementById('purchase-notes');
                        const paymentMethodSelect = document.getElementById('purchase-payment-method');
                        const paidInput = document.getElementById('purchase-paid');

                        if (supplierSelect) supplierSelect.value = purchase.supplierId || '';
                        // Set supplier search input text
                        var supplierSearchInput = document.getElementById('purchase-supplier-search');
                        if (supplierSearchInput && purchase.supplierId) {
                            var sup = suppliers.find(function(s) { return s.id === purchase.supplierId; });
                            supplierSearchInput.value = sup ? (sup.name + (sup.phone ? ' - ' + sup.phone : '')) : purchase.supplierId;
                        }
                        if (notesInput) notesInput.value = purchase.notes || '';
                        if (paymentMethodSelect) paymentMethodSelect.value = purchase.paymentMethod || 'Tiền mặt';
                        if (paidInput) paidInput.value = purchase.paid ? parseInt(purchase.paid).toLocaleString('vi-VN') : '0';

                        // Load items
                        purchaseCart = purchase.items.map(item => ({
                            sku: item.sku || '',
                            qty: parseFloat(item.qty) || 0,
                            importPrice: parseFloat(item.importPrice) || 0,
                            total: parseFloat(item.total) || 0,
                            discountType: item.discountType || 'amount',
                            discountValue: parseFloat(item.discountValue) || 0,
                            vatRate: parseFloat(item.vatRate) || 0,
                            vatIncluded: item.vatIncluded === true || item.vatIncluded === 'Yes',
                            vatAmount: parseFloat(item.vatAmount) || 0
                        }));
                        renderPurchaseItems();
                        updatePurchaseTotal();
                    } else {
                        const errorMsg = res && res.message ? res.message : 'Không tìm thấy phiếu nhập';
                        showToast(errorMsg, 'error');
                        console.warn('loadPurchaseDetail: Response indicates failure:', res);
                    }
                } catch (e) {
                    console.error('Error processing purchase detail:', e);
                    showToast('Lỗi khi xử lý thông tin phiếu nhập: ' + e.toString(), 'error');
                }
            })
            .withFailureHandler((error) => {
                toggleLoading(false);
                console.error('loadPurchaseDetail: API call failed:', error);
                const errorMsg = error && error.message ? error.message : (error && error.toString ? error.toString() : 'Không thể tải chi tiết phiếu nhập');
                showToast('Lỗi: ' + errorMsg, 'error');
            })
            .apiHandler('getPurchaseDetail', purchaseId);
    }

    /**
     * Add product to purchase cart
     */
    function addProductToPurchase() {
        const qtyInput = document.getElementById('purchase-product-qty');
        const priceInput = document.getElementById('purchase-product-import-price');

        // Use selected product or find by search
        if (!selectedPurchaseProduct) {
            showToast('Vui lòng chọn sản phẩm', 'warning');
            const searchInput = document.getElementById('purchase-product-search');
            if (searchInput) searchInput.focus();
            return;
        }

        const product = selectedPurchaseProduct;
        const sku = product.sku;
        const qty = parseFloat(qtyInput.value) || 0;
        const importPrice = parseMoneyInput(priceInput);

        if (qty <= 0) {
            showToast('Số lượng phải lớn hơn 0', 'warning');
            if (qtyInput) qtyInput.focus();
            return;
        }

        if (importPrice <= 0) {
            showToast('Giá nhập phải lớn hơn 0', 'warning');
            if (priceInput) priceInput.focus();
            return;
        }

        // Get VAT inputs
        const vatRateInput = document.getElementById('purchase-product-vat');
        const vatIncludedInput = document.getElementById('purchase-vat-included');
        const vatRate = parseFloat(vatRateInput ? vatRateInput.value : '') || 0;
        const vatIncluded = vatIncludedInput ? vatIncludedInput.checked : false;

        // Check if already in cart
        const existingIndex = purchaseCart.findIndex(item => item.sku === sku);
        if (existingIndex >= 0) {
            purchaseCart[existingIndex].qty += qty;
            purchaseCart[existingIndex].importPrice = importPrice;
            purchaseCart[existingIndex].vatRate = vatRate;
            purchaseCart[existingIndex].vatIncluded = vatIncluded;
            const existItem = purchaseCart[existingIndex];
            existItem.total = existItem.qty * importPrice - getPurchaseItemDiscountAmount(existItem);
        } else {
            purchaseCart.push({
                sku: sku,
                name: product.name || product.productName || sku,
                qty: qty,
                importPrice: importPrice,
                total: qty * importPrice,
                discountType: 'amount',
                discountValue: 0,
                vatRate: vatRate,
                vatIncluded: vatIncluded,
                serialNos: []
            });
        }

        renderPurchaseItems();
        updatePurchaseTotal();

        // Reset inputs and selection
        clearPurchaseProductSelection();
        const searchInput = document.getElementById('purchase-product-search');
        if (searchInput) {
            searchInput.value = '';
            searchInput.focus();
        }
    }

    /**
     * Render purchase items
     */
    function renderPurchaseItems() {
        const listEl = document.getElementById('purchase-items-list');
        if (!listEl) return;

        if (purchaseCart.length === 0) {
            listEl.innerHTML = '<tr><td colspan="9" class="text-center py-4 text-gray-400">Chưa có sản phẩm</td></tr>';
            return;
        }

        listEl.innerHTML = purchaseCart.map((item, index) => {
            let productName = item.name;
            let productCategory = item.category || '';
            const _prod = productBySku.get(item.sku);
            if (_prod) {
                if (!productName || productName === item.sku) productName = _prod.name;
                if (!productCategory) productCategory = _prod.category || '';
            }
            const discountType = item.discountType || 'amount';
            const discountValue = item.discountValue || 0;
            const lineTotal = item.qty * item.importPrice;
            const discountAmt = getPurchaseItemDiscountAmount(item);
            const afterDiscount = lineTotal - discountAmt;
            const hasDiscount = discountValue > 0;
            const vatRate = item.vatRate || 0;
            const vatIncluded = item.vatIncluded || false;
            const vatInfo = getPurchaseItemVATInfo(item);
            return `
            <tr class="border-b border-gray-100">
                <td class="px-3 py-2 text-xs text-gray-500">${item.sku}</td>
                <td class="px-3 py-2 text-sm">${productName || item.sku}</td>
                <td class="px-2 py-2 text-xs text-gray-500">${escapeHtml(productCategory)}</td>
                <td class="px-2 py-2">
                    <input type="number" value="${item.qty}" min="1" step="1"
                        onchange="updatePurchaseItemQty(${index}, this.value)"
                        class="w-16 px-1.5 py-1 text-sm text-right border border-gray-300 rounded focus:outline-none focus:ring-1 focus:ring-blue-400">
                </td>
                <td class="px-2 py-2">
                    <input type="number" value="${item.importPrice}" min="0" step="any"
                        onchange="updatePurchaseItemPrice(${index}, this.value)"
                        class="w-24 px-1.5 py-1 text-sm text-right border border-gray-300 rounded focus:outline-none focus:ring-1 focus:ring-blue-400">
                </td>
                <td class="px-2 py-2">
                    <div class="flex items-center gap-1 justify-center">
                        <input type="number" value="${vatRate}" min="0" max="100" step="1"
                            onchange="updatePurchaseItemVat(${index}, this.value)"
                            class="w-12 px-1 py-1 text-xs text-right border rounded focus:outline-none focus:ring-1 focus:ring-purple-400 ${vatRate > 0 ? 'border-purple-300 bg-purple-50 text-purple-700' : 'border-gray-300'}">
                        <span class="text-xs text-gray-400">%</span>
                    </div>
                    ${vatRate > 0 ? '<div class="flex items-center justify-center mt-0.5"><label class="flex items-center gap-0.5 cursor-pointer"><input type="checkbox" ' + (vatIncluded ? 'checked' : '') + ' onchange="togglePurchaseItemVatIncluded(' + index + ', this.checked)" class="w-3 h-3 accent-purple-500"><span class="text-[10px] text-purple-600">Đã gồm</span></label></div>' : ''}
                    ${vatRate > 0 ? '<div class="text-[10px] text-purple-600 text-center mt-0.5">+' + formatMoneyPrecise(vatInfo.vatAmount) + '</div>' : ''}
                </td>
                <td class="px-2 py-2">
                    <div class="flex items-center gap-1 justify-center">
                        <input type="number" value="${discountValue}" min="0" ${discountType === 'percent' ? 'max="100"' : ''} step="${discountType === 'percent' ? '1' : '1000'}"
                            onchange="updatePurchaseItemDiscount(${index}, this.value)"
                            class="w-14 px-1 py-1 text-xs text-right border rounded focus:outline-none focus:ring-1 focus:ring-orange-400 ${hasDiscount ? 'border-orange-300 bg-orange-50 text-orange-700' : 'border-gray-300'}">
                        <button onclick="togglePurchaseItemDiscountType(${index})"
                            class="px-1 py-1 text-xs font-semibold rounded border transition-colors ${discountType === 'percent' ? 'bg-orange-100 border-orange-300 text-orange-700' : 'bg-gray-100 border-gray-300 text-gray-600'}">${discountType === 'percent' ? '%' : 'đ'}</button>
                    </div>
                    ${hasDiscount ? '<div class="text-[10px] text-orange-600 text-center mt-0.5">-' + formatMoneyPrecise(discountAmt) + '</div>' : ''}
                </td>
                <td class="px-3 py-2 text-right font-medium ${hasDiscount ? 'text-orange-600' : ''}">${formatMoneyPrecise(vatInfo.totalWithVAT - discountAmt)}</td>
                <td class="px-2 py-2 text-center">
                    <button onclick="removePurchaseItem(${index})" class="text-red-600 hover:text-red-800 text-sm" title="Xóa">✕</button>
                </td>
            </tr>
            ${(function(){
                var prod = productBySku.get(item.sku);
                if (!prod || !prod.trackSerial) return '';
                var serials = item.serialNos || [];
                var serialTags = serials.map(function(s,si){
                    return '<span class="inline-flex items-center gap-1 px-2 py-0.5 bg-blue-100 text-blue-700 rounded text-xs mr-1 mb-1">' + s +
                        ' <a onclick="removePurchaseSerial('+index+','+si+')" class="cursor-pointer text-red-400 hover:text-red-600 font-bold">&times;</a></span>';
                }).join('');
                return '<tr class="bg-blue-50/50"><td colspan="9" class="px-3 py-2">' +
                    '<div class="flex items-center gap-2 mb-1"><span class="text-xs font-semibold text-blue-600">🔢 Serial Numbers (' + serials.length + '/' + item.qty + ')</span></div>' +
                    '<div class="flex gap-2 mb-1">' +
                        '<input type="text" id="purchase-serial-scan-'+index+'" placeholder="Quét/gõ serial, Enter để thêm" ' +
                            'onkeydown="if(event.key===\'Enter\'){event.preventDefault();addPurchaseSerial('+index+')}" ' +
                            'class="flex-1 px-2 py-1 text-xs border rounded focus:ring-1 focus:ring-blue-400 focus:outline-none">' +
                        '<button type="button" onclick="addPurchaseSerial('+index+')" class="px-2 py-1 text-xs bg-blue-500 text-white rounded hover:bg-blue-600">+</button>' +
                        '<button type="button" onclick="togglePurchaseSerialTextarea('+index+')" class="px-2 py-1 text-xs bg-gray-200 text-gray-600 rounded hover:bg-gray-300" title="Dán danh sách">📋</button>' +
                    '</div>' +
                    '<textarea id="purchase-serial-textarea-'+index+'" style="display:none" rows="3" placeholder="Dán danh sách serial (mỗi dòng 1 serial)" ' +
                        'class="w-full px-2 py-1 text-xs border rounded mb-1 focus:ring-1 focus:ring-blue-400 focus:outline-none"></textarea>' +
                    '<button type="button" id="purchase-serial-paste-btn-'+index+'" style="display:none" onclick="parsePurchaseSerialTextarea('+index+')" class="px-2 py-0.5 text-xs bg-blue-100 text-blue-600 rounded mb-1">Áp dụng danh sách</button>' +
                    '<div class="flex flex-wrap">' + serialTags + '</div>' +
                    (serials.length !== item.qty ? '<div class="text-xs text-orange-500 mt-1">⚠ Cần nhập đúng ' + item.qty + ' serial</div>' : '<div class="text-xs text-green-600 mt-1">✓ Đủ serial</div>') +
                '</td></tr>';
            })()}
        `}).join('');
    }

    /**
     * Remove item from purchase cart
     */
    function removePurchaseItem(index) {
        purchaseCart.splice(index, 1);
        renderPurchaseItems();
        updatePurchaseTotal();
    }

    // === PURCHASE SERIAL HELPERS ===
    function addPurchaseSerial(index) {
        var input = document.getElementById('purchase-serial-scan-' + index);
        if (!input) return;
        var val = input.value.trim();
        if (!val) return;
        if (!purchaseCart[index].serialNos) purchaseCart[index].serialNos = [];
        if (purchaseCart[index].serialNos.indexOf(val) !== -1) {
            showToast('Serial "' + val + '" đã có trong danh sách', 'warning'); return;
        }
        purchaseCart[index].serialNos.push(val);
        input.value = '';
        renderPurchaseItems();
    }

    function removePurchaseSerial(itemIndex, serialIndex) {
        if (purchaseCart[itemIndex] && purchaseCart[itemIndex].serialNos) {
            purchaseCart[itemIndex].serialNos.splice(serialIndex, 1);
            renderPurchaseItems();
        }
    }

    function togglePurchaseSerialTextarea(index) {
        var ta = document.getElementById('purchase-serial-textarea-' + index);
        var btn = document.getElementById('purchase-serial-paste-btn-' + index);
        if (ta) { ta.style.display = ta.style.display === 'none' ? 'block' : 'none'; }
        if (btn) { btn.style.display = btn.style.display === 'none' ? 'inline-block' : 'none'; }
    }

    function parsePurchaseSerialTextarea(index) {
        var ta = document.getElementById('purchase-serial-textarea-' + index);
        if (!ta) return;
        var lines = ta.value.split('\n').map(function(l){return l.trim();}).filter(Boolean);
        if (!purchaseCart[index].serialNos) purchaseCart[index].serialNos = [];
        var dupes = [];
        lines.forEach(function(s) {
            if (purchaseCart[index].serialNos.indexOf(s) === -1) {
                purchaseCart[index].serialNos.push(s);
            } else { dupes.push(s); }
        });
        ta.value = '';
        ta.style.display = 'none';
        var btn = document.getElementById('purchase-serial-paste-btn-' + index);
        if (btn) btn.style.display = 'none';
        if (dupes.length > 0) showToast('Bỏ qua serial trùng: ' + dupes.join(', '), 'warning');
        renderPurchaseItems();
    }

    // Helper: calculate discount amount for a purchase item
    function getPurchaseItemDiscountAmount(item) {
        if (!item.discountValue || item.discountValue <= 0) return 0;
        const lineTotal = item.qty * item.importPrice;
        if (item.discountType === 'percent') {
            return Math.round(lineTotal * item.discountValue / 100);
        }
        return Math.min(item.discountValue, lineTotal);
    }

    // Helper: calculate VAT info for a purchase item
    function getPurchaseItemVATInfo(item) {
        const lineTotal = item.qty * item.importPrice;
        const vatRate = item.vatRate || 0;
        const vatIncluded = item.vatIncluded || false;
        if (vatRate <= 0) return { priceBeforeVAT: lineTotal, vatAmount: 0, totalWithVAT: lineTotal };
        if (vatIncluded) {
            // Price already includes VAT → extract
            var priceBeforeVAT = Math.round(lineTotal / (1 + vatRate / 100));
            var vatAmount = lineTotal - priceBeforeVAT;
            return { priceBeforeVAT: priceBeforeVAT, vatAmount: vatAmount, totalWithVAT: lineTotal };
        } else {
            // Price is before VAT → add VAT
            var vatAmount2 = Math.round(lineTotal * vatRate / 100);
            return { priceBeforeVAT: lineTotal, vatAmount: vatAmount2, totalWithVAT: lineTotal + vatAmount2 };
        }
    }

    function updatePurchaseItemVat(index, value) {
        var item = purchaseCart[index];
        if (!item) return;
        item.vatRate = parseFloat(value) || 0;
        renderPurchaseItems();
        updatePurchaseTotal();
    }

    function togglePurchaseItemVatIncluded(index, checked) {
        var item = purchaseCart[index];
        if (!item) return;
        item.vatIncluded = checked;
        renderPurchaseItems();
        updatePurchaseTotal();
    }

    function updatePurchaseItemDiscount(index, value) {
        const item = purchaseCart[index];
        if (!item) return;

        const val = parseFloat(value);
        if (isNaN(val) || val < 0) {
            showToast("Giá trị giảm giá không hợp lệ!", "error");
            renderPurchaseItems();
            return;
        }
        if (item.discountType === 'percent' && val > 100) {
            showToast("Giảm giá không được vượt quá 100%!", "error");
            renderPurchaseItems();
            return;
        }

        item.discountValue = val;
        item.total = item.qty * item.importPrice - getPurchaseItemDiscountAmount(item);
        renderPurchaseItems();
        updatePurchaseTotal();
    }

    function updatePurchaseItemQty(index, value) {
        const item = purchaseCart[index];
        if (!item) return;
        const val = parseInt(value);
        if (isNaN(val) || val < 1) {
            showToast('Số lượng phải >= 1!', 'error');
            renderPurchaseItems();
            return;
        }
        item.qty = val;
        item.total = item.qty * item.importPrice - getPurchaseItemDiscountAmount(item);
        renderPurchaseItems();
        updatePurchaseTotal();
    }

    function updatePurchaseItemPrice(index, value) {
        const item = purchaseCart[index];
        if (!item) return;
        const val = parseFloat(value);
        if (isNaN(val) || val < 0) {
            showToast('Giá nhập không hợp lệ!', 'error');
            renderPurchaseItems();
            return;
        }
        item.importPrice = val;
        item.total = item.qty * item.importPrice - getPurchaseItemDiscountAmount(item);
        renderPurchaseItems();
        updatePurchaseTotal();
    }

    function togglePurchaseItemDiscountType(index) {
        const item = purchaseCart[index];
        if (!item) return;

        item.discountType = item.discountType === 'amount' ? 'percent' : 'amount';
        item.discountValue = 0;
        item.total = item.qty * item.importPrice;
        renderPurchaseItems();
        updatePurchaseTotal();
    }

    /**
     * Update purchase total
     */
    function updatePurchaseTotal() {
        var totalDiscount = 0;
        var totalVAT = 0;
        var grandTotal = 0;
        purchaseCart.forEach(function(item) {
            var vatInfo = getPurchaseItemVATInfo(item);
            var discountAmt = getPurchaseItemDiscountAmount(item);
            totalDiscount += discountAmt;
            totalVAT += vatInfo.vatAmount;
            grandTotal += vatInfo.totalWithVAT - discountAmt;
        });

        document.getElementById('purchase-total').innerText = formatMoneyPrecise(grandTotal);

        // Show/hide discount section
        var discountSection = document.getElementById('purchase-discount-section');
        var discountTotalEl = document.getElementById('purchase-discount-total');
        if (discountSection) discountSection.style.display = totalDiscount > 0 ? '' : 'none';
        if (discountTotalEl) discountTotalEl.innerText = '-' + formatMoneyPrecise(totalDiscount);

        // Show/hide VAT section
        var vatSection = document.getElementById('purchase-vat-section');
        var vatTotalEl = document.getElementById('purchase-vat-total');
        if (vatSection) vatSection.style.display = totalVAT > 0 ? '' : 'none';
        if (vatTotalEl) vatTotalEl.innerText = '+' + formatMoneyPrecise(totalVAT);
    }

    /**
     * Print purchase order
     */
    function printPurchase(purchaseId) {
        toggleLoading(true);

        google.script.run
            .withSuccessHandler((res) => {
                toggleLoading(false);
                if (res && res.success && res.data) {
                    const purchase = res.data;
                    openPurchasePrintWindow(purchase);
                } else {
                    showToast('Không thể tải thông tin phiếu nhập', 'error');
                }
            })
            .withFailureHandler((error) => {
                toggleLoading(false);
                showToast('Lỗi: ' + (error.message || error), 'error');
            })
            .apiHandler('getPurchaseDetail', purchaseId);
    }

    /**
     * Open print window for purchase
     */
    function openPurchasePrintWindow(purchase) {
        const date = purchase.date ? new Date(purchase.date).toLocaleDateString('vi-VN') : '';
        const supplierName = purchase.supplier ? purchase.supplier.name : (purchase.supplierId || 'N/A');
        const supplierPhone = purchase.supplier ? purchase.supplier.phone : '';
        const supplierAddress = purchase.supplier ? purchase.supplier.address : '';
        const info = (typeof getMergedCompanyInfo === 'function') ? getMergedCompanyInfo() : (companyInfo || {});
        const totalInWords = (typeof numberToVietnamese === 'function') ? numberToVietnamese(purchase.total || 0) : '';

        // Get items
        const items = purchase.items || [];

        // Check if any item has discount
        const hasItemDiscount = items.some(i => (i.discountAmount || 0) > 0);

        // Generate items table
        let itemsHtml = items.map((item, index) => {
            const productName = item.name || item.productName || item.sku;
            const lineTotal = (item.qty || 0) * (item.importPrice || item.price || 0);
            const discountAmt = item.discountAmount || 0;
            const afterDiscount = lineTotal - discountAmt;
            const discountLabel = item.discountType === 'percent' ? `${item.discountValue}%` : formatMoney(discountAmt);
            return `
                <tr>
                    <td style="border: 1px solid #ddd; padding: 8px; text-align: center;">${index + 1}</td>
                    <td style="border: 1px solid #ddd; padding: 8px;">${item.sku}</td>
                    <td style="border: 1px solid #ddd; padding: 8px;">${productName}</td>
                    <td style="border: 1px solid #ddd; padding: 8px; text-align: center;">${item.qty || item.quantity || 0}</td>
                    <td style="border: 1px solid #ddd; padding: 8px; text-align: right;">${formatMoneyPrecise(item.importPrice || item.price || 0)}</td>
                    ${hasItemDiscount ? `<td style="border: 1px solid #ddd; padding: 8px; text-align: right; color: ${discountAmt > 0 ? '#EA580C' : '#888'};">${discountAmt > 0 ? '-' + discountLabel : '-'}</td>` : ''}
                    <td style="border: 1px solid #ddd; padding: 8px; text-align: right;">${formatMoney(hasItemDiscount && discountAmt > 0 ? afterDiscount : (item.total || lineTotal))}</td>
                </tr>
            `;
        }).join('');

        // Total item discount for summary
        const totalItemDiscountPrint = items.reduce((s, i) => s + (i.discountAmount || 0), 0);

        const printContent = `
            <!DOCTYPE html>
            <html>
            <head>
                <meta charset="UTF-8">
                <title>Phiếu Nhập Hàng - ${purchase.id}</title>
                <style>
                    body {
                        font-family: Arial, sans-serif;
                        margin: 0;
                        padding: 20px;
                        font-size: 14px;
                    }
                    .header {
                        text-align: center;
                        margin-bottom: 20px;
                        border-bottom: 2px solid #333;
                        padding-bottom: 15px;
                    }
                    .header h1 {
                        color: #2563eb;
                        margin: 0 0 5px 0;
                        font-size: 24px;
                    }
                    .header h2 {
                        margin: 0;
                        font-size: 20px;
                        font-weight: normal;
                    }
                    .info-section {
                        display: flex;
                        justify-content: space-between;
                        margin-bottom: 20px;
                    }
                    .info-box {
                        width: 48%;
                    }
                    .info-box h3 {
                        color: #2563eb;
                        border-bottom: 1px solid #2563eb;
                        padding-bottom: 5px;
                        margin-bottom: 10px;
                        font-size: 14px;
                    }
                    .info-box p {
                        margin: 5px 0;
                    }
                    table {
                        width: 100%;
                        border-collapse: collapse;
                        margin-bottom: 20px;
                    }
                    th {
                        background-color: #fff;
                        color: #000;
                        padding: 10px 8px;
                        text-align: left;
                        border: 1px solid #000;
                        border-top: 2px solid #000;
                        border-bottom: 2px solid #000;
                        font-weight: 700;
                    }
                    .summary {
                        text-align: right;
                        margin-top: 20px;
                    }
                    .summary table {
                        width: 300px;
                        margin-left: auto;
                    }
                    .summary td {
                        padding: 8px;
                        border: none;
                    }
                    .summary .total {
                        font-size: 18px;
                        font-weight: bold;
                        color: #2563eb;
                        background-color: #EFF6FF;
                    }
                    .footer {
                        margin-top: 40px;
                        display: flex;
                        justify-content: space-between;
                    }
                    .signature {
                        width: 30%;
                        text-align: center;
                    }
                    .signature h4 {
                        margin-bottom: 60px;
                    }
                    .signature p {
                        font-style: italic;
                        color: #666;
                    }
                    .notes {
                        margin-top: 20px;
                        padding: 10px;
                        background-color: #FFF7ED;
                        border-left: 4px solid #F59E0B;
                    }
                    @media print {
                        body { margin: 0; padding: 15px; }
                        .no-print { display: none; }
                    }
                </style>
            </head>
            <body>
                <div class="header">
                    <h1>${info.name || 'CÔNG TY'}</h1>
                    <h2>PHIẾU NHẬP HÀNG</h2>
                    ${info.address ? `<p style="margin: 5px 0; color: #666;">${info.address}</p>` : ''}
                    ${info.phone ? `<p style="margin: 5px 0; color: #666;">ĐT: ${info.phone}</p>` : ''}
                </div>

                <div class="info-section">
                    <div class="info-box">
                        <h3>Thông tin phiếu nhập</h3>
                        <p><strong>Mã phiếu:</strong> ${purchase.id}</p>
                        <p><strong>Ngày nhập:</strong> ${date}</p>
                        <p><strong>Trạng thái:</strong> ${purchase.status}</p>
                        <p><strong>Phương thức TT:</strong> ${purchase.paymentMethod || 'Tiền mặt'}</p>
                    </div>
                    <div class="info-box">
                        <h3>Nhà cung cấp</h3>
                        <p><strong>Tên NCC:</strong> ${supplierName}</p>
                        ${supplierPhone ? `<p><strong>Điện thoại:</strong> ${supplierPhone}</p>` : ''}
                        ${supplierAddress ? `<p><strong>Địa chỉ:</strong> ${supplierAddress}</p>` : ''}
                    </div>
                </div>

                <table>
                    <thead>
                        <tr>
                            <th style="width: 5%; text-align: center;">STT</th>
                            <th style="width: 15%;">Mã SP</th>
                            <th style="${hasItemDiscount ? 'width: 30%' : 'width: 35%'};">Tên sản phẩm</th>
                            <th style="width: 10%; text-align: center;">SL</th>
                            <th style="width: 15%; text-align: right;">Đơn giá</th>
                            ${hasItemDiscount ? '<th style="width: 10%; text-align: right;">Giảm giá</th>' : ''}
                            <th style="width: ${hasItemDiscount ? '15' : '20'}%; text-align: right;">Thành tiền</th>
                        </tr>
                    </thead>
                    <tbody>
                        ${itemsHtml || '<tr><td colspan="' + (hasItemDiscount ? 7 : 6) + '" style="text-align: center; padding: 20px;">Không có sản phẩm</td></tr>'}
                    </tbody>
                </table>

                <div class="summary">
                    <table>
                        ${totalItemDiscountPrint > 0 ? `
                        <tr>
                            <td><strong>Tạm tính:</strong></td>
                            <td style="text-align: right;">${formatMoney((purchase.total || 0) + totalItemDiscountPrint)}</td>
                        </tr>
                        <tr>
                            <td><strong style="color: #EA580C;">Giảm giá SP:</strong></td>
                            <td style="text-align: right; color: #EA580C;">-${formatMoney(totalItemDiscountPrint)}</td>
                        </tr>
                        ` : ''}
                        <tr>
                            <td><strong>Tổng tiền:</strong></td>
                            <td style="text-align: right;">${formatMoney(purchase.total)}</td>
                        </tr>
                        <tr>
                            <td><strong>Đã thanh toán:</strong></td>
                            <td style="text-align: right;">${formatMoney(purchase.paid)}</td>
                        </tr>
                        <tr class="total">
                            <td><strong>Còn nợ:</strong></td>
                            <td style="text-align: right; color: ${purchase.debt > 0 ? '#DC2626' : '#059669'};">${formatMoney(purchase.debt)}</td>
                        </tr>
                    </table>
                    <p style="font-style: italic; font-size: 12px; color: #666; margin-top: 8px;">
                        <em>Bằng chữ: ${totalInWords}</em>
                    </p>
                </div>

                ${purchase.notes ? `
                <div class="notes">
                    <strong>Ghi chú:</strong> ${purchase.notes}
                </div>
                ` : ''}

                <div class="footer">
                    <div class="signature">
                        <h4>Người lập phiếu</h4>
                        <p>(Ký, ghi rõ họ tên)</p>
                    </div>
                    <div class="signature">
                        <h4>Thủ kho</h4>
                        <p>(Ký, ghi rõ họ tên)</p>
                    </div>
                    <div class="signature">
                        <h4>Người giao hàng</h4>
                        <p>(Ký, ghi rõ họ tên)</p>
                    </div>
                </div>

                <p style="text-align: center; margin-top: 30px; color: #999; font-size: 12px;">
                    In ngày: ${new Date().toLocaleDateString('vi-VN')} lúc ${new Date().toLocaleTimeString('vi-VN')}
                </p>
            </body>
            </html>
        `;

        const printWindow = window.open('', '_blank', 'width=800,height=600');
        printWindow.document.write(printContent);
        printWindow.document.close();

        // Wait for content to load then print
        printWindow.onload = function() {
            printWindow.focus();
            printWindow.print();
        };
    }

    /**
     * Submit purchase (create or update)
     */
    function submitPurchase() {
        const supplierId = document.getElementById('purchase-supplier-select').value;
        const notes = document.getElementById('purchase-notes').value;
        const paymentMethod = document.getElementById('purchase-payment-method').value;
        const paid = parseMoneyInput(document.getElementById('purchase-paid'));

        if (!supplierId) {
            showToast('Vui lòng chọn nhà cung cấp', 'warning');
            return;
        }

        if (purchaseCart.length === 0) {
            // Auto-add nếu có SP đang chọn nhưng chưa bấm "+ Thêm"
            if (selectedPurchaseProduct) {
                addPurchaseItem();
            }
            if (purchaseCart.length === 0) {
                showToast('Vui lòng thêm ít nhất một sản phẩm', 'warning');
                return;
            }
        }

        const purchaseData = {
            supplierId: supplierId,
            items: purchaseCart.map(item => {
                const discountAmt = getPurchaseItemDiscountAmount(item);
                const vatInfo = getPurchaseItemVATInfo(item);
                return {
                    sku: item.sku,
                    qty: item.qty,
                    importPrice: item.importPrice,
                    discountType: item.discountType || 'amount',
                    discountValue: item.discountValue || 0,
                    discountAmount: discountAmt,
                    vatRate: item.vatRate || 0,
                    vatIncluded: item.vatIncluded || false,
                    vatAmount: vatInfo.vatAmount,
                    total: vatInfo.totalWithVAT - discountAmt,
                    serialNos: item.serialNos || []
                };
            }),
            notes: notes,
            paymentMethod: paymentMethod,
            paid: paid
        };

        // Determine if creating or updating
        const isEditing = editingPurchaseId !== null;
        const apiAction = isEditing ? 'updatePurchase' : 'createPurchase';
        const successMessage = isEditing ? 'Cập nhật phiếu nhập thành công!' : 'Tạo phiếu nhập thành công!';
        const errorMessage = isEditing ? 'Lỗi khi cập nhật phiếu nhập' : 'Lỗi khi tạo phiếu nhập';

        // Add purchaseId if editing
        if (isEditing) {
            purchaseData.purchaseId = editingPurchaseId;
        }

        var btnSavePurchase = document.getElementById('btn-save-purchase');
        setBtnLoading(btnSavePurchase, true, isEditing ? 'Đang cập nhật...' : 'Đang lưu phiếu...');
        toggleLoading(true, isEditing ? 'Đang cập nhật phiếu nhập...' : 'Đang tạo phiếu nhập...');
        google.script.run
            .withSuccessHandler((res) => {
                toggleLoading(false);
                setBtnLoading(btnSavePurchase, false);
                if (res && res.success) {
                    showToast(res.message || successMessage, 'success');
                    editingPurchaseId = null; // Reset after successful save
                    closePurchaseModal();
                    localStorage.removeItem('TTL_purchases');
                    loadPurchases();
                    LocalStore.setVersion('PRODUCTS', '0');
                    setProducts([]);
                    loadData(); // Refresh products to update stock
                } else {
                    showToast(res.message || errorMessage, 'error');
                }
            })
            .withFailureHandler((error) => {
                toggleLoading(false);
                setBtnLoading(btnSavePurchase, false);
                showToast('Lỗi: ' + (error.message || error), 'error');
            })
            .apiHandler(apiAction, purchaseData);
    }

    /**
     * Close purchase modal
     */
    function closePurchaseModal() {
        const modal = document.getElementById('purchase-modal');
        if (modal) {
            modal.classList.add('hidden');
        }
        editingPurchaseId = null; // Reset editing state when closing
        resetPurchaseForm();
    }

    /**
     * View purchase detail
     */
    function viewPurchaseDetail(purchaseId) {
        if (!purchaseId) {
            showToast('Mã phiếu nhập không hợp lệ', 'error');
            return;
        }

        // Similar to view order detail, show in a modal or page
        loadPurchaseDetail(purchaseId);
        showPurchaseModal(purchaseId);
    }

    /**
     * Edit purchase
     */
    function editPurchase(purchaseId) {
        showPurchaseModal(purchaseId);
    }

    /**
     * Delete purchase
     */
    function deletePurchase(purchaseId) {
        if (!confirm('Bạn có chắc chắn muốn xóa phiếu nhập này?\n\n⚠️ Hành động này sẽ:\n- Hoàn nguyên tồn kho\n- Xóa các giao dịch thanh toán liên quan\n- Cập nhật lại công nợ nhà cung cấp')) {
            return;
        }

        toggleLoading(true);
        google.script.run
            .withSuccessHandler((res) => {
                toggleLoading(false);
                if (res && res.success) {
                    showToast(res.message || 'Xóa phiếu nhập thành công!', 'success');
                    localStorage.removeItem('TTL_purchases');
                    loadPurchases();
                    LocalStore.setVersion('PRODUCTS', '0');
                    setProducts([]);
                    // Invalidate suppliers cache (debt changed)
                    LocalStore.setVersion('SUPPLIERS', '0');
                    suppliers = [];
                    loadData(); // Refresh products & suppliers
                } else {
                    showToast(res.message || 'Lỗi khi xóa phiếu nhập', 'error');
                }
            })
            .withFailureHandler((error) => {
                toggleLoading(false);
                showToast('Lỗi: ' + (error.message || error), 'error');
            })
            .apiHandler('deletePurchase', purchaseId);
    }

    // ============================================
    // SUPPLIERS MANAGEMENT (NHÀ CUNG CẤP)
    // ============================================

    /**
     * Load suppliers for management page
     */
    function loadSuppliersManage(forceRefresh) {
        // Setup search with debounce
        const searchInput = document.getElementById('supplier-search');
        if (searchInput) {
            searchInput.oninput = debounce(() => filterSuppliersList(), 200);
        }

        // Cache-first
        if (!forceRefresh) {
            var cached = LocalStore.getTTL('suppliers');
            if (cached && Array.isArray(cached) && cached.length > 0) {
                suppliersData = cached;
                renderSuppliersList(suppliersData, true);
                return;
            }
        }

        toggleLoading(true);
        google.script.run
            .withSuccessHandler((res) => {
                toggleLoading(false);
                if (res && res.success !== false) {
                    const data = res.data || res;
                    if (Array.isArray(data)) {
                        suppliersData = data;
                        LocalStore.setTTL('suppliers', data, 600);
                        renderSuppliersList(suppliersData, true);
                    } else {
                        suppliersData = [];
                        renderSuppliersList([]);
                    }
                } else {
                    suppliersData = [];
                    renderSuppliersList([]);
                }
            })
            .withFailureHandler((error) => {
                toggleLoading(false);
                console.error('Error loading suppliers:', error);
                suppliersData = [];
                renderSuppliersList([]);
            })
            .apiHandler('getSuppliers', null);
    }

    /**
     * Filter suppliers list
     */
    function filterSuppliersList() {
        const searchInput = document.getElementById('supplier-search');
        if (!searchInput) return;

        const query = searchInput.value.trim().toLowerCase();
        if (!query) {
            renderSuppliersList(suppliersData);
            return;
        }

        const filtered = suppliersData.filter(supplier => {
            const name = (supplier.name || '').toLowerCase();
            const id = (supplier.id || '').toLowerCase();
            const phone = (supplier.phone || '').toLowerCase();
            const email = (supplier.email || '').toLowerCase();
            const address = (supplier.address || '').toLowerCase();

            return name.includes(query) ||
                id.includes(query) ||
                phone.includes(query) ||
                email.includes(query) ||
                address.includes(query);
        });

        renderSuppliersList(filtered, true); // Reset to page 1
    }

    /**
     * Render suppliers list
     */
    function renderSuppliersList(suppliers, resetPage = false) {
        const tbody = document.getElementById('suppliers-list-body');
        const mobileContainer = document.getElementById('suppliers-list-mobile');
        if (!tbody) return;

        // Save filtered suppliers for pagination
        filteredSuppliers = suppliers || [];

        // Reset to page 1 if requested
        if (resetPage) {
            suppliersCurrentPage = 1;
        }

        // Calculate pagination
        const totalItems = filteredSuppliers.length;
        const totalPages = Math.ceil(totalItems / suppliersItemsPerPage);
        const startIndex = (suppliersCurrentPage - 1) * suppliersItemsPerPage;
        const endIndex = startIndex + suppliersItemsPerPage;
        const dataToRender = filteredSuppliers.slice(startIndex, endIndex);

        if (!dataToRender || dataToRender.length === 0) {
            tbody.innerHTML = '<tr><td colspan="8" class="text-center py-8 text-gray-400">Không có dữ liệu</td></tr>';
            if (mobileContainer) mobileContainer.innerHTML = '<p class="text-center py-8 text-gray-400">Không có dữ liệu</p>';
            return;
        }

        // Desktop table rows
        tbody.innerHTML = dataToRender.map(s => {
            const statusColor = s.status === 'Active'
                ? 'bg-green-100 text-green-800'
                : 'bg-gray-100 text-gray-800';
            const debt = s.debt || 0;

            return `
                <tr class="hover:bg-gray-50 border-b border-gray-100" style="cursor: pointer;" onclick="if(event.target.tagName !== 'BUTTON' && !event.target.closest('button')) viewSupplierDetail('${escapeHtml(s.id)}')">
                    <td class="px-4 py-3 font-medium">${escapeHtml(s.id)}</td>
                    <td class="px-4 py-3">${escapeHtml(s.name)}</td>
                    <td class="px-4 py-3">${escapeHtml(s.phone || '-')}</td>
                    <td class="px-4 py-3">${escapeHtml(s.email || '-')}</td>
                    <td class="px-4 py-3">${escapeHtml(s.address || '-')}</td>
                    <td class="px-4 py-3 text-right ${debt > 0 ? 'text-red-600 font-medium' : ''}">${formatMoney(debt)}</td>
                    <td class="px-4 py-3 text-center">
                        <span class="px-2 py-1 rounded-full text-xs font-medium ${statusColor}">${s.status === 'Active' ? 'Hoạt động' : 'Ngừng hoạt động'}</span>
                    </td>
                    <td class="px-4 py-3 text-center">
                        <button onclick="event.stopPropagation(); viewSupplierDetail('${escapeHtml(s.id)}')" class="text-green-600 hover:text-green-800 mr-2" title="Xem chi tiết">
                            👁️
                        </button>
                        <button onclick="event.stopPropagation(); editSupplier('${escapeHtml(s.id)}')" class="text-blue-600 hover:text-blue-800 mr-2" title="Sửa">
                            ✏️
                        </button>
                        <button onclick="event.stopPropagation(); deleteSupplier('${escapeHtml(s.id)}')" class="text-red-600 hover:text-red-800" title="Xóa">
                            🗑️
                        </button>
                    </td>
                </tr>
            `;
        }).join('');

        // Mobile card view
        if (mobileContainer) {
            mobileContainer.innerHTML = dataToRender.map(s => {
                const statusColor = s.status === 'Active'
                    ? 'bg-green-100 text-green-800'
                    : 'bg-gray-100 text-gray-800';
                const statusText = s.status === 'Active' ? 'Hoạt động' : 'Ngừng HĐ';
                const debt = s.debt || 0;
                const debtClass = debt > 0 ? 'text-red-600 font-bold' : 'text-green-600';

                return `
                    <div class="mobile-card" style="cursor: pointer;" onclick="if(event.target.tagName !== 'BUTTON' && !event.target.closest('button')) viewSupplierDetail('${escapeHtml(s.id)}')">
                        <div class="flex justify-between items-start mb-2">
                            <div>
                                <p class="font-bold text-gray-900">${escapeHtml(s.name)}</p>
                                <p class="text-xs text-gray-500">${escapeHtml(s.id)}</p>
                            </div>
                            <span class="px-2 py-1 rounded-full text-xs font-medium ${statusColor}">${statusText}</span>
                        </div>
                        <div class="grid grid-cols-2 gap-2 text-sm mb-3">
                            <div><span class="text-gray-500">SĐT:</span> ${escapeHtml(s.phone || '-')}</div>
                            <div><span class="text-gray-500">Công nợ:</span> <span class="${debtClass}">${formatMoney(debt)}</span></div>
                        </div>
                        <div class="flex gap-3 pt-2 border-t border-gray-100">
                            <button onclick="event.stopPropagation(); viewSupplierDetail('${escapeHtml(s.id)}')" class="text-green-600 hover:text-green-800 text-sm flex items-center gap-1" title="Xem chi tiết">
                                👁️ Xem
                            </button>
                            <button onclick="event.stopPropagation(); editSupplier('${escapeHtml(s.id)}')" class="text-blue-600 hover:text-blue-800 text-sm flex items-center gap-1" title="Sửa">
                                ✏️ Sửa
                            </button>
                            <button onclick="event.stopPropagation(); deleteSupplier('${escapeHtml(s.id)}')" class="text-red-600 hover:text-red-800 text-sm flex items-center gap-1" title="Xóa">
                                🗑️ Xóa
                            </button>
                        </div>
                    </div>
                `;
            }).join('');
        }

        // Render pagination controls
        renderPagination('suppliers', totalPages, totalItems, suppliersCurrentPage, suppliersItemsPerPage);
    }

    function goToSuppliersPage(page) {
        if (page < 1 || page > Math.ceil(filteredSuppliers.length / suppliersItemsPerPage)) return;
        suppliersCurrentPage = page;
        renderSuppliersList(filteredSuppliers, false);
    }

    /**
     * Show supplier modal
     */
    function showSupplierModal(supplierId = null) {
        const modal = document.getElementById('supplier-modal');
        const title = document.getElementById('supplier-modal-title');

        if (modal) {
            modal.classList.remove('hidden');
            if (title) {
                title.textContent = supplierId ? 'Sửa Nhà Cung Cấp' : 'Thêm Nhà Cung Cấp';
            }

            // Reset form
            resetSupplierForm();

            // Load supplier data if editing
            if (supplierId) {
                loadSupplierDetail(supplierId);
            }
        }
    }

    /**
     * Reset supplier form
     */
    function resetSupplierForm() {
        document.getElementById('supplier-id').value = '';
        document.getElementById('supplier-code').value = '';
        document.getElementById('supplier-name').value = '';
        document.getElementById('supplier-phone').value = '';
        document.getElementById('supplier-email').value = '';
        document.getElementById('supplier-address').value = '';
        document.getElementById('supplier-notes').value = '';
        document.getElementById('supplier-status').value = 'Active';
    }

    /**
     * Load supplier detail for editing
     */
    function loadSupplierDetail(supplierId) {
        const supplier = suppliersData.find(s => s.id === supplierId);
        if (!supplier) {
            showToast('Không tìm thấy nhà cung cấp', 'error');
            return;
        }

        document.getElementById('supplier-id').value = supplier.id;
        document.getElementById('supplier-code').value = supplier.id;
        document.getElementById('supplier-code').disabled = true; // Disable code when editing
        document.getElementById('supplier-name').value = supplier.name || '';
        document.getElementById('supplier-phone').value = supplier.phone || '';
        document.getElementById('supplier-email').value = supplier.email || '';
        document.getElementById('supplier-address').value = supplier.address || '';
        document.getElementById('supplier-notes').value = supplier.notes || '';
        document.getElementById('supplier-status').value = supplier.status || 'Active';
    }

    /**
     * Save supplier (create or update)
     */
    function saveSupplier(event) {
        if (event) event.preventDefault();

        const supplierId = document.getElementById('supplier-id').value;
        const supplierData = {
            id: document.getElementById('supplier-code').value.trim(),
            name: document.getElementById('supplier-name').value.trim(),
            phone: document.getElementById('supplier-phone').value.trim(),
            email: document.getElementById('supplier-email').value.trim(),
            address: document.getElementById('supplier-address').value.trim(),
            notes: document.getElementById('supplier-notes').value.trim(),
            status: document.getElementById('supplier-status').value
        };

        if (!supplierData.id || !supplierData.name) {
            showToast('Vui lòng nhập đầy đủ thông tin bắt buộc', 'warning');
            return;
        }

        toggleLoading(true);
        const action = supplierId ? 'updateSupplier' : 'createSupplier';

        google.script.run
            .withSuccessHandler((res) => {
                toggleLoading(false);
                if (res && res.success) {
                    showToast(res.message || 'Lưu nhà cung cấp thành công!', 'success');
                    closeSupplierModal();
                    localStorage.removeItem('TTL_suppliers');
                    loadSuppliersManage();
                    loadSuppliers();
                } else {
                    showToast(res.message || 'Lỗi khi lưu nhà cung cấp', 'error');
                }
            })
            .withFailureHandler((error) => {
                toggleLoading(false);
                showToast('Lỗi: ' + (error.message || error), 'error');
            })
            .apiHandler(action, supplierData);
    }

    /**
     * Edit supplier
     */
    function editSupplier(supplierId) {
        showSupplierModal(supplierId);
    }

    /**
     * Delete supplier
     */
    function deleteSupplier(supplierId) {
        if (!confirm('Bạn có chắc chắn muốn xóa nhà cung cấp này? Nếu nhà cung cấp đã có sản phẩm liên kết, bạn sẽ không thể xóa.')) {
            return;
        }

        toggleLoading(true);
        google.script.run
            .withSuccessHandler((res) => {
                toggleLoading(false);
                if (res && res.success) {
                    showToast(res.message || 'Xóa nhà cung cấp thành công!', 'success');
                    localStorage.removeItem('TTL_suppliers');
                    loadSuppliersManage();
                    loadSuppliers();
                } else {
                    showToast(res.message || 'Lỗi khi xóa nhà cung cấp', 'error');
                }
            })
            .withFailureHandler((error) => {
                toggleLoading(false);
                showToast('Lỗi: ' + (error.message || error), 'error');
            })
            .apiHandler('deleteSupplier', supplierId);
    }

    /**
     * Close supplier modal
     */
    function closeSupplierModal() {
        const modal = document.getElementById('supplier-modal');
        if (modal) {
            modal.classList.add('hidden');
        }
        resetSupplierForm();
        // Re-enable code input
        const codeInput = document.getElementById('supplier-code');
        if (codeInput) {
            codeInput.disabled = false;
        }
    }

    /**
     * Refresh suppliers data
     */
    function refreshSuppliersData() {
        showToast('Đang làm mới dữ liệu...', 'info');
        localStorage.removeItem('TTL_suppliers');
        google.script.run
            .withSuccessHandler(() => {
                loadSuppliersManage();
                showToast('Đã làm mới dữ liệu nhà cung cấp thành công', 'success');
            })
            .withFailureHandler((err) => {
                console.error('Error clearing cache:', err);
                loadSuppliersManage();
                showToast('Đã làm mới dữ liệu nhà cung cấp', 'success');
            })
            .apiHandler('clearCache', { sheetName: 'Nhà Cung Cấp' });
    }

    /**
     * Load employees for order form dropdown
     */
    function loadEmployeesForOrder() {
        var select = document.getElementById('order-employee');
        google.script.run
            .withSuccessHandler((res) => {
                if (res && res.success && res.data && res.data.length > 0) {
                    employees = res.data;
                    if (select) {
                        var empFrag = document.createDocumentFragment();
                        employees.filter(e => e.status === 'Active').forEach(emp => {
                            var option = document.createElement('option');
                            option.value = emp.id;
                            option.textContent = emp.name + (emp.position ? ' - ' + emp.position : '');
                            empFrag.appendChild(option);
                        });
                        while (select.options.length > 1) select.remove(1);
                        select.appendChild(empFrag);
                        // Auto-select current logged-in user
                        if (currentUser && currentUser.employeeId) {
                            select.value = currentUser.employeeId;
                        }
                    }
                } else {
                    // No permission or no data — fallback to current user only
                    setCurrentUserAsEmployee(select);
                }
            })
            .withFailureHandler((error) => {
                console.error('Error loading employees for order:', error);
                setCurrentUserAsEmployee(select);
            })
            .apiHandler('getEmployees', null);
    }

    /** Fallback: populate employee dropdown with current logged-in user only */
    function setCurrentUserAsEmployee(select) {
        if (!select || !currentUser || !currentUser.employeeId) return;
        // Clear all options and add only current user (no blank default)
        select.innerHTML = '';
        var opt = document.createElement('option');
        opt.value = currentUser.employeeId;
        opt.textContent = currentUser.employeeName || currentUser.username || '';
        opt.selected = true;
        select.appendChild(opt);
    }

    /**
     * Load employees management page
     */
    /**
     * Switch between Employees tab panels (list / accounts)
     */
    function switchEmpTab(tab) {
        var panels = { list: 'emp-panel-list', accounts: 'emp-panel-accounts' };
        var tabs = { list: 'emp-tab-list', accounts: 'emp-tab-accounts' };
        Object.keys(panels).forEach(function(key) {
            var panel = document.getElementById(panels[key]);
            var btn = document.getElementById(tabs[key]);
            if (!panel || !btn) return;
            if (key === tab) {
                panel.classList.remove('hidden');
                btn.classList.add('border-blue-600', 'text-blue-600');
                btn.classList.remove('border-transparent', 'text-gray-500');
            } else {
                panel.classList.add('hidden');
                btn.classList.remove('border-blue-600', 'text-blue-600');
                btn.classList.add('border-transparent', 'text-gray-500');
            }
        });
        if (tab === 'accounts' && currentUser && currentUser.role === 'Admin') {
            loadUsers();
        }
    }

    function loadEmployeesManage(forceRefresh) {
        // Setup search with debounce
        const searchInput = document.getElementById('employee-search');
        if (searchInput) {
            searchInput.oninput = debounce(() => filterEmployeesList(), 200);
        }

        // Cache-first
        if (!forceRefresh) {
            var cached = LocalStore.getTTL('employees');
            if (cached && Array.isArray(cached) && cached.length > 0) {
                employeesData = cached;
                renderEmployeesList(employeesData, true);
                return;
            }
        }

        toggleLoading(true);
        google.script.run
            .withSuccessHandler((res) => {
                toggleLoading(false);
                if (res && res.success !== false) {
                    const data = res.data || res;
                    if (Array.isArray(data)) {
                        employeesData = data;
                        LocalStore.setTTL('employees', data, 600);
                        renderEmployeesList(employeesData, true);
                    } else {
                        employeesData = [];
                        renderEmployeesList([]);
                    }
                } else {
                    employeesData = [];
                    renderEmployeesList([]);
                }
            })
            .withFailureHandler((error) => {
                toggleLoading(false);
                console.error('Error loading employees:', error);
                employeesData = [];
                renderEmployeesList([]);
            })
            .apiHandler('getEmployees', null);
    }

    /**
     * Filter employees list
     */
    function filterEmployeesList() {
        const searchTerm = (document.getElementById('employee-search')?.value || '').toLowerCase().trim();

        if (!searchTerm) {
            filteredEmployees = employeesData;
        } else {
            filteredEmployees = employeesData.filter(emp =>
                (emp.id && emp.id.toLowerCase().includes(searchTerm)) ||
                (emp.name && emp.name.toLowerCase().includes(searchTerm)) ||
                (emp.phone && emp.phone.toLowerCase().includes(searchTerm)) ||
                (emp.email && emp.email.toLowerCase().includes(searchTerm))
            );
        }

        renderEmployeesList(filteredEmployees, true);
    }

    /**
     * Render employees list
     */
    function renderEmployeesList(data, resetPage = false) {
        const tbody = document.getElementById('employees-list-body');
        if (!tbody) return;

        if (resetPage) {
            employeesCurrentPage = 1;
        }

        // Store filtered data
        filteredEmployees = data || [];

        if (!filteredEmployees || filteredEmployees.length === 0) {
            tbody.innerHTML = `
                <tr>
                    <td colspan="10" class="text-center py-8 text-gray-400">Không có dữ liệu</td>
                </tr>
            `;
            renderPagination('employees', 0, 0, 1, employeesItemsPerPage);
            return;
        }

        // Calculate pagination
        const totalItems = filteredEmployees.length;
        const totalPages = Math.ceil(totalItems / employeesItemsPerPage);
        const startIndex = (employeesCurrentPage - 1) * employeesItemsPerPage;
        const endIndex = Math.min(startIndex + employeesItemsPerPage, totalItems);
        const pageData = filteredEmployees.slice(startIndex, endIndex);

        var roleLabels = { 'Admin': 'Quản trị', 'Manager': 'Quản lý', 'Cashier': 'Thu ngân', 'Viewer': 'Chỉ xem' };
        var roleColors = { 'Admin': 'bg-red-100 text-red-700', 'Manager': 'bg-blue-100 text-blue-700', 'Cashier': 'bg-green-100 text-green-700', 'Viewer': 'bg-gray-100 text-gray-600' };

        tbody.innerHTML = pageData.map(emp => {
            const statusColor = emp.status === 'Active' ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800';
            const salary = parseFloat(emp.baseSalary || 0);
            var roleBadge = emp.role ? '<span class="px-2 py-1 rounded-full text-xs font-medium ' + (roleColors[emp.role] || 'bg-gray-100 text-gray-500') + '">' + (roleLabels[emp.role] || emp.role) + '</span>' : '<span class="text-xs text-gray-400">Chưa cấp</span>';

            return `
                <tr class="border-b border-gray-100 hover:bg-gray-50 cursor-pointer" onclick="viewEmployeeDetail('${escapeHtml(emp.id)}')">
                    <td class="px-4 py-3 font-medium">${escapeHtml(emp.id)}</td>
                    <td class="px-4 py-3">${escapeHtml(emp.name || '-')}</td>
                    <td class="px-4 py-3">${escapeHtml(emp.phone || '-')}</td>
                    <td class="px-4 py-3">${escapeHtml(emp.email || '-')}</td>
                    <td class="px-4 py-3">${escapeHtml(emp.position || '-')}</td>
                    <td class="px-4 py-3">${escapeHtml(emp.department || '-')}</td>
                    <td class="px-4 py-3 text-right">${formatMoney(salary)}</td>
                    <td class="px-4 py-3 text-center">${roleBadge}</td>
                    <td class="px-4 py-3 text-center">
                        <span class="px-2 py-1 rounded-full text-xs font-medium ${statusColor}">${emp.status === 'Active' ? 'Hoạt động' : 'Ngừng hoạt động'}</span>
                    </td>
                    <td class="px-4 py-3 text-center" onclick="event.stopPropagation()">
                        <button onclick="viewEmployeeDetail('${escapeHtml(emp.id)}')" class="text-blue-600 hover:text-blue-800 mr-2" title="Xem chi tiết">
                            👁️
                        </button>
                        <button onclick="showEmployeeModal('${escapeHtml(emp.id)}')" class="text-blue-600 hover:text-blue-800 mr-2" title="Sửa">
                            ✏️
                        </button>
                        <button onclick="deleteEmployee('${escapeHtml(emp.id)}')" class="text-red-600 hover:text-red-800 mr-2" title="Xóa">
                            🗑️
                        </button>
                        <button onclick="viewEmployeeStatistics('${escapeHtml(emp.id)}')" class="text-green-600 hover:text-green-800" title="Thống kê">
                            📊
                        </button>
                    </td>
                </tr>
            `;
        }).join('');

        // Render pagination controls
        renderPagination('employees', totalPages, totalItems, employeesCurrentPage, employeesItemsPerPage);
    }

    function goToEmployeesPage(page) {
        if (page < 1 || page > Math.ceil(filteredEmployees.length / employeesItemsPerPage)) return;
        employeesCurrentPage = page;
        renderEmployeesList(filteredEmployees, false);
    }

    /**
     * Tạo mã nhân viên tiếp theo (NV001, NV002, ...)
     */
    function generateNextEmployeeId() {
        var maxNum = 0;
        if (employeesData && employeesData.length > 0) {
            for (var i = 0; i < employeesData.length; i++) {
                var id = String(employeesData[i].id || '');
                var match = id.match(/^NV(\d+)$/i);
                if (match) {
                    var num = parseInt(match[1], 10);
                    if (num > maxNum) maxNum = num;
                }
            }
        }
        var next = maxNum + 1;
        return 'NV' + String(next).padStart(3, '0');
    }

    /**
     * Show employee modal
     */
    function showEmployeeModal(employeeId = null) {
        const modal = document.getElementById('employee-modal');
        const title = document.getElementById('employee-modal-title');

        if (modal) {
            modal.classList.remove('hidden');
            if (title) {
                title.textContent = employeeId ? 'Sửa Nhân Viên' : 'Thêm Nhân Viên';
            }

            // Reset form
            resetEmployeeForm();

            // Auto-generate ID for new employee
            if (!employeeId) {
                var codeInput = document.getElementById('employee-code');
                if (codeInput) {
                    codeInput.value = generateNextEmployeeId();
                }
            }

            // Load employee data if editing
            if (employeeId) {
                loadEmployeeDetail(employeeId);
            }
        }
    }

    /**
     * Reset employee form
     */
    function resetEmployeeForm() {
        const form = document.getElementById('employee-form');
        if (form) {
            form.reset();
        }
        // Clear hidden ID field
        const idField = document.getElementById('employee-id');
        if (idField) idField.value = '';
        // Clear code input (will be auto-filled by showEmployeeModal)
        const codeInput = document.getElementById('employee-code');
        if (codeInput) {
            codeInput.value = '';
        }
        // Reset account fields - mặc định bật
        var enableAcc = document.getElementById('employee-enable-account');
        if (enableAcc) { enableAcc.checked = true; enableAcc.disabled = false; }
        var toggleLabel = document.getElementById('employee-account-toggle-label');
        if (toggleLabel) { toggleLabel.textContent = 'Cấp tài khoản'; toggleLabel.className = 'ml-2 text-xs text-indigo-600 font-medium'; }
        toggleAccountFields();
        var usernameField = document.getElementById('employee-username');
        if (usernameField) { usernameField.value = ''; usernameField.disabled = false; usernameField.classList.remove('bg-gray-100'); }
        var passwordGroup = document.getElementById('employee-password') ? document.getElementById('employee-password').parentElement : null;
        if (passwordGroup) passwordGroup.classList.remove('hidden');
        var passwordField = document.getElementById('employee-password');
        if (passwordField) { passwordField.value = '123456'; passwordField.disabled = false; }
        var roleField = document.getElementById('employee-role');
        if (roleField) { roleField.value = 'Cashier'; roleField.disabled = false; roleField.classList.remove('bg-gray-100'); }
        var accStatus = document.getElementById('employee-account-status');
        if (accStatus) accStatus.classList.add('hidden');
    }

    /**
     * Toggle hiện/ẩn fields tài khoản trong form nhân viên
     */
    function toggleAccountFields() {
        var checkbox = document.getElementById('employee-enable-account');
        var fields = document.getElementById('employee-account-fields');
        var label = document.getElementById('employee-account-toggle-label');
        if (!checkbox || !fields) return;
        if (checkbox.checked) {
            fields.classList.remove('hidden');
            if (label) label.textContent = 'Cấp tài khoản';
        } else {
            fields.classList.add('hidden');
            if (label) label.textContent = 'Không cấp';
        }
    }

    /**
     * Load employee detail for editing
     */
    function loadEmployeeDetail(employeeId) {
        toggleLoading(true);
        google.script.run
            .withSuccessHandler((res) => {
                toggleLoading(false);
                if (res && res.success && res.data) {
                    const emp = res.data;
                    document.getElementById('employee-id').value = emp.id || '';
                    document.getElementById('employee-code').value = emp.id || '';
                    document.getElementById('employee-name').value = emp.name || '';
                    document.getElementById('employee-phone').value = emp.phone || '';
                    document.getElementById('employee-email').value = emp.email || '';
                    document.getElementById('employee-address').value = emp.address || '';
                    document.getElementById('employee-birthday').value = emp.birthday || '';
                    document.getElementById('employee-start-date').value = emp.hireDate || emp.startDate || '';
                    document.getElementById('employee-position').value = emp.position || '';
                    document.getElementById('employee-department').value = emp.department || '';
                    document.getElementById('employee-salary').value = emp.baseSalary || '0';
                    document.getElementById('employee-commission').value = emp.commissionRate || emp.commissionPercent || '0';
                    document.getElementById('employee-status').value = emp.status || 'Active';
                    document.getElementById('employee-notes').value = emp.notes || '';
                    // Load auth info
                    var enableAcc = document.getElementById('employee-enable-account');
                    var toggleLabel = document.getElementById('employee-account-toggle-label');
                    if (emp.username) {
                        // Đã có tài khoản: cho phép Admin chỉnh sửa username/password/role
                        if (enableAcc) { enableAcc.checked = true; enableAcc.disabled = true; }
                        if (toggleLabel) { toggleLabel.textContent = 'Đã cấp'; toggleLabel.className = 'ml-2 text-xs text-green-600 font-medium'; }
                        document.getElementById('employee-account-fields').classList.remove('hidden');

                        var usernameEl = document.getElementById('employee-username');
                        usernameEl.value = emp.username;
                        usernameEl.disabled = false;
                        usernameEl.classList.remove('bg-gray-100');
                        usernameEl.setAttribute('data-original-username', emp.username);

                        var passwordEl = document.getElementById('employee-password');
                        passwordEl.parentElement.classList.remove('hidden');
                        passwordEl.value = '';
                        passwordEl.removeAttribute('required');
                        var pwLabel = passwordEl.parentElement.querySelector('label');
                        if (pwLabel) pwLabel.textContent = 'Mật khẩu mới';
                        var pwHint = passwordEl.parentElement.querySelector('p');
                        if (pwHint) pwHint.textContent = 'Để trống nếu không muốn đổi';

                        var roleEl = document.getElementById('employee-role');
                        roleEl.value = emp.role || 'Cashier';
                        roleEl.disabled = false;
                        roleEl.classList.remove('bg-gray-100');
                        roleEl.setAttribute('data-original-role', emp.role || 'Cashier');

                        var accStatus = document.getElementById('employee-account-status');
                        if (accStatus) {
                            accStatus.innerHTML = '<span class="flex items-center gap-1"><svg class="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg> Đã có tài khoản. Có thể chỉnh sửa username, mật khẩu, vai trò.</span>';
                            accStatus.classList.remove('hidden');
                        }
                    } else {
                        // Chưa có tài khoản: bật toggle mặc định
                        if (enableAcc) { enableAcc.checked = true; enableAcc.disabled = false; }
                        // Reset data-original-username nếu có
                        var usernameEl2 = document.getElementById('employee-username');
                        if (usernameEl2) usernameEl2.removeAttribute('data-original-username');
                        var roleEl2 = document.getElementById('employee-role');
                        if (roleEl2) roleEl2.removeAttribute('data-original-role');
                        toggleAccountFields();
                    }
                } else {
                    showToast('Không tìm thấy nhân viên', 'error');
                }
            })
            .withFailureHandler((error) => {
                toggleLoading(false);
                showToast('Lỗi khi tải thông tin nhân viên: ' + (error.message || error), 'error');
            })
            .apiHandler('getEmployeeDetail', employeeId);
    }

    /**
     * Save employee (create or update)
     */
    function saveEmployee(event) {
        if (event) event.preventDefault();

        const employeeId = document.getElementById('employee-id').value;
        const employeeData = {
            id: document.getElementById('employee-code').value.trim(),
            name: document.getElementById('employee-name').value.trim(),
            phone: document.getElementById('employee-phone').value.trim(),
            email: document.getElementById('employee-email').value.trim(),
            address: document.getElementById('employee-address').value.trim(),
            birthday: document.getElementById('employee-birthday').value.trim(),
            hireDate: document.getElementById('employee-start-date').value.trim(),
            position: document.getElementById('employee-position').value.trim(),
            department: document.getElementById('employee-department').value.trim(),
            baseSalary: parseFloat(document.getElementById('employee-salary').value) || 0,
            commissionRate: parseFloat(document.getElementById('employee-commission').value) || 0,
            status: document.getElementById('employee-status').value,
            notes: document.getElementById('employee-notes').value.trim()
        };

        if (!employeeData.name) {
            showToast('Vui lòng nhập Họ Tên nhân viên', 'warning');
            return;
        }

        // Auto-generate ID nếu chưa có
        if (!employeeData.id) {
            employeeData.id = generateNextEmployeeId();
        }

        // Thêm auth fields nếu cấp tài khoản
        var enableAccEl = document.getElementById('employee-enable-account');
        var accChecked = enableAccEl ? enableAccEl.checked : false;
        var accUsernameEl = document.getElementById('employee-username');
        var originalUsername = accUsernameEl ? accUsernameEl.getAttribute('data-original-username') : null;
        var isExistingAccount = !!originalUsername;

        if (accChecked && !isExistingAccount) {
            // Tạo tài khoản mới
            var accUsername = accUsernameEl ? accUsernameEl.value.trim() : '';
            var accPassword = document.getElementById('employee-password').value;
            var accRole = document.getElementById('employee-role').value;
            if (!accUsername) {
                showToast('Vui lòng nhập Username cho tài khoản', 'warning');
                return;
            }
            if (!accPassword || accPassword.length < 6) {
                showToast('Mật khẩu phải ít nhất 6 ký tự', 'warning');
                return;
            }
            employeeData.enableAccount = true;
            employeeData.username = accUsername;
            employeeData.password = accPassword;
            employeeData.role = accRole;
        } else if (accChecked && isExistingAccount) {
            // Cập nhật tài khoản đã có: phát hiện thay đổi
            var newUsername = accUsernameEl.value.trim();
            var newPassword = document.getElementById('employee-password').value;
            var newRole = document.getElementById('employee-role').value;
            var origRole = document.getElementById('employee-role').getAttribute('data-original-role') || '';
            if (!newUsername) {
                showToast('Username không được để trống', 'warning');
                return;
            }
            if (newPassword && newPassword.length < 6) {
                showToast('Mật khẩu phải ít nhất 6 ký tự', 'warning');
                return;
            }
            // Chỉ cập nhật nếu có thay đổi
            if (newUsername !== originalUsername || newPassword || newRole !== origRole) {
                employeeData._updateAccount = {
                    employeeId: employeeData.id || document.getElementById('employee-code').value.trim(),
                    username: newUsername,
                    password: newPassword,
                    role: newRole
                };
            }
        }

        toggleLoading(true);
        const action = employeeId ? 'updateEmployee' : 'createEmployee';

        google.script.run
            .withSuccessHandler((res) => {
                toggleLoading(false);
                if (res && res.success) {
                    if (employeeData._updateAccount) {
                        // Cập nhật tài khoản sau khi lưu nhân viên thành công
                        toggleLoading(true);
                        google.script.run
                            .withSuccessHandler((accRes) => {
                                toggleLoading(false);
                                closeEmployeeModal();
                                if (accRes && accRes.success) {
                                    showToast('Lưu nhân viên và cập nhật tài khoản thành công!', 'success');
                                } else {
                                    showToast('Lưu nhân viên OK, nhưng lỗi tài khoản: ' + (accRes && accRes.message || ''), 'warning');
                                }
                                localStorage.removeItem('TTL_employees');
                                localStorage.removeItem('TTL_usersManage');
                                loadEmployeesManage();
                            })
                            .withFailureHandler((err) => {
                                toggleLoading(false);
                                closeEmployeeModal();
                                showToast('Lưu nhân viên OK, nhưng lỗi tài khoản: ' + (err.message || err), 'warning');
                                localStorage.removeItem('TTL_employees');
                                localStorage.removeItem('TTL_usersManage');
                                loadEmployeesManage();
                            })
                            .apiHandler('updateEmployeeAccount', employeeData._updateAccount);
                    } else {
                        closeEmployeeModal();
                        showToast(res.message || 'Lưu nhân viên thành công!', 'success');
                        localStorage.removeItem('TTL_employees');
                        loadEmployeesManage();
                    }
                } else {
                    showToast(res.message || 'Lỗi khi lưu nhân viên', 'error');
                }
            })
            .withFailureHandler((error) => {
                toggleLoading(false);
                showToast('Lỗi: ' + (error.message || error), 'error');
            })
            .apiHandler(action, employeeData);
    }

    /**
     * Delete employee
     */
    function deleteEmployee(employeeId) {
        if (!confirm('Bạn có chắc chắn muốn xóa nhân viên này? Nếu nhân viên đã có đơn hàng liên kết, bạn sẽ không thể xóa.')) {
            return;
        }

        toggleLoading(true);
        google.script.run
            .withSuccessHandler((res) => {
                toggleLoading(false);
                if (res && res.success) {
                    showToast(res.message || 'Xóa nhân viên thành công!', 'success');
                    localStorage.removeItem('TTL_employees');
                    localStorage.removeItem('TTL_usersManage');
                    loadEmployeesManage();
                } else {
                    showToast(res.message || 'Lỗi khi xóa nhân viên', 'error');
                }
            })
            .withFailureHandler((error) => {
                toggleLoading(false);
                showToast('Lỗi: ' + (error.message || error), 'error');
            })
            .apiHandler('deleteEmployee', employeeId);
    }

