    /**
     * Update warranty request status
     */
    function updateWarrantyRequestStatus(requestId, status) {
        if (status === 'Hoàn thành') {
            showCompleteWarrantyRequestModal(requestId);
            return;
        }

        toggleLoading(true);
        google.script.run
            .withSuccessHandler((res) => {
                toggleLoading(false);
                if (res && res.success) {
                    showToast('Cập nhật trạng thái thành công!', 'success');
                    closeWarrantyRequestDetailModal();
                    localStorage.removeItem('TTL_warranties');
                    loadWarranties();
                } else {
                    showToast(res.message || 'Lỗi khi cập nhật trạng thái', 'error');
                }
            })
            .withFailureHandler((error) => {
                toggleLoading(false);
                showToast('Lỗi: ' + (error.message || error), 'error');
            })
            .apiHandler('updateWarrantyRequestStatus', {
                requestId: requestId,
                status: status,
                updateData: {}
            });
    }

