    // ========================================
    // SALES VELOCITY ANALYTICS FUNCTIONS
    // ========================================

    /**
     * Load velocity dashboard data
     */
    function loadVelocityDashboard() {
        google.script.run
            .withSuccessHandler((res) => {
                if (res && res.success && res.data) {
                    renderVelocityDashboard(res.data);
                } else {
                    const container = document.getElementById('velocity-dashboard-content');
                    if (container) {
                        container.innerHTML = '<p class="text-sm text-red-500">Không thể tải dữ liệu</p>';
                    }
                }
            })
            .withFailureHandler((err) => {
                console.error('Error loading velocity dashboard:', err);
                const container = document.getElementById('velocity-dashboard-content');
                if (container) {
                    container.innerHTML = '<p class="text-sm text-red-500">Lỗi: ' + err.toString() + '</p>';
                }
            })
            .apiHandler('getVelocityDashboard', null);
    }

    /**
     * Render velocity dashboard widget
     */
    function renderVelocityDashboard(data) {
        const container = document.getElementById('velocity-dashboard-content');
        if (!container) return;

        const summary = data.summary || {};
        const alerts = data.alerts || [];

        let html = '';

        // Summary stats
        html += '<div class="grid grid-cols-3 gap-3 mb-4">';
        html += `
            <div class="bg-white bg-opacity-60 rounded-lg p-3 text-center">
                <div class="text-2xl font-bold text-red-600">${summary.criticalCount || 0}</div>
                <div class="text-xs text-gray-600">🔴 Khẩn cấp</div>
            </div>
            <div class="bg-white bg-opacity-60 rounded-lg p-3 text-center">
                <div class="text-2xl font-bold text-yellow-600">${summary.warningCount || 0}</div>
                <div class="text-xs text-gray-600">🟡 Cảnh báo</div>
            </div>
            <div class="bg-white bg-opacity-60 rounded-lg p-3 text-center">
                <div class="text-2xl font-bold text-green-600">${summary.safeCount || 0}</div>
                <div class="text-xs text-gray-600">🟢 An toàn</div>
            </div>
        `;
        html += '</div>';

        // Alerts list
        if (alerts && alerts.length > 0) {
            html += '<div class="space-y-2">';
            html += '<h4 class="text-sm font-semibold text-gray-700 mb-2">Sản phẩm cần chú ý:</h4>';

            alerts.slice(0, 5).forEach(alert => {
                const icon = alert.alertLevel === 'red' ? '🔴' : '🟡';
                const bgColor = alert.alertLevel === 'red' ? 'bg-red-50' : 'bg-yellow-50';
                const textColor = alert.alertLevel === 'red' ? 'text-red-800' : 'text-yellow-800';

                html += `
                    <div class="${bgColor} rounded-lg p-3 flex items-center justify-between">
                        <div class="flex-1">
                            <div class="font-medium ${textColor}">${icon} ${alert.productName || alert.sku}</div>
                            <div class="text-xs text-gray-600">
                                Tồn: ${alert.currentStock} | 
                                Tốc độ: ${alert.velocity ? alert.velocity.toFixed(1) : 0} cái/ngày |
                                Hết trong: ${alert.daysUntilStockOut} ngày
                            </div>
                        </div>
                        <button onclick="showProductVelocityDetail('${alert.sku}')" 
                            class="text-xs px-2 py-1 bg-white rounded hover:bg-gray-100">
                            Chi tiết
                        </button>
                    </div>
                `;
            });

            html += '</div>';

            if (alerts.length > 5) {
                html += `<p class="text-xs text-gray-500 mt-2">... và ${alerts.length - 5} sản phẩm khác</p>`;
            }
        } else {
            html += '<p class="text-sm text-green-600">✅ Tất cả sản phẩm đều ở mức an toàn</p>';
        }

        container.innerHTML = html;
    }

    /**
     * Show product velocity detail modal
     */
    function showProductVelocityDetail(sku) {
        google.script.run
            .withSuccessHandler((res) => {
                if (res && res.success && res.data) {
                    renderProductVelocityModal(res.data);
                } else {
                    alert('Không thể tải dữ liệu sản phẩm');
                }
            })
            .withFailureHandler((err) => {
                alert('Lỗi: ' + err.toString());
            })
            .apiHandler('getProductVelocity', { sku: sku, days: 7 });
    }

    /**
     * Render product velocity detail modal
     */
    function renderProductVelocityModal(data) {
        const velocity = data.velocity || {};
        const stockOut = data.stockOut || {};
        const trend = data.trend || {};
        const reorder = data.reorder || {};

        const alertColor = stockOut.alertLevel === 'red' ? 'red' : stockOut.alertLevel === 'yellow' ? 'yellow' : 'green';

        const modalHtml = `
            <div id="velocity-modal" class="fixed inset-0 bg-black bg-opacity-50 z-50 flex items-center justify-center p-4" onclick="if(event.target.id==='velocity-modal') closeVelocityModal()">
                <div class="bg-white rounded-xl shadow-2xl max-w-2xl w-full max-h-[90vh] overflow-y-auto">
                    <div class="p-6">
                        <div class="flex justify-between items-center mb-4">
                            <h2 class="text-2xl font-bold text-gray-900">📊 Phân Tích Tốc Độ Bán</h2>
                            <button onclick="closeVelocityModal()" class="text-gray-400 hover:text-gray-600">
                                <svg class="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                    <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M6 18L18 6M6 6l12 12"></path>
                                </svg>
                            </button>
                        </div>
                        
                        <div class="space-y-4">
                            <!-- Product Info -->
                            <div class="bg-gray-50 rounded-lg p-4">
                                <h3 class="font-semibold text-gray-900 mb-2">${stockOut.productName || 'N/A'}</h3>
                                <p class="text-sm text-gray-600">SKU: ${stockOut.sku}</p>
                            </div>
                            
                            <!-- Velocity Stats -->
                            <div class="grid grid-cols-2 gap-4">
                                <div class="bg-blue-50 rounded-lg p-4">
                                    <div class="text-sm text-gray-600">Tốc Độ Bán (7 ngày)</div>
                                    <div class="text-2xl font-bold text-blue-600">${(trend.velocity7Days || 0).toFixed(1)} cái/ngày</div>
                                </div>
                                <div class="bg-purple-50 rounded-lg p-4">
                                    <div class="text-sm text-gray-600">Tốc Độ Bán (30 ngày)</div>
                                    <div class="text-2xl font-bold text-purple-600">${(trend.velocity30Days || 0).toFixed(1)} cái/ngày</div>
                                </div>
                            </div>
                            
                            <!-- Trend -->
                            <div class="bg-gradient-to-r from-green-50 to-emerald-50 rounded-lg p-4 border border-green-200">
                                <div class="flex items-center justify-between">
                                    <div>
                                        <div class="text-sm text-gray-600">Xu Hướng</div>
                                        <div class="text-lg font-semibold ${trend.trendDirection === 'increasing' ? 'text-green-600' : trend.trendDirection === 'decreasing' ? 'text-red-600' : 'text-gray-600'}">
                                            ${trend.trendDirection === 'increasing' ? '📈 Tăng' : trend.trendDirection === 'decreasing' ? '📉 Giảm' : '➡️ Ổn định'}
                                            ${Math.abs(trend.trendPercent || 0).toFixed(1)}%
                                        </div>
                                    </div>
                                </div>
                            </div>
                            
                            <!-- Stock Status -->
                            <div class="bg-${alertColor}-50 rounded-lg p-4 border border-${alertColor}-200">
                                <div class="grid grid-cols-2 gap-4">
                                    <div>
                                        <div class="text-sm text-gray-600">Tồn Kho Hiện Tại</div>
                                        <div class="text-2xl font-bold">${stockOut.currentStock || 0} cái</div>
                                    </div>
                                    <div>
                                        <div class="text-sm text-gray-600">Dự Kiến Hết Hàng</div>
                                        <div class="text-2xl font-bold text-${alertColor}-600">
                                            ${stockOut.daysUntilStockOut || 0} ngày
                                        </div>
                                    </div>
                                </div>
                            </div>
                            
                            <!-- Reorder Recommendation -->
                            <div class="bg-orange-50 rounded-lg p-4 border border-orange-200">
                                <h4 class="font-semibold text-gray-900 mb-2">💡 Đề Xuất Nhập Hàng</h4>
                                <div class="space-y-2 text-sm">
                                    <div class="flex justify-between">
                                        <span class="text-gray-600">Điểm đặt lại:</span>
                                        <span class="font-semibold">${reorder.reorderPoint || 0} cái</span>
                                    </div>
                                    <div class="flex justify-between">
                                        <span class="text-gray-600">Nên nhập:</span>
                                        <span class="font-semibold ${reorder.shouldReorder ? 'text-orange-600' : 'text-green-600'}">
                                            ${reorder.shouldReorder ? '⚠️ Ngay bây giờ' : '✅ Chưa cần'}
                                        </span>
                                    </div>
                                    ${reorder.shouldReorder ? `
                                    <div class="flex justify-between">
                                        <span class="text-gray-600">Số lượng đề xuất:</span>
                                        <span class="font-semibold text-orange-600">${reorder.recommendedOrderQty || 0} cái</span>
                                    </div>
                                    ` : ''}
                                </div>
                            </div>
                        </div>
                        
                        <div class="mt-6 flex gap-2">
                            <button onclick="closeVelocityModal()" class="flex-1 px-4 py-2 bg-gray-100 text-gray-700 rounded-lg hover:bg-gray-200">
                                Đóng
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        `;

        document.body.insertAdjacentHTML('beforeend', modalHtml);
    }

    /**
     * Close velocity modal
     */
    function closeVelocityModal() {
        const modal = document.getElementById('velocity-modal');
        if (modal) {
            modal.remove();
        }
    }

    /* --- REPORT FUNCTIONS --- */

    /**
     * Load report data based on selected filters
     */
    function loadReport() {
        const typeSelect = document.getElementById('report-type');
        const type = typeSelect ? typeSelect.value : 'revenue';

        // Hide all report sections first
        const sections = ['revenue', 'sales', 'products', 'products-detail', 'suppliers', 'customers', 'profit', 'lowstock', 'comparison', 'debt', 'employees', 'warranty', 'inventory-movement'];
        sections.forEach(s => {
            const el = document.getElementById(s + '-report-section');
            if (el) el.classList.add('hidden');
        });
        ['employees-leaderboard-section','employees-commission-section','employees-activity-section','employees-trend-section'].forEach(id => { const el=document.getElementById(id); if(el) el.classList.add('hidden'); });

        // Show loading
        toggleLoading(true);

        // Handle warranty report separately
        if (type === 'warranty') {
            loadWarrantyReport();
            return;
        }

        // Get filters
        const filters = {
            period: document.getElementById('report-period')?.value || 'month',
            startDate: document.getElementById('report-start-date')?.value,
            endDate: document.getElementById('report-end-date')?.value
        };

        // Prepare handler
        const handler = google.script.run
            .withSuccessHandler((res) => {
                toggleLoading(false);
                if (res) {
                    renderReportData(type, res);
                } else {
                    showToast('Không có dữ liệu báo cáo', 'warning');
                }
            })
            .withFailureHandler((err) => {
                toggleLoading(false);
                console.error('Report error:', err);
                showToast('Lỗi tải báo cáo: ' + (err.message || err.toString()), 'error');
            });

        console.log('Loading report:', type, filters);

        // Call appropriate server function
        switch (type) {
            case 'sales':
            case 'revenue': // Map revenue to sales report
                handler.apiHandler('getSalesReport', filters);
                break;
            case 'products': // Top selling
            case 'products-detail': // Inventory
            case 'lowstock': // Low stock - covered by products detail
                handler.apiHandler('getProductsDetailReport', filters);
                break;
            case 'suppliers':
                handler.apiHandler('getSuppliersReport', filters);
                break;
            case 'customers':
                handler.apiHandler('getCustomersReport', filters);
                break;
            case 'profit':
                handler.apiHandler('getProfitReport', filters);
                break;
            case 'debt':
                toggleLoading(false);
                loadDebtReport();
                return;
            case 'employees':
                toggleLoading(false);
                loadEmployeesReport();
                return;
            case 'employees-leaderboard':
                toggleLoading(false);
                loadEmployeesLeaderboard();
                return;
            case 'employees-commission':
                toggleLoading(false);
                loadEmployeesCommission();
                return;
            case 'employees-activity':
                toggleLoading(false);
                loadEmployeesActivity();
                return;
            case 'employees-trend':
                toggleLoading(false);
                loadEmployeesTrend();
                return;
            case 'comparison':
                toggleLoading(false);
                loadComparisonReport();
                return;
            case 'inventory-movement':
                handler.apiHandler('getInventoryMovementReport', filters);
                break;
            default:
                toggleLoading(false);
                showToast('Loại báo cáo chưa được hỗ trợ: ' + type, 'warning');
        }
    }

    /**
     * Render report data to DOM
     */
    function renderReportData(type, res) {
        // Unwrap API response if needed
        const data = (res && res.data) ? res.data : res;

        console.log('renderReportData received (raw):', type, res);
        console.log('renderReportData processing (unwrapped):', type, data);

        if (data.debugInfo) {
            console.warn('DEBUG INFO:', data.debugInfo);
        }

        // Helper
        const safeNum = (v) => {
            const n = Number(v);
            return isNaN(n) ? 0 : n;
        };

        if (type === 'revenue' && data.debugInfo) {
            console.log('Testing formatMoney:', formatMoney(data.totalRevenue));
        }

        // --- DEBUG DISPLAY ---
        // If data is empty but we have debug info, show it on screen for troubleshooting
        const shouldShowDebug = data.debugInfo && (Number(data.totalRevenue) === 0 || Number(data.totalOrders) === 0);
        if (shouldShowDebug) {
            // Find or create debug container
            const existingDebug = document.getElementById('report-debug-info');
            if (existingDebug) existingDebug.remove();

            const sectionId = type === 'revenue' ? 'revenue-report-section' : type + '-report-section';
            const reportSection = document.getElementById(sectionId);

            if (reportSection) {
                const debugDiv = document.createElement('div');
                debugDiv.id = 'report-debug-info';
                debugDiv.className = 'mt-6 p-4 bg-red-50 border border-red-200 rounded-lg text-xs font-mono text-red-800 overflow-auto max-h-96';
                debugDiv.innerHTML = `
                    <h4 class="font-bold mb-2">⚠ DEBUG INFO (Chụp ảnh màn hình này gửi cho kỹ thuật)</h4>
                    <pre>${JSON.stringify(data.debugInfo, null, 2)}</pre>
                    <div class="mt-2 text-gray-600">
                        Date Range: ${document.getElementById('report-start-date')?.value} - ${document.getElementById('report-end-date')?.value}<br>
                        Report Type: ${type}
                    </div>
                `;
                reportSection.appendChild(debugDiv);
            }
        }

        // Determine target section
        let sectionId = type + '-report-section';
        if (type === 'revenue') sectionId = 'revenue-report-section';
        if (type === 'products') sectionId = 'products-report-section';
        if (type === 'products-detail') sectionId = 'products-detail-report-section';
        if (type === 'lowstock') sectionId = 'lowstock-report-section';

        const section = document.getElementById(sectionId);
        if (section) {
            section.classList.remove('hidden');

            switch (type) {
                case 'revenue':
                case 'sales': {
                    const totalRev = safeNum(data.totalRevenue);
                    const totalOrd = safeNum(data.totalOrders);
                    const avgOrd = safeNum(data.avgOrder);

                    console.log('Rendering Revenue/Sales:', { totalRev, totalOrd, avgOrd });

                    // Update Sales Report Section elements if they exist
                    if (document.getElementById('sales-total-revenue'))
                        document.getElementById('sales-total-revenue').innerText = formatMoney(totalRev);
                    if (document.getElementById('sales-total-orders'))
                        document.getElementById('sales-total-orders').innerText = totalOrd;
                    if (document.getElementById('sales-avg-order'))
                        document.getElementById('sales-avg-order').innerText = formatMoney(avgOrd);
                    if (document.getElementById('sales-total-items') && data.totalItems !== undefined)
                        document.getElementById('sales-total-items').innerText = data.totalItems;

                    // NEW: Update VAT specific elements if they exist (need to add them to HTML structure if desired)
                    // For now, let's log them to console to verify
                    console.log('VAT Metrics:', {
                        revWithVAT: data.totalRevenueWithVAT,
                        revNoVAT: data.totalRevenueNoVAT,
                        totalVAT: data.totalVATAmount
                    });

                    // Update Revenue Report Section elements if they exist
                    if (document.getElementById('report-total-revenue')) {
                        document.getElementById('report-total-revenue').innerText = formatMoney(totalRev);
                    }
                    if (document.getElementById('report-total-orders'))
                        document.getElementById('report-total-orders').innerText = totalOrd;
                    if (document.getElementById('report-avg-order'))
                        document.getElementById('report-avg-order').innerText = formatMoney(avgOrd);

                    // Update Chart
                    if (document.getElementById('sales-chart')) {
                        renderSalesChart(data.dailyData || []);
                    }

                    // Render Table
                    const targetBodyId = type === 'revenue' ? 'revenue-report-body' : 'sales-report-body';
                    const listBody = document.getElementById(targetBodyId);
                    if (listBody && data.dailyData) {
                        listBody.innerHTML = data.dailyData.map(d => {
                            const dRev = safeNum(d.revenue);
                            return `
                            <tr>
                                <td class="px-4 py-2 border-b text-gray-900">${d.date}</td>
                                <td class="px-4 py-2 border-b text-right font-medium">${formatMoney(dRev)}</td>
                                <td class="px-4 py-2 border-b text-right text-gray-600">${data.totalOrders || 0}</td>
                                <td class="px-4 py-2 border-b text-right text-gray-600">${d.orderCount || 0}</td>
                            </tr>
                        `;
                        }).join('');
                    }
                    break;
                }

                case 'products': // Top Selling
                    // Products data comes from getProductsDetailReport which returns { products: [...] }
                    // We need to sort by soldQty desc
                    const topProducts = (data.products || []).sort((a, b) => (b.soldQty || 0) - (a.soldQty || 0)).slice(0, 50);

                    const topBody = document.getElementById('products-report-body');
                    if (topBody) {
                        topBody.innerHTML = topProducts.map((p, index) => `
                        <tr>
                            <td class="px-4 py-2 border-b text-center">${index + 1}</td>
                            <td class="px-4 py-2 border-b font-medium text-blue-600">${p.sku}</td>
                            <td class="px-4 py-2 border-b">${p.name}</td>
                            <td class="px-4 py-2 border-b">${p.category || ''}</td>
                            <td class="px-4 py-2 border-b text-right font-bold">${p.soldQty || 0}</td>
                            <td class="px-4 py-2 border-b text-right text-green-600">${formatMoney((p.soldQty || 0) * (p.price || 0))}</td>
                        </tr>
                    `).join('');
                    }
                    break;

                case 'products-detail': // Inventory
                    renderProductsDetailReport(data);
                    break;

                case 'lowstock':
                    const threshold = parseFloat(document.getElementById('lowstock-threshold')?.value || 10);
                    const lowStockProducts = (data.products || []).filter(p => p.stock <= threshold);

                    const lowBody = document.getElementById('lowstock-report-body');
                    if (lowBody) {
                        lowBody.innerHTML = lowStockProducts.map(p => `
                        <tr>
                             <td class="px-4 py-2 border-b font-medium text-blue-600">${p.sku}</td>
                             <td class="px-4 py-2 border-b">${p.name}</td>
                             <td class="px-4 py-2 border-b">${p.category || ''}</td>
                             <td class="px-4 py-2 border-b text-right font-bold text-red-600">${p.stock}</td>
                             <td class="px-4 py-2 border-b text-center text-gray-500">${p.unit || 'Cái'}</td>
                             <td class="px-4 py-2 border-b text-right">${formatMoney(p.price)}</td>
                        </tr>
                     `).join('');
                    }
                    break;

                case 'suppliers':
                    document.getElementById('suppliers-total').innerText = data.totalSuppliers;
                    document.getElementById('suppliers-total-import').innerText = formatMoney(data.totalImportValue);
                    document.getElementById('suppliers-total-debt').innerText = formatMoney(data.totalDebt);
                    document.getElementById('suppliers-total-purchases').innerText = data.totalPurchases;

                    const suppBody = document.getElementById('suppliers-report-body');
                    if (suppBody) {
                        suppBody.innerHTML = (data.suppliers || []).map(s => `
                        <tr>
                            <td class="px-4 py-2 border-b text-blue-600 font-medium">${s.id}</td>
                            <td class="px-4 py-2 border-b">${s.name}</td>
                            <td class="px-4 py-2 border-b text-center">${s.purchaseCount}</td>
                            <td class="px-4 py-2 border-b text-right">${formatMoney(s.totalImport)}</td>
                            <td class="px-4 py-2 border-b text-right text-green-600">${formatMoney(s.totalPaid)}</td>
                            <td class="px-4 py-2 border-b text-right font-bold ${s.debt > 0 ? 'text-red-600' : 'text-green-600'}">${formatMoney(s.debt)}</td>
                            <td class="px-4 py-2 border-b text-center">
                                <span class="px-2 py-1 rounded text-xs ${s.debt > 0 ? 'bg-red-100 text-red-700' : 'bg-green-100 text-green-700'}">
                                    ${s.debt > 0 ? 'Còn nợ' : 'Hoàn thành'}
                                </span>
                            </td>
                        </tr>
                    `).join('');
                    }
                    break;

                case 'customers':
                    document.getElementById('customers-total').innerText = data.totalCustomers;
                    document.getElementById('customers-total-revenue').innerText = formatMoney(data.totalRevenue);
                    document.getElementById('customers-total-debt').innerText = formatMoney(data.totalDebt);
                    document.getElementById('customers-vip').innerText = data.vipCount;

                    const custBody = document.getElementById('customers-report-body');
                    if (custBody) {
                        custBody.innerHTML = (data.customers || []).map(c => `
                        <tr>
                            <td class="px-4 py-2 border-b text-blue-600 font-medium">${c.id}</td>
                            <td class="px-4 py-2 border-b font-medium">${c.name}</td>
                            <td class="px-4 py-2 border-b text-center">${c.orderCount}</td>
                            <td class="px-4 py-2 border-b text-right text-green-600 font-medium">${formatMoney(c.totalRevenue)}</td>
                            <td class="px-4 py-2 border-b text-right text-gray-600">${formatMoney(c.totalPaid)}</td>
                            <td class="px-4 py-2 border-b text-right font-bold ${c.debt > 0 ? 'text-red-600' : 'text-green-600'}">${formatMoney(c.debt)}</td>
                            <td class="px-4 py-2 border-b text-xs text-gray-500">${c.lastOrderDate ? new Date(c.lastOrderDate).toLocaleDateString('vi-VN') : '-'}</td>
                            <td class="px-4 py-2 border-b text-center">
                                <span class="px-2 py-1 rounded text-xs ${c.totalRevenue >= 10000000 ? 'bg-purple-100 text-purple-700' : 'bg-gray-100 text-gray-700'}">
                                    ${c.totalRevenue >= 10000000 ? '⭐ VIP' : 'Thường'}
                                </span>
                            </td>
                        </tr>
                    `).join('');
                    }
                    break;

                case 'profit':
                    const pRevenue = safeNum(data.totalRevenue);
                    const pCost = safeNum(data.totalCost);
                    const pGross = safeNum(data.grossProfit);

                    document.getElementById('profit-total-revenue').innerText = formatMoney(pRevenue);
                    document.getElementById('profit-total-cost').innerText = formatMoney(pCost);
                    document.getElementById('profit-gross').innerText = formatMoney(pGross);
                    const margin = pRevenue > 0 ? (pGross / pRevenue) * 100 : 0;
                    document.getElementById('profit-margin').innerText = margin.toFixed(1) + '%';

                    const profitBody = document.getElementById('profit-report-body');
                    if (profitBody) {
                        profitBody.innerHTML = (data.periodData || []).map(p => {
                            const rev = safeNum(p.revenue);
                            const cst = safeNum(p.cost);
                            const prf = rev - cst;
                            const pMargin = rev > 0 ? (prf) / rev * 100 : 0;
                            return `
                        <tr>
                            <td class="px-4 py-2 border-b font-medium">${p.period}</td>
                            <td class="px-4 py-2 border-b text-right text-blue-600">${formatMoney(rev)}</td>
                            <td class="px-4 py-2 border-b text-right text-red-600">${formatMoney(cst)}</td>
                            <td class="px-4 py-2 border-b text-right font-bold ${prf >= 0 ? 'text-green-600' : 'text-red-600'}">${formatMoney(prf)}</td>
                            <td class="px-4 py-2 border-b text-right text-sm">${pMargin.toFixed(1)}%</td>
                            <td class="px-4 py-2 border-b text-right text-gray-600">${p.orderCount}</td>
                        </tr>
                        `;
                        }).join('');
                    }
                    break;

                case 'inventory-movement': {
                    const summary = data.summary || {};
                    const rows = data.rows || [];

                    // Update summary cards
                    const setEl = (id, val) => { const el = document.getElementById(id); if (el) el.innerText = val; };
                    setEl('inv-mov-imported', (summary.totalImported || 0).toLocaleString('vi-VN'));
                    setEl('inv-mov-sold', (summary.totalSold || 0).toLocaleString('vi-VN'));
                    setEl('inv-mov-returned', (summary.totalReturned || 0).toLocaleString('vi-VN'));
                    setEl('inv-mov-closing-value', formatMoney(summary.totalClosingValue || 0));

                    // Render table
                    const tbody = document.getElementById('inv-mov-tbody');
                    if (tbody) {
                        if (rows.length === 0) {
                            tbody.innerHTML = '<tr><td colspan="9" class="px-4 py-8 text-center text-gray-400">Không có dữ liệu trong khoảng thời gian này</td></tr>';
                        } else {
                            tbody.innerHTML = rows.map(r => {
                                const closingClass = r.closingStock < 0 ? 'text-red-600 font-bold' : (r.closingStock === 0 ? 'text-orange-500' : '');
                                return `<tr class="hover:bg-gray-50">
                                    <td class="px-3 py-2 text-blue-600 font-medium">${r.sku}</td>
                                    <td class="px-3 py-2">${r.name}</td>
                                    <td class="px-3 py-2 text-gray-500 text-xs">${r.category || ''}</td>
                                    <td class="px-3 py-2 text-right text-gray-600">${r.openingStock.toLocaleString('vi-VN')}</td>
                                    <td class="px-3 py-2 text-right text-blue-600 font-medium">${r.imported > 0 ? '+' + r.imported.toLocaleString('vi-VN') : '-'}</td>
                                    <td class="px-3 py-2 text-right text-red-600">${r.sold > 0 ? r.sold.toLocaleString('vi-VN') : '-'}</td>
                                    <td class="px-3 py-2 text-right text-green-600">${r.returned > 0 ? r.returned.toLocaleString('vi-VN') : '-'}</td>
                                    <td class="px-3 py-2 text-right font-semibold ${closingClass}">${r.closingStock.toLocaleString('vi-VN')}</td>
                                    <td class="px-3 py-2 text-right text-gray-600">${formatMoney(r.closingValue)}</td>
                                </tr>`;
                            }).join('');
                        }
                    }
                    break;
                }
            }
        }
    }

    /**
     * Reset report filters
     */
    function resetReportFilters() {
        const today = new Date();
        const firstDay = new Date(today.getFullYear(), today.getMonth(), 1);

        // Set format YYYY-MM-DD
        const formatDate = (date) => {
            const year = date.getFullYear();
            const month = String(date.getMonth() + 1).padStart(2, '0');
            const day = String(date.getDate()).padStart(2, '0');
            return `${year}-${month}-${day}`;
        };

        const startInput = document.getElementById('report-start-date');
        const endInput = document.getElementById('report-end-date');
        const periodSelect = document.getElementById('report-period');

        if (startInput) startInput.value = formatDate(firstDay);
        if (endInput) endInput.value = formatDate(today);
        if (periodSelect) periodSelect.value = 'month';

        // Also clear specific filters if any (like low stock threshold)
        const threshold = document.getElementById('lowstock-threshold');
        if (threshold) threshold.value = 10;
    }

    /**
     * Quick date preset for report filters
     */
    function setReportDatePreset(preset) {
        const today = new Date();
        const formatDate = (d) => {
            return d.getFullYear() + '-' + String(d.getMonth() + 1).padStart(2, '0') + '-' + String(d.getDate()).padStart(2, '0');
        };
        let start, end = today;
        switch (preset) {
            case 'today':
                start = today;
                break;
            case 'yesterday':
                start = new Date(today); start.setDate(today.getDate() - 1);
                end = new Date(start);
                break;
            case '7days':
                start = new Date(today); start.setDate(today.getDate() - 6);
                break;
            case '30days':
                start = new Date(today); start.setDate(today.getDate() - 29);
                break;
            case 'thisMonth':
                start = new Date(today.getFullYear(), today.getMonth(), 1);
                break;
            case 'lastMonth':
                start = new Date(today.getFullYear(), today.getMonth() - 1, 1);
                end = new Date(today.getFullYear(), today.getMonth(), 0);
                break;
            case 'thisQuarter':
                var q = Math.floor(today.getMonth() / 3);
                start = new Date(today.getFullYear(), q * 3, 1);
                break;
            case 'thisYear':
                start = new Date(today.getFullYear(), 0, 1);
                break;
            default:
                start = new Date(today); start.setDate(today.getDate() - 29);
        }
        var startInput = document.getElementById('report-start-date');
        var endInput = document.getElementById('report-end-date');
        if (startInput) startInput.value = formatDate(start);
        if (endInput) endInput.value = formatDate(end);

        // Auto-set period based on range
        var periodSelect = document.getElementById('report-period');
        if (periodSelect) {
            var diffDays = Math.ceil((end - start) / (1000 * 60 * 60 * 24));
            if (diffDays <= 1) periodSelect.value = 'day';
            else if (diffDays <= 14) periodSelect.value = 'day';
            else if (diffDays <= 90) periodSelect.value = 'week';
            else periodSelect.value = 'month';
        }

        // Highlight active button
        var btns = document.querySelectorAll('#report-quick-dates button');
        btns.forEach(function(btn) {
            btn.className = 'px-3 py-1.5 text-xs font-medium rounded-full border border-gray-200 text-gray-700 bg-gray-50 hover:bg-gray-100 transition-colors';
        });
        event.target.className = 'px-3 py-1.5 text-xs font-medium rounded-full border border-blue-200 text-blue-700 bg-blue-50 hover:bg-blue-100 transition-colors';

        // Auto-load report
        loadReport();
    }

    /**
     * Load low stock report (wrapper)
     */
    function loadLowStockReport() {
        // Manually switch to lowstock if not already
        const typeSelect = document.getElementById('report-type');
        if (typeSelect) typeSelect.value = 'lowstock';
        loadReport();
    }

    /**
     * Wrapper to call loadReport from onclick
     */
    function loadReportWrapper() {
        loadReport();
    }

    /**
     * FRONTEND_WARRANTY.JS
     * Frontend functions for Warranty Management Widget
     */

    /**
     * Load warranty dashboard widget
     */
    function loadWarrantyDashboard() {
        const container = document.getElementById('warranty-dashboard-content');
        if (!container) return;

        container.innerHTML = '<p class="text-sm text-gray-400">Đang tải thông tin bảo hành...</p>';

        google.script.run
            .withSuccessHandler((res) => {
                if (res && res.success && res.data) {
                    renderWarrantyDashboard(res.data);
                } else {
                    container.innerHTML = '<p class="text-sm text-red-500">Không thể tải dữ liệu bảo hành</p>';
                }
            })
            .withFailureHandler((err) => {
                container.innerHTML = '<p class="text-sm text-red-500">Lỗi: ' + (err.message || err) + '</p>';
            })
            .apiHandler('getWarrantyStatistics', null);
    }

    /**
     * Render warranty dashboard widget
     */
    function renderWarrantyDashboard(stats) {
        const container = document.getElementById('warranty-dashboard-content');
        if (!container) return;

        let html = '';

        // Summary stats grid
        html += '<div class="grid grid-cols-2 md:grid-cols-4 gap-3 mb-4">';

        // Total warranties
        html += `
            <div class="bg-white bg-opacity-70 rounded-lg p-3 text-center border border-blue-200">
                <div class="text-2xl font-bold text-blue-600">${stats.total || 0}</div>
                <div class="text-xs text-gray-600 mt-1">Tổng Phiếu BH</div>
            </div>
        `;

        // Expiring soon
        html += `
            <div class="bg-white bg-opacity-70 rounded-lg p-3 text-center border border-orange-200">
                <div class="text-2xl font-bold text-orange-600">${stats.expiringSoon || 0}</div>
                <div class="text-xs text-gray-600 mt-1">Sắp Hết Hạn</div>
            </div>
        `;

        // Expired
        html += `
            <div class="bg-white bg-opacity-70 rounded-lg p-3 text-center border border-red-200">
                <div class="text-2xl font-bold text-red-600">${stats.expired || 0}</div>
                <div class="text-xs text-gray-600 mt-1">Đã Hết Hạn</div>
            </div>
        `;

        // Total requests
        html += `
            <div class="bg-white bg-opacity-70 rounded-lg p-3 text-center border border-purple-200">
                <div class="text-2xl font-bold text-purple-600">${stats.totalRequests || 0}</div>
                <div class="text-xs text-gray-600 mt-1">Yêu Cầu BH</div>
            </div>
        `;

        html += '</div>';

        // Status breakdown
        if (stats.byStatus && Object.keys(stats.byStatus).length > 0) {
            html += '<div class="mb-4">';
            html += '<h4 class="text-sm font-semibold text-gray-700 mb-2">Trạng Thái Bảo Hành</h4>';
            html += '<div class="space-y-2">';

            Object.entries(stats.byStatus).forEach(([status, count]) => {
                const statusColors = {
                    'Mới': 'bg-blue-100 text-blue-700',
                    'Đang xử lý': 'bg-yellow-100 text-yellow-700',
                    'Hoàn thành': 'bg-green-100 text-green-700',
                    'Từ chối': 'bg-red-100 text-red-700',
                    'Hết hạn': 'bg-gray-100 text-gray-700'
                };
                const colorClass = statusColors[status] || 'bg-gray-100 text-gray-700';

                html += `
                    <div class="flex justify-between items-center p-2 bg-white bg-opacity-60 rounded ${colorClass}">
                        <span class="text-sm">${status}</span>
                        <span class="text-sm font-bold">${count}</span>
                    </div>
                `;
            });

            html += '</div>';
            html += '</div>';
        }

        // Pending requests alert
        if (stats.requestsByStatus && stats.requestsByStatus['Chờ xử lý']) {
            const pendingCount = stats.requestsByStatus['Chờ xử lý'];
            if (pendingCount > 0) {
                html += `
                    <div class="bg-yellow-50 border border-yellow-200 rounded-lg p-3 mb-4">
                        <div class="flex items-center gap-2">
                            <svg class="w-5 h-5 text-yellow-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z"></path>
                            </svg>
                            <div>
                                <p class="text-sm font-semibold text-yellow-800">Có ${pendingCount} yêu cầu bảo hành đang chờ xử lý</p>
                                <p class="text-xs text-yellow-600">Vui lòng kiểm tra và xử lý sớm</p>
                            </div>
                        </div>
                    </div>
                `;
            }
        }

        // Expiring soon alert
        if (stats.expiringSoon > 0) {
            html += `
                <div class="bg-orange-50 border border-orange-200 rounded-lg p-3">
                    <div class="flex items-center gap-2">
                        <svg class="w-5 h-5 text-orange-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z"></path>
                        </svg>
                        <div>
                            <p class="text-sm font-semibold text-orange-800">${stats.expiringSoon} phiếu bảo hành sắp hết hạn</p>
                            <p class="text-xs text-orange-600">Trong vòng 30 ngày tới</p>
                        </div>
                    </div>
                </div>
            `;
        }

        // Total cost if available
        if (stats.totalCost > 0) {
            html += `
                <div class="mt-4 pt-4 border-t border-gray-200">
                    <div class="flex justify-between items-center">
                        <span class="text-sm text-gray-600">Tổng Chi Phí Bảo Hành:</span>
                        <span class="text-sm font-bold text-gray-900">${formatMoney(stats.totalCost)}</span>
                    </div>
                </div>
            `;
        }

        // Quick actions
        html += `
            <div class="mt-4 pt-4 border-t border-gray-200">
                <div class="flex gap-2">
                    <button onclick="showWarrantyManagement()" 
                        class="flex-1 text-sm px-3 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition">
                        Quản Lý Bảo Hành
                    </button>
                    <button onclick="sendWarrantyEmailAlert()" 
                        class="flex-1 text-sm px-3 py-2 bg-orange-600 text-white rounded-lg hover:bg-orange-700 transition">
                        Gửi Email Cảnh Báo
                    </button>
                </div>
            </div>
        `;

        container.innerHTML = html;
    }

    /**
     * Show warranty management page
     */
    function showWarrantyManagement() {
        // Navigate to warranty page if exists, otherwise show alert
        if (typeof showPage === 'function') {
            // Try to show warranty page
            const warrantyPage = document.getElementById('page-warranty');
            if (warrantyPage) {
                showPage('warranty');
            } else {
                alert('Trang quản lý bảo hành đang được phát triển. Vui lòng sử dụng API để quản lý bảo hành.');
            }
        } else {
            alert('Tính năng quản lý bảo hành đang được phát triển.');
        }
    }

    /**
     * Send warranty expiration email alert
     */
    function sendWarrantyEmailAlert() {
        if (!confirm('Bạn có muốn gửi email cảnh báo cho các phiếu bảo hành sắp hết hạn (30 ngày) không?')) {
            return;
        }

        const container = document.getElementById('warranty-dashboard-content');
        const originalContent = container.innerHTML;
        container.innerHTML = '<p class="text-sm text-gray-400">Đang gửi email...</p>';

        google.script.run
            .withSuccessHandler((res) => {
                if (res && res.success) {
                    alert(`Đã gửi email cảnh báo cho ${res.data.sent || 0} phiếu bảo hành!`);
                    loadWarrantyDashboard(); // Reload dashboard
                } else {
                    alert('Lỗi: ' + (res.message || 'Không thể gửi email'));
                    container.innerHTML = originalContent;
                }
            })
            .withFailureHandler((err) => {
                alert('Lỗi: ' + (err.message || err));
                container.innerHTML = originalContent;
            })
            .apiHandler('sendWarrantyExpirationEmails', { days: 30 });
    }
    /**
   * VAT UI INJECTION - Thêm trường VAT vào form sản phẩm
   * Thêm code này vào cuối file JS.html
   */

    // ============================================
    // AUTO-INJECT VAT FIELD VÀO FORM SẢN PHẨM
    // ============================================

    /**
    * Tự động thêm trường VAT vào form sản phẩm khi form được mở
    */
    function injectVATFieldToProductForm() {
        // Đợi DOM load xong
        if (document.readyState === 'loading') {
            document.addEventListener('DOMContentLoaded', injectVATFieldToProductForm);
            return;
        }

        // Tìm form sản phẩm - thử nhiều selector
        const formSelectors = [
            '#product-form',
            '#productForm',
            'form[name="product"]',
            '.product-form',
            'div[class*="product"] form'
        ];

        let productForm = null;
        for (const selector of formSelectors) {
            productForm = document.querySelector(selector);
            if (productForm) break;
        }

        if (!productForm) {
            console.log('Không tìm thấy form sản phẩm');
            return;
        }

        // Kiểm tra xem đã có trường VAT chưa
        if (document.getElementById('product-vat-rate')) {
            console.log('Trường VAT đã tồn tại');
            return;
        }

        // Tạo HTML cho trường VAT
        const vatFieldHTML = `
<div class="form-group" id="vat-field-container">
  <label for="product-vat-rate">
    <i class="fas fa-percent"></i> VAT Mặc Định (%)
  </label>
  <input type="number" id="product-vat-rate" class="form-control" min="0" max="100" step="0.01" value="0"
    placeholder="Nhập % VAT (0, 5, 8, 10...)" onchange="calcVatPreview()">
  <div style="margin-top:6px;display:flex;align-items:center;gap:8px;">
    <label style="cursor:pointer;display:flex;align-items:center;gap:4px;margin:0;font-weight:normal;font-size:13px;">
      <input type="checkbox" id="product-vat-included" onchange="calcVatPreview()"> Giá bán đã bao gồm VAT
    </label>
  </div>
  <div id="vat-price-preview" style="margin-top:6px;padding:8px 12px;background:#f0fdf4;border-radius:6px;font-size:13px;display:none;">
  </div>
  <small class="form-text text-muted">
    <i class="fas fa-info-circle"></i>
    Mức VAT mặc định của sản phẩm. Có thể thay đổi khi bán.
  </small>
</div>
`;

        // Chèn vào cuối form (trước nút submit)
        const submitButton = productForm.querySelector('button[type="submit"], .btn-primary, button:last-child');
        if (submitButton && submitButton.parentElement) {
            submitButton.parentElement.insertAdjacentHTML('beforebegin', vatFieldHTML);
            console.log('✅ Đã thêm trường VAT vào form sản phẩm');
        } else {
            // Nếu không tìm thấy nút submit, thêm vào cuối form
            productForm.insertAdjacentHTML('beforeend', vatFieldHTML);
            console.log('✅ Đã thêm trường VAT vào cuối form');
        }
    }

    // Auto-calculate VAT price preview
    function calcVatPreview() {
        var preview = document.getElementById('vat-price-preview');
        if (!preview) return;
        var sellPriceEl = document.getElementById('product-sell-price');
        var vatRateEl = document.getElementById('product-vat-rate');
        var vatIncEl = document.getElementById('product-vat-included');
        if (!sellPriceEl || !vatRateEl || !vatIncEl) { preview.classList.add('hidden'); preview.style.display = 'none'; return; }

        var sellPrice = parseMoneyInput(sellPriceEl);
        var vatRate = parseFloat(vatRateEl.value) || 0;
        var vatIncluded = vatIncEl.checked;

        if (vatRate <= 0 || sellPrice <= 0) { preview.classList.add('hidden'); preview.style.display = 'none'; return; }

        preview.classList.remove('hidden');
        preview.style.display = 'block';
        if (vatIncluded) {
            var priceBeforeVAT = Math.round(sellPrice / (1 + vatRate / 100));
            var vatAmount = sellPrice - priceBeforeVAT;
            preview.innerHTML = '<strong>Giá chưa VAT:</strong> ' + priceBeforeVAT.toLocaleString('vi-VN') + ' ₫ | <strong>VAT ' + vatRate + '%:</strong> ' + vatAmount.toLocaleString('vi-VN') + ' ₫';
            preview.style.background = '#fef3c7';
            preview.style.color = '#92400e';
        } else {
            var vatAmount2 = Math.round(sellPrice * vatRate / 100);
            var priceWithVAT = sellPrice + vatAmount2;
            preview.innerHTML = '<strong>Giá sau VAT:</strong> ' + priceWithVAT.toLocaleString('vi-VN') + ' ₫ | <strong>VAT ' + vatRate + '%:</strong> ' + vatAmount2.toLocaleString('vi-VN') + ' ₫';
            preview.style.background = '#f0fdf4';
            preview.style.color = '#065f46';
        }
    }

    // Chạy khi trang load
    injectVATFieldToProductForm();

    // Chạy lại khi có sự kiện mở modal/form sản phẩm
    document.addEventListener('click', function (e) {
        // Nếu click vào nút "Thêm sản phẩm" hoặc "Sửa sản phẩm"
        if (e.target.matches('[data-action="add-product"], [data-action="edit-product"], .add-product, .edit-product')) {
            setTimeout(injectVATFieldToProductForm, 100);
        }
    });

    // ============================================
    // WRAPPER CHO HÀM LƯU SẢN PHẨM HIỆN CÓ
    // ============================================

    /**
    * Wrap hàm saveProduct hiện có để thêm VAT
    */
    (function () {
        // Lưu hàm gốc
        const originalSaveProduct = window.saveProduct;

        if (typeof originalSaveProduct !== 'function') {
            console.log('Chưa tìm thấy hàm saveProduct, sẽ tạo mới');
            return;
        }

        // Override hàm saveProduct
        window.saveProduct = function () {
            // Đọc VAT rate
            const vatInput = document.getElementById('product-vat-rate');
            if (vatInput) {
                const vatRate = parseFloat(vatInput.value) || 0;

                // Validate
                if (vatRate < 0 || vatRate > 100) {
                    alert('VAT phải từ 0-100%!');
                    return;
                }

                // Thêm vào window để hàm gốc có thể đọc
                window._tempVATRate = vatRate;
            }

            // Gọi hàm gốc
            return originalSaveProduct.apply(this, arguments);
        };

        console.log('✅ Đã wrap hàm saveProduct để hỗ trợ VAT');
    })();

    /**
    * Wrapper cho hàm tạo productData
    * Thêm vào bất kỳ nơi nào tạo object productData
    */
    function addVATToProductData(productData) {
        const vatInput = document.getElementById('product-vat-rate');
        if (vatInput) {
            productData.defaultVatRate = parseFloat(vatInput.value) || 0;
        } else if (window._tempVATRate !== undefined) {
            productData.defaultVatRate = window._tempVATRate;
        }
        const vatIncInput = document.getElementById('product-vat-included');
        if (vatIncInput) {
            productData.vatIncluded = vatIncInput.checked;
        }
        return productData;
    }

    /**
    * Wrapper cho hàm edit/hiển thị sản phẩm - Improved version
    */
    (function () {
        // Store current product being edited
        window._currentEditingProduct = null;

        // Watch for VAT input field and populate it when it appears
        const observer = new MutationObserver(function (mutations) {
            const vatInput = document.getElementById('product-vat-rate');
            if (vatInput && window._currentEditingProduct) {
                const vatValue = window._currentEditingProduct.defaultVatRate || 0;
                if (vatInput.value != vatValue) {
                    vatInput.value = vatValue;
                    console.log('✅ Đã điền VAT:', vatValue, '% cho sản phẩm:', window._currentEditingProduct.name);
                }
            }
        });

        // Start observing
        observer.observe(document.body, {
            childList: true,
            subtree: true
        });

        // Wrap common edit functions
        const functionsToWrap = ['editProduct', 'showProductDetail', 'showProductModal'];

        functionsToWrap.forEach(funcName => {
            const originalFunc = window[funcName];
            if (typeof originalFunc === 'function') {
                window[funcName] = function (product) {
                    // Store product data
                    if (typeof product === 'object') {
                        window._currentEditingProduct = product;
                        console.log('📝 Editing product:', product.name, 'VAT:', product.defaultVatRate);
                    } else if (typeof product === 'string') {
                        // If SKU is passed, find product in products array
                        if (window.products && Array.isArray(window.products)) {
                            const foundProduct = productBySku.get(product);
                            if (foundProduct) {
                                window._currentEditingProduct = foundProduct;
                                console.log('📝 Editing product by SKU:', foundProduct.name, 'VAT:', foundProduct.defaultVatRate);
                            }
                        }
                    }

                    // Call original function
                    const result = originalFunc.apply(this, arguments);

                    // Try to populate VAT field immediately
                    setTimeout(function () {
                        const vatInput = document.getElementById('product-vat-rate');
                        if (vatInput && window._currentEditingProduct) {
                            vatInput.value = window._currentEditingProduct.defaultVatRate || 0;
                            console.log('✅ Đã điền VAT ngay:', vatInput.value, '%');
                        }
                    }, 50);

                    return result;
                };
                console.log('✅ Đã wrap hàm', funcName, 'để hiển thị VAT');
            }
        });
    })();

