    /**
    * Tạo badge VAT
    */
    function getVATBadge(vatRate) {
        vatRate = parseFloat(vatRate) || 0;
        let badgeClass = 'badge-secondary';

        if (vatRate === 0) {
            badgeClass = 'badge-secondary';
        } else if (vatRate > 0 && vatRate < 8) { badgeClass = 'badge-info'; } else if (vatRate >= 8 && vatRate < 10) {
            badgeClass = 'badge-warning';
        } else if (vatRate >= 10) {
            badgeClass = 'badge-danger';
        }

        return `<span class="badge ${badgeClass}">${vatRate}%</span>`;
    }

    // Export để các hàm khác sử dụng
    window.getVATBadge = getVATBadge;
    window.addVATToProductData = addVATToProductData;


