    // --- Helper Functions for VAT Report ---
    function showLoading(message) {
        const loadingEl = document.getElementById('loading');
        if (loadingEl) {
            loadingEl.classList.remove('hidden');
            // Optional: Update loading message if you have a text element for it
        }
    }

    function hideLoading() {
        const loadingEl = document.getElementById('loading');
        if (loadingEl) {
            loadingEl.classList.add('hidden');
        }
    }

    /**
     * Load VAT Report Data
     */
    function loadVATReport() {
        console.log('🔍 loadVATReport called');
        let startDateValue = document.getElementById('vat-report-start-date').value;
        let endDateValue = document.getElementById('vat-report-end-date').value;

        // Fallback if inputs are empty
        if (!startDateValue || !endDateValue) {
            console.warn('⚠️ Date inputs empty, using defaults');
            const end = new Date();
            const start = new Date();
            start.setDate(start.getDate() - 30);

            // Update inputs
            const endInput = document.getElementById('vat-report-end-date');
            const startInput = document.getElementById('vat-report-start-date');
            if (endInput) endInput.valueAsDate = end;
            if (startInput) startInput.valueAsDate = start;

            startDateValue = startInput.value;
            endDateValue = endInput.value;
        }

        const start = new Date(startDateValue);
        start.setHours(0, 0, 0, 0);

        const end = new Date(endDateValue);
        end.setHours(23, 59, 59, 999);

        console.log('🕒 Adjusted Date Range:', { start: start.toLocaleString(), end: end.toLocaleString() });

        // Strict validation
        if (isNaN(start.getTime()) || isNaN(end.getTime())) {
            console.error('❌ Invalid Date objects created:', { startDateValue, endDateValue });
            showToast('Ngày tháng không hợp lệ', 'error');
            return;
        }

        console.log('Valid Dates:', { start, end });

        // Cache-first bằng composite key (VAT report tính toán nặng)
        const vatCacheKey = 'report-vat_' + startDateValue + '_' + endDateValue;
        var cachedVat = LocalStore.getTTL(vatCacheKey);
        if (cachedVat) {
            renderVATReport(cachedVat);
            return;
        }

        showLoading('Đang tải báo cáo VAT...');

        google.script.run
            .withSuccessHandler(function(res) {
                // Cache result trước khi render (5 phút)
                if (res) LocalStore.setTTL(vatCacheKey, res, 300);
                renderVATReport(res);
            })
            .withFailureHandler(function (error) {
                console.error('Error in getVATReport:', error);
                hideLoading();
                showToast('Lỗi: ' + error.message, 'error');
            })
            .getVATReportSecure(start.getTime(), end.getTime());
    }

    /**
     * Render VAT Report Data
     */
    function renderVATReport(data) {
        console.log('✅ renderVATReport called with data:', data);
        hideLoading();

        if (!data || !data.success) {
            console.error('❌ Invalid data:', data);
            showToast('Không thể tải báo cáo VAT', 'error');
            return;
        }

        console.log('📊 Rendering summary cards...');
        // Render Summary Cards
        document.getElementById('vat-revenue-with').textContent = formatCurrency(data.summary.totalRevenueWithVAT || 0);
        document.getElementById('vat-revenue-without').textContent = formatCurrency(data.summary.totalRevenueNoVAT || 0);
        document.getElementById('vat-total-collected').textContent = formatCurrency(data.summary.totalVAT || 0);
        document.getElementById('vat-orders-with-count').textContent = data.summary.ordersWithVATCount || 0;
        document.getElementById('vat-orders-without-count').textContent = data.summary.ordersNoVATCount || 0;

        console.log('📊 Rendering tables...');
        // Render By Rate Table
        renderByRateTable(data.breakdown || []);

        // Render Order Details Table
        renderOrderDetailsTable(data.orderDetails || []);

        // Render Product Stats Table
        renderProductStatsTable(data.productStats || []);

        console.log('✅ VAT Report rendered successfully');
        showToast('Đã tải báo cáo VAT thành công', 'success');
    }

    /**
     * Render By Rate Table
     */
    function renderByRateTable(breakdown) {
        const tbody = document.getElementById('vat-by-rate-table');

        if (!breakdown || breakdown.length === 0) {
            tbody.innerHTML = '<tr><td colspan="7" class="text-center text-gray-500 py-8">Không có dữ liệu</td></tr>';
            return;
        }

        tbody.innerHTML = breakdown.map(item => `
            <tr>
                <td><span class="badge-modern badge-info">${item.vatRate}%</span></td>
                <td>${formatCurrency(item.revenue)}</td>
                <td>${formatCurrency(item.vatAmount)}</td>
                <td>${formatCurrency(item.totalWithVAT)}</td>
                <td>${item.orderCount}</td>
                <td>${item.itemCount}</td>
                <td>${item.percentage.toFixed(1)}%</td>
            </tr>
        `).join('');
    }

    /**
     * Render Order Details Table
     */
    function renderOrderDetailsTable(orders) {
        const tbody = document.getElementById('vat-orders-table');

        if (!orders || orders.length === 0) {
            tbody.innerHTML = '<tr><td colspan="7" class="text-center text-gray-500 py-8">Không có đơn hàng nào</td></tr>';
            return;
        }

        tbody.innerHTML = orders.map(order => `
            <tr>
                <td><strong>${order.orderId}</strong></td>
                <td>${formatDate(order.date)}</td>
                <td>${order.customerName}</td>
                <td>${formatCurrency(order.subtotal)}</td>
                <td class="text-green-600 font-semibold">${formatCurrency(order.vatAmount)}</td>
                <td class="font-bold">${formatCurrency(order.total)}</td>
                <td>${getVATStatusBadge(order.status)}</td>
            </tr>
        `).join('');
    }

    /**
     * Render Product Stats Table
     */
    function renderProductStatsTable(products) {
        const tbody = document.getElementById('vat-products-table');

        if (!products || products.length === 0) {
            tbody.innerHTML = '<tr><td colspan="6" class="text-center text-gray-500 py-8">Không có sản phẩm nào</td></tr>';
            return;
        }

        tbody.innerHTML = products.map(product => `
            <tr>
                <td><code>${product.sku}</code></td>
                <td>${product.name}</td>
                <td class="text-center">${product.qtyWithVAT}</td>
                <td class="text-center">${product.qtyNoVAT}</td>
                <td>${formatCurrency(product.revenueWithVAT)}</td>
                <td class="text-green-600 font-semibold">${formatCurrency(product.vatCollected)}</td>
            </tr>
        `).join('');
    }

    /**
     * Get Status Badge HTML for VAT Report
     */
    function getVATStatusBadge(status) {
        const badges = {
            'Completed': '<span class="badge-modern badge-success">Hoàn Thành</span>',
            'Pending': '<span class="badge-modern badge-warning">Chờ Xử Lý</span>',
            'Cancelled': '<span class="badge-modern badge-error">Đã Hủy</span>'
        };
        return badges[status] || '<span class="badge-modern badge-info">' + status + '</span>';
    }

    // Helper to format date
    function formatDate(dateString) {
        if (!dateString) return '';
        const date = new Date(dateString);
        if (isNaN(date.getTime())) return dateString;
        return date.toLocaleDateString('vi-VN');
    }


    /**
     * Initialize VAT Report Page
     */
    function initVATReportPage() {
        console.log('🚀 initVATReportPage called');
        // Set default date range (last 30 days)
        const endDate = new Date();
        const startDate = new Date();
        startDate.setDate(startDate.getDate() - 30);

        const endInput = document.getElementById('vat-report-end-date');
        const startInput = document.getElementById('vat-report-start-date');

        if (endInput && startInput) {
            if (!endInput.value) endInput.valueAsDate = endDate;
            if (!startInput.value) startInput.valueAsDate = startDate;
        }

        // Auto load data
        loadVATReport();
    }

