    /**
     * Hiện modal cấp tài khoản cho nhân viên
     */
    function showAssignAccountModal() {
        editingUsername = null;
        document.getElementById('user-modal-title').textContent = 'Cấp Tài Khoản Nhân Viên';
        document.getElementById('user-modal-save-btn').textContent = 'Cấp Tài Khoản';
        document.getElementById('user-modal-username').value = '';
        document.getElementById('user-modal-username').disabled = false;
        document.getElementById('user-modal-password').value = '123456';
        document.getElementById('user-modal-password-group').classList.remove('hidden');
        document.getElementById('user-modal-employee-group').classList.remove('hidden');
        document.getElementById('user-modal-employee-info').classList.add('hidden');
        document.getElementById('user-modal-role').value = 'Cashier';
        document.getElementById('user-modal-error').classList.add('hidden');

        // Load nhân viên chưa có tài khoản
        loadEmployeesWithoutAccount();

        document.getElementById('user-modal').classList.remove('hidden');
    }

    /**
     * Sửa vai trò tài khoản nhân viên
     */
    function editAccountRole(username) {
        const user = usersData.find(function(u) { return u.username === username; });
        if (!user) return;

        editingUsername = username;
        document.getElementById('user-modal-title').textContent = 'Đổi Vai Trò - ' + (user.name || username);
        document.getElementById('user-modal-save-btn').textContent = 'Cập Nhật';
        document.getElementById('user-modal-username').value = user.username;
        document.getElementById('user-modal-username').disabled = true;
        document.getElementById('user-modal-password-group').classList.add('hidden');
        document.getElementById('user-modal-employee-group').classList.add('hidden');
        // Hiện thông tin nhân viên
        document.getElementById('user-modal-employee-info').classList.remove('hidden');
        document.getElementById('user-modal-emp-name').textContent = user.name || '-';
        document.getElementById('user-modal-emp-detail').textContent = (user.id || '') + ' - ' + (user.position || 'Chưa có chức vụ');
        document.getElementById('user-modal-role').value = user.role;
        document.getElementById('user-modal-error').classList.add('hidden');

        document.getElementById('user-modal').classList.remove('hidden');
    }

    function closeUserModal() {
        document.getElementById('user-modal').classList.add('hidden');
    }

    /**
     * Load nhân viên chưa có tài khoản vào dropdown
     */
    function loadEmployeesWithoutAccount() {
        const select = document.getElementById('user-modal-employee');
        select.innerHTML = '<option value="">-- Chọn nhân viên --</option>';

        // Lấy danh sách username đã có tài khoản
        const assignedIds = usersData.map(function(u) { return u.id; });

        var emps = employeesData || [];
        if (emps.length > 0) {
            populateEmployeeDropdown(emps, assignedIds, select);
        } else {
            google.script.run
                .withSuccessHandler(function(res) {
                    if (res && res.success && res.data) {
                        populateEmployeeDropdown(res.data, assignedIds, select);
                    }
                })
                .apiHandler('getEmployees', {});
        }
    }

    function populateEmployeeDropdown(emps, assignedIds, select) {
        emps.forEach(function(emp) {
            // Chỉ hiện nhân viên chưa có tài khoản
            if (assignedIds.indexOf(emp.id) === -1) {
                var opt = document.createElement('option');
                opt.value = emp.id;
                opt.textContent = emp.name + ' (' + emp.id + ')' + (emp.position ? ' - ' + emp.position : '');
                select.appendChild(opt);
            }
        });
    }

    /**
     * Lưu tài khoản (cấp mới hoặc đổi vai trò)
     */
    function handleSaveAccount() {
        var errorEl = document.getElementById('user-modal-error');
        var username = document.getElementById('user-modal-username').value.trim();
        var role = document.getElementById('user-modal-role').value;

        if (!username) {
            errorEl.textContent = 'Vui lòng nhập username';
            errorEl.classList.remove('hidden');
            return;
        }

        errorEl.classList.add('hidden');

        if (editingUsername) {
            // Đổi vai trò
            google.script.run
                .withSuccessHandler(function(res) {
                    if (res && res.success) {
                        closeUserModal();
                        localStorage.removeItem('TTL_usersManage');
                        loadUsers();
                        showToast('Cập nhật vai trò thành công!', 'success');
                    } else {
                        errorEl.textContent = res.message || 'Lỗi cập nhật';
                        errorEl.classList.remove('hidden');
                    }
                })
                .withFailureHandler(function() {
                    errorEl.textContent = 'Lỗi kết nối';
                    errorEl.classList.remove('hidden');
                })
                .apiHandler('updateAccountRole', { username: editingUsername, role: role });
        } else {
            // Cấp tài khoản mới
            var employeeId = document.getElementById('user-modal-employee').value;
            var password = document.getElementById('user-modal-password').value;

            if (!employeeId) {
                errorEl.textContent = 'Vui lòng chọn nhân viên';
                errorEl.classList.remove('hidden');
                return;
            }

            if (!password || password.length < 6) {
                errorEl.textContent = 'Mật khẩu phải ít nhất 6 ký tự';
                errorEl.classList.remove('hidden');
                return;
            }

            google.script.run
                .withSuccessHandler(function(res) {
                    if (res && res.success) {
                        closeUserModal();
                        localStorage.removeItem('TTL_usersManage');
                        loadUsers();
                        showToast('Cấp tài khoản thành công!', 'success');
                    } else {
                        errorEl.textContent = res.message || 'Lỗi cấp tài khoản';
                        errorEl.classList.remove('hidden');
                    }
                })
                .withFailureHandler(function() {
                    errorEl.textContent = 'Lỗi kết nối';
                    errorEl.classList.remove('hidden');
                })
                .apiHandler('assignAccount', { employeeId: employeeId, username: username, password: password, role: role });
        }
    }

