    // ============================================
    // SESSION TOKEN MANAGEMENT
    // ============================================

    function getSessionToken() {
        return localStorage.getItem('auth_token') || sessionStorage.getItem('auth_token') || '';
    }

    function setSessionToken(token) {
        if (token) {
            var remember = document.getElementById('login-remember');
            if (remember && remember.checked) {
                localStorage.setItem('auth_token', token);
                localStorage.setItem('auth_remember', '1');
            } else if (localStorage.getItem('auth_remember') === '1') {
                // Đang ở chế độ remember (auto-login) — giữ trong localStorage
                localStorage.setItem('auth_token', token);
            } else {
                sessionStorage.setItem('auth_token', token);
            }
        }
    }

    function clearSessionToken() {
        sessionStorage.removeItem('auth_token');
        localStorage.removeItem('auth_token');
        localStorage.removeItem('auth_remember');
    }

    // ============================================
    // HANDLE SESSION EXPIRED + AUTO-INJECT TOKEN
    // ============================================

    // Monkey-patch google.script.run để tự động gắn _token vào payload của apiHandler
    (function() {
        var _origGoogleScriptRun = google.script.run;

        function createRunProxy() {
            // Mỗi lần gọi google.script.run tạo proxy mới với handler riêng (thread-safe)
            var _successHandler = null;
            var _failureHandler = null;

            var proxy = new Proxy({}, {
                get: function(target, prop) {
                    if (prop === 'withSuccessHandler') {
                        return function(fn) {
                            _successHandler = fn;
                            return proxy;
                        };
                    }
                    if (prop === 'withFailureHandler') {
                        return function(fn) {
                            _failureHandler = fn;
                            return proxy;
                        };
                    }
                    if (prop === 'apiHandler') {
                        return function(action, payload) {
                            // Đảm bảo payload là plain object để gắn _token
                            // GAS serialize chỉ giữ index properties của Array,
                            // nên custom properties (như _token) trên Array sẽ bị mất
                            if (payload === null || payload === undefined) {
                                payload = {};
                            } else if (Array.isArray(payload)) {
                                // Wrap array thành object để không mất _token khi serialize
                                payload = { _payload: payload };
                            } else if (typeof payload !== 'object') {
                                // Wrap primitive (string, number) thành object để inject _token
                                payload = { _payload: payload };
                            }
                            payload._token = getSessionToken();

                            // Wrap success handler để detect SESSION_EXPIRED
                            var origSuccess = _successHandler;
                            var wrappedSuccess = function(res) {
                                if (res && !res.success && res.message === 'SESSION_EXPIRED') {
                                    clearSessionToken();
                                    showLoginScreen();
                                    return;
                                }
                                if (origSuccess) origSuccess(res);
                            };

                            var runner = _origGoogleScriptRun;
                            if (wrappedSuccess) runner = runner.withSuccessHandler(wrappedSuccess);
                            if (_failureHandler) runner = runner.withFailureHandler(_failureHandler);
                            runner.apiHandler(action, payload);
                        };
                    }
                    // Pass-through: các hàm GAS khác (không qua apiHandler)
                    return function() {
                        var runner = _origGoogleScriptRun;
                        if (_successHandler) runner = runner.withSuccessHandler(_successHandler);
                        if (_failureHandler) runner = runner.withFailureHandler(_failureHandler);
                        runner[prop].apply(runner, arguments);
                    };
                }
            });
            return proxy;
        }

        // Override google.script.run
        Object.defineProperty(google.script, 'run', {
            get: function() {
                return createRunProxy();
            }
        });

        // Patch showPage để load users khi vào settings
        var originalShowPage = window.showPage;
        if (originalShowPage) {
            window.showPage = function(page, event) {
                originalShowPage(page, event);
                if (page === 'settings' && currentUser && currentUser.role === 'Admin') {
                    loadUsers();
                }
            };
        }
    })();

    // ==========================================
    // LOGO UPLOAD HANDLING
    // ==========================================
    let currentPrintLogo = null;

    // Handle logo file selection
    document.addEventListener('DOMContentLoaded', function() {
        const logoInput = document.getElementById('print-logo-upload');
        if (logoInput) {
            logoInput.addEventListener('change', function(e) {
                const file = e.target.files[0];
                if (!file) return;

                // Check file type
                if (!file.type.startsWith('image/')) {
                    showToast('Vui lòng chọn file hình ảnh', 'error');
                    return;
                }

                // Check file size (max 500KB)
                if (file.size > 500 * 1024) {
                    showToast('Logo không được lớn hơn 500KB', 'error');
                    return;
                }

                // Convert to base64 with resize to fit PropertiesService 9KB limit
                const reader = new FileReader();
                reader.onload = function(event) {
                    const originalDataUrl = event.target.result;

                    // Resize image using Canvas to keep base64 small enough for PropertiesService
                    const img = new Image();
                    img.onload = function() {
                        // Compress to fit within PropertiesService 9000-char limit
                        // Target: JPEG quality step-down until size fits
                        const MAX_W = 200, MAX_H = 80;
                        let w = img.width, h = img.height;
                        if (w > MAX_W || h > MAX_H) {
                            const ratio = Math.min(MAX_W / w, MAX_H / h);
                            w = Math.round(w * ratio);
                            h = Math.round(h * ratio);
                        }
                        const canvas = document.createElement('canvas');
                        canvas.width = w; canvas.height = h;
                        const ctx = canvas.getContext('2d');
                        // White background for JPEG (no transparency issue)
                        ctx.fillStyle = '#FFFFFF';
                        ctx.fillRect(0, 0, w, h);
                        ctx.drawImage(img, 0, 0, w, h);

                        // Try JPEG with decreasing quality until < 6KB base64
                        let resized = '';
                        for (let q = 0.7; q >= 0.2; q -= 0.1) {
                            resized = canvas.toDataURL('image/jpeg', q);
                            if (resized.length <= 6000) break;
                        }

                        if (resized.length > 9000) {
                            showToast('Logo quá lớn để lưu (' + Math.round(resized.length/1024) + 'KB). Vui lòng dùng ảnh nhỏ hơn 50KB.', 'error');
                            return;
                        }

                        currentPrintLogo = resized;
                        document.getElementById('print-logo-filename').textContent = file.name + ' (~' + Math.round(resized.length/1024) + 'KB)';
                        document.getElementById('print-logo-preview').style.display = 'block';
                        document.getElementById('print-logo-preview-img').src = currentPrintLogo;
                        document.getElementById('print-logo-clear').style.display = 'inline-block';
                    };
                    img.src = originalDataUrl;
                };
                reader.readAsDataURL(file);
            });
        }
    });

    function clearPrintLogo() {
        currentPrintLogo = null;
        document.getElementById('print-logo-upload').value = '';
        document.getElementById('print-logo-filename').textContent = 'Chưa chọn file';
        document.getElementById('print-logo-preview').style.display = 'none';
        document.getElementById('print-logo-preview-img').src = '';
        document.getElementById('print-logo-clear').style.display = 'none';
    }


