  // ===== INVOICE EDITOR =====
  let editorOrder = null;
  // Cache named templates loaded from sheet — [{id, name, templateType}]
  var editorNamedTemplates = [];
  // Cache named template HTML to avoid re-fetching — { tplId: { html, templateType } }
  var namedTemplateHtmlCache = {};

  // Hardcoded built-in template IDs (not named templates from sheet)
  // a4/a5/receipt are now served as named templates from the sheet (seeded via settings)
  var BUILTIN_TEMPLATE_IDS = ['professional', 'a4', 'a5', 'receipt'];

  /** Returns true if templateId is a named template from the INVOICE_TEMPLATES sheet. */
  function isNamedTemplate(tplId) {
    return tplId && !BUILTIN_TEMPLATE_IDS.includes(tplId) && !tplId.startsWith('gas-');
  }

  /** Get templateType for a named template (a4/a5/receipt) — used for paper size. */
  function getNamedTemplateType(tplId) {
    var tpl = editorNamedTemplates.find(function(t) { return t.id === tplId; });
    return tpl ? (tpl.templateType || 'a4') : 'a4';
  }

  /**
   * Load named templates from sheet, append to editor-template-id dropdown.
   * Calls onReady(finalTemplateId) after done — use to trigger refreshEditorPreview.
   * Priority: localStorage saved templateId > settings templateId > 'professional'
   */
  function _loadEditorNamedTemplates(preferredTplId, onReady) {
    var select = document.getElementById('editor-template-id');
    if (!select) { if (onReady) onReady(preferredTplId); return; }

    // Remove any previously appended named template options (keep first 1 built-in: "professional")
    while (select.options.length > 1) select.remove(1);

    var _apply = function(resp) {
      editorNamedTemplates = [];
      if (resp && resp.success && resp.data && resp.data.length > 0) {
        var sep = document.createElement('option');
        sep.disabled = true;
        sep.textContent = '── Mẫu Đã Lưu ──';
        select.appendChild(sep);
        resp.data.forEach(function(tpl) {
          editorNamedTemplates.push({ id: tpl.id, name: tpl.name, templateType: tpl.templateType });
          var opt = document.createElement('option');
          opt.value = tpl.id;
          opt.textContent = tpl.name;
          select.appendChild(opt);
        });
      }
      // Apply preferred template — preferredTplId already accounts for localStorage via applyLocalPrefsToEditor
      select.value = preferredTplId;
      if (!select.value) select.value = 'professional';
      if (onReady) onReady(select.value);
    };

    google.script.run
      .withSuccessHandler(_apply)
      .withFailureHandler(function() {
        select.value = preferredTplId;
        if (!select.value) select.value = 'professional';
        if (onReady) onReady(select.value);
      })
      .apiHandler('listNamedTemplates', { templateType: '' });
  }

  /**
   * Open Invoice Editor modal with order data
   */
  function openInvoiceEditor(order) {
    if (!order || !order.id) {
      showToast('Dữ liệu đơn hàng không hợp lệ', 'error');
      return;
    }
    editorOrder = order;

    // Ensure print settings are loaded before opening editor
    const _doOpenEditor = () => {
      const settings = currentPrintSettings || {};
      const info = companyInfo || {};

      // Determine preferred template: localStorage takes priority over settings
      var localPrefs = loadPrintPrefsFromLocal();
      var preferredTplId = (localPrefs && localPrefs.templateId) || settings.templateId || 'professional';

      document.getElementById('editor-invoice-title').value = settings.invoiceTitle || 'HÓA ĐƠN TẠM TÍNH';
      document.getElementById('editor-footer-note').value = settings.footerNote || 'Cảm ơn quý khách và hẹn gặp lại';

      // Toggles - use saved defaults
      document.getElementById('editor-show-unit').checked = settings.showUnit !== false && settings.showUnit !== 'false';
      document.getElementById('editor-show-vat').checked = order.items && order.items.some(i => i.applyVat && (i.vatRate || 0) > 0);
      document.getElementById('editor-show-discount').checked = (order.discountAmount || 0) > 0;
      document.getElementById('editor-show-shipping').checked = (order.shippingFee || 0) > 0;
      document.getElementById('editor-show-debt').checked = true;
      document.getElementById('editor-show-bank').checked = settings.showBankInfo === true || settings.showBankInfo === 'true';
      document.getElementById('editor-show-signatures').checked = settings.showSignatures === true || settings.showSignatures === 'true';
      document.getElementById('editor-show-employee').checked = true;

      // Reset font scale to Vừa (1.0)
      var fsRadio = document.querySelector('input[name="editor-fontscale"][value="1.0"]');
      if (fsRadio) fsRadio.checked = true;

      // Reset orientation to portrait and toggle section visibility
      var portraitRadio = document.querySelector('input[name="editor-orientation"][value="portrait"]');
      if (portraitRadio) portraitRadio.checked = true;
      var editor2up = document.getElementById('editor-2up');
      if (editor2up) editor2up.checked = false;

      // Restore previously saved user preferences (overrides checkboxes above, but NOT templateId — handled by _loadEditorNamedTemplates)
      applyLocalPrefsToEditor(localPrefs);

      // Initialize block editor (reads saved blocks from localStorage)
      initBlockEditor();

      toggleOrientationSection();

      // Bank info from settings
      document.getElementById('editor-bank-name').value = settings.bankName || '';
      document.getElementById('editor-bank-account').value = settings.bankAccount || '';
      document.getElementById('editor-bank-account-name').value = settings.bankAccountName || '';
      document.getElementById('editor-bank-transfer-note').value = '';

      // Show/hide bank section based on checkbox
      toggleBankSection();

      // Show modal
      document.getElementById('invoice-editor-modal').classList.remove('hidden');

      // On mobile, adjust controls height
      const controls = document.getElementById('invoice-editor-controls');
      if (window.innerWidth < 768) {
        controls.style.maxHeight = '40vh';
      } else {
        controls.style.maxHeight = 'none';
      }

      // Load named templates then render preview — preview fires AFTER template ID is set
      var libs = [];
      if ((settings.showQR !== false && settings.showQR !== 'false') && typeof QRCode === 'undefined') libs.push('qrcode');
      if ((settings.showBarcode === true || settings.showBarcode === 'true') && typeof JsBarcode === 'undefined') libs.push('jsbarcode');
      var _doPreview = function() { refreshEditorPreview(); };
      _loadEditorNamedTemplates(preferredTplId, function() {
        if (libs.length > 0) {
          lazyLoadLibs(libs).then(_doPreview).catch(_doPreview);
        } else {
          _doPreview();
        }
      });
    };

    if (!currentPrintSettings) {
      loadPrintSettings().finally(_doOpenEditor);
    } else {
      _doOpenEditor();
    }
  }

  function closeInvoiceEditor() {
    document.getElementById('invoice-editor-modal').classList.add('hidden');
    editorOrder = null;
  }

  function toggleBankSection() {
    const showBank = document.getElementById('editor-show-bank').checked;
    document.getElementById('editor-bank-section').classList.toggle('hidden', !showBank);
  }

  function toggleOrientationSection() {
    const tplId = document.getElementById('editor-template-id').value;
    const show = (tplId === 'a4' || tplId === 'a5');
    document.getElementById('editor-orientation-section').classList.toggle('hidden', !show);
    // Only show 2-up option when landscape is selected
    const isLandscape = (document.querySelector('input[name="editor-orientation"]:checked') || {}).value === 'landscape';
    const label2up = document.getElementById('editor-2up-label');
    if (label2up) label2up.style.display = isLandscape ? '' : 'none';
  }

  // Override the onchange to also toggle bank section
  document.getElementById('editor-show-bank').addEventListener('change', function () {
    toggleBankSection();
    refreshEditorPreview();
  });

  /**
   * Collect current editor options
   */
  function collectEditorOptions() {
    const settings = (typeof currentPrintSettings !== 'undefined' && currentPrintSettings) || {};
    return {
      templateId: document.getElementById('editor-template-id').value,
      invoiceTitle: document.getElementById('editor-invoice-title').value,
      footerNote: document.getElementById('editor-footer-note').value,
      showUnit: document.getElementById('editor-show-unit').checked,
      showVat: document.getElementById('editor-show-vat').checked,
      showDiscount: document.getElementById('editor-show-discount').checked,
      showItemDiscount: editorOrder && editorOrder.items ? editorOrder.items.some(i => (i.discountAmount || 0) > 0) : false,
      showShipping: document.getElementById('editor-show-shipping').checked,
      showDebt: document.getElementById('editor-show-debt').checked,
      showBank: document.getElementById('editor-show-bank').checked,
      showSignatures: document.getElementById('editor-show-signatures').checked,
      showEmployee: document.getElementById('editor-show-employee').checked,
      fontScale: parseFloat((document.querySelector('input[name="editor-fontscale"]:checked') || {}).value || '1.0'),
      orientation: (document.querySelector('input[name="editor-orientation"]:checked') || {}).value || 'portrait',
      print2up: !!(document.getElementById('editor-2up') && document.getElementById('editor-2up').checked),
      showLogo: settings.showLogo !== false && settings.showLogo !== 'false',
      logo: settings.logo || '',
      showQR: settings.showQR !== false && settings.showQR !== 'false',
      showBarcode: settings.showBarcode !== false && settings.showBarcode !== 'false',
      bankId: settings.bankId || '',
      bankName: document.getElementById('editor-bank-name').value,
      bankAccount: document.getElementById('editor-bank-account').value,
      bankAccountName: document.getElementById('editor-bank-account-name').value,
      transferNote: document.getElementById('editor-bank-transfer-note').value,
      blockOrder: getBlockOrder()
    };
  }

  // --- Print preferences localStorage helpers ---
  var PRINT_PREFS_KEY = 'printEditorPrefs';

  function savePrintPrefsToLocal() {
    try {
      var prefs = {
        templateId: document.getElementById('editor-template-id').value,
        invoiceTitle: document.getElementById('editor-invoice-title').value,
        footerNote: document.getElementById('editor-footer-note').value,
        showUnit: document.getElementById('editor-show-unit').checked,
        showVat: document.getElementById('editor-show-vat').checked,
        showDiscount: document.getElementById('editor-show-discount').checked,
        showShipping: document.getElementById('editor-show-shipping').checked,
        showDebt: document.getElementById('editor-show-debt').checked,
        showBank: document.getElementById('editor-show-bank').checked,
        showSignatures: document.getElementById('editor-show-signatures').checked,
        showEmployee: document.getElementById('editor-show-employee').checked,
        fontScale: (document.querySelector('input[name="editor-fontscale"]:checked') || {}).value || '1.0',
        orientation: (document.querySelector('input[name="editor-orientation"]:checked') || {}).value || 'portrait',
        blocks: blockEditorState.map(function(b) { return { id: b.id, enabled: b.enabled, order: b.order }; })
      };
      localStorage.setItem(PRINT_PREFS_KEY, JSON.stringify(prefs));
    } catch(e) {}
  }

  function loadPrintPrefsFromLocal() {
    try {
      var raw = localStorage.getItem(PRINT_PREFS_KEY);
      return raw ? JSON.parse(raw) : null;
    } catch(e) { return null; }
  }

  function applyLocalPrefsToEditor(prefs) {
    if (!prefs) return;
    if (prefs.templateId) document.getElementById('editor-template-id').value = prefs.templateId;
    if (prefs.invoiceTitle !== undefined) document.getElementById('editor-invoice-title').value = prefs.invoiceTitle;
    if (prefs.footerNote !== undefined) document.getElementById('editor-footer-note').value = prefs.footerNote;
    if (prefs.showUnit !== undefined) document.getElementById('editor-show-unit').checked = !!prefs.showUnit;
    if (prefs.showVat !== undefined) document.getElementById('editor-show-vat').checked = !!prefs.showVat;
    if (prefs.showDiscount !== undefined) document.getElementById('editor-show-discount').checked = !!prefs.showDiscount;
    if (prefs.showShipping !== undefined) document.getElementById('editor-show-shipping').checked = !!prefs.showShipping;
    if (prefs.showDebt !== undefined) document.getElementById('editor-show-debt').checked = !!prefs.showDebt;
    if (prefs.showBank !== undefined) document.getElementById('editor-show-bank').checked = !!prefs.showBank;
    if (prefs.showSignatures !== undefined) document.getElementById('editor-show-signatures').checked = !!prefs.showSignatures;
    if (prefs.showEmployee !== undefined) document.getElementById('editor-show-employee').checked = !!prefs.showEmployee;
    if (prefs.fontScale) {
      var fsRadio = document.querySelector('input[name="editor-fontscale"][value="' + prefs.fontScale + '"]');
      if (fsRadio) fsRadio.checked = true;
    }
    if (prefs.orientation) {
      var orRadio = document.querySelector('input[name="editor-orientation"][value="' + prefs.orientation + '"]');
      if (orRadio) orRadio.checked = true;
    }
  }
  // --- End print preferences helpers ---

  // === BLOCK EDITOR ===
  // Default block definitions: id, label, defaultEnabled, maps to checkbox id
  var BLOCK_DEFS = [
    { id: 'header',     label: 'Header (Công ty)',    defaultOn: true,  checkboxId: null },
    { id: 'title',      label: 'Tiêu đề hóa đơn',   defaultOn: true,  checkboxId: null },
    { id: 'customer',   label: 'Thông tin KH',       defaultOn: true,  checkboxId: null },
    { id: 'employee',   label: 'Nhân Viên',          defaultOn: true,  checkboxId: 'editor-show-employee' },
    { id: 'items',      label: 'Bảng sản phẩm',      defaultOn: true,  checkboxId: null },
    { id: 'unit',       label: '↳ Cột Đơn Vị',       defaultOn: true,  checkboxId: 'editor-show-unit' },
    { id: 'vat',        label: '↳ Cột VAT',           defaultOn: false, checkboxId: 'editor-show-vat' },
    { id: 'discount',   label: 'Chiết khấu',         defaultOn: false, checkboxId: 'editor-show-discount' },
    { id: 'shipping',   label: 'Phí vận chuyển',     defaultOn: false, checkboxId: 'editor-show-shipping' },
    { id: 'summary',    label: 'Tổng cộng',          defaultOn: true,  checkboxId: null },
    { id: 'debt',       label: 'Nợ / Thanh toán',    defaultOn: true,  checkboxId: 'editor-show-debt' },
    { id: 'bank',       label: 'Ngân hàng / QR',     defaultOn: false, checkboxId: 'editor-show-bank' },
    { id: 'signatures', label: 'Chữ ký (KH & NB)',   defaultOn: false, checkboxId: 'editor-show-signatures' },
    { id: 'footer',     label: 'Ghi chú cuối',       defaultOn: true,  checkboxId: null }
  ];

  var blockEditorState = []; // [{id, enabled, order}]

  function getDefaultBlockState() {
    return BLOCK_DEFS.map(function(b, i) {
      return { id: b.id, enabled: b.defaultOn, order: i };
    });
  }

  function initBlockEditor() {
    // Load saved state from localStorage or use defaults
    var saved = loadPrintPrefsFromLocal();
    if (saved && saved.blocks && Array.isArray(saved.blocks)) {
      // Merge saved with current BLOCK_DEFS (handle new blocks added after save)
      var savedMap = {};
      saved.blocks.forEach(function(b) { savedMap[b.id] = b; });
      blockEditorState = BLOCK_DEFS.map(function(def, i) {
        var s = savedMap[def.id];
        return { id: def.id, enabled: s ? s.enabled : def.defaultOn, order: s ? s.order : i };
      });
      // Sort by saved order
      blockEditorState.sort(function(a, b) { return a.order - b.order; });
    } else {
      blockEditorState = getDefaultBlockState();
    }
    renderBlockList();
    syncBlocksToCheckboxes();
  }

  function renderBlockList() {
    var container = document.getElementById('block-editor-list');
    if (!container) return;

    container.innerHTML = blockEditorState.map(function(block, idx) {
      var def = BLOCK_DEFS.find(function(d) { return d.id === block.id; });
      var label = def ? def.label : block.id;
      var isSubItem = label.indexOf('↳') === 0;
      return '<div class="flex items-center gap-1 p-1.5 rounded-md ' + (block.enabled ? 'bg-white border border-gray-200' : 'bg-gray-100 border border-gray-100 opacity-60') + ' group" data-block-id="' + block.id + '" draggable="true">' +
        '<span class="cursor-grab text-gray-300 group-hover:text-gray-500 text-xs" title="Kéo để sắp xếp">≡</span>' +
        '<input type="checkbox" ' + (block.enabled ? 'checked' : '') + ' onchange="toggleBlock(\'' + block.id + '\', this.checked)" class="rounded border-gray-300 w-3.5 h-3.5">' +
        '<span class="text-xs flex-1 ' + (isSubItem ? 'pl-2 text-gray-500' : 'text-gray-700 font-medium') + '">' + label + '</span>' +
        '<span class="text-gray-300 text-xs">' +
          (idx > 0 ? '<button onclick="moveBlock(\'' + block.id + '\',-1)" class="hover:text-gray-600 px-0.5" title="Lên">▲</button>' : '') +
          (idx < blockEditorState.length - 1 ? '<button onclick="moveBlock(\'' + block.id + '\',1)" class="hover:text-gray-600 px-0.5" title="Xuống">▼</button>' : '') +
        '</span>' +
      '</div>';
    }).join('');

    // Add drag-and-drop listeners
    var items = container.querySelectorAll('[data-block-id]');
    items.forEach(function(item) {
      item.addEventListener('dragstart', function(e) {
        e.dataTransfer.setData('text/plain', item.getAttribute('data-block-id'));
        item.style.opacity = '0.4';
      });
      item.addEventListener('dragend', function() { item.style.opacity = '1'; });
      item.addEventListener('dragover', function(e) { e.preventDefault(); item.classList.add('ring-2', 'ring-blue-300'); });
      item.addEventListener('dragleave', function() { item.classList.remove('ring-2', 'ring-blue-300'); });
      item.addEventListener('drop', function(e) {
        e.preventDefault();
        item.classList.remove('ring-2', 'ring-blue-300');
        var draggedId = e.dataTransfer.getData('text/plain');
        var targetId = item.getAttribute('data-block-id');
        if (draggedId !== targetId) reorderBlock(draggedId, targetId);
      });
    });
  }

  function toggleBlock(blockId, enabled) {
    var block = blockEditorState.find(function(b) { return b.id === blockId; });
    if (block) block.enabled = enabled;
    renderBlockList();
    syncBlocksToCheckboxes();
    refreshEditorPreview();
  }

  function moveBlock(blockId, direction) {
    var idx = blockEditorState.findIndex(function(b) { return b.id === blockId; });
    if (idx < 0) return;
    var newIdx = idx + direction;
    if (newIdx < 0 || newIdx >= blockEditorState.length) return;
    // Swap
    var tmp = blockEditorState[idx];
    blockEditorState[idx] = blockEditorState[newIdx];
    blockEditorState[newIdx] = tmp;
    // Update order values
    blockEditorState.forEach(function(b, i) { b.order = i; });
    renderBlockList();
    syncBlocksToCheckboxes();
    refreshEditorPreview();
  }

  function reorderBlock(draggedId, targetId) {
    var fromIdx = blockEditorState.findIndex(function(b) { return b.id === draggedId; });
    var toIdx = blockEditorState.findIndex(function(b) { return b.id === targetId; });
    if (fromIdx < 0 || toIdx < 0) return;
    var item = blockEditorState.splice(fromIdx, 1)[0];
    blockEditorState.splice(toIdx, 0, item);
    blockEditorState.forEach(function(b, i) { b.order = i; });
    renderBlockList();
    syncBlocksToCheckboxes();
    refreshEditorPreview();
  }

  // Sync block enabled states to hidden checkboxes (backward compat)
  function syncBlocksToCheckboxes() {
    blockEditorState.forEach(function(block) {
      var def = BLOCK_DEFS.find(function(d) { return d.id === block.id; });
      if (def && def.checkboxId) {
        var cb = document.getElementById(def.checkboxId);
        if (cb) cb.checked = block.enabled;
      }
    });
    // Also update bank section visibility
    toggleBankSection();
  }

  // Get block order for template rendering
  function getBlockOrder() {
    return blockEditorState
      .filter(function(b) { return b.enabled; })
      .map(function(b) { return b.id; });
  }
  // === END BLOCK EDITOR ===

  // ═══════════════════════════════════════════════════════════════
  // HTML TEMPLATE EDITOR (Settings > Mẫu In)
  // textarea + live preview via GAS previewInvoiceTemplate
  // ═══════════════════════════════════════════════════════════════

  var tplCurrentTplId = null;   // Currently loaded template ID (for update vs create)
  var tplPreviewTimer = null;   // Debounce timer for live preview

  var tplEditorMode = 'wysiwyg'; // 'wysiwyg' or 'source'

  var _tplOriginalHead = ''; // Store original <head>...<style>...</head> for reconstruction

  /** Get current HTML from active editor. */
  function getTplHtml() {
    if (tplEditorMode === 'wysiwyg') {
      var div = document.getElementById('html-tpl-wysiwyg');
      if (!div) return '';
      var bodyHtml = div.innerHTML.trim();
      // Reconstruct full HTML with original head/style
      if (_tplOriginalHead) {
        return '<!DOCTYPE html>\n<html>\n' + _tplOriginalHead + '\n<body>\n' + bodyHtml + '\n</body>\n</html>';
      }
      return bodyHtml;
    }
    var ta = document.getElementById('html-tpl-editor');
    return ta ? ta.value.trim() : '';
  }

  /** Set HTML content into both editors. For WYSIWYG: extract body + inject styles. */
  function setTplHtml(html) {
    var ta = document.getElementById('html-tpl-editor');
    var div = document.getElementById('html-tpl-wysiwyg');
    if (ta) ta.value = html || '';
    if (div) _setWysiwygContent(div, html || '');
  }

  /** Parse full HTML template, extract body content + styles, render in WYSIWYG div. */
  function _setWysiwygContent(div, html) {
    // Store original <head> for reconstruction when saving
    var headMatch = html.match(/<head[^>]*>([\s\S]*?)<\/head>/i);
    if (headMatch) _tplOriginalHead = '<head>' + headMatch[1] + '</head>';

    // Remove old injected style
    var oldStyle = document.getElementById('tpl-wysiwyg-style');
    if (oldStyle) oldStyle.remove();

    // Extract <style> content from template
    var styleMatch = html.match(/<style[^>]*>([\s\S]*?)<\/style>/i);
    if (styleMatch) {
      var style = document.createElement('style');
      style.id = 'tpl-wysiwyg-style';
      // Scope styles to the WYSIWYG div by prefixing selectors
      var css = styleMatch[1]
        .replace(/body\b/g, '#html-tpl-wysiwyg')
        .replace(/:root/g, '#html-tpl-wysiwyg');
      // Add placeholder highlight style
      css += '\n/* Highlight {{placeholders}} */\n';
      style.textContent = css;
      document.head.appendChild(style);
    }

    // Extract <body> content (or use full HTML if no body tag)
    var bodyMatch = html.match(/<body[^>]*>([\s\S]*?)<\/body>/i);
    div.innerHTML = bodyMatch ? bodyMatch[1] : html;
  }

  /** Toggle between WYSIWYG and Source mode. */
  function toggleTplEditorMode() {
    var div = document.getElementById('html-tpl-wysiwyg');
    var ta = document.getElementById('html-tpl-editor');
    var btn = document.getElementById('tpl-mode-toggle');
    if (tplEditorMode === 'wysiwyg') {
      // Switch to Source: sync WYSIWYG → textarea
      if (ta && div) ta.value = div.innerHTML;
      if (div) div.style.display = 'none';
      if (ta) ta.style.display = 'block';
      if (btn) btn.textContent = 'WYSIWYG';
      tplEditorMode = 'source';
    } else {
      // Switch to WYSIWYG: sync textarea → WYSIWYG (with style extraction)
      if (div && ta) _setWysiwygContent(div, ta.value);
      if (ta) ta.style.display = 'none';
      if (div) div.style.display = 'block';
      if (btn) btn.textContent = 'Source';
      tplEditorMode = 'wysiwyg';
    }
  }

  /** Called on WYSIWYG div input — debounce live preview. */
  function onWysiwygInput() {
    if (tplPreviewTimer) clearTimeout(tplPreviewTimer);
    tplPreviewTimer = setTimeout(refreshTplLivePreview, 1200);
  }

  /** Insert variable text at cursor position (WYSIWYG or Source). */
  function insertQuillVar(varText) {
    if (tplEditorMode === 'wysiwyg') {
      // Insert into contenteditable div at cursor
      var div = document.getElementById('html-tpl-wysiwyg');
      if (!div) return;
      div.focus();
      // Use execCommand insertText for contenteditable
      document.execCommand('insertText', false, varText);
      onWysiwygInput();
      return;
    }
    var ta = document.getElementById('html-tpl-editor');
    if (!ta) return;
    var start = ta.selectionStart;
    var end = ta.selectionEnd;
    ta.value = ta.value.substring(0, start) + varText + ta.value.substring(end);
    ta.selectionStart = ta.selectionEnd = start + varText.length;
    ta.focus();
    onHtmlTplEditorInput();
  }

  /** Called on textarea input — debounce live preview update. */
  function onHtmlTplEditorInput() {
    if (tplPreviewTimer) clearTimeout(tplPreviewTimer);
    tplPreviewTimer = setTimeout(refreshTplLivePreview, 1200);
  }

  /** Refresh live preview iframe with current textarea HTML via GAS render. */
  function refreshTplLivePreview() {
    var html = getTplHtml();
    var typeEl = document.getElementById('quill-tpl-type');
    var type = typeEl ? typeEl.value : 'a4';
    var statusEl = document.getElementById('tpl-preview-status');
    var iframe = document.getElementById('html-tpl-preview-frame');
    if (!iframe) return;
    if (!html) {
      var doc = iframe.contentDocument || iframe.contentWindow.document;
      doc.open(); doc.write('<p style="color:#9ca3af;padding:20px;">Chưa có nội dung mẫu...</p>'); doc.close();
      return;
    }
    if (statusEl) statusEl.textContent = '⏳ Đang render...';
    var dummyOrder = {
      id: 'DH-PREVIEW-001', date: new Date().toISOString(),
      customerName: 'Nguyễn Văn A', customerPhone: '0901234567',
      customerAddress: '123 Lê Lợi, Q1, TP.HCM', employeeName: 'Nhân viên Demo',
      notes: 'Giao hàng trước 5h chiều', total: 1500000, paid: 1000000, debt: 500000,
      discountAmount: 50000, shippingFee: 30000,
      items: [
        { productName: 'Sản phẩm mẫu 1', sku: 'SP001', qty: 2, price: 500000, total: 1000000, unit: 'Cái', discountAmount: 0 },
        { productName: 'Sản phẩm mẫu 2', sku: 'SP002', qty: 1, price: 550000, total: 500000, unit: 'Cái', discountAmount: 50000 }
      ]
    };
    google.script.run
      .withSuccessHandler(function(resp) {
        if (statusEl) statusEl.textContent = '';
        if (resp && resp.success) {
          var previewHtml = (resp.data && resp.data.html) ? resp.data.html : (resp.html || '');
          var doc = iframe.contentDocument || iframe.contentWindow.document;
          doc.open(); doc.write(previewHtml); doc.close();
        } else {
          if (statusEl) statusEl.textContent = '❌ ' + ((resp && resp.message) || 'Lỗi');
        }
      })
      .withFailureHandler(function(e) {
        if (statusEl) statusEl.textContent = '❌ Lỗi kết nối';
      })
      .apiHandler('previewInvoiceTemplate', {
        order: dummyOrder, templateId: type,
        options: { customHtml: html, showUnit: true, showItemDiscount: true, showDebt: true, showDiscount: true, showShipping: true }
      });
  }

  /** Refresh saved templates dropdown for the currently selected type. */
  function onQuillTplTypeChange() { refreshQuillSavedList(); }

  /** Populate the quill-saved-list dropdown from a templates array. */
  function _applyTemplateList(templates, autoSelectId) {
    var select = document.getElementById('quill-saved-list');
    if (!select) return;
    var count = templates ? templates.length : 0;
    select.innerHTML = '<option value="">-- Chọn mẫu (' + count + ') --</option>';
    if (templates) {
      templates.forEach(function(tpl) {
        var opt = document.createElement('option');
        opt.value = tpl.id;
        opt.textContent = tpl.name + ' (' + new Date(tpl.updatedAt).toLocaleDateString('vi-VN') + ')';
        select.appendChild(opt);
      });
    }
    if (autoSelectId) select.value = autoSelectId;
    else if (tplCurrentTplId) select.value = tplCurrentTplId;
  }

  function refreshQuillSavedList(autoSelectId) {
    var typeEl = document.getElementById('quill-tpl-type');
    var select = document.getElementById('quill-saved-list');
    if (!typeEl || !select) {
      console.warn('[refreshQuillSavedList] elements not found');
      return;
    }
    var type = typeEl.value || '';
    select.innerHTML = '<option value="">-- Đang tải... --</option>';
    google.script.run
      .withSuccessHandler(function(resp) {
        console.log('[refreshQuillSavedList] resp success=' + (resp && resp.success) + ' count=' + (resp && resp.data ? resp.data.length : 0));
        if (resp && resp.success && resp.data) {
          _applyTemplateList(resp.data, autoSelectId);
        } else {
          select.innerHTML = '<option value="">-- Lỗi: ' + ((resp && resp.message) || 'không tải được') + ' --</option>';
          console.error('[refreshQuillSavedList] error:', resp && resp.message);
        }
      })
      .withFailureHandler(function(err) {
        console.error('[refreshQuillSavedList] fail:', err);
        select.innerHTML = '<option value="">-- Lỗi tải danh sách --</option>';
      })
      .apiHandler('listNamedTemplates', { templateType: type });
  }

  /** Load selected saved template HTML into textarea. */
  function loadSelectedQuillTemplate() {
    var select = document.getElementById('quill-saved-list');
    var tplId = select ? select.value : '';
    if (!tplId) { showToast('Vui lòng chọn mẫu cần tải', 'warning'); return; }
    google.script.run
      .withSuccessHandler(function(resp) {
        if (resp && resp.success && resp.data) {
          setTplHtml(resp.data.html || '');
          tplCurrentTplId = resp.data.id;
          var nameEl = document.getElementById('quill-tpl-name');
          var typeEl = document.getElementById('quill-tpl-type');
          if (nameEl) nameEl.value = resp.data.name;
          if (typeEl) typeEl.value = resp.data.templateType;
          showToast('Đã tải mẫu: ' + resp.data.name, 'success');
          refreshTplLivePreview();
        } else {
          showToast((resp && resp.message) || 'Lỗi tải mẫu', 'error');
        }
      })
      .withFailureHandler(function(e) { showToast('Lỗi kết nối: ' + e, 'error'); })
      .apiHandler('loadNamedTemplate', { templateId: tplId });
  }

  /** Delete selected saved template with confirmation. */
  function deleteSelectedQuillTemplate() {
    var select = document.getElementById('quill-saved-list');
    var tplId = select ? select.value : '';
    var tplName = (select && select.selectedIndex >= 0) ? select.options[select.selectedIndex].text : '';
    if (!tplId) { showToast('Vui lòng chọn mẫu cần xóa', 'warning'); return; }
    if (!confirm('Bạn có chắc muốn xóa mẫu "' + tplName + '"?')) return;
    google.script.run
      .withSuccessHandler(function(resp) {
        if (resp && resp.success) {
          showToast('Đã xóa mẫu', 'success');
          if (tplCurrentTplId === tplId) tplCurrentTplId = null;
          refreshQuillSavedList();
        } else {
          showToast((resp && resp.message) || 'Lỗi xóa mẫu', 'error');
        }
      })
      .withFailureHandler(function(e) { showToast('Lỗi kết nối: ' + e, 'error'); })
      .apiHandler('deleteNamedTemplate', { templateId: tplId });
  }

  /** Delete ALL saved templates with confirmation. */
  function deleteAllQuillTemplates() {
    if (!confirm('Bạn có chắc muốn XÓA TẤT CẢ mẫu đã lưu? Hành động này không thể hoàn tác.')) return;
    google.script.run
      .withSuccessHandler(function(resp) {
        if (resp && resp.success) {
          showToast(resp.message || 'Đã xóa tất cả mẫu', 'success');
          tplCurrentTplId = null;
          refreshQuillSavedList();
        } else {
          showToast((resp && resp.message) || 'Lỗi xóa mẫu', 'error');
        }
      })
      .withFailureHandler(function(e) { showToast('Lỗi kết nối: ' + e, 'error'); })
      .apiHandler('deleteAllNamedTemplates', {});
  }

  /** Load the default GAS template HTML into textarea for editing. */
  function loadDefaultTemplateToQuill() {
    var typeEl = document.getElementById('quill-tpl-type');
    var type = typeEl ? typeEl.value : 'a4';
    google.script.run
      .withSuccessHandler(function(resp) {
        if (resp && resp.success && resp.data && resp.data.html) {
          setTplHtml(resp.data.html);
          tplCurrentTplId = null;
          var nameEl = document.getElementById('quill-tpl-name');
          if (nameEl) nameEl.value = '';
          showToast('Đã tải mẫu gốc ' + type.toUpperCase(), 'success');
          refreshTplLivePreview();
        } else {
          showToast((resp && resp.message) || 'Lỗi tải mẫu gốc', 'error');
        }
      })
      .withFailureHandler(function(e) { showToast('Lỗi kết nối: ' + e, 'error'); })
      .apiHandler('getTemplateSource', { templateId: type, forceOriginal: true });
  }

  /** Save current editor HTML as a named template to Sheet. */
  function saveQuillTemplate() {
    var nameEl = document.getElementById('quill-tpl-name');
    var typeEl = document.getElementById('quill-tpl-type');
    var name = nameEl ? nameEl.value.trim() : '';
    var type = typeEl ? typeEl.value : 'a4';
    // In WYSIWYG mode, sync to textarea first to ensure consistency
    if (tplEditorMode === 'wysiwyg') {
      var div = document.getElementById('html-tpl-wysiwyg');
      var ta = document.getElementById('html-tpl-editor');
      if (div && ta) ta.value = div.innerHTML;
    }
    // Always read from textarea (source of truth for saving)
    var ta = document.getElementById('html-tpl-editor');
    var html = ta ? ta.value.trim() : '';
    if (!name) { showToast('Vui lòng nhập tên mẫu', 'warning'); return; }
    if (!html) { showToast('Nội dung mẫu trống', 'warning'); return; }
    console.log('[saveQuillTemplate] name=' + name + ', type=' + type + ', html.length=' + html.length);
    // listType = '' means return all types (same as current filter)
    var payload = { name: name, templateType: type, html: html, listType: '' };
    if (tplCurrentTplId) payload.id = tplCurrentTplId;
    showToast('Đang lưu mẫu...', 'info');
    try {
      google.script.run
        .withSuccessHandler(function(resp) {
          try {
            console.log('[saveQuillTemplate] resp success=' + (resp && resp.success) + ' msg=' + (resp && resp.message));
            if (resp && resp.success) {
              // Combined response: { id, templates: [...] }
              if (resp.data && resp.data.id) tplCurrentTplId = resp.data.id;
              showToast(resp.message || 'Đã lưu mẫu', 'success');
              _applyTemplateList(resp.data && resp.data.templates, tplCurrentTplId);
            } else {
              showToast((resp && resp.message) || 'Lỗi lưu mẫu', 'error');
            }
          } catch(handlerErr) {
            console.error('[saveQuillTemplate] handler error:', handlerErr);
            showToast('Lỗi xử lý response: ' + handlerErr, 'error');
          }
        })
        .withFailureHandler(function(e) {
          console.error('[saveQuillTemplate] fail:', e);
          showToast('Lỗi kết nối: ' + e, 'error');
        })
        .apiHandler('saveAndListNamedTemplates', payload);
    } catch(callErr) {
      console.error('[saveQuillTemplate] call error:', callErr);
      showToast('Lỗi gọi API: ' + callErr, 'error');
    }
  }

  /** Apply current textarea HTML as active custom template (replaces mẫu in mặc định). */
  function applyQuillAsCustomTemplate() {
    var typeEl = document.getElementById('quill-tpl-type');
    var type = typeEl ? typeEl.value : 'a4';
    var html = getTplHtml();
    if (!html) { showToast('Nội dung mẫu trống', 'warning'); return; }
    if (!confirm('Áp dụng mẫu này làm mẫu in mặc định cho loại ' + type.toUpperCase() + '?')) return;
    google.script.run
      .withSuccessHandler(function(resp) {
        if (resp && resp.success) { showToast('Đã áp dụng làm mẫu mặc định', 'success'); }
        else { showToast((resp && resp.message) || 'Lỗi áp dụng', 'error'); }
      })
      .withFailureHandler(function(e) { showToast('Lỗi kết nối: ' + e, 'error'); })
      .apiHandler('saveInvoiceTemplate', { templateId: type, html: html });
  }

  /**
   * Seed all 3 default templates (A4, A5, Receipt) into the saved templates list.
   * Single server-side call reads template files and saves to sheet.
   */
  function seedDefaultTemplatesToList() {
    if (!confirm('Tạo lại 3 mẫu in gốc (A4, A5, 80mm POS) vào danh sách?\nNếu mẫu đã tồn tại sẽ được cập nhật.')) return;
    showToast('Đang tạo mẫu...', 'info');
    google.script.run
      .withSuccessHandler(function(resp) {
        if (resp && resp.success) {
          showToast(resp.message || 'Đã tạo 3 mẫu gốc', 'success');
        } else {
          showToast((resp && resp.message) || 'Lỗi tạo mẫu', 'error');
        }
        refreshQuillSavedList();
      })
      .withFailureHandler(function(e) { showToast('Lỗi kết nối: ' + e, 'error'); })
      .apiHandler('seedDefaultTemplates', { overwrite: true });
  }

  // === END HTML TEMPLATE EDITOR ===

  /**
   * Refresh live preview in editor
   */
  function refreshEditorPreview() {
    if (!editorOrder) return;
    savePrintPrefsToLocal(); // auto-save prefs on every preview refresh
    const options = collectEditorOptions();
    const container = document.getElementById('invoice-editor-preview');

    // Named template from sheet: use cached HTML if available, else 1 combined API call
    if (isNamedTemplate(options.templateId)) {
      var namedTplId = options.templateId;
      var cached = namedTemplateHtmlCache[namedTplId];
      var renderOpts = {
        showUnit: options.showUnit, showVat: options.showVat,
        showItemDiscount: options.showItemDiscount || false,
        showSignatures: options.showSignatures, showDebt: options.showDebt,
        showDiscount: options.showDiscount, showShipping: options.showShipping,
        showEmployee: options.showEmployee, showBank: options.showBank,
        invoiceTitle: options.invoiceTitle, footerNote: options.footerNote,
        bankName: options.bankName, bankAccount: options.bankAccount,
        bankAccountName: options.bankAccountName, transferNote: options.transferNote
      };

      if (cached && cached.html) {
        // Cache hit: use previewInvoiceTemplate with cached customHtml (1 call, no load needed)
        container.innerHTML = '<div style="text-align:center;padding:40px;color:#888;">⏳ Đang render...</div>';
        renderOpts.customHtml = cached.html;
        google.script.run
          .withSuccessHandler(function(res) {
            if (res && res.success && res.data && res.data.html) container.innerHTML = res.data.html;
            else container.innerHTML = '<div style="text-align:center;padding:40px;color:#DC2626;">❌ Lỗi render: ' + ((res && res.message) || '') + '</div>';
          })
          .withFailureHandler(function(err) { container.innerHTML = '<div style="text-align:center;padding:40px;color:#DC2626;">❌ ' + err + '</div>'; })
          .apiHandler('previewInvoiceTemplate', { order: editorOrder, templateId: cached.templateType || 'a4', options: renderOpts });
      } else {
        // Cache miss: use combined previewNamedTemplate (1 call = load + render)
        container.innerHTML = '<div style="text-align:center;padding:40px;color:#888;">⏳ Đang tải mẫu...</div>';
        google.script.run
          .withSuccessHandler(function(res) {
            if (res && res.success && res.data && res.data.html) {
              container.innerHTML = res.data.html;
              // Cache the template HTML for next time
              namedTemplateHtmlCache[namedTplId] = { html: res.data.templateHtml, templateType: res.data.templateType };
            } else {
              container.innerHTML = '<div style="text-align:center;padding:40px;color:#DC2626;">❌ Lỗi: ' + ((res && res.message) || '') + '</div>';
            }
          })
          .withFailureHandler(function(err) { container.innerHTML = '<div style="text-align:center;padding:40px;color:#DC2626;">❌ ' + err + '</div>'; })
          .apiHandler('previewNamedTemplate', { order: editorOrder, namedTemplateId: namedTplId, options: renderOpts });
      }
      return;
    }

    // GAS template: render server-side via previewInvoiceTemplate
    // 'gas-*' prefix OR built-in 'a4'/'a5'/'receipt' all use GAS HTML files
    var isGasTemplate = options.templateId && (
      options.templateId.startsWith('gas-') ||
      options.templateId === 'a4' ||
      options.templateId === 'a5' ||
      options.templateId === 'receipt'
    );
    if (isGasTemplate) {
      var gasTemplateId = options.templateId.startsWith('gas-')
        ? options.templateId.replace('gas-', '')
        : options.templateId;
      container.innerHTML = '<div style="text-align:center;padding:40px;color:#888;">⏳ Đang render từ GAS server...</div>';
      google.script.run
        .withSuccessHandler(function(res) {
          if (res && res.success && res.data && res.data.html) {
            container.innerHTML = res.data.html;
          } else {
            container.innerHTML = '<div style="text-align:center;padding:40px;color:#DC2626;">❌ Lỗi render: ' + (res && res.message || 'Unknown') + '</div>';
          }
        })
        .withFailureHandler(function(err) {
          container.innerHTML = '<div style="text-align:center;padding:40px;color:#DC2626;">❌ Lỗi GAS: ' + err.toString() + '</div>';
        })
        .apiHandler('previewInvoiceTemplate', {
          order: editorOrder,
          templateId: gasTemplateId,
          options: {
            showUnit: options.showUnit,
            showVat: options.showVat,
            showItemDiscount: options.showItemDiscount || false,
            showSignatures: options.showSignatures,
            showDebt: options.showDebt,
            showDiscount: options.showDiscount,
            showShipping: options.showShipping,
            showEmployee: options.showEmployee,
            showBank: options.showBank,
            invoiceTitle: options.invoiceTitle,
            footerNote: options.footerNote,
            bankName: options.bankName,
            bankAccount: options.bankAccount,
            bankAccountName: options.bankAccountName,
            transferNote: options.transferNote
          }
        });
      return;
    }

    // Local JS template rendering
    const info = getMergedCompanyInfo();
    const html = renderInvoiceTemplate(editorOrder, info, options);
    container.innerHTML = html;

    // Post-render: generate QR codes from data-qr attributes
    container.querySelectorAll('[data-qr]').forEach(function(el) {
      var text = el.getAttribute('data-qr');
      if (text && typeof QRCode !== 'undefined') {
        try { new QRCode(el, { text: text, width: 100, height: 100, correctLevel: QRCode.CorrectLevel.M }); } catch(e) {}
      }
    });
    // Post-render: generate barcodes from data-barcode attributes
    container.querySelectorAll('svg[data-barcode]').forEach(function(el) {
      var val = el.getAttribute('data-barcode');
      if (val && typeof JsBarcode !== 'undefined') {
        try { JsBarcode(el, val, { format: 'CODE128', width: 1.5, height: 40, displayValue: false, margin: 0 }); } catch(e) {}
      }
    });
  }

  /**
   * Merge company info from print settings and companyInfo
   */
  function getMergedCompanyInfo() {
    const settings = currentPrintSettings || {};
    const rawInfo = companyInfo || {};
    return {
      name: settings.companyName || rawInfo.name || '',
      address: settings.companyAddress || rawInfo.address || '',
      phone: settings.companyPhone || rawInfo.phone || '',
      email: settings.companyEmail || rawInfo.email || '',
      tax: settings.companyTax || rawInfo.tax || '',
      website: settings.companyWebsite || rawInfo.website || '',
      notes: settings.footerNote || rawInfo.notes || ''
    };
  }

  /**
   * Print from editor
   */
  function printFromEditor() {
    if (!editorOrder) return;
    const options = collectEditorOptions();
    var html;

    // Named templates and GAS templates: reuse HTML already rendered in preview container
    var isPrintGasTemplate = options.templateId && (
      isNamedTemplate(options.templateId) ||
      options.templateId.startsWith('gas-') ||
      options.templateId === 'a4' ||
      options.templateId === 'a5' ||
      options.templateId === 'receipt'
    );
    if (isPrintGasTemplate) {
      html = document.getElementById('invoice-editor-preview').innerHTML;
      if (!html || html.includes('Đang render') || html.includes('Đang tải')) {
        showToast('Vui lòng đợi mẫu render xong trước khi in', 'warning');
        return;
      }
    } else {
      const info = getMergedCompanyInfo();
      html = renderInvoiceTemplate(editorOrder, info, options);
    }

    // Paper size per template + orientation
    // For named templates, derive paper size from templateType stored in editorNamedTemplates
    var resolvedTplId = isNamedTemplate(options.templateId)
      ? getNamedTemplateType(options.templateId)
      : options.templateId.replace('gas-', '');
    const tplId = resolvedTplId;
    const isLandscape = (tplId === 'a4' || tplId === 'a5') && options.orientation === 'landscape';
    const is2up = isLandscape && options.print2up;
    let pageSize, bodyWidth, bodyPadding;
    if (tplId === 'receipt') {
      pageSize = '80mm auto'; bodyWidth = '80mm'; bodyPadding = '4mm 3mm';
    } else if (tplId === 'a5') {
      pageSize = isLandscape ? 'A5 landscape' : 'A5';
      bodyWidth = isLandscape ? '210mm' : '148mm';
      bodyPadding = '0.8cm';
    } else {
      pageSize = isLandscape ? 'A4 landscape' : 'A4';
      bodyWidth = isLandscape ? '297mm' : '210mm';
      bodyPadding = '1.2cm';
    }

    // 2-up: print 2 A5 invoices side-by-side on A4 landscape
    let twoUpCSS = '';
    if (is2up) {
      pageSize = 'A4 landscape';
      bodyWidth = '297mm';
      bodyPadding = '0';
      twoUpCSS = `
        .invoice-2up-wrapper { display:flex; width:297mm; }
        .invoice-2up-col { width:148mm; padding:0.8cm; overflow:hidden; box-sizing:border-box; }
        .invoice-2up-divider { width:1px; background:#ccc; flex-shrink:0; }
      `;
    }

    const pageCSS = `@media print { @page { size: ${pageSize}; margin: 0; } html, body { width: ${bodyWidth}; margin: 0; } body { padding: ${is2up ? '0' : bodyPadding}; } .no-print { display: none !important; } }`;

    // For 2-up: duplicate the invoice side by side
    const bodyContent = is2up
      ? `<div class="invoice-2up-wrapper"><div class="invoice-2up-col">${html}</div><div class="invoice-2up-divider"></div><div class="invoice-2up-col">${html}</div></div>`
      : html;

    const printHTML = `<!DOCTYPE html><html><head><meta charset="UTF-8">
<style>
  * { box-sizing: border-box; }
  html, body { margin: 0; padding: 0; width: ${bodyWidth}; }
  body { font-family: Arial, sans-serif; padding: ${is2up ? '0' : bodyPadding}; color: #000; }
  table { width: 100% !important; }
  ${pageCSS}
  ${twoUpCSS}
  @media print { * { -webkit-print-color-adjust: exact; print-color-adjust: exact; } }
</style></head><body>${bodyContent}</body></html>`;

    // In-page print: inject print-only content + CSS, call window.print(), then clean up
    // This is the only approach that works reliably in GAS iframe sandbox
    try {
      // Clean up any previous print elements
      var oldStyle = document.getElementById('editor-print-style');
      var oldDiv = document.getElementById('editor-print-content');
      if (oldStyle) oldStyle.remove();
      if (oldDiv) oldDiv.remove();

      // Inject @media print CSS to hide everything except our print div
      var style = document.createElement('style');
      style.id = 'editor-print-style';
      style.textContent = `
        @media print {
          body > *:not(#editor-print-content) { display: none !important; visibility: hidden !important; height: 0 !important; overflow: hidden !important; }
          #editor-print-content { display: block !important; visibility: visible !important; position: static !important; }
          @page { size: ${pageSize}; margin: 0; }
          * { -webkit-print-color-adjust: exact; print-color-adjust: exact; }
        }
        #editor-print-content { display: none; }
      `;
      document.head.appendChild(style);

      // Create print div (hidden on screen, visible only in print)
      var printDiv = document.createElement('div');
      printDiv.id = 'editor-print-content';
      printDiv.style.cssText = 'font-family:Arial,sans-serif; color:#000; padding:' + (is2up ? '0' : bodyPadding) + '; width:' + bodyWidth + '; margin:0 auto;';
      printDiv.innerHTML = bodyContent;
      document.body.appendChild(printDiv);

      // Clean up function
      var _cleanupPrint = function() {
        var s = document.getElementById('editor-print-style');
        var d = document.getElementById('editor-print-content');
        if (s) s.remove();
        if (d) d.remove();
        window.removeEventListener('afterprint', _cleanupPrint);
      };
      // Listen for afterprint event (fires when print dialog closes)
      window.addEventListener('afterprint', _cleanupPrint);

      // Small delay to ensure DOM is ready, then print
      setTimeout(function() {
        window.print();
        // Fallback cleanup if afterprint doesn't fire
        setTimeout(_cleanupPrint, 3000);
      }, 100);
    } catch (e) {
      showToast('Lỗi khi in: ' + e.toString(), 'error');
      // Ensure cleanup on error
      var s = document.getElementById('editor-print-style');
      var d = document.getElementById('editor-print-content');
      if (s) s.remove();
      if (d) d.remove();
    }
  }

  /**
   * Export PDF from editor
   */
  function exportPDFFromEditor() {
    if (!editorOrder) return;

    if (typeof html2canvas === 'undefined' || typeof jspdf === 'undefined') {
      showToast('Đang tải thư viện PDF...', 'info');
      lazyLoadLibs(['jspdf', 'html2canvas']).then(function() { exportPDFFromEditor(); }).catch(function() { showToast('Không thể tải thư viện PDF', 'error'); });
      return;
    }

    const previewEl = document.getElementById('invoice-editor-preview');
    showToast('Đang tạo PDF...', 'info');

    html2canvas(previewEl, { scale: 1.5, useCORS: true, backgroundColor: '#ffffff' }).then(canvas => {
      const imgData = canvas.toDataURL('image/png');
      const { jsPDF } = jspdf;
      const pdf = new jsPDF('p', 'mm', 'a4');
      const pdfWidth = pdf.internal.pageSize.getWidth();
      const pdfHeight = (canvas.height * pdfWidth) / canvas.width;
      pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
      pdf.save('HoaDon_' + editorOrder.id + '.pdf');
      showToast('Đã xuất PDF thành công!', 'success');
    }).catch(err => {
      showToast('Lỗi tạo PDF: ' + err.toString(), 'error');
    });
  }

  /**
   * Export Image from editor
   */
  function exportImageFromEditor() {
    if (!editorOrder) return;

    if (typeof html2canvas === 'undefined') {
      showToast('Đang tải thư viện...', 'info');
      lazyLoadLibs(['html2canvas']).then(function() { exportImageFromEditor(); }).catch(function() { showToast('Không thể tải thư viện', 'error'); });
      return;
    }

    var previewEl = document.getElementById('invoice-editor-preview');
    showToast('Đang tạo ảnh...', 'info');

    html2canvas(previewEl, { scale: 2, useCORS: true, backgroundColor: '#ffffff' }).then(function(canvas) {
      var link = document.createElement('a');
      link.download = 'HoaDon_' + editorOrder.id + '.png';
      link.href = canvas.toDataURL('image/png');
      link.click();
      showToast('Đã xuất ảnh thành công!', 'success');
    }).catch(function(err) {
      showToast('Lỗi tạo ảnh: ' + err.toString(), 'error');
    });
  }

  /**
   * Open Invoice Editor for a specific order ID (fetches order data first)
   */
  function openInvoiceEditorById(orderId) {
    if (!orderId) {
      showToast('Mã đơn hàng không hợp lệ', 'error');
      return;
    }
    toggleLoading(true);
    google.script.run
      .withSuccessHandler(function (res) {
        toggleLoading(false);
        if (res && res.success && res.data) {
          openInvoiceEditor(res.data);
        } else {
          showToast('Không tìm thấy đơn hàng', 'error');
        }
      })
      .withFailureHandler(function (err) {
        toggleLoading(false);
        showToast('Lỗi: ' + err.toString(), 'error');
      })
      .apiHandler('getOrderDetail', { orderId: orderId });
  }

  /**
   * Open Invoice Editor for current cart (draft invoice)
   */
  function openInvoiceEditorForCart() {
    if (!cart || cart.length === 0) {
      showToast('Giỏ hàng đang trống!', 'warning');
      return;
    }

    // Build temporary order object from cart
    const subtotal = cart.reduce((sum, item) => sum + (item.total || item.qty * item.price), 0);
    const discountEl = document.getElementById('discount-amount');
    const shippingEl = document.getElementById('shipping-fee');
    const discount = discountEl ? parseFloat(discountEl.value) || 0 : 0;
    const shipping = shippingEl ? parseFloat(shippingEl.value) || 0 : 0;
    const total = subtotal - discount + shipping;

    // Resolve customer info from selectedCustomerId (POS) or fallback to DOM elements
    let resolvedCustomerName = 'Khách lẻ';
    let resolvedCustomerPhone = '';
    let resolvedCustomerAddress = '';
    if (typeof selectedCustomerId !== 'undefined' && selectedCustomerId) {
      const customers = (typeof allCustomers !== 'undefined' && allCustomers) ? allCustomers : [];
      const customer = customers.find(c => c.id === selectedCustomerId);
      if (customer) {
        resolvedCustomerName = customer.name || 'Khách lẻ';
        resolvedCustomerPhone = customer.phone || '';
        resolvedCustomerAddress = customer.address || '';
      } else {
        // Fallback: read name from display span
        const nameSpan = document.getElementById('selected-customer-name');
        if (nameSpan && nameSpan.textContent.trim()) resolvedCustomerName = nameSpan.textContent.trim();
      }
    }

    const orderForEdit = {
      id: 'DRAFT-' + Date.now(),
      date: new Date().toISOString(),
      customerName: resolvedCustomerName,
      customerPhone: resolvedCustomerPhone,
      customerAddress: resolvedCustomerAddress,
      items: cart.map(item => {
        const baseTotal = (item.qty || 0) * (item.price || 0);
        const itemDiscount = typeof getItemDiscountAmount === 'function' ? getItemDiscountAmount(item) : 0;
        const afterDiscount = baseTotal - itemDiscount;
        const vatAmt = item.applyVat ? afterDiscount * ((item.vatRate || 0) / 100) : 0;
        return {
          productName: item.name || item.productName || '',
          sku: item.sku || '',
          qty: item.qty || 0,
          price: item.price || 0,
          total: afterDiscount,
          unit: item.unit || '',
          applyVat: item.applyVat || false,
          vatRate: item.vatRate || 0,
          vatAmount: vatAmt,
          totalWithVAT: afterDiscount + vatAmt,
          discountType: item.discountType || 'amount',
          discountValue: item.discountValue || 0,
          discountAmount: itemDiscount
        };
      }),
      subtotal: subtotal,
      discountAmount: discount,
      shippingFee: shipping,
      total: total,
      paid: 0,
      debt: total,
      notes: (document.getElementById('order-notes') ? document.getElementById('order-notes').value.trim() : '') || '',
      employeeName: currentUser ? currentUser.employeeName || currentUser.fullName || currentUser.username || '' : ''
    };

    openInvoiceEditor(orderForEdit);
  }

  // ===== INVOICE TEMPLATES =====

  /**
   * Main router - render invoice based on template ID
   */
  function renderInvoiceTemplate(order, info, options) {
    // Apply showEmployee filter — hide employeeName if unchecked
    const orderForRender = Object.assign({}, order);
    if (options.showEmployee === false) orderForRender.employeeName = '';

    const fs = options.fontScale || 1.0;
    let html;
    switch (options.templateId) {
      case 'professional': html = renderTemplate_professional(orderForRender, info, options); break;
      case 'receipt': html = renderTemplate_receipt(orderForRender, info, options); break;
      case 'a5': html = renderTemplate_a5(orderForRender, info, options); break;
      case 'a4':
      default: html = renderTemplate_a4(orderForRender, info, options); break;
    }
    // Wrap with zoom scale for font size control (works in preview + print)
    if (fs !== 1.0) {
      html = `<div style="zoom:${fs};-webkit-text-size-adjust:none;">${html}</div>`;
    }
    return html;
  }

  /**
   * Helper: format money for templates
   */
  function fmtMoney(val) {
    return (val || 0).toLocaleString('vi-VN');
  }

  /**
   * Helper: convert number to Vietnamese words
   */
  function numberToVietnamese(n) {
    if (n === 0) return 'Không đồng';
    if (!n || isNaN(n)) return '';
    n = Math.round(n);
    const units = ['', 'một', 'hai', 'ba', 'bốn', 'năm', 'sáu', 'bảy', 'tám', 'chín'];
    const groups = ['', 'nghìn', 'triệu', 'tỷ', 'nghìn tỷ', 'triệu tỷ'];

    function readThreeDigits(num, hasHigher) {
      let result = '';
      const h = Math.floor(num / 100);
      const t = Math.floor((num % 100) / 10);
      const u = num % 10;
      if (h > 0) {
        result += units[h] + ' trăm';
        if (t === 0 && u > 0) result += ' lẻ';
      } else if (hasHigher && (t > 0 || u > 0)) {
        result += 'không trăm';
        if (t === 0 && u > 0) result += ' lẻ';
      }
      if (t > 1) {
        result += ' ' + units[t] + ' mươi';
        if (u === 1) result += ' mốt';
        else if (u === 4) result += ' tư';
        else if (u === 5) result += ' lăm';
        else if (u > 0) result += ' ' + units[u];
      } else if (t === 1) {
        result += ' mười';
        if (u === 5) result += ' lăm';
        else if (u > 0) result += ' ' + units[u];
      } else if (u > 0) {
        result += ' ' + units[u];
      }
      return result.trim();
    }

    const parts = [];
    let groupIdx = 0;
    let remaining = n;
    while (remaining > 0) {
      const chunk = remaining % 1000;
      remaining = Math.floor(remaining / 1000);
      if (chunk > 0) {
        parts.unshift(readThreeDigits(chunk, remaining > 0) + ' ' + groups[groupIdx]);
      }
      groupIdx++;
    }
    const text = parts.join(' ').replace(/\s+/g, ' ').trim();
    return text.charAt(0).toUpperCase() + text.slice(1) + ' đồng';
  }

  /**
   * Helper: parse order date
   */
  function parseOrderDate(dateStr) {
    try {
      const d = dateStr instanceof Date ? dateStr : new Date(dateStr);
      if (isNaN(d.getTime())) return new Date();
      return d;
    } catch (e) { return new Date(); }
  }

  /**
   * Helper: format date for display
   */
  function fmtDate(dateStr) {
    const d = parseOrderDate(dateStr);
    const pad = n => n.toString().padStart(2, '0');
    return `${pad(d.getDate())}/${pad(d.getMonth() + 1)}/${d.getFullYear()} ${pad(d.getHours())}:${pad(d.getMinutes())}`;
  }

  // ============================================================
  // Shared: Build QR/Barcode/Bank HTML blocks
  // ============================================================
  // Lookup bankId from bankName keyword (fallback when bankId not saved in settings)
  var _BANK_NAME_TO_ID = {
    'techcombank': 'TCB', 'tcb': 'TCB',
    'vietcombank': 'VCB', 'vcb': 'VCB',
    'mb bank': 'MB', 'mb': 'MB', 'mbbank': 'MB',
    'acb': 'ACB',
    'tpbank': 'TPB', 'tp bank': 'TPB', 'tpb': 'TPB',
    'vpbank': 'VPB', 'vp bank': 'VPB', 'vpb': 'VPB',
    'bidv': 'BIDV',
    'vietinbank': 'VTB', 'viettinbank': 'VTB', 'vtb': 'VTB',
    'sacombank': 'STB', 'stb': 'STB',
    'hdbank': 'HDB', 'hdb': 'HDB',
    'msb': 'MSB',
    'shb': 'SHB',
    'eximbank': 'EIB', 'eib': 'EIB',
    'ocb': 'OCB',
    'lienvietpostbank': 'LPB', 'lpb': 'LPB',
    'nam a bank': 'NAB', 'nab': 'NAB',
    'cake': 'CAKE',
    'ubank': 'UBANK',
  };
  function _resolveBankId(bankId, bankName) {
    if (bankId) return bankId;
    if (!bankName) return '';
    var key = bankName.toLowerCase().trim();
    if (_BANK_NAME_TO_ID[key]) return _BANK_NAME_TO_ID[key];
    // Partial match
    for (var k in _BANK_NAME_TO_ID) {
      if (key.includes(k)) return _BANK_NAME_TO_ID[k];
    }
    return '';
  }

  function _buildQRBlock(order, options) {
    let qrHtml = '';
    const resolvedBankId = _resolveBankId(options.bankId, options.bankName);
    if (options.showQR && options.bankAccount && resolvedBankId) {
      const qrNote = options.transferNote || ('TT ' + (order.id || ''));
      const qrUrl = escapeHtml(buildVietQRUrl(resolvedBankId, options.bankAccount, order.debt || order.total || 0, qrNote, options.bankAccountName, 'compact2'));
      qrHtml = `<div style="text-align:center;"><img src="${qrUrl}" alt="QR" style="width:150px; height:auto; border-radius:6px;"><div style="font-size:10px; color:#888; margin-top:4px;">Quét QR chuyển khoản</div></div>`;
    } else if (options.showQR && options.bankAccount && options.bankName) {
      const fallbackNote = options.transferNote || ('TT ' + (order.id || ''));
      const qrText = escapeHtml(options.bankName) + ' - ' + escapeHtml(options.bankAccount) + ' - ' + escapeHtml(fallbackNote);
      qrHtml = '<div style="text-align:center;"><div data-qr="' + qrText + '" style="display:inline-block;"></div><div style="font-size:10px; color:#888; margin-top:4px;">Quét QR thanh toán</div></div>';
    }
    let barcodeHtml = '';
    if (options.showBarcode && order.id) {
      barcodeHtml = `<div style="text-align:center;"><svg data-barcode="${escapeHtml(order.id)}" style="display:block; margin:0 auto;"></svg><div style="font-size:10px; color:#888; margin-top:2px;">${escapeHtml(order.id)}</div></div>`;
    }
    if (!qrHtml && !barcodeHtml) return '';
    return `<div style="display:flex; gap:20px; align-items:flex-start; flex-wrap:wrap; justify-content:center; margin-top:12px;">${qrHtml}${barcodeHtml}</div>`;
  }

  function _buildBankBlock(order, options) {
    if (!options.showBank || (!options.bankAccountName && !options.bankAccount)) return '';
    return `
      <div style="margin-top:12px; padding:10px 14px; background:#F0F7FF; border:1px solid #BFDBFE; border-radius:8px; font-size:13px;">
        <div style="font-weight:600; color:#1E40AF; margin-bottom:6px; font-size:12px; text-transform:uppercase; letter-spacing:0.5px;">Thông tin chuyển khoản</div>
        <table style="width:100%;">
          ${options.bankAccountName ? `<tr><td style="padding:2px 0; color:#64748B; width:110px;">Chủ TK</td><td style="padding:2px 0; font-weight:600;">${escapeHtml(options.bankAccountName)}</td></tr>` : ''}
          ${options.bankAccount ? `<tr><td style="padding:2px 0; color:#64748B;">Số TK</td><td style="padding:2px 0; font-weight:600; letter-spacing:0.5px;">${escapeHtml(options.bankAccount)}</td></tr>` : ''}
          ${options.bankName ? `<tr><td style="padding:2px 0; color:#64748B;">Ngân hàng</td><td style="padding:2px 0;">${escapeHtml(options.bankName)}</td></tr>` : ''}
          <tr><td style="padding:2px 0; color:#64748B;">Nội dung</td><td style="padding:2px 0; font-weight:600; color:#1E40AF;">${escapeHtml(options.transferNote || ('TT ' + order.id))}</td></tr>
        </table>
      </div>`;
  }

  // ============================================================
  // TEMPLATE: PROFESSIONAL (modern, clean design, block-ordered)
  // ============================================================
  function renderTemplate_professional(order, info, options) {
    const title = options.invoiceTitle || 'HÓA ĐƠN TẠM TÍNH';
    const footer = options.footerNote || 'Cảm ơn quý khách và hẹn gặp lại';
    const showUnit = options.showUnit;
    const showVat = options.showVat;
    const hasItemDiscount = order.items.some(i => (i.discountAmount || 0) > 0);
    const showItemDiscount = options.showItemDiscount !== false && hasItemDiscount;
    let logoHtml = '';
    if (options.showLogo && options.logo) {
      logoHtml = `<img src="${escapeHtml(options.logo)}" alt="Logo" style="max-width:140px; max-height:70px;">`;
    }

    // Block render map: each block id → HTML string
    var blockMap = {};

    blockMap['header'] = `
      <div style="display:flex; justify-content:space-between; align-items:flex-start; padding-bottom:14px; border-bottom:3px solid #2563EB; margin-bottom:16px;">
        <div>
          ${logoHtml}
          ${info.name ? `<div style="font-size:18px; font-weight:700; color:#0F172A; margin-top:4px;">${escapeHtml(info.name)}</div>` : ''}
          ${info.address ? `<div style="font-size:12px; color:#64748B; margin-top:2px;">${escapeHtml(info.address)}</div>` : ''}
          ${info.phone ? `<div style="font-size:12px; color:#64748B;">ĐT: ${escapeHtml(info.phone)}</div>` : ''}
        </div>
        <div style="text-align:right;">
          <div style="font-size:13px; color:#64748B; margin-top:4px;">${escapeHtml(order.id)}</div>
          <div style="font-size:13px; color:#64748B;">${fmtDate(order.date)}</div>
        </div>
      </div>`;

    blockMap['title'] = `
      <div style="text-align:center; margin-bottom:12px;">
        <div style="font-size:20px; font-weight:800; color:#2563EB; letter-spacing:-0.5px;">${escapeHtml(title)}</div>
      </div>`;

    blockMap['customer'] = `
      <div style="flex:1; background:#F8FAFC; padding:10px 14px; border-radius:8px; border-left:3px solid #2563EB; margin-bottom:16px; font-size:13px;">
        <div style="font-weight:600; color:#475569; font-size:11px; text-transform:uppercase; letter-spacing:0.5px; margin-bottom:4px;">Khách hàng</div>
        <div style="font-weight:600;">${escapeHtml(order.customerName || 'Khách lẻ')}</div>
        ${order.customerPhone ? `<div style="color:#64748B;">SĐT: ${escapeHtml(order.customerPhone)}</div>` : ''}
        ${order.customerAddress ? `<div style="color:#64748B;">${escapeHtml(order.customerAddress)}</div>` : ''}
      </div>`;

    blockMap['employee'] = order.employeeName ? `
      <div style="background:#F8FAFC; padding:10px 14px; border-radius:8px; margin-bottom:16px; font-size:13px;">
        <div style="font-weight:600; color:#475569; font-size:11px; text-transform:uppercase; letter-spacing:0.5px; margin-bottom:4px;">Nhân viên</div>
        <div>${escapeHtml(order.employeeName)}</div>
      </div>` : '';

    // Items table (always rendered as one block; unit/vat are sub-toggles)
    let itemsHtml = order.items.map((item, idx) => {
      const lineTotal = (item.qty || 0) * (item.price || 0);
      const discountAmt = item.discountAmount || 0;
      const afterDiscount = lineTotal - discountAmt;
      const discountLabel = item.discountType === 'percent' ? `${item.discountValue || 0}%` : fmtMoney(discountAmt);
      const bg = idx % 2 === 0 ? '#FAFAFA' : '#fff';
      return `
      <tr style="background:${bg};">
        <td style="padding:8px 6px; text-align:center; font-size:13px;">${idx + 1}</td>
        <td style="padding:8px; font-size:13px;">${escapeHtml(item.productName || item.sku || '')}${item.promoNote ? `<div style="font-size:11px;color:#be185d;font-weight:600;">🎁 ${escapeHtml(item.promoNote)}</div>` : ''}</td>
        ${showUnit ? `<td style="padding:8px 6px; text-align:center; font-size:13px; color:#64748B;">${escapeHtml(item.unit || 'Cái')}</td>` : ''}
        <td style="padding:8px 6px; text-align:center; font-size:13px;">${item.qty || 0}</td>
        <td style="padding:8px; text-align:right; font-size:13px;">${fmtMoney(item.price)}</td>
        ${showItemDiscount ? `<td style="padding:8px 6px; text-align:right; font-size:13px; color:${discountAmt > 0 ? '#EA580C' : '#CCC'};">${discountAmt > 0 ? '-' + discountLabel : '-'}</td>` : ''}
        ${showVat ? `<td style="padding:8px 6px; text-align:right; font-size:13px; color:#6366F1;">${item.applyVat && item.vatRate ? item.vatRate + '%' : '-'}</td>` : ''}
        <td style="padding:8px; text-align:right; font-size:13px; font-weight:500;">${fmtMoney(item.applyVat && item.totalWithVAT ? item.totalWithVAT : (showItemDiscount && discountAmt > 0 ? afterDiscount : (item.total || lineTotal)))}</td>
      </tr>`;
    }).join('');

    blockMap['items'] = `
      <table style="width:100%; border-collapse:collapse; table-layout:auto;">
        <thead>
          <tr style="border-bottom:2px solid #000; border-top:2px solid #000;">
            <th style="padding:10px 6px; text-align:center; font-size:12px; font-weight:700; color:#000; width:36px;">STT</th>
            <th style="padding:10px 8px; text-align:left; font-size:12px; font-weight:700; color:#000;">Sản phẩm</th>
            ${showUnit ? '<th style="padding:10px 6px; text-align:center; font-size:12px; font-weight:700; color:#000; width:56px;">ĐVT</th>' : ''}
            <th style="padding:10px 6px; text-align:center; font-size:12px; font-weight:700; color:#000; width:40px;">SL</th>
            <th style="padding:10px 8px; text-align:right; font-size:12px; font-weight:700; color:#000; width:100px;">Đơn giá</th>
            ${showItemDiscount ? '<th style="padding:10px 6px; text-align:right; font-size:12px; font-weight:700; color:#000; width:85px;">Giảm</th>' : ''}
            ${showVat ? '<th style="padding:10px 6px; text-align:right; font-size:12px; font-weight:700; color:#000; width:70px;">VAT</th>' : ''}
            <th style="padding:10px 8px; text-align:right; font-size:12px; font-weight:700; color:#000; width:110px;">Thành tiền</th>
          </tr>
        </thead>
        <tbody>${itemsHtml}</tbody>
      </table>`;

    // unit and vat are sub-blocks of items — not rendered separately, they toggle columns inside items
    blockMap['unit'] = '';
    blockMap['vat'] = '';

    // Discount & shipping lines for summary
    const totalItemDiscountAmt = order.items.reduce((s, i) => s + (i.discountAmount || 0), 0);
    let discountHtml = '';
    if (showItemDiscount && totalItemDiscountAmt > 0) {
      discountHtml = `<div style="display:flex; justify-content:space-between; padding:4px 0; color:#EA580C;"><span>Giảm giá SP</span><span>-${fmtMoney(totalItemDiscountAmt)}</span></div>`;
    }
    blockMap['discount'] = options.showDiscount && (order.discountAmount || 0) > 0
      ? `<div style="display:flex; justify-content:space-between; padding:4px 0; font-size:13px;"><span>Chiết khấu ĐH</span><span>-${fmtMoney(order.discountAmount)}</span></div>` : '';

    blockMap['shipping'] = options.showShipping && (order.shippingFee || 0) > 0
      ? `<div style="display:flex; justify-content:space-between; padding:4px 0; font-size:13px;"><span>Phí vận chuyển</span><span>+${fmtMoney(order.shippingFee)}</span></div>` : '';

    blockMap['summary'] = `
      <div style="margin-top:12px; padding:12px 14px; background:#F8FAFC; border-radius:8px; font-size:13px;">
        ${discountHtml}
        ${blockMap['discount']}
        ${blockMap['shipping']}
        <div style="display:flex; justify-content:space-between; padding:8px 0 4px; border-top:2px solid #2563EB; margin-top:6px;">
          <span style="font-size:16px; font-weight:700;">TỔNG CỘNG</span>
          <span style="font-size:18px; font-weight:800; color:#2563EB;">${fmtMoney(order.total)} ₫</span>
        </div>
        <div style="font-style:italic; font-size:12px; color:#94A3B8; padding-bottom:4px;">${numberToVietnamese(order.total || 0)}</div>
      </div>`;

    let debtLines = '';
    if (options.showDebt) {
      if ((order.paid || 0) > 0) debtLines += `<div style="display:flex; justify-content:space-between; padding:4px 0;"><span>Đã thanh toán</span><span style="color:#059669;">${fmtMoney(order.paid)}</span></div>`;
      if ((order.debt || 0) !== 0) debtLines += `<div style="display:flex; justify-content:space-between; padding:4px 0; font-weight:600;"><span>Còn nợ</span><span style="color:#DC2626;">${fmtMoney(order.debt)}</span></div>`;
    }
    blockMap['debt'] = debtLines ? `<div style="padding:4px 14px; font-size:13px;">${debtLines}</div>` : '';

    blockMap['bank'] = `
      <div style="display:flex; gap:16px; align-items:flex-start; flex-wrap:wrap; margin-top:12px;">
        <div style="flex:1; min-width:200px;">${_buildBankBlock(order, options)}</div>
        <div>${_buildQRBlock(order, options)}</div>
      </div>`;

    blockMap['signatures'] = options.showSignatures ? `
      <div style="margin-top:30px; display:flex; justify-content:space-around; text-align:center;">
        <div><div style="font-weight:600; font-size:13px;">KHÁCH HÀNG</div><div style="color:#94A3B8; font-size:11px; font-style:italic;">(Ký và ghi rõ họ tên)</div><div style="height:55px;"></div></div>
        <div><div style="font-weight:600; font-size:13px;">NGƯỜI BÁN</div><div style="color:#94A3B8; font-size:11px; font-style:italic;">(Ký và ghi rõ họ tên)</div><div style="height:55px;"></div></div>
      </div>` : '';

    blockMap['footer'] = `
      <div style="text-align:center; margin-top:20px; padding-top:12px; border-top:1px solid #E2E8F0; font-size:13px; color:#94A3B8;">
        ${escapeHtml(footer)}
      </div>`;

    // Notes block (always shown if present, not controlled by blocks)
    var notesHtml = order.notes ? `<div style="margin-top:12px; padding:10px 14px; background:#FFFBEB; border-left:3px solid #F59E0B; border-radius:0 8px 8px 0; font-size:13px;"><span style="font-weight:600;">Ghi chú:</span> <span style="color:#64748B; white-space:pre-line;">${escapeHtml(order.notes)}</span></div>` : '';

    // Assemble blocks in user-defined order
    var blockOrder = options.blockOrder || ['header','title','customer','employee','items','summary','debt','bank','signatures','footer'];
    var bodyParts = [];
    blockOrder.forEach(function(blockId) {
      // sub-blocks (unit, vat, discount, shipping) are already folded into their parent
      if (blockId === 'unit' || blockId === 'vat' || blockId === 'discount' || blockId === 'shipping') return;
      var html = blockMap[blockId];
      if (html) bodyParts.push(html);
      // Insert notes after summary block
      if (blockId === 'summary' && notesHtml) bodyParts.push(notesHtml);
    });

    return `<div style="width:100%; font-family:'Segoe UI',Arial,sans-serif; font-size:14px; color:#1E293B;">${bodyParts.join('')}</div>`;
  }

  // ============================================================
  // TEMPLATE: A4 STANDARD (clean, minimal design)
  // ============================================================
  function renderTemplate_a4(order, info, options) {
    const title = options.invoiceTitle || 'HÓA ĐƠN BÁN HÀNG';
    const footer = options.footerNote || 'Cảm ơn quý khách đã sử dụng dịch vụ!';
    const showUnit_a4 = options.showUnit;
    const showVat_a4 = options.showVat;
    const hasItemDiscount_a4 = order.items.some(i => (i.discountAmount || 0) > 0);
    const showItemDiscount_a4 = options.showItemDiscount !== false && hasItemDiscount_a4;

    let itemsHtml = order.items.map((item, idx) => {
      const lineTotal = (item.qty || 0) * (item.price || 0);
      const discountAmt = item.discountAmount || 0;
      const afterDiscount = lineTotal - discountAmt;
      const discountLabel = item.discountType === 'percent' ? `${item.discountValue || 0}%` : fmtMoney(discountAmt);
      return `
      <tr style="border-bottom:1px solid #F1F5F9;">
        <td style="padding:10px 8px; text-align:center; color:#64748B;">${idx + 1}</td>
        <td style="padding:10px 8px; font-weight:500;">${escapeHtml(item.productName || item.sku || '')}${item.promoNote ? `<div style="font-size:11px;color:#be185d;font-weight:600;">🎁 ${escapeHtml(item.promoNote)}</div>` : ''}</td>
        ${showUnit_a4 ? `<td style="padding:10px 8px; text-align:center; color:#64748B;">${escapeHtml(item.unit || 'Cái')}</td>` : ''}
        <td style="padding:10px 8px; text-align:center;">${item.qty || 0}</td>
        <td style="padding:10px 8px; text-align:right;">${fmtMoney(item.price)}</td>
        ${showItemDiscount_a4 ? `<td style="padding:10px 8px; text-align:right; color:${discountAmt > 0 ? '#EA580C' : '#CBD5E1'};">${discountAmt > 0 ? '-' + discountLabel : '-'}</td>` : ''}
        ${showVat_a4 ? `<td style="padding:10px 8px; text-align:right; color:#6366F1;">${item.applyVat && item.vatRate ? item.vatRate + '%' : '-'}</td>` : ''}
        <td style="padding:10px 8px; text-align:right; font-weight:600;">${fmtMoney(item.applyVat && item.totalWithVAT ? item.totalWithVAT : (showItemDiscount_a4 && discountAmt > 0 ? afterDiscount : (item.total || lineTotal)))}</td>
      </tr>`;
    }).join('');

    const totalItemDiscountAmt_a4 = order.items.reduce((s, i) => s + (i.discountAmount || 0), 0);
    let summaryHtml = '';
    if (showItemDiscount_a4 && totalItemDiscountAmt_a4 > 0) {
      summaryHtml += `<div style="display:flex; justify-content:space-between; padding:5px 0; color:#EA580C;"><span>Giảm giá SP</span><span>-${fmtMoney(totalItemDiscountAmt_a4)}</span></div>`;
    }
    if (options.showDiscount && (order.discountAmount || 0) > 0) {
      summaryHtml += `<div style="display:flex; justify-content:space-between; padding:5px 0;"><span>Chiết khấu ĐH</span><span>-${fmtMoney(order.discountAmount)}</span></div>`;
    }
    if (options.showShipping && (order.shippingFee || 0) > 0) {
      summaryHtml += `<div style="display:flex; justify-content:space-between; padding:5px 0;"><span>Vận chuyển</span><span>+${fmtMoney(order.shippingFee)}</span></div>`;
    }

    summaryHtml += `
      <div style="display:flex; justify-content:space-between; padding:10px 0 4px; border-top:2px solid #E2E8F0; margin-top:6px;">
        <span style="font-size:17px; font-weight:700;">TỔNG CỘNG</span>
        <span style="font-size:20px; font-weight:800; color:#0F172A;">${fmtMoney(order.total)} ₫</span>
      </div>
      <div style="font-style:italic; font-size:12px; color:#94A3B8; padding-bottom:6px;">${numberToVietnamese(order.total || 0)}</div>`;

    if (options.showDebt) {
      if ((order.paid || 0) > 0) summaryHtml += `<div style="display:flex; justify-content:space-between; padding:4px 0;"><span>Đã thanh toán</span><span style="color:#059669;">${fmtMoney(order.paid)}</span></div>`;
      if ((order.debt || 0) !== 0) summaryHtml += `<div style="display:flex; justify-content:space-between; padding:4px 0; font-weight:600;"><span>Còn nợ</span><span style="color:#DC2626;">${fmtMoney(order.debt)}</span></div>`;
    }

    let logoHtml = '';
    if (options.showLogo && options.logo) {
      logoHtml = `<img src="${escapeHtml(options.logo)}" alt="Logo" style="max-width:140px; max-height:70px; margin-bottom:8px;">`;
    }

    return `
      <div style="width:100%; font-family:'Segoe UI',Arial,sans-serif; color:#1E293B; font-size:14px;">
        <!-- Header -->
        <div style="text-align:center; margin-bottom:24px;">
          ${logoHtml}
          ${info.name ? `<div style="font-size:22px; font-weight:700; color:#0F172A;">${escapeHtml(info.name)}</div>` : ''}
          ${info.address ? `<div style="font-size:13px; color:#94A3B8; margin-top:4px;">${escapeHtml(info.address)}</div>` : ''}
          <div style="font-size:13px; color:#94A3B8;">
            ${info.phone ? `ĐT: ${escapeHtml(info.phone)}` : ''}${info.tax ? ` | MST: ${escapeHtml(info.tax)}` : ''}
          </div>
          <div style="margin-top:16px; padding:10px 0; border-top:1px solid #E2E8F0; border-bottom:1px solid #E2E8F0;">
            <div style="font-size:22px; font-weight:800; letter-spacing:1px;">${escapeHtml(title)}</div>
          </div>
        </div>

        <!-- Order + Customer info side by side -->
        <div style="display:flex; gap:20px; margin-bottom:20px; font-size:13px;">
          <div style="flex:1;">
            <div style="font-weight:600; color:#64748B; font-size:11px; text-transform:uppercase; letter-spacing:0.5px; margin-bottom:6px;">Thông tin đơn hàng</div>
            <div style="padding:4px 0;"><strong>Mã ĐH:</strong> ${escapeHtml(order.id)}</div>
            <div style="padding:4px 0;"><strong>Ngày:</strong> ${fmtDate(order.date)}</div>
            ${order.employeeName ? `<div style="padding:4px 0;"><strong>NV:</strong> ${escapeHtml(order.employeeName)}</div>` : ''}
          </div>
          <div style="flex:1;">
            <div style="font-weight:600; color:#64748B; font-size:11px; text-transform:uppercase; letter-spacing:0.5px; margin-bottom:6px;">Khách hàng</div>
            <div style="padding:4px 0; font-weight:600;">${escapeHtml(order.customerName || 'Khách lẻ')}</div>
            ${order.customerPhone ? `<div style="padding:4px 0; color:#64748B;">SĐT: ${escapeHtml(order.customerPhone)}</div>` : ''}
            ${order.customerAddress ? `<div style="padding:4px 0; color:#64748B;">${escapeHtml(order.customerAddress)}</div>` : ''}
          </div>
        </div>

        <!-- Items -->
        <table style="width:100%; border-collapse:collapse; table-layout:auto;">
          <thead>
            <tr style="border-bottom:2px solid #000; border-top:2px solid #000;">
              <th style="padding:10px 8px; text-align:center; font-size:12px; font-weight:700; color:#000; width:36px;">STT</th>
              <th style="padding:10px 8px; text-align:left; font-size:12px; font-weight:700; color:#000;">Sản phẩm</th>
              ${showUnit_a4 ? '<th style="padding:10px 8px; text-align:center; font-size:12px; font-weight:700; color:#000; width:56px;">ĐVT</th>' : ''}
              <th style="padding:10px 8px; text-align:center; font-size:12px; font-weight:700; color:#000; width:40px;">SL</th>
              <th style="padding:10px 8px; text-align:right; font-size:12px; font-weight:700; color:#000; width:100px;">Đơn giá</th>
              ${showItemDiscount_a4 ? '<th style="padding:10px 8px; text-align:right; font-size:12px; font-weight:700; color:#000; width:80px;">Giảm</th>' : ''}
              ${showVat_a4 ? '<th style="padding:10px 8px; text-align:right; font-size:12px; font-weight:700; color:#000; width:70px;">VAT</th>' : ''}
              <th style="padding:10px 8px; text-align:right; font-size:12px; font-weight:700; color:#000; width:110px;">Thành tiền</th>
            </tr>
          </thead>
          <tbody>${itemsHtml}</tbody>
        </table>

        <!-- Summary -->
        <div style="margin-top:16px; padding:14px; font-size:14px;">${summaryHtml}</div>

        ${order.notes ? `<div style="margin-top:16px; padding:12px 14px; background:#FFFBEB; border-left:3px solid #F59E0B; border-radius:0 8px 8px 0; font-size:13px;"><strong>Ghi chú:</strong> <span style="color:#64748B; white-space:pre-line;">${escapeHtml(order.notes)}</span></div>` : ''}

        <!-- Bank + QR -->
        <div style="display:flex; gap:16px; align-items:flex-start; flex-wrap:wrap; margin-top:16px;">
          <div style="flex:1; min-width:200px;">${_buildBankBlock(order, options)}</div>
          <div>${_buildQRBlock(order, options)}</div>
        </div>

        ${options.showSignatures ? `
        <div style="margin-top:30px; display:flex; justify-content:space-around; text-align:center;">
          <div><div style="font-weight:600; font-size:13px;">KHÁCH HÀNG</div><div style="color:#94A3B8; font-size:11px; font-style:italic;">(Ký và ghi rõ họ tên)</div><div style="height:55px;"></div></div>
          <div><div style="font-weight:600; font-size:13px;">NGƯỜI BÁN</div><div style="color:#94A3B8; font-size:11px; font-style:italic;">(Ký và ghi rõ họ tên)</div><div style="height:55px;"></div></div>
        </div>` : ''}

        <!-- Footer -->
        <div style="margin-top:28px; padding-top:16px; border-top:1px solid #E2E8F0; text-align:center; font-size:12px; color:#94A3B8;">
          <div>${escapeHtml(footer)}</div>
          ${info.email ? `<div>Email: ${escapeHtml(info.email)}</div>` : ''}
          ${info.website ? `<div>${escapeHtml(info.website)}</div>` : ''}
        </div>
      </div>`;
  }

  // ============================================================
  // TEMPLATE: A5 CLASSIC (traditional Vietnamese invoice style)
  // Layout matches: company header centered, full-border table,
  // STT|Tên Hàng|ĐVT|SL|Đơn giá|Chiết khấu|Thành tiền columns,
  // amount-in-words, date + dual signatures at bottom
  // ============================================================
  function renderTemplate_a5(order, info, options) {
    const title = options.invoiceTitle || 'HÓA ĐƠN BÁN HÀNG';
    const footer = options.footerNote || '';
    const showUnit = options.showUnit !== false;
    const showDiscount = options.showItemDiscount !== false;

    // Table rows
    let totalQty = 0;
    const itemsHtml = order.items.map((item, idx) => {
      const qty = item.qty || 0;
      const price = item.price || 0;
      const discountAmt = item.discountAmount || 0;
      const lineTotal = item.total || (qty * price - discountAmt);
      totalQty += qty;
      const discountLabel = discountAmt > 0
        ? (item.discountType === 'percent' ? `${item.discountValue || 0}%` : fmtMoney(discountAmt))
        : '0';
      const td = 'style="border:1px solid #333; padding:4px 6px;"';
      return `<tr>
        <td ${td} style="border:1px solid #333; padding:4px 6px; text-align:center;">${idx + 1}</td>
        <td ${td} style="border:1px solid #333; padding:4px 6px;">${escapeHtml(item.productName || item.sku || '')}</td>
        ${showUnit ? `<td ${td} style="border:1px solid #333; padding:4px 6px; text-align:center;">${escapeHtml(item.unit || '')}</td>` : ''}
        <td ${td} style="border:1px solid #333; padding:4px 6px; text-align:center;">${qty}</td>
        <td ${td} style="border:1px solid #333; padding:4px 6px; text-align:right;">${fmtMoney(price)}</td>
        ${showDiscount ? `<td ${td} style="border:1px solid #333; padding:4px 6px; text-align:right;">${discountLabel}</td>` : ''}
        <td ${td} style="border:1px solid #333; padding:4px 6px; text-align:right;">${fmtMoney(lineTotal)}</td>
      </tr>`;
    }).join('');

    // Summary rows
    let summaryExtra = '';
    if (options.showDiscount && (order.discountAmount || 0) > 0) {
      summaryExtra += `<div style="margin-top:4px;"><strong>Chiết khấu ĐH:</strong> -${fmtMoney(order.discountAmount)} ₫</div>`;
    }
    if (options.showShipping && (order.shippingFee || 0) > 0) {
      summaryExtra += `<div style="margin-top:4px;"><strong>Phí vận chuyển:</strong> ${fmtMoney(order.shippingFee)} ₫</div>`;
    }
    if (options.showDebt) {
      if ((order.paid || 0) > 0) summaryExtra += `<div style="margin-top:4px;"><strong>Đã thanh toán:</strong> ${fmtMoney(order.paid)} ₫</div>`;
      if ((order.debt || 0) !== 0) summaryExtra += `<div style="margin-top:4px;"><strong>Còn nợ:</strong> ${fmtMoney(order.debt)} ₫</div>`;
    }

    // Logo
    let logoHtml = '';
    if (options.showLogo && options.logo) {
      logoHtml = `<img src="${escapeHtml(options.logo)}" alt="Logo" style="max-width:100px; max-height:60px; margin-bottom:6px; display:block; margin-left:auto; margin-right:auto;">`;
    }

    // Date string: "Ngày DD tháng MM năm YYYY"
    const d = order.date ? new Date(order.date) : new Date();
    const dateStr = `Ngày ${d.getDate()} tháng ${d.getMonth() + 1} năm ${d.getFullYear()}`;

    // Column span for CỘNG row
    const colSpan = 2 + (showUnit ? 1 : 0) + (showDiscount ? 1 : 0); // STT+name+unit+discount cols before SL

    const thStyle = 'border:1px solid #333; padding:5px 6px; text-align:center; font-weight:700; background:#fff; color:#000;';

    return `
      <div style="width:100%; font-family:Arial,'Times New Roman',serif; color:#000; font-size:13px; line-height:1.4;">
        <!-- Company Header - centered -->
        <div style="text-align:center; margin-bottom:8px;">
          ${logoHtml}
          ${info.name ? `<div style="font-size:18px; font-weight:900; text-transform:uppercase; letter-spacing:0.5px;">${escapeHtml(info.name)}</div>` : ''}
          ${info.address ? `<div style="font-size:12px; margin-top:2px;"><strong>Địa chỉ:</strong> ${escapeHtml(info.address)}</div>` : ''}
          ${info.phone ? `<div style="font-size:12px;"><strong>SĐT:</strong> ${escapeHtml(info.phone)}</div>` : ''}
          ${info.tax ? `<div style="font-size:12px;">MST: ${escapeHtml(info.tax)}</div>` : ''}
        </div>

        <!-- Invoice title + number -->
        <div style="display:flex; justify-content:space-between; align-items:flex-end; margin-bottom:8px;">
          <div style="flex:1;"></div>
          <div style="text-align:center; flex:2;">
            <div style="font-size:17px; font-weight:900; text-transform:uppercase; letter-spacing:1px;">${escapeHtml(title)}</div>
          </div>
          <div style="flex:1; text-align:right; font-size:12px; font-weight:700;">Số: ${escapeHtml(order.id || '')}</div>
        </div>

        <!-- Customer info -->
        <div style="margin-bottom:8px; font-size:12px;">
          <div style="display:flex; gap:16px;">
            <span><strong>Khách hàng:</strong> ${escapeHtml(order.customerName || 'Khách lẻ')}</span>
            <span><strong>Số điện thoại:</strong> ${escapeHtml(order.customerPhone || '')}</span>
          </div>
          ${order.customerAddress ? `<div><strong>Địa chỉ:</strong> ${escapeHtml(order.customerAddress)}</div>` : ''}
          ${order.employeeName ? `<div><strong>Nhân viên:</strong> ${escapeHtml(order.employeeName)}</div>` : ''}
        </div>

        <!-- Items Table - full borders, classic style -->
        <table style="width:100%; border-collapse:collapse; font-size:12px;">
          <thead>
            <tr>
              <th style="${thStyle} width:32px;">STT</th>
              <th style="${thStyle} text-align:left;">Tên Hàng</th>
              ${showUnit ? `<th style="${thStyle} width:48px;">ĐVT</th>` : ''}
              <th style="${thStyle} width:40px;">SL</th>
              <th style="${thStyle} width:90px;">Đơn giá</th>
              ${showDiscount ? `<th style="${thStyle} width:70px;">Chiết khấu</th>` : ''}
              <th style="${thStyle} width:90px;">Thành tiền</th>
            </tr>
          </thead>
          <tbody>
            ${itemsHtml}
            <!-- CỘNG row -->
            <tr style="font-weight:700;">
              <td colspan="${colSpan}" style="border:1px solid #333; padding:5px 6px; text-align:center; font-weight:700;">CỘNG</td>
              <td style="border:1px solid #333; padding:5px 6px; text-align:center;">${totalQty % 1 === 0 ? totalQty : totalQty.toLocaleString('vi-VN')}</td>
              <td style="border:1px solid #333; padding:5px 6px;"></td>
              ${showDiscount ? '<td style="border:1px solid #333; padding:5px 6px;"></td>' : ''}
              <td style="border:1px solid #333; padding:5px 6px; text-align:right; font-weight:700;">${fmtMoney(order.total)}</td>
            </tr>
          </tbody>
        </table>

        <!-- Amount in words -->
        <div style="margin-top:6px; font-size:12px; font-style:italic;">
          <strong>Viết bằng chữ:</strong> ${numberToVietnamese(order.total || 0)}
        </div>

        ${summaryExtra ? `<div style="margin-top:6px; font-size:12px;">${summaryExtra}</div>` : ''}

        ${order.notes ? `<div style="margin-top:6px; font-size:12px;"><strong>Ghi chú:</strong> <span style="white-space:pre-line;">${escapeHtml(order.notes)}</span></div>` : ''}

        <!-- Bank + QR -->
        ${(options.showBank || options.showQR) ? `
        <div style="display:flex; gap:16px; align-items:flex-start; flex-wrap:wrap; margin-top:10px;">
          <div style="flex:1; min-width:180px;">${_buildBankBlock(order, options)}</div>
          <div>${_buildQRBlock(order, options)}</div>
        </div>` : ''}

        <!-- Date + Signatures -->
        <div style="margin-top:16px; display:flex; justify-content:flex-end; font-size:12px;">
          <div style="text-align:center; font-style:italic;">${dateStr}</div>
        </div>
        <div style="display:flex; justify-content:space-between; margin-top:8px; font-size:12px; font-weight:700; text-transform:uppercase; text-align:center;">
          <div style="flex:1;">
            <div>Khách Hàng</div>
            <div style="height:60px;"></div>
            <div style="font-size:11px; font-weight:400; font-style:italic;">(Ký, ghi rõ họ tên)</div>
          </div>
          <div style="flex:1;">
            <div>Người Viết Hóa Đơn</div>
            <div style="height:60px;"></div>
            <div style="font-size:11px; font-weight:400; font-style:italic;">(Ký, ghi rõ họ tên)</div>
          </div>
        </div>

        ${footer ? `<div style="margin-top:12px; text-align:center; font-size:11px; color:#555;">${escapeHtml(footer)}</div>` : ''}
      </div>`;
  }

  // ============================================================
  // TEMPLATE: RECEIPT (compact 80mm thermal - modern)
  // ============================================================
  function renderTemplate_receipt(order, info, options) {
    const title = options.invoiceTitle || 'HÓA ĐƠN BÁN HÀNG';
    const footer = options.footerNote || 'Cảm ơn quý khách!';
    const showVatR = options.showVat;
    const showUnitR = options.showUnit !== false && options.showUnit !== 'false';
    const totalQty = order.items.reduce((s, i) => s + (i.qty || 0), 0);
    const totalVatAmount = showVatR ? order.items.reduce((s, i) => s + (i.vatAmount || 0), 0) : 0;
    const colSpanR = 4 + (showVatR ? 1 : 0);

    // POS 80mm: 2-line layout per item to avoid overflow on narrow paper
    // Line 1: product name (full width)
    // Line 2: qty [unit] × price = total (+ VAT if enabled)
    let itemsHtml = order.items.map((item, idx) => {
      const lineTotal = (item.qty || 0) * (item.price || 0);
      const discountAmt = item.discountAmount || 0;
      const afterDiscount = lineTotal - discountAmt;
      const finalTotal = discountAmt > 0 ? afterDiscount : (item.applyVat && item.totalWithVAT ? item.totalWithVAT : (item.total || lineTotal));
      const discountLabel = item.discountType === 'percent' ? `${item.discountValue || 0}%` : fmtMoney(discountAmt);
      const vatLabel = showVatR && item.applyVat && item.vatRate ? ` (VAT ${item.vatRate}%)` : '';
      const unitLabel = showUnitR && item.unit ? ` ${escapeHtml(item.unit)}` : '';
      return `
      <tr style="border-bottom:1px dotted #999;">
        <td colspan="2" style="padding:4px 0 0 0; font-size:13px; font-weight:600; color:#000; word-break:break-word;">${escapeHtml(item.productName || item.sku || '')}${item.promoNote ? `<span style="font-size:11px;color:#be185d;font-weight:600;margin-left:4px;">🎁 ${escapeHtml(item.promoNote)}</span>` : ''}</td>
      </tr>
      <tr style="border-bottom:1px solid #eee;">
        <td style="padding:0 0 4px 0; font-size:12px; color:#333;">${item.qty}${unitLabel} × ${fmtMoney(item.price)}${vatLabel}</td>
        <td style="padding:0 0 4px 0; text-align:right; font-size:13px; font-weight:700; color:#000;">${fmtMoney(finalTotal)}</td>
      </tr>
      ${discountAmt > 0 ? `<tr><td colspan="2" style="padding:0 0 2px 0; font-size:11px; font-weight:600; color:#000; text-align:right;">Giảm: -${discountLabel}</td></tr>` : ''}`;
    }).join('');

    let logoHtml = '';
    if (options.showLogo && options.logo) {
      logoHtml = `<img src="${escapeHtml(options.logo)}" alt="Logo" style="max-width:100px; max-height:50px; margin-bottom:6px;">`;
    }

    const itemDiscountTotal = order.items.reduce((s, i) => s + (i.discountAmount || 0), 0);

    // Build QR/barcode via shared helper
    const receiptQRBlock = _buildQRBlock(order, options);

    return `
      <div style="max-width:300px; margin:0 auto; font-family:Arial,'Segoe UI',sans-serif; font-size:13px; color:#000;">
        <!-- Header -->
        <div style="text-align:center; margin-bottom:10px;">
          ${logoHtml}
          ${info.name ? `<div style="font-weight:800; font-size:16px; color:#000;">${escapeHtml(info.name)}</div>` : ''}
          ${info.address ? `<div style="font-size:12px; font-weight:500; color:#333; margin-top:2px;">${escapeHtml(info.address)}</div>` : ''}
          ${info.phone ? `<div style="font-size:12px; font-weight:500; color:#333;">ĐT: ${escapeHtml(info.phone)}</div>` : ''}
        </div>

        <!-- Title -->
        <div style="text-align:center; padding:6px 0; margin-bottom:10px; border-top:2px solid #000; border-bottom:2px solid #000;">
          <div style="font-size:16px; font-weight:900; letter-spacing:1px; color:#000;">${escapeHtml(title)}</div>
        </div>

        <!-- Order info -->
        <div style="font-size:12px; font-weight:500; margin-bottom:8px; padding:6px 8px; border:1px solid #333; border-radius:4px;">
          <div style="display:flex; justify-content:space-between; padding:3px 0; border-bottom:1px dotted #999;"><span style="color:#333;">Mã ĐH</span><span style="font-weight:700; color:#000;">${escapeHtml(order.id)}</span></div>
          <div style="display:flex; justify-content:space-between; padding:3px 0; border-bottom:1px dotted #999;"><span style="color:#333;">Ngày</span><span style="color:#000;">${fmtDate(order.date)}</span></div>
          <div style="display:flex; justify-content:space-between; padding:3px 0; border-bottom:1px dotted #999;"><span style="color:#333;">KH</span><span style="color:#000;">${escapeHtml(order.customerName || 'Khách lẻ')}</span></div>
          ${order.customerPhone ? `<div style="display:flex; justify-content:space-between; padding:3px 0; border-bottom:1px dotted #999;"><span style="color:#333;">SĐT</span><span style="color:#000;">${escapeHtml(order.customerPhone)}</span></div>` : ''}
          ${order.customerAddress ? `<div style="display:flex; justify-content:space-between; padding:3px 0; border-bottom:1px dotted #999;"><span style="color:#333; white-space:nowrap;">Địa chỉ</span><span style="color:#000; text-align:right; max-width:70%;">${escapeHtml(order.customerAddress)}</span></div>` : ''}
          ${order.employeeName ? `<div style="display:flex; justify-content:space-between; padding:3px 0;"><span style="color:#333;">NV</span><span style="color:#000;">${escapeHtml(order.employeeName)}</span></div>` : ''}
        </div>

        <!-- Items -->
        <table style="width:100%; border-collapse:collapse;">
          <thead>
            <tr style="border-bottom:2px solid #000;">
              <th style="text-align:left; font-size:12px; padding:4px 0; font-weight:800; color:#000;">Sản phẩm / SL × Giá</th>
              <th style="text-align:right; font-size:12px; padding:4px 0; font-weight:800; color:#000;">Thành tiền</th>
            </tr>
          </thead>
          <tbody>${itemsHtml}</tbody>
        </table>

        <!-- Summary -->
        <div style="border-top:2px solid #000; margin-top:6px; padding-top:8px;">
          <div style="text-align:right; font-size:13px; font-weight:600; color:#000;">
            ${itemDiscountTotal > 0 ? `<div>Giảm giá SP: -${fmtMoney(itemDiscountTotal)}</div>` : ''}
            ${options.showDiscount && (order.discountAmount || 0) > 0 ? `<div>Chiết khấu ĐH: -${fmtMoney(order.discountAmount)}</div>` : ''}
            ${showVatR && totalVatAmount > 0 ? `<div>Thuế VAT: +${fmtMoney(totalVatAmount)}</div>` : ''}
            ${options.showShipping && (order.shippingFee || 0) > 0 ? `<div>Vận chuyển: +${fmtMoney(order.shippingFee)}</div>` : ''}
          </div>
          <div style="text-align:right; margin-top:6px; padding:8px; border:2px solid #000; border-radius:4px;">
            <div style="font-size:18px; font-weight:900; color:#000;">TỔNG: ${fmtMoney(order.total)} ₫</div>
            <div style="font-size:11px; font-weight:500; font-style:italic; color:#333; margin-top:2px;">(${totalQty} SP) ${numberToVietnamese(order.total || 0)}</div>
          </div>
          ${options.showDebt && (order.paid || 0) > 0 ? `<div style="text-align:right; margin-top:4px; font-size:13px; font-weight:700; color:#000;">Đã TT: ${fmtMoney(order.paid)}</div>` : ''}
          ${options.showDebt && (order.debt || 0) !== 0 ? `<div style="text-align:right; margin-top:2px; font-size:14px; font-weight:900; color:#000;">Còn nợ: ${fmtMoney(order.debt)}</div>` : ''}
        </div>

        ${order.notes ? `<div style="margin:8px 0; padding:6px 8px; border:1px solid #333; border-radius:4px; font-size:12px; font-weight:500; color:#000; white-space:pre-line;"><strong>Ghi chú:</strong> ${escapeHtml(order.notes)}</div>` : ''}

        <!-- Bank info compact -->
        ${options.showBank && options.bankAccount ? `
        <div style="margin:8px 0; padding:6px 8px; border:1px solid #333; border-radius:4px; font-size:11px; font-weight:600; color:#000;">
          ${options.bankAccountName ? `<div><strong>${escapeHtml(options.bankAccountName)}</strong></div>` : ''}
          <div>${escapeHtml(options.bankName || '')} | ${escapeHtml(options.bankAccount)}</div>
          <div>ND: <strong>TT ${escapeHtml(order.id)}</strong></div>
        </div>` : ''}

        ${receiptQRBlock}

        <!-- Footer -->
        <div style="text-align:center; padding-top:8px; border-top:2px solid #000; margin-top:8px;">
          <div style="font-size:13px; font-weight:700; color:#000;">${escapeHtml(footer)}</div>
          <div style="font-size:10px; color:#333; margin-top:4px;">★ ★ ★</div>
        </div>
      </div>`;
  }


