    function closeImportExcelModal() {
        const modal = document.getElementById('import-excel-modal');
        if (modal) modal.remove();
        excelImportData = [];
    }

    function setupExcelDropZone() {
        const dropZone = document.getElementById('excel-drop-zone');
        if (!dropZone) return;

        dropZone.addEventListener('dragover', (e) => {
            e.preventDefault();
            dropZone.classList.add('border-blue-400', 'bg-blue-50');
        });

        dropZone.addEventListener('dragleave', () => {
            dropZone.classList.remove('border-blue-400', 'bg-blue-50');
        });

        dropZone.addEventListener('drop', (e) => {
            e.preventDefault();
            dropZone.classList.remove('border-blue-400', 'bg-blue-50');
            const file = e.dataTransfer.files[0];
            if (file) processExcelFile(file);
        });
    }

    let excelImportData = [];

    function handleExcelFileSelect(event) {
        const file = event.target.files[0];
        if (file) processExcelFile(file);
    }

    function processExcelFile(file) {
        if (typeof XLSX === 'undefined') {
            lazyLoadLib('xlsx').then(function() { processExcelFile(file); }).catch(function() { showToast('Không thể tải thư viện Excel', 'error'); });
            return;
        }

        const validTypes = [
            'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
            'application/vnd.ms-excel',
            'text/csv'
        ];

        if (!validTypes.includes(file.type) && !file.name.match(/\.(xlsx|xls|csv)$/i)) {
            showToast('Vui lòng chọn file Excel hoặc CSV', 'error');
            return;
        }

        if (file.size > 10 * 1024 * 1024) {
            showToast('File quá lớn (tối đa 10MB)', 'error');
            return;
        }

        // Show file info
        document.getElementById('excel-file-info').classList.remove('hidden');
        document.getElementById('excel-file-name').textContent = file.name;
        document.getElementById('excel-file-size').textContent = formatFileSize(file.size);

        // Read file
        const reader = new FileReader();
        reader.onload = function(e) {
            try {
                const data = new Uint8Array(e.target.result);
                const workbook = XLSX.read(data, { type: 'array' });
                const firstSheet = workbook.Sheets[workbook.SheetNames[0]];
                const jsonData = XLSX.utils.sheet_to_json(firstSheet, { header: 1 });

                if (jsonData.length < 2) {
                    showToast('File không có dữ liệu', 'error');
                    return;
                }

                previewExcelData(jsonData);
            } catch (err) {
                showToast('Lỗi đọc file: ' + err.message, 'error');
            }
        };
        reader.readAsArrayBuffer(file);
    }

    function previewExcelData(data) {
        const headers = data[0];
        const rows = data.slice(1).filter(row => row.some(cell => cell !== null && cell !== ''));

        excelImportData = rows.map(row => {
            const obj = {};
            headers.forEach((h, i) => {
                obj[h] = row[i] || '';
            });
            return obj;
        });

        // Build preview table
        const headerHtml = headers.map(h => `<th class="px-3 py-2 text-left text-xs font-semibold text-gray-600">${h}</th>`).join('');
        document.getElementById('excel-preview-header').innerHTML = headerHtml;

        const bodyHtml = rows.slice(0, 20).map((row, idx) => {
            const cells = row.map(cell => `<td class="px-3 py-2 border-t text-sm">${cell || ''}</td>`).join('');
            return `<tr class="hover:bg-gray-50">${cells}</tr>`;
        }).join('');
        document.getElementById('excel-preview-body').innerHTML = bodyHtml;

        document.getElementById('excel-preview-count').textContent = `${rows.length} sản phẩm (hiển thị ${Math.min(20, rows.length)} dòng đầu)`;
        document.getElementById('excel-preview-container').classList.remove('hidden');
        document.getElementById('excel-preview-empty').classList.add('hidden');
        document.getElementById('btn-import-excel').disabled = false;
    }

    function clearExcelFile() {
        document.getElementById('excel-file-input').value = '';
        document.getElementById('excel-file-info').classList.add('hidden');
        document.getElementById('excel-preview-container').classList.add('hidden');
        document.getElementById('excel-preview-empty').classList.remove('hidden');
        document.getElementById('btn-import-excel').disabled = true;
        excelImportData = [];
    }

    function downloadProductTemplate(format) {
        if (typeof XLSX === 'undefined') {
            lazyLoadLib('xlsx').then(function() { downloadProductTemplate(format); }).catch(function() { showToast('Không thể tải thư viện Excel', 'error'); });
            return;
        }

        const template = [
            ['Mã SP', 'Tên Sản Phẩm', 'Danh Mục', 'Giá Nhập', 'Giá Bán', 'Tồn Kho', 'Đơn Vị', 'Bảo Hành (tháng)', 'Trạng Thái', 'Mô Tả', 'Mã Vạch', 'Tồn Tối Thiểu', 'Giá VIP', 'Giá Sỉ', 'VAT (%)'],
            ['SP001', 'Sản phẩm mẫu 1', 'Điện tử', 500000, 750000, 100, 'Cái', 12, 'Active', 'Mô tả sản phẩm', '8901234567890', 10, 700000, 650000, 10],
            ['SP002', 'Sản phẩm mẫu 2', 'Thời trang', 200000, 350000, 50, 'Cái', 0, 'Active', '', '', 5, 0, 0, 8]
        ];

        const wb = XLSX.utils.book_new();
        const ws = XLSX.utils.aoa_to_sheet(template);

        // Set column widths
        ws['!cols'] = [
            {wch: 12}, {wch: 25}, {wch: 15}, {wch: 12}, {wch: 12}, {wch: 10},
            {wch: 10}, {wch: 15}, {wch: 10}, {wch: 30}, {wch: 15}, {wch: 12},
            {wch: 12}, {wch: 12}, {wch: 10}
        ];

        XLSX.utils.book_append_sheet(wb, ws, 'Products');

        if (format === 'csv') {
            XLSX.writeFile(wb, 'mau_nhap_san_pham.csv', { bookType: 'csv' });
        } else {
            XLSX.writeFile(wb, 'mau_nhap_san_pham.xlsx');
        }

        showToast('Đã tải mẫu thành công', 'success');
    }

    function importExcelProducts() {
        if (excelImportData.length === 0) {
            showToast('Không có dữ liệu để nhập', 'warning');
            return;
        }

        const skipExisting = document.getElementById('excel-skip-existing').checked;
        const updateExisting = document.getElementById('excel-update-existing').checked;

        showToast('Đang nhập ' + excelImportData.length + ' sản phẩm...', 'info');

        google.script.run
            .withSuccessHandler(function(result) {
                if (result.success) {
                    showToast(`Nhập thành công ${result.imported} sản phẩm` +
                        (result.skipped > 0 ? `, bỏ qua ${result.skipped}` : '') +
                        (result.updated > 0 ? `, cập nhật ${result.updated}` : ''), 'success');
                    closeImportExcelModal();
                    loadProducts(); // Refresh product list
                } else {
                    showToast('Lỗi: ' + result.message, 'error');
                }
            })
            .withFailureHandler(function(error) {
                showToast('Lỗi: ' + error.message, 'error');
            })
            .importProductsFromExcel(excelImportData, { skipExisting, updateExisting });
    }

