    function closeComboModal() {
        const modal = document.getElementById('combo-modal');
        if (modal) modal.remove();
    }

    let comboItems = [];

    /**
     * Search products for combo
     */
    function searchComboProduct() {
        const searchInput = document.getElementById('combo-search-product');
        const resultsDiv = document.getElementById('combo-search-results');

        if (!searchInput || !resultsDiv) return;

        const query = searchInput.value.trim().toLowerCase();

        if (!query) {
            resultsDiv.classList.add('hidden');
            return;
        }

        // Filter products from global products array
        const filtered = products.filter(p =>
            p.name.toLowerCase().includes(query) ||
            p.sku.toLowerCase().includes(query)
        ).slice(0, 10); // Limit to 10 results

        if (filtered.length === 0) {
            resultsDiv.innerHTML = '<div class="p-3 text-sm text-gray-500 text-center">Không tìm thấy sản phẩm</div>';
            resultsDiv.classList.remove('hidden');
            return;
        }

        const html = filtered.map(p => `
            <div class="p-3 hover:bg-gray-50 cursor-pointer border-b last:border-b-0 flex justify-between items-center"
                 onclick="addToCombo('${p.sku}', '${p.name.replace(/'/g, "\\'")}', ${p.price})">
                <div>
                    <div class="font-medium text-sm">${p.name}</div>
                    <div class="text-xs text-gray-500">SKU: ${p.sku} - ${formatMoney(p.price)}</div>
                </div>
                <button class="text-blue-600 hover:text-blue-700 text-sm">
                    <i class="fas fa-plus"></i> Thêm
                </button>
            </div>
        `).join('');

        resultsDiv.innerHTML = html;
        resultsDiv.classList.remove('hidden');
    }

    // Add Enter key support for search
    document.addEventListener('DOMContentLoaded', function() {
        document.addEventListener('keydown', function(e) {
            const searchInput = document.getElementById('combo-search-product');
            if (searchInput && document.activeElement === searchInput && e.key === 'Enter') {
                e.preventDefault();
                searchComboProduct();
            }
        });
    });

    function addToCombo(sku, name, price) {
        const existing = comboItems.find(i => i.sku === sku);
        if (existing) {
            existing.qty++;
        } else {
            comboItems.push({ sku, name, price, qty: 1 });
        }
        renderComboItems();
        calculateComboPrice();
    }

    function removeFromCombo(sku) {
        comboItems = comboItems.filter(i => i.sku !== sku);
        renderComboItems();
        calculateComboPrice();
    }

    function renderComboItems() {
        const container = document.getElementById('combo-items-list');
        if (comboItems.length === 0) {
            container.innerHTML = `<div class="text-center text-gray-500 py-8">
                <i class="fas fa-box-open text-3xl mb-2"></i>
                <p>Thêm sản phẩm vào combo</p>
            </div>`;
            return;
        }

        container.innerHTML = comboItems.map(item => `
            <div class="flex items-center gap-3 p-3 bg-gray-50 rounded-lg">
                <div class="flex-1">
                    <p class="font-medium">${item.name}</p>
                    <p class="text-sm text-gray-500">${item.sku} - ${formatMoney(item.price)}</p>
                </div>
                <div class="flex items-center gap-2">
                    <button onclick="updateComboItemQty('${item.sku}', -1)" class="w-8 h-8 bg-gray-200 rounded-full">-</button>
                    <span class="w-8 text-center">${item.qty}</span>
                    <button onclick="updateComboItemQty('${item.sku}', 1)" class="w-8 h-8 bg-gray-200 rounded-full">+</button>
                </div>
                <button onclick="removeFromCombo('${item.sku}')" class="text-red-500 hover:text-red-600">
                    <i class="fas fa-times"></i>
                </button>
            </div>
        `).join('');
    }

    function updateComboItemQty(sku, delta) {
        const item = comboItems.find(i => i.sku === sku);
        if (item) {
            item.qty = Math.max(1, item.qty + delta);
            renderComboItems();
            calculateComboPrice();
        }
    }

    function calculateComboPrice() {
        const originalPrice = comboItems.reduce((sum, item) => sum + (item.price * item.qty), 0);
        document.getElementById('combo-original-price').value = formatMoney(originalPrice);

        const comboPrice = parseFloat(document.getElementById('combo-price').value) || 0;
        const savings = originalPrice - comboPrice;
        const discountPercent = originalPrice > 0 ? ((savings / originalPrice) * 100).toFixed(1) : 0;

        document.getElementById('combo-savings').textContent = formatMoney(savings);
        document.getElementById('combo-discount-percent').textContent = discountPercent;
    }

    /**
     * Save combo product
     */
    function saveCombo() {
        // Get combo data from form
        const comboSKU = document.getElementById('combo-sku').value.trim();
        const comboName = document.getElementById('combo-name').value.trim();
        const comboDescription = document.getElementById('combo-description').value.trim();
        const comboPrice = parseFloat(document.getElementById('combo-price').value) || 0;
        const comboStock = parseFloat(document.getElementById('combo-stock').value) || 0;

        // Validate
        if (!comboSKU) {
            showToast('Vui lòng nhập mã combo', 'error');
            return;
        }

        if (!comboName) {
            showToast('Vui lòng nhập tên combo', 'error');
            return;
        }

        if (comboItems.length === 0) {
            showToast('Vui lòng thêm ít nhất 1 sản phẩm vào combo', 'error');
            return;
        }

        if (comboPrice <= 0) {
            showToast('Vui lòng nhập giá combo hợp lệ', 'error');
            return;
        }

        // Prepare combo data
        const comboData = {
            sku: comboSKU,
            name: comboName,
            description: comboDescription,
            price: comboPrice,
            stock: comboStock,
            items: comboItems.map(item => ({
                sku: item.sku,
                qty: item.qty
            }))
        };

        // Show loading
        showToast('Đang lưu combo...', 'info');

        // Call API
        google.script.run
            .withSuccessHandler(function(res) {
                if (res.success) {
                    showToast(res.message || 'Lưu combo thành công!', 'success');

                    // Reset combo items
                    comboItems = [];

                    // Close modal
                    closeComboModal();

                    // Reload products
                    loadProducts();
                } else {
                    showToast(res.message || 'Lỗi khi lưu combo', 'error');
                }
            })
            .withFailureHandler(function(error) {
                showToast('Lỗi kết nối: ' + error.message, 'error');
            })
            .apiHandler('saveProductCombo', comboData);
    }

