    function renderAlertList(items, type) {
        if (!items || items.length === 0) {
            return `<div class="text-center text-gray-500 py-8">Không có cảnh báo</div>`;
        }

        return `<div class="space-y-2">
            ${items.map(item => `
                <div class="flex items-center gap-4 p-3 bg-gray-50 rounded-lg hover:bg-gray-100">
                    <div class="flex-1">
                        <p class="font-medium">${item.name}</p>
                        <p class="text-sm text-gray-500">${item.sku} | ${item.category}</p>
                    </div>
                    <div class="text-right">
                        <p class="font-bold ${type === 'outOfStock' ? 'text-red-600' : type === 'lowStock' ? 'text-orange-600' : 'text-blue-600'}">
                            Tồn: ${item.stock} ${item.unit}
                        </p>
                        <p class="text-sm text-gray-500">Min: ${item.minStock}</p>
                    </div>
                    <button onclick="quickImportStock('${item.sku}')" class="px-3 py-1 bg-blue-500 text-white rounded text-sm hover:bg-blue-600">
                        Nhập kho
                    </button>
                </div>
            `).join('')}
        </div>`;
    }

    function closeStockAlertsModal() {
        const modal = document.getElementById('stock-alerts-modal');
        if (modal) modal.remove();
    }

    // Store current alerts data for export
    let currentStockAlerts = null;

    function exportStockAlerts() {
        if (!currentStockAlerts) {
            showToast('Không có dữ liệu cảnh báo để xuất', 'warning');
            return;
        }

        // Combine all alerts
        const allAlerts = [
            ...(currentStockAlerts.outOfStock || []).map(p => ({ ...p, status: 'Hết hàng' })),
            ...(currentStockAlerts.lowStock || []).map(p => ({ ...p, status: 'Sắp hết' })),
            ...(currentStockAlerts.overStock || []).map(p => ({ ...p, status: 'Tồn quá nhiều' })),
            ...(currentStockAlerts.slowMoving || []).map(p => ({ ...p, status: 'Bán chậm' }))
        ];

        if (allAlerts.length === 0) {
            showToast('Không có cảnh báo nào để xuất', 'info');
            return;
        }

        // Create CSV content
        const headers = ['Mã SP', 'Tên SP', 'Danh Mục', 'Tồn Kho', 'Tồn Tối Thiểu', 'Đơn Vị', 'Trạng Thái'];
        const rows = allAlerts.map(p => [
            p.sku,
            p.name,
            p.category || '',
            p.stock,
            p.minStock || 0,
            p.unit || '',
            p.status
        ]);

        let csvContent = headers.join(',') + '\n';
        rows.forEach(row => {
            csvContent += row.map(cell => `"${cell}"`).join(',') + '\n';
        });

        // Add BOM for UTF-8
        const BOM = '\uFEFF';
        const blob = new Blob([BOM + csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        link.download = `canh_bao_ton_kho_${toLocalDateStr()}.csv`;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        URL.revokeObjectURL(url);

        showToast('Đã xuất báo cáo cảnh báo tồn kho', 'success');
    }

    function createPurchaseOrderFromAlerts() {
        if (!currentStockAlerts) {
            showToast('Không có dữ liệu cảnh báo', 'warning');
            return;
        }

        // Get products that need restocking (out of stock + low stock)
        const needRestock = [
            ...(currentStockAlerts.outOfStock || []),
            ...(currentStockAlerts.lowStock || [])
        ];

        if (needRestock.length === 0) {
            showToast('Không có sản phẩm cần nhập kho', 'info');
            return;
        }

        // Close current modal
        closeStockAlertsModal();

        // Navigate to purchases page and auto-fill
        if (typeof showPage === 'function') {
            showPage('purchases');

            // Wait for page to load then show create purchase modal
            setTimeout(() => {
                if (typeof showCreatePurchaseModal === 'function') {
                    showCreatePurchaseModal();
                    showToast(`Đã chọn ${needRestock.length} sản phẩm cần nhập kho. Vui lòng điền thông tin đơn nhập hàng.`, 'info');
                } else {
                    showToast('Vui lòng tạo đơn nhập hàng thủ công trong trang Nhập Hàng', 'info');
                }
            }, 500);
        } else {
            showToast('Vui lòng vào trang Nhập Hàng để tạo đơn nhập', 'info');
        }
    }

    function quickImportStock(sku) {
        const quantity = prompt('Nhập số lượng cần nhập kho:');
        if (quantity === null) return;

        const qty = parseFloat(quantity);
        if (isNaN(qty) || qty <= 0) {
            showToast('Số lượng không hợp lệ', 'error');
            return;
        }

        showToast('Đang cập nhật tồn kho...', 'info');

        google.script.run
            .withSuccessHandler(function(result) {
                if (result && result.success) {
                    showToast(`Đã nhập ${qty} sản phẩm vào kho`, 'success');
                    // Refresh alerts
                    closeStockAlertsModal();
                    showStockAlertsModal();
                } else {
                    showToast('Lỗi: ' + (result?.message || 'Không thể cập nhật'), 'error');
                }
            })
            .withFailureHandler(function(error) {
                showToast('Lỗi: ' + error.message, 'error');
            })
            .quickAdjustStock(sku, qty, 'import', 'Nhập kho nhanh từ cảnh báo tồn kho');
    }

    // ============================================
    // 6. LỊCH SỬ NHẬP/XUẤT KHO
    // ============================================

    function showStockHistoryModal(sku, productName) {
        const modalHtml = `
        <div id="stock-history-modal" class="adv-modal" onclick="if(event.target===this)closeStockHistoryModal()">
            <div class="adv-modal-content" style="max-width: 800px;">
                <div class="adv-modal-header bg-gradient-to-r from-teal-500 to-cyan-600">
                    <h3 class="text-white">
                        <i class="fas fa-history"></i>Lịch Sử Kho - ${productName}
                    </h3>
                    <button onclick="closeStockHistoryModal()" class="adv-modal-close" style="background: rgba(255,255,255,0.2); color: white;" title="Đóng">
                        <i class="fas fa-times"></i>
                    </button>
                </div>
                <div class="adv-modal-body">
                    <!-- Filter -->
                    <div class="flex gap-4 mb-4 flex-wrap">
                        <select id="stock-history-type" class="px-3 py-2 border rounded-lg" onchange="filterStockHistory()">
                            <option value="">Tất cả</option>
                            <option value="import">Nhập kho</option>
                            <option value="export">Xuất kho</option>
                            <option value="adjust">Điều chỉnh</option>
                        </select>
                        <input type="date" id="stock-history-from" class="px-3 py-2 border rounded-lg" onchange="filterStockHistory()">
                        <input type="date" id="stock-history-to" class="px-3 py-2 border rounded-lg" onchange="filterStockHistory()">
                    </div>

                    <!-- Timeline -->
                    <div id="stock-history-timeline" class="stock-timeline">
                        <div class="text-center py-8 text-gray-500">
                            <i class="fas fa-spinner fa-spin mr-2"></i>Đang tải...
                        </div>
                    </div>
                </div>
                <div class="adv-modal-footer">
                    <button onclick="closeStockHistoryModal()" class="adv-btn adv-btn-secondary">
                        <i class="fas fa-times"></i> Đóng
                    </button>
                </div>
            </div>
        </div>`;

        document.body.insertAdjacentHTML('beforeend', modalHtml);
        loadStockHistory(sku);
    }

    function closeStockHistoryModal() {
        const modal = document.getElementById('stock-history-modal');
        if (modal) modal.remove();
    }

    function loadStockHistory(sku) {
        google.script.run
            .withSuccessHandler(function(history) {
                renderStockHistory(history);
            })
            .withFailureHandler(function(error) {
                document.getElementById('stock-history-timeline').innerHTML =
                    `<div class="text-center text-red-500 py-8">Lỗi: ${error.message}</div>`;
            })
            .getStockHistory(sku);
    }

    function renderStockHistory(history) {
        const container = document.getElementById('stock-history-timeline');

        if (!history || history.length === 0) {
            container.innerHTML = `<div class="text-center text-gray-500 py-8">Chưa có lịch sử</div>`;
            return;
        }

        container.innerHTML = history.map(item => `
            <div class="stock-timeline-item ${item.type}">
                <div class="flex justify-between items-start">
                    <div>
                        <p class="font-medium">
                            ${item.type === 'import' ? '📥 Nhập kho' : item.type === 'export' ? '📤 Xuất kho' : '🔧 Điều chỉnh'}
                        </p>
                        <p class="text-sm text-gray-500">${item.note || ''}</p>
                        <p class="text-xs text-gray-400">${item.user || 'System'}</p>
                    </div>
                    <div class="text-right">
                        <p class="font-bold ${item.type === 'import' ? 'text-green-600' : 'text-red-600'}">
                            ${item.type === 'import' ? '+' : '-'}${item.quantity}
                        </p>
                        <p class="text-sm text-gray-500">Sau: ${item.stockAfter}</p>
                        <p class="text-xs text-gray-400">${formatDateTime(item.date)}</p>
                    </div>
                </div>
            </div>
        `).join('');
    }

    // ============================================
    // 7. KIỂM KÊ KHO
    // ============================================

    function showInventoryCheckModal() {
        const modalHtml = `
        <div id="inventory-check-modal" class="adv-modal" onclick="if(event.target===this)closeInventoryCheckModal()">
            <div class="adv-modal-content" style="max-width: 1100px;">
                <div class="adv-modal-header bg-gradient-to-r from-indigo-500 to-purple-600">
                    <h3 class="text-white">
                        <i class="fas fa-clipboard-check"></i>Kiểm Kê Kho
                    </h3>
                    <button onclick="closeInventoryCheckModal()" class="adv-modal-close" style="background: white; color: #6366f1; font-weight: bold; width: 32px; height: 32px; border-radius: 50%; display: flex; align-items: center; justify-content: center; font-size: 16px;" title="Đóng">✕</button>
                </div>
                <div class="adv-modal-body">
                    <!-- Quick Actions -->
                    <div class="flex gap-4 mb-6 flex-wrap">
                        <button onclick="loadInventoryForCheck('all')" class="px-4 py-2 bg-blue-500 text-white rounded-lg hover:bg-blue-600">
                            Tất cả sản phẩm
                        </button>
                        <button onclick="loadInventoryForCheck('category')" class="px-4 py-2 bg-gray-200 text-gray-700 rounded-lg hover:bg-gray-300">
                            Theo danh mục
                        </button>
                        <button onclick="loadInventoryForCheck('lowstock')" class="px-4 py-2 bg-orange-500 text-white rounded-lg hover:bg-orange-600">
                            SP sắp hết
                        </button>
                        <div class="flex-1"></div>
                    </div>

                    <!-- Inventory Check Table -->
                    <div class="border rounded-lg overflow-hidden">
                        <div class="inventory-check-item bg-gray-100 font-semibold">
                            <div>Sản phẩm</div>
                            <div class="text-center">Hệ thống</div>
                            <div class="text-center">Thực tế</div>
                            <div class="text-center">Chênh lệch</div>
                            <div class="text-center">Trạng thái</div>
                        </div>
                        <div id="inventory-check-list" class="max-h-[400px] overflow-y-auto">
                            <div class="text-center py-8 text-gray-500">
                                Chọn nhóm sản phẩm để bắt đầu kiểm kê
                            </div>
                        </div>
                    </div>

                    <!-- Summary -->
                    <div id="inventory-check-summary" class="mt-4 p-4 bg-gray-50 rounded-lg hidden">
                        <div class="grid grid-cols-4 gap-4 text-center">
                            <div>
                                <p class="text-sm text-gray-500">Tổng SP</p>
                                <p class="text-xl font-bold" id="inv-total">0</p>
                            </div>
                            <div>
                                <p class="text-sm text-gray-500">Đúng</p>
                                <p class="text-xl font-bold text-green-600" id="inv-correct">0</p>
                            </div>
                            <div>
                                <p class="text-sm text-gray-500">Thừa</p>
                                <p class="text-xl font-bold text-blue-600" id="inv-over">0</p>
                            </div>
                            <div>
                                <p class="text-sm text-gray-500">Thiếu</p>
                                <p class="text-xl font-bold text-red-600" id="inv-under">0</p>
                            </div>
                        </div>
                    </div>
                </div>
                <div class="adv-modal-footer">
                    <button onclick="closeInventoryCheckModal()" class="adv-btn adv-btn-secondary">
                        <i class="fas fa-times"></i> Đóng
                    </button>
                    <button onclick="showInventoryCheckHistory()" class="adv-btn" style="background:#0ea5e9;color:#fff;">
                        <i class="fas fa-history"></i> Lịch sử
                    </button>
                    <button onclick="printInventoryCheck()" class="adv-btn" style="background:#7c3aed;color:#fff;">
                        <i class="fas fa-print"></i> In kiểm kê
                    </button>
                    <button onclick="exportInventoryCheck()" class="adv-btn adv-btn-success">
                        <i class="fas fa-file-excel"></i> Xuất báo cáo
                    </button>
                    <button onclick="saveInventoryCheck()" class="adv-btn adv-btn-primary">
                        <i class="fas fa-save"></i> Lưu & Điều chỉnh kho
                    </button>
                </div>
            </div>
        </div>`;

        document.body.insertAdjacentHTML('beforeend', modalHtml);
        // Tự động load tất cả sản phẩm khi mở modal
        loadInventoryForCheck('all');
    }

    function closeInventoryCheckModal() {
        const modal = document.getElementById('inventory-check-modal');
        if (modal) modal.remove();
    }

    function loadInventoryForCheck(type) {
        google.script.run
            .withSuccessHandler(function(products) {
                renderInventoryCheckList(products);
            })
            .getProductsForInventoryCheck(type);
    }

    function renderInventoryCheckList(products) {
        const container = document.getElementById('inventory-check-list');
        inventoryCheckData = products.map(p => ({ ...p, actual: p.stock, diff: 0 }));

        container.innerHTML = inventoryCheckData.map((p, idx) => `
            <div class="inventory-check-item">
                <div>
                    <p class="font-medium">${p.name}</p>
                    <p class="text-sm text-gray-500">${p.sku}</p>
                </div>
                <div class="text-center font-medium">${p.stock}</div>
                <div>
                    <input type="number" value="${p.stock}" onchange="updateInventoryActual(${idx}, this.value)" class="inventory-actual-input">
                </div>
                <div class="text-center inventory-diff" id="inv-diff-${idx}">0</div>
                <div class="text-center" id="inv-status-${idx}">
                    <span class="px-2 py-1 bg-green-100 text-green-700 rounded text-xs">Đúng</span>
                </div>
            </div>
        `).join('');

        document.getElementById('inventory-check-summary').classList.remove('hidden');
        updateInventorySummary();
    }

    function updateInventoryActual(idx, value) {
        const actual = parseInt(value) || 0;
        inventoryCheckData[idx].actual = actual;
        inventoryCheckData[idx].diff = actual - inventoryCheckData[idx].stock;

        const diffEl = document.getElementById(`inv-diff-${idx}`);
        const statusEl = document.getElementById(`inv-status-${idx}`);
        const diff = inventoryCheckData[idx].diff;

        diffEl.textContent = diff > 0 ? `+${diff}` : diff;
        diffEl.className = `text-center inventory-diff ${diff > 0 ? 'positive' : diff < 0 ? 'negative' : ''}`;

        if (diff === 0) {
            statusEl.innerHTML = `<span class="px-2 py-1 bg-green-100 text-green-700 rounded text-xs">Đúng</span>`;
        } else if (diff > 0) {
            statusEl.innerHTML = `<span class="px-2 py-1 bg-blue-100 text-blue-700 rounded text-xs">Thừa</span>`;
        } else {
            statusEl.innerHTML = `<span class="px-2 py-1 bg-red-100 text-red-700 rounded text-xs">Thiếu</span>`;
        }

        updateInventorySummary();
    }

    function updateInventorySummary() {
        const total = inventoryCheckData.length;
        const correct = inventoryCheckData.filter(p => p.diff === 0).length;
        const over = inventoryCheckData.filter(p => p.diff > 0).length;
        const under = inventoryCheckData.filter(p => p.diff < 0).length;

        document.getElementById('inv-total').textContent = total;
        document.getElementById('inv-correct').textContent = correct;
        document.getElementById('inv-over').textContent = over;
        document.getElementById('inv-under').textContent = under;
    }

    // Export inventory check to CSV
    function exportInventoryCheck() {
        if (!inventoryCheckData || inventoryCheckData.length === 0) {
            showToast('Chưa có dữ liệu kiểm kê để xuất', 'warning');
            return;
        }

        // Create CSV content
        const headers = ['Mã SP', 'Tên SP', 'Tồn Kho Hệ Thống', 'Thực Tế', 'Chênh Lệch', 'Trạng Thái'];
        const rows = inventoryCheckData.map(p => {
            let status = 'Đúng';
            if (p.diff > 0) status = 'Thừa';
            else if (p.diff < 0) status = 'Thiếu';
            return [p.sku, p.name, p.stock, p.actual, p.diff, status];
        });

        let csvContent = headers.join(',') + '\n';
        rows.forEach(row => {
            csvContent += row.map(cell => `"${cell}"`).join(',') + '\n';
        });

        // Add BOM for UTF-8
        const BOM = '\uFEFF';
        const blob = new Blob([BOM + csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        link.download = `kiem_ke_kho_${toLocalDateStr()}.csv`;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        URL.revokeObjectURL(url);

        showToast('Đã xuất báo cáo kiểm kê kho', 'success');
    }

    // Print inventory check report
    function printInventoryCheck() {
        if (!inventoryCheckData || inventoryCheckData.length === 0) {
            showToast('Chưa có dữ liệu kiểm kê để in', 'warning');
            return;
        }

        const now = new Date();
        const dateStr = now.toLocaleDateString('vi-VN', { day: '2-digit', month: '2-digit', year: 'numeric' });
        const timeStr = now.toLocaleTimeString('vi-VN', { hour: '2-digit', minute: '2-digit' });

        // Summary counts
        const total = inventoryCheckData.length;
        const correct = inventoryCheckData.filter(p => p.diff === 0).length;
        const over = inventoryCheckData.filter(p => p.diff > 0).length;
        const under = inventoryCheckData.filter(p => p.diff < 0).length;

        // Company info
        const info = (typeof getMergedCompanyInfo === 'function') ? getMergedCompanyInfo() : (companyInfo || {});

        // Build rows
        let rowsHtml = '';
        inventoryCheckData.forEach((p, idx) => {
            let status = 'Đúng';
            let statusColor = '#16a34a';
            let bgColor = idx % 2 === 0 ? '#fff' : '#f9fafb';
            if (p.diff > 0) { status = 'Thừa (+' + p.diff + ')'; statusColor = '#2563eb'; }
            else if (p.diff < 0) { status = 'Thiếu (' + p.diff + ')'; statusColor = '#dc2626'; bgColor = p.diff < 0 ? '#fef2f2' : bgColor; }

            rowsHtml += `
                <tr style="background:${bgColor};">
                    <td style="border:1px solid #d1d5db;padding:6px 8px;text-align:center;">${idx + 1}</td>
                    <td style="border:1px solid #d1d5db;padding:6px 8px;">${p.sku || ''}</td>
                    <td style="border:1px solid #d1d5db;padding:6px 8px;">${p.name}</td>
                    <td style="border:1px solid #d1d5db;padding:6px 8px;text-align:center;">${p.stock}</td>
                    <td style="border:1px solid #d1d5db;padding:6px 8px;text-align:center;font-weight:600;">${p.actual}</td>
                    <td style="border:1px solid #d1d5db;padding:6px 8px;text-align:center;font-weight:600;color:${p.diff !== 0 ? statusColor : '#374151'};">${p.diff > 0 ? '+' + p.diff : p.diff}</td>
                    <td style="border:1px solid #d1d5db;padding:6px 8px;text-align:center;color:${statusColor};font-weight:500;">${status}</td>
                </tr>`;
        });

        const html = `<!DOCTYPE html>
<html><head><meta charset="UTF-8"><title>Kiểm Kê Kho - ${dateStr}</title>
<style>
    @page { size: A4 landscape; margin: 15mm; }
    body { font-family: 'Times New Roman', Times, serif; margin: 0; padding: 20px; color: #1f2937; font-size: 13px; }
    @media print { body { padding: 0; } }
</style></head><body>

<!-- Header -->
<div style="text-align:center;margin-bottom:5px;">
    <div style="font-weight:bold;font-size:16px;text-transform:uppercase;">${info.name || 'CÔNG TY'}</div>
    ${info.address ? '<div style="font-size:12px;color:#6b7280;">' + info.address + '</div>' : ''}
    ${info.phone ? '<div style="font-size:12px;color:#6b7280;">ĐT: ' + info.phone + '</div>' : ''}
</div>

<!-- Title -->
<div style="text-align:center;margin:15px 0;">
    <div style="font-size:22px;font-weight:bold;color:#4f46e5;text-transform:uppercase;">BIÊN BẢN KIỂM KÊ KHO</div>
    <div style="font-size:13px;color:#6b7280;margin-top:4px;">Ngày kiểm kê: ${dateStr} - ${timeStr}</div>
    ${(typeof currentUser !== 'undefined' && currentUser) ? '<div style="font-size:13px;color:#6b7280;">Người kiểm kê: ' + (currentUser.fullName || currentUser.username || '') + '</div>' : ''}
</div>

<!-- Summary -->
<div style="display:flex;gap:20px;margin-bottom:15px;justify-content:center;">
    <div style="border:1px solid #d1d5db;border-radius:8px;padding:10px 20px;text-align:center;min-width:100px;">
        <div style="font-size:12px;color:#6b7280;">Tổng SP</div>
        <div style="font-size:20px;font-weight:bold;">${total}</div>
    </div>
    <div style="border:1px solid #bbf7d0;border-radius:8px;padding:10px 20px;text-align:center;background:#f0fdf4;min-width:100px;">
        <div style="font-size:12px;color:#16a34a;">Đúng</div>
        <div style="font-size:20px;font-weight:bold;color:#16a34a;">${correct}</div>
    </div>
    <div style="border:1px solid #bfdbfe;border-radius:8px;padding:10px 20px;text-align:center;background:#eff6ff;min-width:100px;">
        <div style="font-size:12px;color:#2563eb;">Thừa</div>
        <div style="font-size:20px;font-weight:bold;color:#2563eb;">${over}</div>
    </div>
    <div style="border:1px solid #fecaca;border-radius:8px;padding:10px 20px;text-align:center;background:#fef2f2;min-width:100px;">
        <div style="font-size:12px;color:#dc2626;">Thiếu</div>
        <div style="font-size:20px;font-weight:bold;color:#dc2626;">${under}</div>
    </div>
</div>

<!-- Table -->
<table style="width:100%;border-collapse:collapse;font-size:13px;">
    <thead>
        <tr style="background:#4f46e5;color:white;">
            <th style="border:1px solid #4338ca;padding:8px;text-align:center;width:40px;">STT</th>
            <th style="border:1px solid #4338ca;padding:8px;text-align:left;">Mã SP</th>
            <th style="border:1px solid #4338ca;padding:8px;text-align:left;">Tên Sản Phẩm</th>
            <th style="border:1px solid #4338ca;padding:8px;text-align:center;width:80px;">Hệ Thống</th>
            <th style="border:1px solid #4338ca;padding:8px;text-align:center;width:80px;">Thực Tế</th>
            <th style="border:1px solid #4338ca;padding:8px;text-align:center;width:80px;">Chênh Lệch</th>
            <th style="border:1px solid #4338ca;padding:8px;text-align:center;width:100px;">Trạng Thái</th>
        </tr>
    </thead>
    <tbody>
        ${rowsHtml}
    </tbody>
</table>

<!-- Footer -->
<div style="margin-top:30px;display:flex;justify-content:space-between;padding:0 40px;">
    <div style="text-align:center;">
        <div style="font-weight:bold;margin-bottom:60px;">THỦ KHO</div>
        <div style="font-style:italic;font-size:12px;">(Ký, ghi rõ họ tên)</div>
    </div>
    <div style="text-align:center;">
        <div style="font-weight:bold;margin-bottom:60px;">NGƯỜI KIỂM KÊ</div>
        <div style="font-style:italic;font-size:12px;">(Ký, ghi rõ họ tên)</div>
    </div>
    <div style="text-align:center;">
        <div style="font-weight:bold;margin-bottom:60px;">QUẢN LÝ</div>
        <div style="font-style:italic;font-size:12px;">(Ký, ghi rõ họ tên)</div>
    </div>
</div>

</body></html>`;

        const printWindow = window.open('', '_blank', 'width=1000,height=700');
        if (!printWindow) {
            showToast('Trình duyệt chặn popup. Vui lòng cho phép popup.', 'error');
            return;
        }
        printWindow.document.write(html);
        printWindow.document.close();
        printWindow.onload = function() { printWindow.print(); };
    }

    // Save inventory check and adjust stock
    function saveInventoryCheck() {
        if (!inventoryCheckData || inventoryCheckData.length === 0) {
            showToast('Chưa có dữ liệu kiểm kê để lưu', 'warning');
            return;
        }

        // Filter only items with differences
        const adjustments = inventoryCheckData.filter(p => p.diff !== 0).map(p => ({
            sku: p.sku,
            name: p.name,
            systemStock: p.stock,
            actual: p.actual,
            diff: p.diff
        }));

        if (adjustments.length === 0) {
            showToast('Không có sản phẩm nào cần điều chỉnh', 'info');
            return;
        }

        if (!confirm(`Bạn có chắc muốn điều chỉnh kho cho ${adjustments.length} sản phẩm?`)) {
            return;
        }

        showToast('Đang lưu điều chỉnh kho...', 'info');

        google.script.run
            .withSuccessHandler(function(result) {
                if (result && result.success) {
                    showToast(`Đã điều chỉnh kho cho ${adjustments.length} sản phẩm`, 'success');
                    closeInventoryCheckModal();
                    // Invalidate products cache (stock đã thay đổi sau kiểm kê)
                    if (typeof LocalStore !== 'undefined') {
                        LocalStore.setVersion('PRODUCTS', '0');
                    }
                    if (typeof products !== 'undefined') {
                        products = [];
                    }
                    // Reload products to reflect changes
                    if (typeof loadProductsManage === 'function') {
                        loadProductsManage();
                    }
                } else {
                    showToast('Lỗi: ' + (result?.message || 'Không thể lưu'), 'error');
                }
            })
            .withFailureHandler(function(error) {
                showToast('Lỗi: ' + error.message, 'error');
            })
            .saveInventoryCheck(adjustments);
    }

    // =============================================
    // INVENTORY CHECK HISTORY
    // =============================================
    function showInventoryCheckHistory() {
        var existing = document.getElementById('inventory-history-modal');
        if (existing) existing.remove();
        var modal = document.createElement('div');
        modal.id = 'inventory-history-modal';
        modal.className = 'fixed inset-0 bg-black/60 z-[60] flex items-center justify-center';
        modal.onclick = function(e) { if (e.target === modal) modal.remove(); };
        modal.innerHTML = '<div class="bg-white rounded-2xl shadow-xl w-full max-w-3xl mx-4 flex flex-col" style="max-height:85vh">'
            + '<div class="flex items-center justify-between px-6 py-4 border-b flex-shrink-0 bg-gradient-to-r from-sky-500 to-indigo-600 text-white rounded-t-2xl">'
            + '<h3 class="text-base font-bold">📋 Lịch Sử Kiểm Kho</h3>'
            + '<button onclick="document.getElementById(\'inventory-history-modal\').remove()" class="text-white/80 hover:text-white text-2xl">&times;</button>'
            + '</div>'
            + '<div id="inv-history-content" class="flex-1 overflow-y-auto p-4">'
            + '<div class="text-center py-8 text-gray-400">Đang tải...</div>'
            + '</div>'
            + '<div class="px-6 py-3 border-t flex justify-end flex-shrink-0">'
            + '<button onclick="document.getElementById(\'inventory-history-modal\').remove()" class="px-5 py-2 bg-gray-200 text-gray-700 rounded-lg hover:bg-gray-300 text-sm">Đóng</button>'
            + '</div></div>';
        document.body.appendChild(modal);
        // Load history — call directly like other inventory functions (not via apiHandler)
        google.script.run
            .withSuccessHandler(function(res) {
                var data = res && res.success ? res.data : (Array.isArray(res) ? res : []);
                _renderInventoryHistory(data);
            })
            .withFailureHandler(function(err) {
                var c = document.getElementById('inv-history-content');
                if (c) c.innerHTML = '<div class="text-center py-8 text-red-500">Lỗi tải lịch sử: ' + (err && err.message ? err.message : '') + '</div>';
            })
            .getInventoryCheckHistory(50);
    }

    function _renderInventoryHistory(sessions) {
        var container = document.getElementById('inv-history-content');
        if (!sessions || sessions.length === 0) {
            container.innerHTML = '<div class="text-center py-8 text-gray-400">Chưa có lịch sử kiểm kho</div>';
            return;
        }
        container.innerHTML = sessions.map(function(s, idx) {
            var d = s.date ? new Date(s.date) : null;
            var dateStr = d ? d.toLocaleDateString('vi-VN', { day:'2-digit', month:'2-digit', year:'numeric' }) : '';
            var timeStr = d ? d.toLocaleTimeString('vi-VN', { hour:'2-digit', minute:'2-digit' }) : '';
            return '<div class="border border-gray-200 rounded-xl mb-3 overflow-hidden">'
                + '<div class="flex items-center justify-between px-4 py-3 bg-gray-50 cursor-pointer hover:bg-gray-100" onclick="_toggleInvDetail(' + idx + ')">'
                + '<div class="flex items-center gap-3">'
                + '<span class="text-xs font-mono bg-indigo-100 text-indigo-700 px-2 py-0.5 rounded">' + (s.id || '') + '</span>'
                + '<span class="text-sm font-medium">' + dateStr + ' ' + timeStr + '</span>'
                + '<span class="text-xs text-gray-500">' + (s.employee || '') + '</span>'
                + '</div>'
                + '<div class="flex items-center gap-3 text-xs">'
                + '<span class="px-2 py-0.5 bg-blue-50 text-blue-700 rounded">' + s.total + ' SP</span>'
                + (s.over > 0 ? '<span class="px-2 py-0.5 bg-blue-100 text-blue-700 rounded">+' + s.over + ' thừa</span>' : '')
                + (s.under > 0 ? '<span class="px-2 py-0.5 bg-red-100 text-red-700 rounded">-' + s.under + ' thiếu</span>' : '')
                + '<span class="px-2 py-0.5 bg-green-100 text-green-700 rounded">' + s.adjusted + ' đã sửa</span>'
                + '<span class="text-gray-400">▼</span>'
                + '</div></div>'
                + '<div id="inv-detail-' + idx + '" class="hidden px-4 py-3 border-t bg-white">'
                + _buildInvDetailTable(s.details)
                + '</div></div>';
        }).join('');
    }

    function _toggleInvDetail(idx) {
        var el = document.getElementById('inv-detail-' + idx);
        if (el) el.classList.toggle('hidden');
    }

    function _buildInvDetailTable(detailsJson) {
        try {
            var items = JSON.parse(detailsJson || '[]');
            if (!items || items.length === 0) return '<p class="text-sm text-gray-400">Không có SP chênh lệch</p>';
            return '<table class="w-full text-xs border-collapse">'
                + '<thead><tr class="bg-gray-50"><th class="px-2 py-1.5 text-left border">SKU</th><th class="px-2 py-1.5 text-left border">Tên SP</th><th class="px-2 py-1.5 text-center border">Hệ thống</th><th class="px-2 py-1.5 text-center border">Thực tế</th><th class="px-2 py-1.5 text-center border">Chênh lệch</th></tr></thead>'
                + '<tbody>' + items.map(function(it) {
                    var cls = it.diff > 0 ? 'text-blue-600' : 'text-red-600';
                    var sign = it.diff > 0 ? '+' : '';
                    return '<tr><td class="px-2 py-1 border font-mono">' + (it.sku || '') + '</td>'
                        + '<td class="px-2 py-1 border">' + (it.name || '') + '</td>'
                        + '<td class="px-2 py-1 border text-center">' + (it.sys || 0) + '</td>'
                        + '<td class="px-2 py-1 border text-center">' + (it.act || 0) + '</td>'
                        + '<td class="px-2 py-1 border text-center font-semibold ' + cls + '">' + sign + it.diff + '</td></tr>';
                }).join('') + '</tbody></table>';
        } catch(e) {
            return '<p class="text-sm text-red-400">Lỗi hiển thị chi tiết</p>';
        }
    }

    // ============================================
    // 8. HẠN SỬ DỤNG SẢN PHẨM
    // ============================================

    function showExpiryManagementModal() {
        google.script.run
            .withSuccessHandler(function(data) {
                renderExpiryManagementModal(data);
            })
            .getProductExpiryData();
    }

    function renderExpiryManagementModal(data) {
        const modalHtml = `
        <div id="expiry-modal" class="adv-modal" onclick="if(event.target===this)closeExpiryModal()">
            <div class="adv-modal-content" style="max-width: 1000px;">
                <div class="adv-modal-header bg-gradient-to-r from-amber-500 to-orange-500">
                    <h3 class="text-white">
                        <i class="fas fa-calendar-times"></i>Quản Lý Hạn Sử Dụng
                    </h3>
                    <button onclick="closeExpiryModal()" class="adv-modal-close" style="background: rgba(255,255,255,0.2); color: white;" title="Đóng">
                        <i class="fas fa-times"></i>
                    </button>
                </div>
                <div class="adv-modal-body">
                    <!-- Stats -->
                    <div class="grid grid-cols-4 gap-4 mb-6">
                        <div class="quick-stat-card danger">
                            <p class="text-sm text-gray-500">Đã hết hạn</p>
                            <p class="text-2xl font-bold text-red-600">${data.expired?.length || 0}</p>
                        </div>
                        <div class="quick-stat-card warning">
                            <p class="text-sm text-gray-500">Sắp hết hạn (7 ngày)</p>
                            <p class="text-2xl font-bold text-orange-600">${data.expiringSoon?.length || 0}</p>
                        </div>
                        <div class="quick-stat-card info">
                            <p class="text-sm text-gray-500">Còn 30 ngày</p>
                            <p class="text-2xl font-bold text-blue-600">${data.expiring30Days?.length || 0}</p>
                        </div>
                        <div class="quick-stat-card success">
                            <p class="text-sm text-gray-500">Còn hạn tốt</p>
                            <p class="text-2xl font-bold text-green-600">${data.ok?.length || 0}</p>
                        </div>
                    </div>

                    <!-- Expiry List -->
                    <div class="border rounded-lg overflow-hidden">
                        <table class="w-full text-sm">
                            <thead class="bg-gray-50">
                                <tr>
                                    <th class="px-4 py-3 text-left">Sản phẩm</th>
                                    <th class="px-4 py-3 text-left">Lô hàng</th>
                                    <th class="px-4 py-3 text-center">Số lượng</th>
                                    <th class="px-4 py-3 text-center">Ngày hết hạn</th>
                                    <th class="px-4 py-3 text-center">Còn lại</th>
                                    <th class="px-4 py-3 text-center">Trạng thái</th>
                                    <th class="px-4 py-3 text-center">Thao tác</th>
                                </tr>
                            </thead>
                            <tbody id="expiry-table-body">
                                ${renderExpiryRows(data)}
                            </tbody>
                        </table>
                    </div>
                </div>
                <div class="adv-modal-footer">
                    <button onclick="closeExpiryModal()" class="adv-btn adv-btn-secondary">
                        <i class="fas fa-times"></i> Đóng
                    </button>
                </div>
            </div>
        </div>`;

        document.body.insertAdjacentHTML('beforeend', modalHtml);
    }

    function renderExpiryRows(data) {
        const allItems = [
            ...(data.expired || []).map(i => ({ ...i, status: 'expired' })),
            ...(data.expiringSoon || []).map(i => ({ ...i, status: 'expiring-soon' })),
            ...(data.expiring30Days || []).map(i => ({ ...i, status: 'expiring-30' }))
        ].sort((a, b) => new Date(a.expiryDate) - new Date(b.expiryDate));

        if (allItems.length === 0) {
            return `<tr><td colspan="7" class="text-center py-8 text-gray-500">Không có sản phẩm cần chú ý</td></tr>`;
        }

        return allItems.map(item => `
            <tr class="border-t hover:bg-gray-50">
                <td class="px-4 py-3">
                    <p class="font-medium">${item.name}</p>
                    <p class="text-xs text-gray-500">${item.sku}</p>
                </td>
                <td class="px-4 py-3">${item.batchNo || '-'}</td>
                <td class="px-4 py-3 text-center">${item.quantity}</td>
                <td class="px-4 py-3 text-center">${formatDate(item.expiryDate)}</td>
                <td class="px-4 py-3 text-center">
                    <span class="font-medium ${item.daysLeft < 0 ? 'text-red-600' : item.daysLeft < 7 ? 'text-orange-600' : 'text-blue-600'}">
                        ${item.daysLeft < 0 ? 'Đã hết ' + Math.abs(item.daysLeft) + ' ngày' : item.daysLeft + ' ngày'}
                    </span>
                </td>
                <td class="px-4 py-3 text-center">
                    <span class="expiry-badge ${item.status}">
                        ${item.status === 'expired' ? 'Hết hạn' : item.status === 'expiring-soon' ? 'Sắp hết' : 'Còn 30 ngày'}
                    </span>
                </td>
                <td class="px-4 py-3 text-center">
                    <button onclick="markAsDisposed('${item.sku}', '${item.batchNo}')" class="text-red-500 hover:text-red-600" title="Xử lý/Hủy">
                        <i class="fas fa-trash"></i>
                    </button>
                </td>
            </tr>
        `).join('');
    }

    function closeExpiryModal() {
        const modal = document.getElementById('expiry-modal');
        if (modal) modal.remove();
    }

