    function closePriceModal() {
        const modal = document.getElementById('price-modal');
        if (modal) modal.remove();
    }

    function showPriceTab(tab) {
        document.querySelectorAll('.price-tab-content').forEach(el => el.classList.add('hidden'));
        document.querySelectorAll('.product-detail-tab').forEach(el => el.classList.remove('active'));

        document.getElementById(`price-tab-${tab}`).classList.remove('hidden');
        event.target.classList.add('active');
    }

    // Load current product prices into modal form
    function loadProductPrices(sku) {
        const product = (typeof products !== 'undefined' ? products : []).find(p => p.sku === sku);
        if (!product) { showToast('Không tìm thấy sản phẩm', 'error'); return; }

        const setVal = (id, val) => { const el = document.getElementById(id); if (el) el.value = val || 0; };
        setVal('price-import', product.importPrice);
        setVal('price-retail', product.price);
        setVal('price-vip', product.vipPrice);
        setVal('price-wholesale', product.wholesalePrice);

        // Bind profit margin recalculation
        ['price-import', 'price-retail'].forEach(id => {
            const el = document.getElementById(id);
            if (el) el.oninput = updateProfitMargin;
        });
        updateProfitMargin();

        // Render group prices list from existing data
        const groupList = document.getElementById('group-prices-list');
        if (groupList) {
            groupList.innerHTML = '';
            if (product.vipPrice > 0) renderGroupPriceItem('VIP', product.vipPrice);
            if (product.wholesalePrice > 0) renderGroupPriceItem('Doanh Nghiệp / Đại lý', product.wholesalePrice);
        }

        // Quantity and history: placeholders
        const qtyList = document.getElementById('quantity-prices-list');
        if (qtyList) qtyList.innerHTML = '<p class="text-sm text-gray-400 italic py-2">Tính năng giá theo số lượng đang phát triển</p>';
        const histList = document.getElementById('price-history-list');
        if (histList) histList.innerHTML = '<p class="text-sm text-gray-400 italic py-2">Chưa có lịch sử thay đổi giá</p>';
    }

    // Recalculate profit margin display
    function updateProfitMargin() {
        const importPrice = parseFloat((document.getElementById('price-import') || {}).value) || 0;
        const retailPrice = parseFloat((document.getElementById('price-retail') || {}).value) || 0;
        const profit = retailPrice - importPrice;
        const margin = importPrice > 0 ? ((profit / importPrice) * 100).toFixed(1) : 0;
        const marginEl = document.getElementById('profit-margin');
        const amountEl = document.getElementById('profit-amount');
        if (marginEl) marginEl.textContent = margin + '%';
        if (amountEl) amountEl.textContent = (typeof formatMoney === 'function' ? formatMoney(profit) : profit.toLocaleString());
    }

    // Render a single group price item row
    function renderGroupPriceItem(groupName, price) {
        const list = document.getElementById('group-prices-list');
        if (!list) return;
        const item = document.createElement('div');
        item.className = 'flex items-center justify-between p-3 bg-gray-50 rounded-lg mb-2';
        const safeGroup = typeof escapeHtml === 'function' ? escapeHtml(groupName) : groupName;
        item.innerHTML = `
            <div>
                <span class="font-medium text-sm">${safeGroup}</span>
                <span class="text-sm text-gray-500 ml-2">${typeof formatMoney === 'function' ? formatMoney(price) : price.toLocaleString()}đ</span>
            </div>
            <button onclick="this.closest('div.flex').remove()" class="text-red-400 hover:text-red-600 text-sm px-2" title="Xóa">✕</button>
        `;
        list.appendChild(item);
    }

    // Add a group price entry from the form
    function addGroupPrice() {
        const groupSelect = document.getElementById('customer-group-select');
        const priceInput = document.getElementById('group-price');
        const group = groupSelect ? groupSelect.value : '';
        const price = parseFloat(priceInput ? priceInput.value : 0);

        if (!group) { showToast('Vui lòng chọn nhóm khách hàng', 'warning'); return; }
        if (!price || price <= 0) { showToast('Vui lòng nhập giá hợp lệ', 'warning'); return; }

        // Map group to specific price field inputs
        if (group === 'VIP') {
            const el = document.getElementById('price-vip'); if (el) el.value = price;
        } else if (group === 'Doanh Nghiệp' || group === 'Đại lý') {
            const el = document.getElementById('price-wholesale'); if (el) el.value = price;
        }

        renderGroupPriceItem(group, price);
        groupSelect.value = '';
        priceInput.value = '';
        showToast('Đã thêm giá cho nhóm ' + group, 'success');
    }

    // Quantity-based pricing: placeholder
    function addQuantityPrice() {
        showToast('Tính năng giá theo số lượng đang phát triển', 'info');
    }

    // Save prices — updates vipPrice + wholesalePrice via existing updateProduct API
    function savePrices(sku) {
        // Load existing product to avoid zeroing unrelated fields on updateProduct (full-row write)
        const product = (typeof products !== 'undefined' ? products : []).find(p => p.sku === sku);
        if (!product) { showToast('Không tìm thấy sản phẩm', 'error'); return; }

        const retailPrice = parseFloat((document.getElementById('price-retail') || {}).value) || 0;
        const vipPrice = parseFloat((document.getElementById('price-vip') || {}).value) || 0;
        const wholesalePrice = parseFloat((document.getElementById('price-wholesale') || {}).value) || 0;
        const importPrice = parseFloat((document.getElementById('price-import') || {}).value) || product.importPrice || 0;

        if (retailPrice <= 0) { showToast('Giá bán lẻ phải lớn hơn 0', 'warning'); return; }

        // Merge with existing product data — only override price fields
        const payload = Object.assign({}, product, {
            price: retailPrice,
            sellPrice: retailPrice,
            importPrice: importPrice,
            vipPrice: vipPrice,
            wholesalePrice: wholesalePrice,
        });

        google.script.run
            .withSuccessHandler(function(result) {
                if (result && result.success !== false) {
                    // Update local products[] cache
                    product.price = retailPrice;
                    product.vipPrice = vipPrice;
                    product.wholesalePrice = wholesalePrice;
                    product.importPrice = importPrice;
                    showToast('Đã lưu bảng giá thành công', 'success');
                    closePriceModal();
                    if (typeof renderProductsManage === 'function') renderProductsManage();
                } else {
                    showToast((result && result.message) || 'Lỗi khi lưu giá', 'error');
                }
            })
            .withFailureHandler(function(err) {
                showToast('Lỗi: ' + (err.message || err), 'error');
            })
            .apiHandler('updateProduct', payload);
    }

