    function promoRenderProductList(search) {
        const container = document.getElementById('promo-product-list');
        if (!container) return;
        const allProds = (typeof products !== 'undefined' ? products : []).filter(p => p.status !== 'Inactive');
        const q = (search || '').toLowerCase();
        const filtered = q ? allProds.filter(p => p.name.toLowerCase().includes(q) || p.sku.toLowerCase().includes(q)) : allProds;
        if (!filtered.length) { container.innerHTML = '<p class="text-center text-gray-400 py-4 text-sm">Không tìm thấy sản phẩm</p>'; return; }
        container.innerHTML = filtered.map(p => `
            <label class="flex items-center gap-2 px-3 py-2 hover:bg-pink-50 cursor-pointer border-b last:border-b-0">
                <input type="checkbox" class="promo-product-cb" data-sku="${p.sku}">
                <span class="flex-1 text-sm">${p.name}</span>
                <span class="text-xs text-gray-400">${p.sku}</span>
            </label>`).join('');
    }

    function promoSelectAll() {
        document.querySelectorAll('#promo-product-list .promo-product-cb').forEach(cb => cb.checked = true);
    }

    function promoClearAll() {
        document.querySelectorAll('#promo-product-list .promo-product-cb').forEach(cb => cb.checked = false);
    }

    function promoRenderCategoryList() {
        const container = document.getElementById('promo-category-list');
        if (!container) return;
        // Get unique categories from products list
        const allProds = (typeof products !== 'undefined' ? products : []);
        const cats = [...new Set(allProds.map(p => p.category).filter(Boolean))].sort();
        if (!cats.length) { container.innerHTML = '<p class="text-center text-gray-400 py-4 text-sm">Không có danh mục</p>'; return; }
        container.innerHTML = cats.map(cat => `
            <label class="flex items-center gap-2 px-2 py-2 hover:bg-pink-50 cursor-pointer border-b last:border-b-0">
                <input type="checkbox" class="promo-category-cb" data-category="${cat}">
                <span class="text-sm">${cat}</span>
            </label>`).join('');
    }

    function closePromotionModal() {
        const modal = document.getElementById('promotion-modal');
        if (modal) modal.remove();
    }

    function savePromotion() {
        const type = document.querySelector('input[name="promo-type"]:checked')?.value;
        const applyTo = document.querySelector('input[name="promo-apply"]:checked')?.value;
        const startDate = document.getElementById('promo-start')?.value;
        const endDate = document.getElementById('promo-end')?.value;

        if (!type) { showToast('Vui lòng chọn loại khuyến mãi', 'error'); return; }

        let value = 0;
        const promoData = { type, applyTo, startDate, endDate, products: [] };

        if (type === 'percent') {
            value = parseFloat(document.getElementById('promo-percent')?.value || 0);
            if (!value || value <= 0 || value > 100) { showToast('Phần trăm giảm không hợp lệ (1-100)', 'error'); return; }
            promoData.value = value;
            promoData.maxDiscount = parseFloat(document.getElementById('promo-max-discount')?.value || 0);
        } else if (type === 'fixed') {
            value = parseFloat(document.getElementById('promo-fixed-amount')?.value || 0);
            if (!value || value <= 0) { showToast('Số tiền giảm không hợp lệ', 'error'); return; }
            promoData.value = value;
        } else if (type === 'buyget') {
            const buyQty = parseInt(document.getElementById('promo-buy-qty')?.value || 0);
            const getQty = parseInt(document.getElementById('promo-get-qty')?.value || 0);
            if (!buyQty || !getQty) { showToast('Vui lòng nhập số lượng mua và tặng', 'error'); return; }
            promoData.value = buyQty;
            promoData.getQty = getQty;
        }

        // Collect selected SKUs if applyTo === 'selected'
        if (applyTo === 'selected') {
            const checked = document.querySelectorAll('.promo-product-cb:checked');
            promoData.products = Array.from(checked).map(cb => cb.dataset.sku).filter(Boolean);
            if (!promoData.products.length) { showToast('Vui lòng chọn ít nhất 1 sản phẩm', 'error'); return; }
        }
        // Collect selected categories if applyTo === 'category'
        if (applyTo === 'category') {
            const checkedCats = document.querySelectorAll('.promo-category-cb:checked');
            promoData.categories = Array.from(checkedCats).map(cb => cb.dataset.category).filter(Boolean);
            if (!promoData.categories.length) { showToast('Vui lòng chọn ít nhất 1 danh mục', 'error'); return; }
        }

        const saveBtn = document.querySelector('#promotion-modal button[onclick="savePromotion()"]');
        if (saveBtn) { saveBtn.disabled = true; saveBtn.textContent = 'Đang lưu...'; }

        google.script.run
            .withSuccessHandler(function(res) {
                if (saveBtn) { saveBtn.disabled = false; saveBtn.innerHTML = '<i class="fas fa-save"></i> Lưu khuyến mãi'; }
                if (res && res.success) {
                    showToast('Lưu khuyến mãi thành công!', 'success');
                    closePromotionModal();
                    // Refresh promotion map so order page picks up new promotions immediately
                    if (typeof loadActivePromotions === 'function') loadActivePromotions();
                } else {
                    showToast('Lỗi: ' + (res && res.message ? res.message : 'Không thể lưu'), 'error');
                }
            })
            .withFailureHandler(function(err) {
                if (saveBtn) { saveBtn.disabled = false; saveBtn.innerHTML = '<i class="fas fa-save"></i> Lưu khuyến mãi'; }
                showToast('Lỗi: ' + (err.message || err.toString()), 'error');
            })
            .apiHandler('saveProductPromotion', promoData);
    }

