    function renderTopSellingList(products) {
        if (!products || products.length === 0) {
            return `<div class="text-center text-gray-500 py-4">Chưa có dữ liệu</div>`;
        }

        return products.map((p, idx) => `
            <div class="top-product-item">
                <div class="top-product-rank ${idx === 0 ? 'gold' : idx === 1 ? 'silver' : idx === 2 ? 'bronze' : ''}" style="${idx > 2 ? 'background: #e5e7eb; color: #374151;' : ''}">
                    ${idx + 1}
                </div>
                <div class="flex-1">
                    <p class="font-medium">${p.name}</p>
                    <p class="text-xs text-gray-500">${p.sku}</p>
                </div>
                <div class="text-right">
                    <p class="font-bold text-green-600">${p.soldQty} sp</p>
                    <p class="text-sm text-gray-500">${formatMoney(p.revenue)}</p>
                </div>
            </div>
        `).join('');
    }

    function renderSlowMovingList(products) {
        if (!products || products.length === 0) {
            return `<div class="text-center text-gray-500 py-4">Không có SP chậm bán</div>`;
        }

        return products.map(p => `
            <div class="flex items-center gap-3 p-3 bg-orange-50 rounded-lg mb-2">
                <div class="flex-1">
                    <p class="font-medium">${p.name}</p>
                    <p class="text-xs text-gray-500">${p.sku} | Tồn: ${p.stock}</p>
                </div>
                <div class="text-right">
                    <p class="text-sm text-orange-600">${p.daysSinceLastSale} ngày</p>
                    <p class="text-xs text-gray-500">chưa bán</p>
                </div>
            </div>
        `).join('');
    }

    function renderProfitAnalysisList(products) {
        if (!products || products.length === 0) {
            return `<div class="text-center text-gray-500 py-4">Chưa có dữ liệu</div>`;
        }

        return products.slice(0, 5).map(p => `
            <div class="flex items-center justify-between p-3 bg-gray-50 rounded-lg mb-2">
                <div>
                    <p class="font-medium">${p.name}</p>
                    <p class="text-xs text-gray-500">${p.sku}</p>
                </div>
                <div class="text-right">
                    <p class="font-bold text-blue-600">${p.profitMargin}%</p>
                    <p class="text-sm text-green-600">+${formatMoney(p.totalProfit)}</p>
                </div>
            </div>
        `).join('');
    }

    function closeAnalysisModal() {
        const modal = document.getElementById('analysis-modal');
        if (modal) modal.remove();
    }

    function initAnalysisCharts(data) {
        // Tạo biểu đồ Doanh Thu Theo Danh Mục
        const ctx = document.getElementById('category-revenue-chart');
        if (!ctx) return;

        // Lấy dữ liệu danh mục
        const categoryData = data.categoryRevenue || [];

        if (categoryData.length === 0) {
            // Hiển thị thông báo nếu không có dữ liệu
            const container = ctx.parentElement;
            container.innerHTML = `
                <div class="flex flex-col items-center justify-center h-full text-gray-400">
                    <i class="fas fa-chart-pie text-4xl mb-2"></i>
                    <p>Chưa có dữ liệu doanh thu</p>
                </div>
            `;
            return;
        }

        // Màu sắc cho biểu đồ
        const colors = [
            '#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6',
            '#ec4899', '#06b6d4', '#84cc16', '#f97316', '#6366f1'
        ];

        // Tạo biểu đồ dạng thanh ngang (horizontal bar) bằng HTML/CSS
        const maxRevenue = Math.max(...categoryData.map(c => c.revenue || 0));
        const totalRevenue = categoryData.reduce((sum, c) => sum + (c.revenue || 0), 0);

        const chartHtml = `
            <div class="space-y-3">
                ${categoryData.slice(0, 8).map((cat, idx) => {
                    const percent = maxRevenue > 0 ? ((cat.revenue || 0) / maxRevenue * 100) : 0;
                    const sharePercent = totalRevenue > 0 ? ((cat.revenue || 0) / totalRevenue * 100).toFixed(1) : 0;
                    return `
                        <div class="category-bar-item">
                            <div class="flex justify-between items-center mb-1">
                                <span class="text-sm font-medium text-gray-700">${cat.category || 'Khác'}</span>
                                <span class="text-sm text-gray-500">${sharePercent}%</span>
                            </div>
                            <div class="h-6 bg-gray-100 rounded-full overflow-hidden relative">
                                <div class="h-full rounded-full transition-all duration-500"
                                     style="width: ${percent}%; background-color: ${colors[idx % colors.length]};">
                                </div>
                                <span class="absolute right-2 top-1/2 -translate-y-1/2 text-xs font-medium ${percent > 60 ? 'text-white' : 'text-gray-600'}">
                                    ${formatMoney(cat.revenue || 0)}
                                </span>
                            </div>
                        </div>
                    `;
                }).join('')}
            </div>
            <div class="mt-4 pt-4 border-t border-gray-200">
                <div class="flex justify-between items-center">
                    <span class="font-semibold text-gray-700">Tổng cộng:</span>
                    <span class="font-bold text-blue-600">${formatMoney(totalRevenue)}</span>
                </div>
            </div>
        `;

        ctx.parentElement.innerHTML = chartHtml;
    }

