    // 12. TÌM KIẾM NÂNG CAO & TIỆN ÍCH
    // ============================================

    function initAdvancedSearch() {
        // Debounced search
        let searchTimeout;
        const searchInput = document.getElementById('advanced-product-search');
        if (searchInput) {
            searchInput.addEventListener('input', function() {
                clearTimeout(searchTimeout);
                searchTimeout = setTimeout(() => {
                    performAdvancedSearch();
                }, 300);
            });
        }
    }

    function performAdvancedSearch() {
        const query = document.getElementById('advanced-product-search')?.value || '';
        const category = document.getElementById('search-category')?.value || '';
        const status = document.getElementById('search-status')?.value || '';
        const stockStatus = document.getElementById('search-stock-status')?.value || '';
        const priceFrom = document.getElementById('search-price-from')?.value || '';
        const priceTo = document.getElementById('search-price-to')?.value || '';

        const filters = { query, category, status, stockStatus, priceFrom, priceTo };

        google.script.run
            .withSuccessHandler(function(products) {
                renderProductsTable(products);
            })
            .searchProductsAdvanced(filters);
    }

    function toggleFavorite(sku) {
        const idx = favoriteProducts.indexOf(sku);
        if (idx === -1) {
            favoriteProducts.push(sku);
        } else {
            favoriteProducts.splice(idx, 1);
        }
        localStorage.setItem('favoriteProducts', JSON.stringify(favoriteProducts));

        // Update UI
        const star = document.querySelector(`[data-favorite="${sku}"]`);
        if (star) {
            star.classList.toggle('active', favoriteProducts.includes(sku));
        }
    }

    function loadFavoriteProducts() {
        favoriteProducts = JSON.parse(localStorage.getItem('favoriteProducts') || '[]');
    }

    function showFavoriteProducts() {
        if (favoriteProducts.length === 0) {
            showToast('Chưa có sản phẩm yêu thích', 'info');
            return;
        }

        google.script.run
            .withSuccessHandler(function(products) {
                renderProductsTable(products);
                showToast(`Hiển thị ${products.length} sản phẩm yêu thích`, 'info');
            })
            .getProductsBySkus(favoriteProducts);
    }

    function duplicateProduct(sku) {
        google.script.run
            .withSuccessHandler(function(product) {
                if (product) {
                    // Open product modal with pre-filled data
                    showProductModal();
                    setTimeout(() => {
                        document.getElementById('product-sku').value = product.sku + '_COPY';
                        document.getElementById('product-name').value = product.name + ' (Copy)';
                        document.getElementById('product-category').value = product.category;
                        document.getElementById('product-import-price').value = product.importPrice;
                        document.getElementById('product-sell-price').value = product.price;
                        document.getElementById('product-stock').value = 0;
                        document.getElementById('product-unit').value = product.unit;
                        // ... other fields
                    }, 100);
                }
            })
            .getProductBySku(sku);
    }

    function saveProductNote(sku, note) {
        productNotes[sku] = note;
        localStorage.setItem('productNotes', JSON.stringify(productNotes));
        showToast('Đã lưu ghi chú', 'success');
    }

    function loadProductNotes() {
        productNotes = JSON.parse(localStorage.getItem('productNotes') || '{}');
    }

    function showProductNote(sku) {
        const note = productNotes[sku] || '';
        const popup = document.createElement('div');
        popup.className = 'notes-popup';
        popup.innerHTML = `
            <textarea id="note-input-${sku}" class="w-full px-3 py-2 border rounded-lg mb-2" rows="3" placeholder="Ghi chú...">${note}</textarea>
            <div class="flex gap-2 justify-end">
                <button onclick="this.closest('.notes-popup').remove()" class="px-3 py-1 bg-gray-200 rounded text-sm">Hủy</button>
                <button onclick="saveProductNote('${sku}', document.getElementById('note-input-${sku}').value); this.closest('.notes-popup').remove();" class="px-3 py-1 bg-blue-500 text-white rounded text-sm">Lưu</button>
            </div>
        `;
        event.target.closest('td').appendChild(popup);
    }

    // ============================================
    // UTILITY FUNCTIONS
    // ============================================

    function formatMoney(amount) {
        return new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(amount || 0);
    }

    function formatDate(date) {
        if (!date) return '-';
        return new Date(date).toLocaleDateString('vi-VN');
    }

    function formatDateTime(date) {
        if (!date) return '-';
        return new Date(date).toLocaleString('vi-VN');
    }

    function formatFileSize(bytes) {
        if (bytes === 0) return '0 Bytes';
        const k = 1024;
        const sizes = ['Bytes', 'KB', 'MB', 'GB'];
        const i = Math.floor(Math.log(bytes) / Math.log(k));
        return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
    }

