    document.addEventListener('DOMContentLoaded', function() {
        initAdvancedProductFeatures();
        initAdvancedSearch();
    });


// === Frontend_DailyVATSummary.html JS (72,067 chars) ===

    let currentDailyVATData = null;
    let vatTrendChart = null;
    let vatPieChart = null;
    let vatProductChart = null;

    /**
     * Format money for display
     */
    function formatVATMoney(amount) {
        if (!amount && amount !== 0) return '0 ₫';
        return new Intl.NumberFormat('vi-VN').format(amount) + ' ₫';
    }

    /**
     * Set quick date filter
     */
    function setQuickDate(period) {
        const dateFromInput = document.getElementById('daily-vat-date-from');
        const dateToInput = document.getElementById('daily-vat-date-to');
        const today = new Date();

        const formatDate = (date) => {
            const year = date.getFullYear();
            const month = String(date.getMonth() + 1).padStart(2, '0');
            const day = String(date.getDate()).padStart(2, '0');
            return `${year}-${month}-${day}`;
        };

        switch (period) {
            case 'today':
                dateFromInput.value = formatDate(today);
                dateToInput.value = formatDate(today);
                break;
            case 'yesterday':
                const yesterday = new Date(today);
                yesterday.setDate(yesterday.getDate() - 1);
                dateFromInput.value = formatDate(yesterday);
                dateToInput.value = formatDate(yesterday);
                break;
            case '7days':
                const sevenDaysAgo = new Date(today);
                sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 6);
                dateFromInput.value = formatDate(sevenDaysAgo);
                dateToInput.value = formatDate(today);
                break;
            case '30days':
                const thirtyDaysAgo = new Date(today);
                thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 29);
                dateFromInput.value = formatDate(thirtyDaysAgo);
                dateToInput.value = formatDate(today);
                break;
            case 'thisMonth':
                const firstDay = new Date(today.getFullYear(), today.getMonth(), 1);
                dateFromInput.value = formatDate(firstDay);
                dateToInput.value = formatDate(today);
                break;
        }

        loadDailyVATSummary();
    }

    /**
     * Switch VAT tab
     */
    function switchVATTab(tabName) {
        document.querySelectorAll('.vat-tab-btn').forEach(btn => btn.classList.remove('active'));
        document.querySelectorAll('.vat-tab-content').forEach(content => content.classList.remove('active'));

        document.querySelector(`[onclick="switchVATTab('${tabName}')"]`).classList.add('active');
        document.getElementById(`vat-tab-${tabName}`).classList.add('active');

        if (tabName === 'chart' && currentDailyVATData) {
            renderVATCharts(currentDailyVATData);
        }

        // Load VAT inventory when switching to inventory tab
        if (tabName === 'inventory') {
            loadVATInventory();
        }

        // Load returns data when switching to returns tab
        if (tabName === 'returns') {
            loadVATReturns();
        }
    }

    // ============================================
    // VAT INVENTORY FUNCTIONS
    // ============================================

    let currentVATInventoryData = null;

    /**
     * Load VAT Inventory
     */
    function loadVATInventory() {
        console.log('📦 Loading VAT Inventory...');

        google.script.run
            .withSuccessHandler(renderVATInventory)
            .withFailureHandler(function (error) {
                console.error('❌ Error loading VAT inventory:', error);
                showToast('Lỗi tải tồn kho VAT: ' + error.message, 'error');
                document.getElementById('vat-inventory-table').innerHTML = `
                    <tr><td colspan="10" class="text-center text-red-500 py-8">
                        <i class="fas fa-exclamation-circle mr-2"></i> Lỗi: ${error.message}
                    </td></tr>`;
            })
            .getVATInventorySummary();
    }

    /**
     * Render VAT Inventory
     */
    function renderVATInventory(data) {
        console.log('✅ VAT Inventory data received:', data);

        if (!data || !data.success) {
            showToast('Không thể tải tồn kho VAT: ' + (data?.message || ''), 'error');
            return;
        }

        currentVATInventoryData = data;

        // Render summary stats
        const summary = data.summary || {};
        document.getElementById('vat-inv-total-products').textContent = summary.totalProducts || 0;
        document.getElementById('vat-inv-total-qty').textContent = new Intl.NumberFormat('vi-VN').format(summary.totalQuantity || 0);
        document.getElementById('vat-inv-total-value').textContent = formatVATMoney(summary.totalValue || 0);
        document.getElementById('vat-inv-potential-tax').textContent = formatVATMoney(summary.potentialVATAmount || 0);

        // Render by rate breakdown
        const byRate = data.byRate || {};
        ['0', '5', '8', '10'].forEach(rate => {
            const rateData = byRate[rate] || { quantity: 0, value: 0 };
            document.getElementById(`vat-inv-rate-${rate}-qty`).textContent = new Intl.NumberFormat('vi-VN').format(rateData.quantity || 0);
            document.getElementById(`vat-inv-rate-${rate}-value`).textContent = formatVATMoney(rateData.value || 0);
        });

        // Render inventory table
        renderVATInventoryTable(data.products || []);
    }

    /**
     * Render VAT Inventory Table
     */
    function renderVATInventoryTable(products) {
        const tbody = document.getElementById('vat-inventory-table');

        if (!products || products.length === 0) {
            tbody.innerHTML = `<tr><td colspan="10" class="text-center text-gray-500 py-8">
                <i class="fas fa-box-open mr-2"></i> Không có sản phẩm VAT nào trong kho
            </td></tr>`;
            return;
        }

        tbody.innerHTML = products.map(p => {
            // Determine badge class based on stock status
            let statusBadgeClass = 'badge-success';
            if (p.stockStatus === 'Hết hàng') {
                statusBadgeClass = 'badge-danger';
            } else if (p.stockStatus === 'Sắp hết') {
                statusBadgeClass = 'badge-warning';
            } else if (p.stockStatus === 'Đầy kho') {
                statusBadgeClass = 'badge-info';
            }

            return `
                <tr>
                    <td class="text-left"><code class="text-blue-600 text-xs">${p.sku || ''}</code></td>
                    <td class="text-left font-medium" title="${p.name || ''}">${p.name || ''}</td>
                    <td class="text-left text-gray-600">${p.category || ''}</td>
                    <td class="text-center font-bold ${p.stock <= (p.minStock || 5) ? 'text-red-600' : 'text-green-600'}">${new Intl.NumberFormat('vi-VN').format(p.stock || 0)}</td>
                    <td class="text-center text-gray-500">${p.unit || ''}</td>
                    <td class="text-right">${formatVATMoney(p.sellPrice || 0)}</td>
                    <td class="text-center">
                        <span class="px-2 py-1 rounded text-xs font-semibold ${p.vatRate === 10 ? 'bg-purple-100 text-purple-700' : p.vatRate === 8 ? 'bg-green-100 text-green-700' : p.vatRate === 5 ? 'bg-blue-100 text-blue-700' : 'bg-gray-100 text-gray-700'}">
                            ${p.vatRate || 0}%
                        </span>
                    </td>
                    <td class="text-right font-semibold">${formatVATMoney(p.stockValue || 0)}</td>
                    <td class="text-right text-orange-600 font-medium">${formatVATMoney(p.potentialVAT || 0)}</td>
                    <td class="text-center">
                        <span class="badge-modern ${statusBadgeClass}">${p.stockStatus || ''}</span>
                    </td>
                </tr>
            `;
        }).join('');
    }

    /**
     * Refresh VAT Inventory
     */
    function refreshVATInventory() {
        showToast('Đang làm mới dữ liệu...', 'info');
        loadVATInventory();
    }

    /**
     * Export VAT Inventory to Excel
     */
    function exportVATInventory() {
        if (!currentVATInventoryData || !currentVATInventoryData.products) {
            showToast('Không có dữ liệu để xuất', 'warning');
            return;
        }

        if (typeof XLSX === 'undefined') {
            showToast('Đang tải thư viện Excel, vui lòng thử lại...', 'info');
            lazyLoadLib('xlsx');
            return;
        }

        const wb = XLSX.utils.book_new();
        const data = currentVATInventoryData;

        // Summary sheet
        const summaryData = [
            ['BÁO CÁO TỒN KHO VAT'],
            ['Ngày xuất báo cáo:', new Date().toLocaleDateString('vi-VN')],
            [''],
            ['TỔNG KẾT', ''],
            ['Tổng SP có VAT:', data.summary.totalProducts],
            ['Tổng số lượng tồn:', data.summary.totalQuantity],
            ['Tổng giá trị (Giá bán):', data.summary.totalValue],
            ['Tiền thuế VAT tiềm năng:', data.summary.potentialVATAmount],
            [''],
            ['PHÂN THEO MỨC THUẾ', 'Số lượng', 'Giá trị', 'Thuế VAT'],
            ['VAT 0%', data.byRate['0']?.quantity || 0, data.byRate['0']?.value || 0, data.byRate['0']?.vatAmount || 0],
            ['VAT 5%', data.byRate['5']?.quantity || 0, data.byRate['5']?.value || 0, data.byRate['5']?.vatAmount || 0],
            ['VAT 8%', data.byRate['8']?.quantity || 0, data.byRate['8']?.value || 0, data.byRate['8']?.vatAmount || 0],
            ['VAT 10%', data.byRate['10']?.quantity || 0, data.byRate['10']?.value || 0, data.byRate['10']?.vatAmount || 0]
        ];
        const ws1 = XLSX.utils.aoa_to_sheet(summaryData);
        XLSX.utils.book_append_sheet(wb, ws1, 'Tổng Kết');

        // Products sheet
        const productData = [['Mã SP', 'Tên Sản Phẩm', 'Danh Mục', 'Tồn Kho', 'Đơn Vị', 'Giá Bán', 'VAT (%)', 'Giá Trị Tồn', 'Thuế VAT Tiềm Năng', 'Trạng Thái']];
        (data.products || []).forEach(p => {
            productData.push([
                p.sku,
                p.name,
                p.category,
                p.stock,
                p.unit,
                p.sellPrice,
                p.vatRate,
                p.stockValue,
                p.potentialVAT,
                p.stockStatus
            ]);
        });
        const ws2 = XLSX.utils.aoa_to_sheet(productData);
        XLSX.utils.book_append_sheet(wb, ws2, 'Chi Tiết Sản Phẩm');

        const fileName = `TonKhoVAT_${toLocalDateStr()}.xlsx`;
        XLSX.writeFile(wb, fileName);
        showToast('Đã xuất báo cáo tồn kho VAT!', 'success');
    }

