    /**
     * Load VAT Returns data
     */
    function loadVATReturns() {
        console.log('📦 Loading VAT Returns...');

        const dateFromValue = document.getElementById('daily-vat-date-from').value;
        const dateToValue = document.getElementById('daily-vat-date-to').value;

        if (!dateFromValue || !dateToValue) {
            showToast('Vui lòng chọn khoảng thời gian', 'warning');
            return;
        }

        const startDate = new Date(dateFromValue);
        const endDate = new Date(dateToValue);
        endDate.setHours(23, 59, 59, 999);

        showLoading(true);

        google.script.run
            .withSuccessHandler(function(res) {
                showLoading(false);
                if (res && res.success) {
                    renderVATReturns(res.data);
                } else {
                    showToast(res?.message || 'Lỗi tải dữ liệu trả hàng', 'error');
                }
            })
            .withFailureHandler(function(err) {
                showLoading(false);
                console.error('Error loading VAT returns:', err);
                showToast('Lỗi kết nối server!', 'error');
            })
            .getVATReturnsData(startDate.getTime(), endDate.getTime());
    }

    /**
     * Render VAT Returns table
     */
    function renderVATReturns(data) {
        const tbody = document.getElementById('vat-returns-table');
        const footer = document.getElementById('vat-returns-footer');

        if (!data || !data.items || data.items.length === 0) {
            tbody.innerHTML = `
                <tr>
                    <td colspan="11" class="text-center text-gray-500 py-8">
                        <i class="fas fa-inbox mr-2"></i> Không có dữ liệu trả hàng trong khoảng thời gian này
                    </td>
                </tr>
            `;
            footer.style.display = 'none';
            return;
        }

        let html = '';
        data.items.forEach((item, index) => {
            const total = item.itemTotal + item.vatAmount;
            const statusBadge = getReturnStatusBadge(item.status);

            html += `
                <tr>
                    <td class="text-center">${index + 1}</td>
                    <td><span class="text-blue-600 font-medium">${item.returnId}</span></td>
                    <td><code class="text-xs bg-gray-100 px-2 py-1 rounded">${item.sku}</code></td>
                    <td>${item.name}</td>
                    <td class="text-center">
                        <span class="px-2 py-1 bg-orange-100 text-orange-700 rounded text-sm font-medium">${item.qty}</span>
                    </td>
                    <td class="text-right">${formatVATMoney(item.unitPrice)}</td>
                    <td class="text-right font-medium">${formatVATMoney(item.itemTotal)}</td>
                    <td class="text-center">
                        ${item.vatRate > 0 ? `<span class="px-2 py-1 bg-green-100 text-green-700 rounded text-sm font-medium">${item.vatRate}%</span>` : '<span class="text-gray-400">-</span>'}
                    </td>
                    <td class="text-right ${item.vatAmount > 0 ? 'text-green-600 font-medium' : 'text-gray-400'}">${formatVATMoney(item.vatAmount)}</td>
                    <td class="text-right font-bold text-red-600">${formatVATMoney(total)}</td>
                    <td class="text-center">${statusBadge}</td>
                </tr>
            `;
        });

        tbody.innerHTML = html;

        // Update footer
        document.getElementById('vat-returns-total-amount').textContent = formatVATMoney(data.summary.totalAmount);
        document.getElementById('vat-returns-total-vat').textContent = formatVATMoney(data.summary.totalVAT);
        document.getElementById('vat-returns-grand-total').textContent = formatVATMoney(data.summary.grandTotal);
        footer.style.display = '';
    }

    /**
     * Get return status badge
     */
    function getReturnStatusBadge(status) {
        const badges = {
            'Requested': '<span class="px-2 py-1 bg-yellow-100 text-yellow-700 rounded text-xs">Chờ duyệt</span>',
            'Approved': '<span class="px-2 py-1 bg-blue-100 text-blue-700 rounded text-xs">Đã duyệt</span>',
            'Completed': '<span class="px-2 py-1 bg-green-100 text-green-700 rounded text-xs">Hoàn thành</span>',
            'Rejected': '<span class="px-2 py-1 bg-red-100 text-red-700 rounded text-xs">Từ chối</span>'
        };
        return badges[status] || '<span class="px-2 py-1 bg-gray-100 text-gray-700 rounded text-xs">N/A</span>';
    }

    /**
     * Load Daily VAT Summary
     */
    function loadDailyVATSummary() {
        console.log('📊 Loading Daily VAT Summary...');

        const dateFromValue = document.getElementById('daily-vat-date-from').value;
        const dateToValue = document.getElementById('daily-vat-date-to').value;

        if (!dateFromValue || !dateToValue) {
            showToast('Vui lòng chọn khoảng thời gian', 'warning');
            return;
        }

        const dateFrom = new Date(dateFromValue);
        const dateTo = new Date(dateToValue);
        dateFrom.setHours(0, 0, 0, 0);
        dateTo.setHours(23, 59, 59, 999);

        const filters = {
            productSku: document.getElementById('daily-vat-product-filter').value || null,
            customerId: document.getElementById('daily-vat-customer-filter').value || null,
            orderStatus: document.getElementById('daily-vat-status-filter').value || null,
            vatRate: document.getElementById('daily-vat-rate-filter').value || null
        };

        showLoading('Đang tải báo cáo...');

        google.script.run
            .withSuccessHandler(renderDailyVATSummary)
            .withFailureHandler(function (error) {
                console.error('❌ Error:', error);
                hideLoading();
                showToast('Lỗi: ' + error.message, 'error');
            })
            .getAdvancedVATSummary(dateFrom.getTime(), dateTo.getTime(), filters);
    }

    /**
     * Render Daily VAT Summary
     */
    function renderDailyVATSummary(data) {
        console.log('✅ Data received:', data);
        hideLoading();

        if (!data || !data.success) {
            showToast('Không thể tải báo cáo: ' + (data?.message || ''), 'error');
            return;
        }

        currentDailyVATData = data;

        // Render overview stats
        document.getElementById('daily-vat-total-orders').textContent = data.overview?.totalOrders || 0;
        document.getElementById('daily-vat-orders-with').textContent = data.overview?.ordersWithVAT || 0;
        document.getElementById('daily-vat-orders-without').textContent = data.overview?.ordersWithoutVAT || 0;
        document.getElementById('daily-vat-mixed-orders').textContent = data.overview?.mixedOrders || 0;

        // Render financial stats
        const financial = data.financial || {};
        document.getElementById('vat-revenue-before').textContent = formatVATMoney(financial.revenueBeforeVAT || 0);
        document.getElementById('vat-revenue-after').textContent = formatVATMoney(financial.revenueAfterVAT || 0);
        document.getElementById('vat-total-tax').textContent = formatVATMoney(financial.totalVATAmount || 0);

        // Render comparison
        const comparePercent = financial.comparePercent;
        const compareEl = document.getElementById('vat-compare-percent');
        const compareBadge = document.getElementById('vat-compare-badge');
        if (comparePercent !== undefined && comparePercent !== null) {
            const isPositive = comparePercent >= 0;
            compareEl.textContent = (isPositive ? '+' : '') + comparePercent.toFixed(1) + '%';
            compareBadge.textContent = isPositive ? '↑ Tăng' : '↓ Giảm';
        } else {
            compareEl.textContent = '--';
            compareBadge.textContent = 'So sánh';
        }

        // Render VAT by rate breakdown
        const rateBreakdown = data.rateBreakdown || {};
        ['0', '5', '8', '10'].forEach(rate => {
            const rateData = rateBreakdown[rate] || { amount: 0, count: 0 };
            document.getElementById(`vat-rate-${rate}`).textContent = formatVATMoney(rateData.amount);
            document.getElementById(`vat-rate-${rate}-count`).textContent = rateData.count;
        });

        // Render warnings
        renderVATWarnings(data.warnings || []);

        // Render tables
        renderProductTable(data.products || []);
        renderInvoiceTable(data.invoices || []);
        renderMixedOrdersTable(data.mixedOrdersList || []);

        showToast('Đã tải báo cáo thành công', 'success');
    }

    /**
     * Render VAT Warnings
     */
    function renderVATWarnings(warnings) {
        const section = document.getElementById('vat-warnings-section');
        const textEl = document.getElementById('vat-warning-text');

        if (!warnings || warnings.length === 0) {
            section.classList.add('hidden');
            return;
        }

        section.classList.remove('hidden');
        textEl.textContent = `Có ${warnings.length} đơn hàng chưa xuất hóa đơn VAT quá 3 ngày`;
    }

    /**
     * Render Product Table
     */
    function renderProductTable(products) {
        const tbody = document.getElementById('daily-vat-product-table');

        if (!products || products.length === 0) {
            tbody.innerHTML = '<tr><td colspan="8" class="text-center text-gray-500 py-8">Không có sản phẩm nào</td></tr>';
            return;
        }

        tbody.innerHTML = products.map(p => `
            <tr>
                <td><code>${p.sku}</code></td>
                <td>${p.name}</td>
                <td class="text-center text-green-600 font-semibold">${p.qtyWithVAT || 0}</td>
                <td class="text-center text-red-600">${p.qtyWithoutVAT || 0}</td>
                <td class="text-center font-bold">${p.total || 0}</td>
                <td class="text-right">${formatVATMoney(p.revenueVAT || 0)}</td>
                <td class="text-right text-orange-600">${formatVATMoney(p.taxAmount || 0)}</td>
                <td class="text-center">
                    <span class="badge-modern ${(p.percentageVAT || 0) >= 50 ? 'badge-success' : 'badge-warning'}">
                        ${(p.percentageVAT || 0).toFixed(1)}%
                    </span>
                </td>
            </tr>
        `).join('');
    }

    /**
     * Render Invoice Table
     */
    function renderInvoiceTable(invoices) {
        const tbody = document.getElementById('vat-invoice-table');
        document.getElementById('vat-invoice-count').textContent = invoices?.length || 0;

        if (!invoices || invoices.length === 0) {
            tbody.innerHTML = '<tr><td colspan="10" class="text-center text-gray-500 py-8">Chưa có hóa đơn VAT</td></tr>';
            return;
        }

        tbody.innerHTML = invoices.map((inv, idx) => `
            <tr>
                <td class="text-center">${idx + 1}</td>
                <td><strong>${inv.orderId}</strong></td>
                <td>${inv.date || '--'}</td>
                <td>${inv.customerName || 'Khách lẻ'}</td>
                <td><code>${inv.taxCode || '--'}</code></td>
                <td class="text-right">${formatVATMoney(inv.amountBeforeVAT || 0)}</td>
                <td class="text-right text-orange-600">${formatVATMoney(inv.vatAmount || 0)}</td>
                <td class="text-right font-bold">${formatVATMoney(inv.totalAmount || 0)}</td>
                <td class="text-center">
                    <span class="badge-modern ${inv.invoiceStatus === 'Đã xuất' ? 'badge-success' : 'badge-warning'}">
                        ${inv.invoiceStatus || 'Chưa xuất'}
                    </span>
                </td>
                <td class="text-center">
                    <button onclick="viewOrderDetail('${inv.orderId}')" class="text-blue-600 hover:text-blue-800 text-sm">
                        <i class="fas fa-eye"></i>
                    </button>
                </td>
            </tr>
        `).join('');
    }

    /**
     * Render Mixed Orders Table
     */
    function renderMixedOrdersTable(orders) {
        const tbody = document.getElementById('daily-vat-mixed-orders-table');

        if (!orders || orders.length === 0) {
            tbody.innerHTML = '<tr><td colspan="9" class="text-center text-gray-500 py-8">Không có đơn hàng hỗn hợp</td></tr>';
            return;
        }

        tbody.innerHTML = orders.map(o => `
            <tr>
                <td><strong>${o.orderId}</strong></td>
                <td>${o.customerName || 'Khách lẻ'}</td>
                <td>${o.date || '--'}</td>
                <td class="text-center">${o.totalItems || 0}</td>
                <td class="text-center text-green-600">${o.itemsWithVAT || 0}</td>
                <td class="text-center text-red-600">${o.itemsWithoutVAT || 0}</td>
                <td class="text-right">${formatVATMoney(o.amountWithVAT || 0)}</td>
                <td class="text-right">${formatVATMoney(o.amountWithoutVAT || 0)}</td>
                <td>
                    <span class="badge-modern badge-warning">
                        <i class="fas fa-exclamation-triangle"></i> Hỗn hợp
                    </span>
                </td>
            </tr>
        `).join('');
    }

    /**
     * Render VAT Charts
     */
    function renderVATCharts(data) {
        if (typeof Chart === 'undefined') {
            lazyLoadLib('chart').then(function() { renderVATCharts(data); });
            return;
        }

        // Trend Chart
        const trendCtx = document.getElementById('vat-trend-chart');
        if (trendCtx && data.trendData) {
            if (vatTrendChart) vatTrendChart.destroy();
            vatTrendChart = new Chart(trendCtx, {
                type: 'line',
                data: {
                    labels: data.trendData.labels || [],
                    datasets: [{
                        label: 'Tiền Thuế VAT',
                        data: data.trendData.values || [],
                        borderColor: '#8b5cf6',
                        backgroundColor: 'rgba(139, 92, 246, 0.1)',
                        fill: true,
                        tension: 0.4
                    }]
                },
                options: {
                    responsive: true,
                    maintainAspectRatio: false,
                    plugins: {
                        legend: { display: false }
                    },
                    scales: {
                        y: {
                            beginAtZero: true,
                            ticks: {
                                callback: function(value) {
                                    return new Intl.NumberFormat('vi-VN', { notation: 'compact' }).format(value);
                                }
                            }
                        }
                    }
                }
            });
        }

        // Pie Chart
        const pieCtx = document.getElementById('vat-pie-chart');
        if (pieCtx && data.rateBreakdown) {
            if (vatPieChart) vatPieChart.destroy();
            const rateData = data.rateBreakdown;
            vatPieChart = new Chart(pieCtx, {
                type: 'doughnut',
                data: {
                    labels: ['VAT 0%', 'VAT 5%', 'VAT 8%', 'VAT 10%'],
                    datasets: [{
                        data: [
                            rateData['0']?.amount || 0,
                            rateData['5']?.amount || 0,
                            rateData['8']?.amount || 0,
                            rateData['10']?.amount || 0
                        ],
                        backgroundColor: ['#9ca3af', '#3b82f6', '#10b981', '#8b5cf6']
                    }]
                },
                options: {
                    responsive: true,
                    maintainAspectRatio: false
                }
            });
        }

        // Product Chart
        const productCtx = document.getElementById('vat-product-chart');
        if (productCtx && data.products) {
            if (vatProductChart) vatProductChart.destroy();
            const topProducts = (data.products || []).slice(0, 10);
            vatProductChart = new Chart(productCtx, {
                type: 'bar',
                data: {
                    labels: topProducts.map(p => p.name?.substring(0, 20) || p.sku),
                    datasets: [{
                        label: 'Tiền Thuế VAT',
                        data: topProducts.map(p => p.taxAmount || 0),
                        backgroundColor: '#8b5cf6'
                    }]
                },
                options: {
                    responsive: true,
                    maintainAspectRatio: false,
                    indexAxis: 'y',
                    plugins: {
                        legend: { display: false }
                    },
                    scales: {
                        x: {
                            beginAtZero: true,
                            ticks: {
                                callback: function(value) {
                                    return new Intl.NumberFormat('vi-VN', { notation: 'compact' }).format(value);
                                }
                            }
                        }
                    }
                }
            });
        }
    }

