    /**
     * Export to PDF
     */
    function exportDailyVATToPDF() {
        if (!currentDailyVATData) {
            showToast('Vui lòng tải báo cáo trước khi xuất', 'warning');
            return;
        }
        // Lazy-load jsPDF + html2canvas
        if (typeof html2canvas === 'undefined' || typeof jspdf === 'undefined') {
            showToast('Đang tải thư viện PDF...', 'info');
            lazyLoadLibs(['jspdf', 'html2canvas']).then(function() { exportDailyVATToPDF(); }).catch(function() { showToast('Không thể tải thư viện PDF', 'error'); });
            return;
        }

        showLoading('Đang tạo file PDF...');

        const element = document.getElementById('page-daily-vat-summary');

        html2canvas(element, { scale: 2 }).then(canvas => {
            const imgData = canvas.toDataURL('image/jpeg', 0.98);
            const pdf = new jspdf.jsPDF('p', 'mm', 'a4');
            const imgWidth = 190;
            const pageHeight = 277;
            const imgHeight = canvas.height * imgWidth / canvas.width;
            let heightLeft = imgHeight;
            let position = 10;

            pdf.addImage(imgData, 'JPEG', 10, position, imgWidth, imgHeight);
            heightLeft -= pageHeight;

            while (heightLeft >= 0) {
                position = heightLeft - imgHeight + 10;
                pdf.addPage();
                pdf.addImage(imgData, 'JPEG', 10, position, imgWidth, imgHeight);
                heightLeft -= pageHeight;
            }

            const fileName = `TongKetVAT_${currentDailyVATData.date}.pdf`;
            pdf.save(fileName);
            hideLoading();
            showToast('Đã xuất file PDF thành công!', 'success');
        }).catch(err => {
            hideLoading();
            showToast('Lỗi xuất PDF: ' + err.message, 'error');
        });
    }


    // --- EXPORT FUNCTIONS ---

    function exportToVNPTExcel() {
        const dateStr = document.getElementById('daily-vat-date').value;
        if (!dateStr) {
            showToast('Vui lòng chọn ngày!', 'warning');
            return;
        }

        showLoading(true);
        google.script.run
            .withSuccessHandler(function (response) {
                showLoading(false);
                if (response && response.success) {
                    if (!response.data || response.data.length === 0) {
                        showToast('Không có dữ liệu xuất VAT cho ngày này!', 'warning');
                        return;
                    }
                    downloadVNPTExcel(response.data, response.date);
                } else {
                    showToast('Lỗi: ' + (response ? response.message : 'Unknown error'), 'error');
                }
            })
            .withFailureHandler(function (err) {
                showLoading(false);
                console.error('Error exporting VNPT data:', err);
                showToast('Lỗi kết nối server!', 'error');
            })
            .getVNPTExportData(dateStr);
    }

    function downloadVNPTExcel(data, dateStr) {
        // VNPT Standard Columns
        // FKey, MaKH, TenKH, DiaChi, MaSoThue, DienGiai, MaHang, TenHang, DVT, SoLuong, DonGia, ThanhTien, ThueSuat, TienThue, TongTien
        const headers = [
            'STT',
            'Ngày chứng từ',
            'Số chứng từ',
            'Tên người mua',
            'Mã số thuế',
            'Địa chỉ',
            'Email',
            'Sản phẩm',
            'Đơn vị tính',
            'Số lượng',
            'Đơn giá',
            'Thành tiền',
            'Thuế suất (%)',
            'Tiền thuế',
            'Tổng cộng',
            'Ghi chú'
        ];

        // Creates CSV content with BOM for Excel
        let csvContent = '\uFEFF' + headers.join(',') + '\n';

        data.forEach((row, index) => {
            const csvRow = [
                index + 1,
                row.date,
                row.orderId,
                escapeCSV(row.customerName),
                escapeCSV(row.taxCode),
                escapeCSV(row.address),
                escapeCSV(row.email),
                escapeCSV(row.productName),
                escapeCSV(row.unit),
                row.qty,
                row.price,
                row.amount,
                row.vatRate,
                (row.amount * row.vatRate / 100), // VAT Amount
                (row.amount * (1 + row.vatRate / 100)), // Total
                escapeCSV(row.note)
            ];
            csvContent += csvRow.join(',') + '\n';
        });

        // Create download link
        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement("a");
        link.setAttribute("href", url);
        link.setAttribute("download", `VNPT_Import_${dateStr.replace(/\//g, '-')}.csv`);
        link.style.visibility = 'hidden';
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    }

    function escapeCSV(str) {
        if (str === null || str === undefined) return '';
        str = String(str);
        if (str.includes(',') || str.includes('"') || str.includes('\n')) {
            return '"' + str.replace(/"/g, '""') + '"';
        }
        return str;
    }

    /**
     * Initialize page
     */
    function initDailyVATSummaryPage() {
        console.log('🚀 Init Daily VAT Summary Page');

        // Set default date range to today
        const today = new Date();
        const formatDate = (date) => {
            const year = date.getFullYear();
            const month = String(date.getMonth() + 1).padStart(2, '0');
            const day = String(date.getDate()).padStart(2, '0');
            return `${year}-${month}-${day}`;
        };

        document.getElementById('daily-vat-date-from').value = formatDate(today);
        document.getElementById('daily-vat-date-to').value = formatDate(today);

        // Load filter options
        loadDailyVATFilterOptions();

        // Auto load data
        loadDailyVATSummary();
    }

    /**
     * Load filter options
     */
    function loadDailyVATFilterOptions() {
        google.script.run
            .withSuccessHandler(function (data) {
                if (data && data.success) {
                    // Populate product dropdown
                    const productSelect = document.getElementById('daily-vat-product-filter');
                    productSelect.innerHTML = '<option value="">-- Tất cả sản phẩm --</option>';
                    (data.products || []).forEach(p => {
                        productSelect.innerHTML += `<option value="${p.sku}">${p.name} (${p.sku})</option>`;
                    });

                    // Populate customer dropdown
                    const customerSelect = document.getElementById('daily-vat-customer-filter');
                    customerSelect.innerHTML = '<option value="">-- Tất cả khách hàng --</option>';
                    (data.customers || []).forEach(c => {
                        customerSelect.innerHTML += `<option value="${c.id}">${c.name}</option>`;
                    });
                }
            })
            .withFailureHandler(function (err) {
                console.error('Error loading filter options:', err);
            })
            .getVATReportFilterOptions();
    }

