    // ============================================
    // CUSTOM EXPORT MODAL FUNCTIONS
    // ============================================

    /**
     * Show custom export modal
     */
    function showCustomExportModal() {
        const modal = document.getElementById('custom-export-modal');

        // Set default dates from main filters
        document.getElementById('custom-export-date-from').value = document.getElementById('daily-vat-date-from').value;
        document.getElementById('custom-export-date-to').value = document.getElementById('daily-vat-date-to').value;

        // Setup save template checkbox listener
        const saveTemplateCheckbox = document.getElementById('save-export-template');
        const templateNameInput = document.getElementById('export-template-name');
        saveTemplateCheckbox.onchange = function() {
            templateNameInput.classList.toggle('hidden', !this.checked);
        };

        modal.classList.remove('hidden');
    }

    /**
     * Close custom export modal
     */
    function closeCustomExportModal() {
        document.getElementById('custom-export-modal').classList.add('hidden');
    }

    /**
     * Set custom export period
     */
    function setCustomExportPeriod(period) {
        const today = new Date();
        let fromDate, toDate;

        switch(period) {
            case 'thisMonth':
                fromDate = new Date(today.getFullYear(), today.getMonth(), 1);
                toDate = today;
                break;
            case 'lastMonth':
                fromDate = new Date(today.getFullYear(), today.getMonth() - 1, 1);
                toDate = new Date(today.getFullYear(), today.getMonth(), 0);
                break;
            case 'thisQuarter':
                const quarter = Math.floor(today.getMonth() / 3);
                fromDate = new Date(today.getFullYear(), quarter * 3, 1);
                toDate = today;
                break;
            case 'thisYear':
                fromDate = new Date(today.getFullYear(), 0, 1);
                toDate = today;
                break;
        }

        const formatDate = (d) => d.getFullYear() + '-' + String(d.getMonth() + 1).padStart(2, '0') + '-' + String(d.getDate()).padStart(2, '0');
        document.getElementById('custom-export-date-from').value = formatDate(fromDate);
        document.getElementById('custom-export-date-to').value = formatDate(toDate);
    }

    /**
     * Select all export columns
     */
    function selectAllExportCols() {
        document.querySelectorAll('.export-col').forEach(cb => cb.checked = true);
    }

    /**
     * Deselect all export columns
     */
    function deselectAllExportCols() {
        document.querySelectorAll('.export-col').forEach(cb => cb.checked = false);
    }

    /**
     * Execute custom export
     */
    function executeCustomExport() {
        const reportType = document.querySelector('input[name="report-type"]:checked').value;
        const dateFrom = document.getElementById('custom-export-date-from').value;
        const dateTo = document.getElementById('custom-export-date-to').value;
        const format = document.querySelector('input[name="export-format"]:checked').value;
        const selectedCols = Array.from(document.querySelectorAll('.export-col:checked')).map(cb => cb.value);

        if (!dateFrom || !dateTo) {
            showToast('Vui lòng chọn khoảng thời gian', 'warning');
            return;
        }

        if (selectedCols.length === 0) {
            showToast('Vui lòng chọn ít nhất một cột dữ liệu', 'warning');
            return;
        }

        showLoading('Đang xuất báo cáo...');

        // Fetch data and export
        google.script.run
            .withSuccessHandler(function(data) {
                hideLoading();
                if (data && data.success) {
                    generateCustomReport(data, reportType, format, selectedCols);

                    // Save template if checked
                    if (document.getElementById('save-export-template').checked) {
                        const templateName = document.getElementById('export-template-name').value;
                        if (templateName) {
                            saveExportTemplate(templateName, { reportType, selectedCols, format });
                        }
                    }

                    closeCustomExportModal();
                } else {
                    showToast('Lỗi: ' + (data?.message || 'Không thể tải dữ liệu'), 'error');
                }
            })
            .withFailureHandler(function(err) {
                hideLoading();
                showToast('Lỗi: ' + err.message, 'error');
            })
            .getAdvancedVATSummary(new Date(dateFrom).getTime(), new Date(dateTo + 'T23:59:59').getTime(), {});
    }

    /**
     * Generate custom report based on type and format
     */
    function generateCustomReport(data, reportType, format, selectedCols) {
        let exportData;
        let fileName = 'BaoCaoVAT';

        switch(reportType) {
            case 'summary':
                exportData = buildSummaryReport(data, selectedCols);
                fileName += '_TongHop';
                break;
            case 'by-customer':
                exportData = buildCustomerReport(data, selectedCols);
                fileName += '_TheoKhachHang';
                break;
            case 'by-product':
                exportData = buildProductReport(data, selectedCols);
                fileName += '_TheoSanPham';
                break;
            case 'comparison':
                exportData = buildComparisonReport(data, selectedCols);
                fileName += '_SoSanh';
                break;
        }

        fileName += `_${toLocalDateStr()}`;

        switch(format) {
            case 'xlsx':
                exportToExcelFormat(exportData, fileName);
                break;
            case 'csv':
                exportToCSVFormat(exportData, fileName);
                break;
            case 'pdf':
                exportToPDFFormat(exportData, fileName);
                break;
            case 'json':
                downloadFile(JSON.stringify(exportData, null, 2), fileName + '.json', 'application/json');
                break;
        }

        showToast('Đã xuất báo cáo thành công!', 'success');
        addExportHistory(format.toUpperCase(), `Báo cáo ${reportType}`);
    }

    function buildSummaryReport(data, cols) {
        return {
            title: 'Báo Cáo Tổng Hợp VAT',
            overview: data.overview,
            financial: data.financial,
            rateBreakdown: data.rateBreakdown,
            columns: cols
        };
    }

    function buildCustomerReport(data, cols) {
        // Group by customer
        const customerData = {};
        (data.invoices || []).forEach(inv => {
            const custId = inv.customerId || 'unknown';
            if (!customerData[custId]) {
                customerData[custId] = {
                    name: inv.customerName || 'Khách lẻ',
                    taxCode: inv.taxCode || '',
                    totalOrders: 0,
                    totalAmount: 0,
                    totalVAT: 0
                };
            }
            customerData[custId].totalOrders++;
            customerData[custId].totalAmount += inv.amountBeforeVAT || 0;
            customerData[custId].totalVAT += inv.vatAmount || 0;
        });

        return {
            title: 'Báo Cáo VAT Theo Khách Hàng',
            data: Object.values(customerData),
            columns: cols
        };
    }

    function buildProductReport(data, cols) {
        return {
            title: 'Báo Cáo VAT Theo Sản Phẩm',
            data: data.products || [],
            columns: cols
        };
    }

    function buildComparisonReport(data, cols) {
        return {
            title: 'Báo Cáo So Sánh',
            current: data.financial,
            previous: data.previousPeriod || {},
            columns: cols
        };
    }

    function exportToExcelFormat(data, fileName) {
        if (typeof XLSX === 'undefined') {
            showToast('Đang tải thư viện Excel, vui lòng thử lại...', 'info');
            lazyLoadLib('xlsx');
            return;
        }

        const wb = XLSX.utils.book_new();
        const sheetData = [[data.title], ['Ngày xuất:', new Date().toLocaleDateString('vi-VN')], []];

        if (data.data) {
            // Add headers
            const headers = Object.keys(data.data[0] || {});
            sheetData.push(headers);
            // Add rows
            data.data.forEach(row => {
                sheetData.push(headers.map(h => row[h]));
            });
        } else if (data.overview) {
            sheetData.push(['Tổng đơn hàng', data.overview.totalOrders]);
            sheetData.push(['Đơn có VAT', data.overview.ordersWithVAT]);
            sheetData.push(['Đơn không VAT', data.overview.ordersWithoutVAT]);
        }

        const ws = XLSX.utils.aoa_to_sheet(sheetData);
        XLSX.utils.book_append_sheet(wb, ws, 'Báo Cáo');
        XLSX.writeFile(wb, fileName + '.xlsx');
    }

    function exportToCSVFormat(data, fileName) {
        let csv = '\uFEFF' + data.title + '\n\n';

        if (data.data && data.data.length > 0) {
            const headers = Object.keys(data.data[0]);
            csv += headers.join(',') + '\n';
            data.data.forEach(row => {
                csv += headers.map(h => escapeCSV(row[h])).join(',') + '\n';
            });
        }

        downloadFile(csv, fileName + '.csv', 'text/csv;charset=utf-8;');
    }

    function exportToPDFFormat(data, fileName) {
        showToast('Đang tạo PDF...', 'info');
        if (typeof jspdf === 'undefined') {
            lazyLoadLibs(['jspdf', 'html2canvas']).then(function() { exportToPDFFormat(data, fileName); }).catch(function() { showToast('Không thể tải thư viện PDF', 'error'); });
            return;
        }

        const pdf = new jspdf.jsPDF();
        pdf.setFontSize(16);
        pdf.text(data.title, 20, 20);
        pdf.setFontSize(10);
        pdf.text('Ngày xuất: ' + new Date().toLocaleDateString('vi-VN'), 20, 30);

        let y = 50;
        if (data.overview) {
            pdf.text('Tổng đơn hàng: ' + data.overview.totalOrders, 20, y);
            y += 10;
            pdf.text('Đơn có VAT: ' + data.overview.ordersWithVAT, 20, y);
            y += 10;
            pdf.text('Đơn không VAT: ' + data.overview.ordersWithoutVAT, 20, y);
        }

        pdf.save(fileName + '.pdf');
    }

    // ============================================
    // SCHEDULE EXPORT MODAL FUNCTIONS
    // ============================================

    let exportSchedules = JSON.parse(localStorage.getItem('vatExportSchedules') || '[]');

    /**
     * Show schedule export modal
     */
    function showScheduleExportModal() {
        const modal = document.getElementById('schedule-export-modal');
        renderActiveSchedules();
        modal.classList.remove('hidden');
    }

    /**
     * Close schedule export modal
     */
    function closeScheduleExportModal() {
        document.getElementById('schedule-export-modal').classList.add('hidden');
    }

    /**
     * Save schedule export
     */
    function saveScheduleExport() {
        const freq = document.querySelector('input[name="schedule-freq"]:checked').value;
        const hour = document.getElementById('schedule-hour').value;
        const day = document.getElementById('schedule-day').value;
        const reportType = document.getElementById('schedule-report-type').value;
        const email = document.getElementById('schedule-email').value;
        const format = document.querySelector('input[name="schedule-format"]:checked').value;

        if (!email) {
            showToast('Vui lòng nhập email nhận báo cáo', 'warning');
            return;
        }

        const schedule = {
            id: Date.now(),
            frequency: freq,
            hour: hour,
            day: day,
            reportType: reportType,
            email: email,
            format: format,
            createdAt: new Date().toISOString(),
            active: true
        };

        exportSchedules.push(schedule);
        localStorage.setItem('vatExportSchedules', JSON.stringify(exportSchedules));

        // Register with backend
        google.script.run
            .withSuccessHandler(function(result) {
                if (result.success) {
                    showToast('Đã lưu lịch xuất báo cáo!', 'success');
                    renderActiveSchedules();
                } else {
                    showToast('Lỗi: ' + result.message, 'error');
                }
            })
            .withFailureHandler(function(err) {
                showToast('Lỗi: ' + err.message, 'error');
            })
            .saveVATExportSchedule(schedule);
    }

    /**
     * Render active schedules
     */
    function renderActiveSchedules() {
        const container = document.getElementById('active-schedules-list');

        if (exportSchedules.length === 0) {
            container.innerHTML = '<div class="text-gray-500 italic">Chưa có lịch xuất nào</div>';
            return;
        }

        const freqLabels = { daily: 'Hàng ngày', weekly: 'Hàng tuần', monthly: 'Hàng tháng', quarterly: 'Hàng quý' };
        const reportLabels = { 'vat-summary': 'Tổng kết VAT', 'vat-invoices': 'Hóa đơn VAT', 'vat-inventory': 'Tồn kho VAT', 'vat-declaration': 'Tờ khai thuế' };

        container.innerHTML = exportSchedules.map(s => `
            <div class="flex items-center justify-between p-2 bg-white rounded border ${s.active ? 'border-green-200' : 'border-gray-200'}">
                <div>
                    <div class="font-medium">${reportLabels[s.reportType] || s.reportType}</div>
                    <div class="text-xs text-gray-500">${freqLabels[s.frequency]} lúc ${s.hour}:00 → ${s.email}</div>
                </div>
                <div class="flex gap-2">
                    <button onclick="toggleSchedule(${s.id})" class="text-xs px-2 py-1 rounded ${s.active ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-600'}">
                        ${s.active ? 'Hoạt động' : 'Tắt'}
                    </button>
                    <button onclick="deleteSchedule(${s.id})" class="text-xs px-2 py-1 bg-red-100 text-red-600 rounded hover:bg-red-200">
                        <i class="fas fa-trash"></i>
                    </button>
                </div>
            </div>
        `).join('');
    }

    /**
     * Toggle schedule active state
     */
    function toggleSchedule(id) {
        const schedule = exportSchedules.find(s => s.id === id);
        if (schedule) {
            schedule.active = !schedule.active;
            localStorage.setItem('vatExportSchedules', JSON.stringify(exportSchedules));
            renderActiveSchedules();
        }
    }

    /**
     * Delete schedule
     */
    function deleteSchedule(id) {
        exportSchedules = exportSchedules.filter(s => s.id !== id);
        localStorage.setItem('vatExportSchedules', JSON.stringify(exportSchedules));
        renderActiveSchedules();
        showToast('Đã xóa lịch xuất', 'success');
    }

    // ============================================
    // EXPORT HISTORY & TEMPLATES
    // ============================================

    let exportHistory = JSON.parse(localStorage.getItem('vatExportHistory') || '[]');
    let exportTemplates = JSON.parse(localStorage.getItem('vatExportTemplates') || '[]');

    /**
     * Add export to history
     */
    function addExportHistory(format, description) {
        exportHistory.unshift({
            id: Date.now(),
            format: format,
            description: description,
            date: new Date().toISOString(),
            user: 'Current User'
        });

        // Keep only last 50 records
        if (exportHistory.length > 50) {
            exportHistory = exportHistory.slice(0, 50);
        }

        localStorage.setItem('vatExportHistory', JSON.stringify(exportHistory));
    }

    /**
     * Show export history modal
     */
    function showExportHistory() {
        const modal = document.getElementById('export-history-modal');
        const list = document.getElementById('export-history-list');

        if (exportHistory.length === 0) {
            list.innerHTML = '<div class="text-gray-500 text-center py-8">Chưa có lịch sử xuất file</div>';
        } else {
            list.innerHTML = exportHistory.map(h => `
                <div class="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                    <div class="flex items-center gap-3">
                        <div class="w-10 h-10 rounded-full flex items-center justify-center ${h.format === 'Excel' ? 'bg-green-100 text-green-600' : h.format === 'PDF' ? 'bg-red-100 text-red-600' : h.format === 'CSV' ? 'bg-blue-100 text-blue-600' : 'bg-purple-100 text-purple-600'}">
                            <i class="fas ${h.format === 'Excel' ? 'fa-file-excel' : h.format === 'PDF' ? 'fa-file-pdf' : h.format === 'CSV' ? 'fa-file-csv' : 'fa-file-code'}"></i>
                        </div>
                        <div>
                            <div class="font-medium">${h.description}</div>
                            <div class="text-xs text-gray-500">${new Date(h.date).toLocaleString('vi-VN')}</div>
                        </div>
                    </div>
                    <span class="px-2 py-1 bg-gray-200 text-gray-700 text-xs rounded">${h.format}</span>
                </div>
            `).join('');
        }

        modal.classList.remove('hidden');
    }

    /**
     * Close export history modal
     */
    function closeExportHistoryModal() {
        document.getElementById('export-history-modal').classList.add('hidden');
    }

    /**
     * Save export template
     */
    function saveExportTemplate(name, config) {
        exportTemplates.push({
            id: Date.now(),
            name: name,
            config: config,
            createdAt: new Date().toISOString()
        });
        localStorage.setItem('vatExportTemplates', JSON.stringify(exportTemplates));
        showToast('Đã lưu mẫu báo cáo: ' + name, 'success');
    }

    /**
     * Show export templates modal
     */
    function showExportTemplates() {
        const modal = document.getElementById('export-templates-modal');
        const list = document.getElementById('export-templates-list');

        if (exportTemplates.length === 0) {
            list.innerHTML = '<div class="text-gray-500 text-center py-8">Chưa có mẫu báo cáo nào được lưu</div>';
        } else {
            list.innerHTML = exportTemplates.map(t => `
                <div class="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                    <div>
                        <div class="font-medium">${t.name}</div>
                        <div class="text-xs text-gray-500">Tạo: ${new Date(t.createdAt).toLocaleDateString('vi-VN')}</div>
                    </div>
                    <div class="flex gap-2">
                        <button onclick="useExportTemplate(${t.id})" class="btn-modern btn-primary-modern text-xs">
                            <i class="fas fa-play mr-1"></i> Sử dụng
                        </button>
                        <button onclick="deleteExportTemplate(${t.id})" class="btn-modern btn-danger-modern text-xs">
                            <i class="fas fa-trash"></i>
                        </button>
                    </div>
                </div>
            `).join('');
        }

        modal.classList.remove('hidden');
    }

    /**
     * Close export templates modal
     */
    function closeExportTemplatesModal() {
        document.getElementById('export-templates-modal').classList.add('hidden');
    }

    /**
     * Use export template
     */
    function useExportTemplate(id) {
        const template = exportTemplates.find(t => t.id === id);
        if (template) {
            closeExportTemplatesModal();
            showCustomExportModal();

            // Apply template config
            const config = template.config;
            document.querySelector(`input[name="report-type"][value="${config.reportType}"]`).checked = true;
            document.querySelector(`input[name="export-format"][value="${config.format}"]`).checked = true;

            document.querySelectorAll('.export-col').forEach(cb => {
                cb.checked = config.selectedCols.includes(cb.value);
            });
        }
    }

    /**
     * Delete export template
     */
    function deleteExportTemplate(id) {
        exportTemplates = exportTemplates.filter(t => t.id !== id);
        localStorage.setItem('vatExportTemplates', JSON.stringify(exportTemplates));
        showExportTemplates();
        showToast('Đã xóa mẫu báo cáo', 'success');
    }

    // ============================================
    // UTILITY FUNCTIONS
    // ============================================

    /**
     * Download file helper
     */
    function downloadFile(content, filename, mimeType) {
        const blob = new Blob([content], { type: mimeType });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        link.download = filename;
        link.style.display = 'none';
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        URL.revokeObjectURL(url);
    }



