/**
 * Load velocity dashboard data
 */
function loadVelocityDashboard() {
    google.script.run
        .withSuccessHandler((res) => {
            if (res && res.success && res.data) {
                renderVelocityDashboard(res.data);
            } else {
                document.getElementById('velocity-dashboard-content').innerHTML =
                    '<p class="text-sm text-red-500">Không thể tải dữ liệu</p>';
            }
        })
        .withFailureHandler((err) => {
            console.error('Error loading velocity dashboard:', err);
            document.getElementById('velocity-dashboard-content').innerHTML =
                '<p class="text-sm text-red-500">Lỗi: ' + err.toString() + '</p>';
        })
        .apiHandler('getVelocityDashboard', null);
}

/**
 * Render velocity dashboard widget
 */
function renderVelocityDashboard(data) {
    const container = document.getElementById('velocity-dashboard-content');
    if (!container) return;

    const { summary, alerts } = data;

    let html = '';

    // Summary stats
    html += '<div class="grid grid-cols-3 gap-3 mb-4">';
    html += `
        <div class="bg-white bg-opacity-60 rounded-lg p-3 text-center">
            <div class="text-2xl font-bold text-red-600">${summary.criticalCount || 0}</div>
            <div class="text-xs text-gray-600">🔴 Khẩn cấp</div>
        </div>
        <div class="bg-white bg-opacity-60 rounded-lg p-3 text-center">
            <div class="text-2xl font-bold text-yellow-600">${summary.warningCount || 0}</div>
            <div class="text-xs text-gray-600">🟡 Cảnh báo</div>
        </div>
        <div class="bg-white bg-opacity-60 rounded-lg p-3 text-center">
            <div class="text-2xl font-bold text-green-600">${summary.safeCount || 0}</div>
            <div class="text-xs text-gray-600">🟢 An toàn</div>
        </div>
    `;
    html += '</div>';

    // Alerts list
    if (alerts && alerts.length > 0) {
        html += '<div class="space-y-2">';
        html += '<h4 class="text-sm font-semibold text-gray-700 mb-2">Sản phẩm cần chú ý:</h4>';

        alerts.slice(0, 5).forEach(alert => {
            const icon = alert.alertLevel === 'red' ? '🔴' : '🟡';
            const bgColor = alert.alertLevel === 'red' ? 'bg-red-50' : 'bg-yellow-50';
            const textColor = alert.alertLevel === 'red' ? 'text-red-800' : 'text-yellow-800';

            html += `
                <div class="${bgColor} rounded-lg p-3 flex items-center justify-between">
                    <div class="flex-1">
                        <div class="font-medium ${textColor}">${icon} ${alert.productName || alert.sku}</div>
                        <div class="text-xs text-gray-600">
                            Tồn: ${alert.currentStock} | 
                            Tốc độ: ${alert.velocity ? alert.velocity.toFixed(1) : 0} cái/ngày |
                            Hết trong: ${alert.daysUntilStockOut} ngày
                        </div>
                    </div>
                    <button onclick="showProductVelocityDetail('${alert.sku}')" 
                        class="text-xs px-2 py-1 bg-white rounded hover:bg-gray-100">
                        Chi tiết
                    </button>
                </div>
            `;
        });

        html += '</div>';

        if (alerts.length > 5) {
            html += `<p class="text-xs text-gray-500 mt-2">... và ${alerts.length - 5} sản phẩm khác</p>`;
        }
    } else {
        html += '<p class="text-sm text-green-600">✅ Tất cả sản phẩm đều ở mức an toàn</p>';
    }

    container.innerHTML = html;
}

/**
 * Show product velocity detail modal
 */
function showProductVelocityDetail(sku) {
    google.script.run
        .withSuccessHandler((res) => {
            if (res && res.success && res.data) {
                renderProductVelocityModal(res.data);
            } else {
                alert('Không thể tải dữ liệu sản phẩm');
            }
        })
        .withFailureHandler((err) => {
            alert('Lỗi: ' + err.toString());
        })
        .apiHandler('getProductVelocity', { sku: sku, days: 7 });
}

/**
 * Render product velocity detail modal
 */
function renderProductVelocityModal(data) {
    const { velocity, stockOut, trend, reorder } = data;

    const modalHtml = `
        <div id="velocity-modal" class="fixed inset-0 bg-black bg-opacity-50 z-50 flex items-center justify-center p-4">
            <div class="bg-white rounded-xl shadow-2xl max-w-2xl w-full max-h-[90vh] overflow-y-auto">
                <div class="p-6">
                    <div class="flex justify-between items-center mb-4">
                        <h2 class="text-2xl font-bold text-gray-900">📊 Phân Tích Tốc Độ Bán</h2>
                        <button onclick="closeVelocityModal()" class="text-gray-400 hover:text-gray-600">
                            <svg class="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M6 18L18 6M6 6l12 12"></path>
                            </svg>
                        </button>
                    </div>
                    
                    <div class="space-y-4">
                        <!-- Product Info -->
                        <div class="bg-gray-50 rounded-lg p-4">
                            <h3 class="font-semibold text-gray-900 mb-2">${stockOut.productName}</h3>
                            <p class="text-sm text-gray-600">SKU: ${stockOut.sku}</p>
                        </div>
                        
                        <!-- Velocity Stats -->
                        <div class="grid grid-cols-2 gap-4">
                            <div class="bg-blue-50 rounded-lg p-4">
                                <div class="text-sm text-gray-600">Tốc Độ Bán (7 ngày)</div>
                                <div class="text-2xl font-bold text-blue-600">${trend.velocity7Days.toFixed(1)} cái/ngày</div>
                            </div>
                            <div class="bg-purple-50 rounded-lg p-4">
                                <div class="text-sm text-gray-600">Tốc Độ Bán (30 ngày)</div>
                                <div class="text-2xl font-bold text-purple-600">${trend.velocity30Days.toFixed(1)} cái/ngày</div>
                            </div>
                        </div>
                        
                        <!-- Trend -->
                        <div class="bg-gradient-to-r from-green-50 to-emerald-50 rounded-lg p-4 border border-green-200">
                            <div class="flex items-center justify-between">
                                <div>
                                    <div class="text-sm text-gray-600">Xu Hướng</div>
                                    <div class="text-lg font-semibold ${trend.trendDirection === 'increasing' ? 'text-green-600' : trend.trendDirection === 'decreasing' ? 'text-red-600' : 'text-gray-600'}">
                                        ${trend.trendDirection === 'increasing' ? '📈 Tăng' : trend.trendDirection === 'decreasing' ? '📉 Giảm' : '➡️ Ổn định'}
                                        ${Math.abs(trend.trendPercent).toFixed(1)}%
                                    </div>
                                </div>
                            </div>
                        </div>
                        
                        <!-- Stock Status -->
                        <div class="bg-${stockOut.alertLevel === 'red' ? 'red' : stockOut.alertLevel === 'yellow' ? 'yellow' : 'green'}-50 rounded-lg p-4 border border-${stockOut.alertLevel === 'red' ? 'red' : stockOut.alertLevel === 'yellow' ? 'yellow' : 'green'}-200">
                            <div class="grid grid-cols-2 gap-4">
                                <div>
                                    <div class="text-sm text-gray-600">Tồn Kho Hiện Tại</div>
                                    <div class="text-2xl font-bold">${stockOut.currentStock} cái</div>
                                </div>
                                <div>
                                    <div class="text-sm text-gray-600">Dự Kiến Hết Hàng</div>
                                    <div class="text-2xl font-bold ${stockOut.alertLevel === 'red' ? 'text-red-600' : stockOut.alertLevel === 'yellow' ? 'text-yellow-600' : 'text-green-600'}">
                                        ${stockOut.daysUntilStockOut} ngày
                                    </div>
                                </div>
                            </div>
                        </div>
                        
                        <!-- Reorder Recommendation -->
                        <div class="bg-orange-50 rounded-lg p-4 border border-orange-200">
                            <h4 class="font-semibold text-gray-900 mb-2">💡 Đề Xuất Nhập Hàng</h4>
                            <div class="space-y-2 text-sm">
                                <div class="flex justify-between">
                                    <span class="text-gray-600">Điểm đặt lại:</span>
                                    <span class="font-semibold">${reorder.reorderPoint} cái</span>
                                </div>
                                <div class="flex justify-between">
                                    <span class="text-gray-600">Nên nhập:</span>
                                    <span class="font-semibold ${reorder.shouldReorder ? 'text-orange-600' : 'text-green-600'}">
                                        ${reorder.shouldReorder ? '⚠️ Ngay bây giờ' : '✅ Chưa cần'}
                                    </span>
                                </div>
                                ${reorder.shouldReorder ? `
                                <div class="flex justify-between">
                                    <span class="text-gray-600">Số lượng đề xuất:</span>
                                    <span class="font-semibold text-orange-600">${reorder.recommendedOrderQty} cái</span>
                                </div>
                                ` : ''}
                            </div>
                        </div>
                    </div>
                    
                    <div class="mt-6 flex gap-2">
                        <button onclick="closeVelocityModal()" class="flex-1 px-4 py-2 bg-gray-100 text-gray-700 rounded-lg hover:bg-gray-200">
                            Đóng
                        </button>
                        ${reorder.shouldReorder ? `
                        <button onclick="createPurchaseFromVelocity('${stockOut.sku}', ${reorder.recommendedOrderQty})" 
                            class="flex-1 px-4 py-2 bg-orange-600 text-white rounded-lg hover:bg-orange-700">
                            📦 Tạo Phiếu Nhập
                        </button>
                        ` : ''}
                    </div>
                </div>
            </div>
        </div>
    `;

    document.body.insertAdjacentHTML('beforeend', modalHtml);
}

/**
 * Close velocity modal
 */
function closeVelocityModal() {
    const modal = document.getElementById('velocity-modal');
    if (modal) {
        modal.remove();
    }
}

/**
 * Create purchase order from velocity recommendation
 */
function createPurchaseFromVelocity(sku, qty) {
    closeVelocityModal();
    // Navigate to purchase page and pre-fill
    showPage('purchases');
    setTimeout(() => {
        showPurchaseModal();
        // TODO: Pre-fill purchase form with SKU and qty
    }, 500);
}

