/**
 * FRONTEND_WARRANTY.JS
 * Frontend functions for Warranty Management Widget
 */

/**
 * Load warranty dashboard widget
 */
function loadWarrantyDashboard() {
    const container = document.getElementById('warranty-dashboard-content');
    if (!container) return;

    container.innerHTML = '<p class="text-sm text-gray-400">Đang tải thông tin bảo hành...</p>';

    google.script.run
        .withSuccessHandler((res) => {
            if (res && res.success && res.data) {
                renderWarrantyDashboard(res.data);
            } else {
                container.innerHTML = '<p class="text-sm text-red-500">Không thể tải dữ liệu bảo hành</p>';
            }
        })
        .withFailureHandler((err) => {
            container.innerHTML = '<p class="text-sm text-red-500">Lỗi: ' + (err.message || err) + '</p>';
        })
        .apiHandler('getWarrantyStatistics', null);
}

/**
 * Render warranty dashboard widget
 */
function renderWarrantyDashboard(stats) {
    const container = document.getElementById('warranty-dashboard-content');
    if (!container) return;

    let html = '';

    // Summary stats grid
    html += '<div class="grid grid-cols-2 md:grid-cols-4 gap-3 mb-4">';
    
    // Total warranties
    html += `
        <div class="bg-white bg-opacity-70 rounded-lg p-3 text-center border border-blue-200">
            <div class="text-2xl font-bold text-blue-600">${stats.total || 0}</div>
            <div class="text-xs text-gray-600 mt-1">Tổng Phiếu BH</div>
        </div>
    `;

    // Expiring soon
    html += `
        <div class="bg-white bg-opacity-70 rounded-lg p-3 text-center border border-orange-200">
            <div class="text-2xl font-bold text-orange-600">${stats.expiringSoon || 0}</div>
            <div class="text-xs text-gray-600 mt-1">Sắp Hết Hạn</div>
        </div>
    `;

    // Expired
    html += `
        <div class="bg-white bg-opacity-70 rounded-lg p-3 text-center border border-red-200">
            <div class="text-2xl font-bold text-red-600">${stats.expired || 0}</div>
            <div class="text-xs text-gray-600 mt-1">Đã Hết Hạn</div>
        </div>
    `;

    // Total requests
    html += `
        <div class="bg-white bg-opacity-70 rounded-lg p-3 text-center border border-purple-200">
            <div class="text-2xl font-bold text-purple-600">${stats.totalRequests || 0}</div>
            <div class="text-xs text-gray-600 mt-1">Yêu Cầu BH</div>
        </div>
    `;
    
    html += '</div>';

    // Status breakdown
    if (stats.byStatus && Object.keys(stats.byStatus).length > 0) {
        html += '<div class="mb-4">';
        html += '<h4 class="text-sm font-semibold text-gray-700 mb-2">Trạng Thái Bảo Hành</h4>';
        html += '<div class="space-y-2">';
        
        Object.entries(stats.byStatus).forEach(([status, count]) => {
            const statusColors = {
                'Mới': 'bg-blue-100 text-blue-700',
                'Đang xử lý': 'bg-yellow-100 text-yellow-700',
                'Hoàn thành': 'bg-green-100 text-green-700',
                'Từ chối': 'bg-red-100 text-red-700',
                'Hết hạn': 'bg-gray-100 text-gray-700'
            };
            const colorClass = statusColors[status] || 'bg-gray-100 text-gray-700';
            
            html += `
                <div class="flex justify-between items-center p-2 bg-white bg-opacity-60 rounded ${colorClass}">
                    <span class="text-sm">${status}</span>
                    <span class="text-sm font-bold">${count}</span>
                </div>
            `;
        });
        
        html += '</div>';
        html += '</div>';
    }

    // Pending requests alert
    if (stats.requestsByStatus && stats.requestsByStatus['Chờ xử lý']) {
        const pendingCount = stats.requestsByStatus['Chờ xử lý'];
        if (pendingCount > 0) {
            html += `
                <div class="bg-yellow-50 border border-yellow-200 rounded-lg p-3 mb-4">
                    <div class="flex items-center gap-2">
                        <svg class="w-5 h-5 text-yellow-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z"></path>
                        </svg>
                        <div>
                            <p class="text-sm font-semibold text-yellow-800">Có ${pendingCount} yêu cầu bảo hành đang chờ xử lý</p>
                            <p class="text-xs text-yellow-600">Vui lòng kiểm tra và xử lý sớm</p>
                        </div>
                    </div>
                </div>
            `;
        }
    }

    // Expiring soon alert
    if (stats.expiringSoon > 0) {
        html += `
            <div class="bg-orange-50 border border-orange-200 rounded-lg p-3">
                <div class="flex items-center gap-2">
                    <svg class="w-5 h-5 text-orange-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z"></path>
                    </svg>
                    <div>
                        <p class="text-sm font-semibold text-orange-800">${stats.expiringSoon} phiếu bảo hành sắp hết hạn</p>
                        <p class="text-xs text-orange-600">Trong vòng 30 ngày tới</p>
                    </div>
                </div>
            </div>
        `;
    }

    // Total cost if available
    if (stats.totalCost > 0) {
        html += `
            <div class="mt-4 pt-4 border-t border-gray-200">
                <div class="flex justify-between items-center">
                    <span class="text-sm text-gray-600">Tổng Chi Phí Bảo Hành:</span>
                    <span class="text-sm font-bold text-gray-900">${formatMoney(stats.totalCost)}</span>
                </div>
            </div>
        `;
    }

    // Quick actions
    html += `
        <div class="mt-4 pt-4 border-t border-gray-200">
            <div class="flex gap-2">
                <button onclick="showWarrantyManagement()" 
                    class="flex-1 text-sm px-3 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition">
                    Quản Lý Bảo Hành
                </button>
                <button onclick="sendWarrantyEmailAlert()" 
                    class="flex-1 text-sm px-3 py-2 bg-orange-600 text-white rounded-lg hover:bg-orange-700 transition">
                    Gửi Email Cảnh Báo
                </button>
            </div>
        </div>
    `;

    container.innerHTML = html;
}

/**
 * Show warranty management page
 */
function showWarrantyManagement() {
    // Navigate to warranty page if exists, otherwise show alert
    if (typeof showPage === 'function') {
        // Try to show warranty page
        const warrantyPage = document.getElementById('page-warranty');
        if (warrantyPage) {
            showPage('warranty');
        } else {
            alert('Trang quản lý bảo hành đang được phát triển. Vui lòng sử dụng API để quản lý bảo hành.');
        }
    } else {
        alert('Tính năng quản lý bảo hành đang được phát triển.');
    }
}

/**
 * Send warranty expiration email alert
 */
function sendWarrantyEmailAlert() {
    if (!confirm('Bạn có muốn gửi email cảnh báo cho các phiếu bảo hành sắp hết hạn (30 ngày) không?')) {
        return;
    }

    const container = document.getElementById('warranty-dashboard-content');
    const originalContent = container.innerHTML;
    container.innerHTML = '<p class="text-sm text-gray-400">Đang gửi email...</p>';

    google.script.run
        .withSuccessHandler((res) => {
            if (res && res.success) {
                alert(`Đã gửi email cảnh báo cho ${res.data.sent || 0} phiếu bảo hành!`);
                loadWarrantyDashboard(); // Reload dashboard
            } else {
                alert('Lỗi: ' + (res.message || 'Không thể gửi email'));
                container.innerHTML = originalContent;
            }
        })
        .withFailureHandler((err) => {
            alert('Lỗi: ' + (err.message || err));
            container.innerHTML = originalContent;
        })
        .apiHandler('sendWarrantyExpirationEmails', { days: 30 });
}

/**
 * Format money (VND)
 */
function formatMoney(amount) {
    if (typeof amount !== 'number') return '0 ₫';
    return new Intl.NumberFormat('vi-VN', {
        style: 'currency',
        currency: 'VND'
    }).format(amount);
}


